(** * Public theorem bundle for the extracted Cadeque9 fast surface.

    This is a Gate-D proof bundle for the current catenable experiment.
    It does not claim the full catenable release gate is closed: the
    Buf6-to-KTDeque refinement and operation-level cost proof are still
    separate obligations.  The bundle records the mechanically checked
    facts already available for the exact extracted [kcad9_*_fast]
    family, including the new boundary-element invariant that makes
    pop/eject total under non-empty public states.

    The final theorems are a narrower bridge to the hand-edited OCaml
    KCadeque9 implementation: they cover the list semantics of the
    [StoredMiddle9]-based normalizer/refill/concat shape, including the
    fuel-parameterized pop/eject wrappers that call those refills.  They also
    prove those exact wrappers total under [inv_kcad9_public] and preserve the
    weaker OCaml non-empty-boundary invariant when they return.  The bundle
    now names a depth-indexed OCaml-ready surface carrying base boundaries plus
    front/back middle readiness, plus the more reachable empty-or-ready variant
    that admits triples with an empty middle.  Push/inject preserve that
    empty-or-ready surface, and the exact OCaml-shaped concat now preserves it
    at the same depth by splitting one cell off the back of the right middle
    before storing the remaining right-middle spine.  The empty-or-ready
    surface also proves exact fuelled pop/eject totality and weak-boundary
    preservation with [S depth] fuel; the stricter ready surface remains the
    one used for non-empty replacement-boundary exposure.  It also includes
    the first one-step normalization cases, depth-indexed nested-middle
    exposure, and refill-wrapper bounded-fuel exposure under that same
    depth-indexed premise.  It also
    exposes the T+T concat readiness fact that this scheduled split preserves
    the right middle's explicit back-readiness depth, plus a small
    arbitrary-depth family proving that shallower readiness depths are still
    insufficient.
    It also adds a deep XBase-only invariant for the [StoredMiddle9]-capable
    OCaml shape and proves that push/inject/concat, the fuelled normalizers,
    refills, and pop/eject wrappers preserve it; this is the totality-ready
    half needed before the ready-depth surface can become a full reachable
    invariant.  The bundle now packages those two halves as an explicit
    reachable-depth invariant: push/inject/concat preserve it, and pop/eject
    preserve the full reachable-depth invariant in the no-refill branches where
    the drained boundary remains at size at least 5.  The present-boundary
    pop/eject refill branches now preserve the full reachable-depth invariant
    while the scheduled middle expansion runs.  General pop/eject are proved
    total and return states that still satisfy the weak boundary and
    deep-XBase halves.  Full preservation of the current ready-depth scheduler
    across the empty-boundary refill branches is not just unproved: this bundle
    records concrete pop/eject counterexamples showing that
    [inv_kcad9_ocaml_reachable_depth] can refill from an empty boundary to a
    result whose exposed middle edge is not ready at the same depth.  Gate D
    therefore needs a strengthened scheduler invariant or a revised refill
    shape before the reachable-state constant-fuel/cost proof can close.
    These theorems intentionally do not claim the full reachable-state
    constant-fuel invariant or cost proof.  The bundle also records a
    counterexample for the tempting direct-[StoredBig9] concat shape, which
    preserves constant shape but puts the right deque's middle before its head
    boundary.  The current bounded-middle-depth slice also proves that the
    normalizer/refill/pop/eject path preserves nested [StoredMiddle9] depth
    with an explicit [fuel + S depth] bump.  That is useful accounting, not the
    final Gate-D invariant: the release proof still needs a representation or
    scheduler argument that collapses this fuel-indexed bump to a uniform
    constant for reachable states.  The follow-up exposure-aware
    [inv_kcad9_ocaml_refill_depth_bound] predicate makes refill/pop/eject
    same-depth again; concat preserves it with an explicit split budget where
    the right operand is one exposure level shallower than the result. *)

From Stdlib Require Import List Lia.
Import ListNotations.

From KTDeque.Buffer6 Require Import SizedBuffer SmallMoves.
From KTDeque.Cadeque9 Require Import Model Ops OpsFast WFStrong WFInvariant Normalize.

Theorem empty_kcad9_inv_public_thm :
  forall X : Type, inv_kcad9_public (@kcad9_empty X).
Proof. apply empty_kcad9_inv_public. Qed.

Theorem singleton_kcad9_inv_public_thm :
  forall (X : Type) (x : X), inv_kcad9_public (kcad9_singleton x).
Proof. apply singleton_kcad9_inv_public. Qed.

Theorem kcad9_inv_public_wf_strong_thm :
  forall (X : Type) (k : KCadeque9 X),
    inv_kcad9_public k -> wf_kcad9_strong k.
Proof. apply inv_kcad9_public_wf_strong. Qed.

Theorem kcad9_push_fast_seq_thm :
  forall (X : Type) (x : X) (k : KCadeque9 X),
    kcad9_to_list (kcad9_push_fast x k) = x :: kcad9_to_list k.
Proof. apply kcad9_push_fast_seq. Qed.

Theorem kcad9_inject_fast_seq_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    kcad9_to_list (kcad9_inject_fast k x) = kcad9_to_list k ++ [x].
Proof. apply kcad9_inject_fast_seq. Qed.

Theorem kcad9_concat_fast_seq_thm :
  forall (X : Type) (a b : KCadeque9 X),
    kcad9_to_list (kcad9_concat_fast a b) =
    kcad9_to_list a ++ kcad9_to_list b.
Proof. apply kcad9_concat_fast_seq. Qed.

Theorem kcad9_pop_fast_seq_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X) (k' : KCadeque9 X),
    kcad9_pop_fast k = PopOk9 x k' ->
    kcad9_to_list k = x :: kcad9_to_list k'.
Proof. apply kcad9_pop_fast_seq. Qed.

Theorem kcad9_eject_fast_seq_thm :
  forall (X : Type) (k : KCadeque9 X) (k' : KCadeque9 X) (x : X),
    kcad9_eject_fast k = EjectOk9 k' x ->
    kcad9_to_list k = kcad9_to_list k' ++ [x].
Proof. apply kcad9_eject_fast_seq. Qed.

