Theorem kcad9_pop_fast_total_under_inv_public_thm :
  forall (X : Type) (k : KCadeque9 X),
    inv_kcad9_public k ->
    k <> K9Empty ->
    exists x k', kcad9_pop_fast k = PopOk9 x k'.
Proof. apply kcad9_pop_fast_total_under_inv_public. Qed.

Theorem kcad9_eject_fast_total_under_inv_public_thm :
