         (m : Buf6 (Stored9 X)) (t : Buf6 (KElem9 X)),
    buf6_size_ge 1 h' ->
    buf6_size_ge 1 t ->
    inv_kcad9_ocaml_boundaries (refill_h_K9Triple_fuel fuel h' m t).
Proof. apply refill_h_K9Triple_fuel_inv_boundaries_present. Qed.

Theorem refill_t_K9Triple_fuel_inv_boundaries_present_thm :
  forall (fuel : nat) (X : Type) (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X)) (t' : Buf6 (KElem9 X)),
    buf6_size_ge 1 h ->
    buf6_size_ge 1 t' ->
    inv_kcad9_ocaml_boundaries (refill_t_K9Triple_fuel fuel h m t').
Proof. apply refill_t_K9Triple_fuel_inv_boundaries_present. Qed.

Theorem kcad9_pop_ocaml_shape_fuel_total_under_inv_public_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_public k ->
    k <> K9Empty ->
    exists x k', kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k').
Proof.
  intros fuel X [|b|h m t] Hinv Hne; [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_pop_xbase9 X b Hb Hxb) as [x [b' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [Hh [_ [Hxh _]]].
    assert (Hh1 : buf6_size_ge 1 h).
    { eapply buf6_size_ge_weaken; [|exact Hh]. lia. }
    destruct (buf6_pop_xbase9 X h Hh1 Hxh) as [x [h' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (Nat.leb 5 (buf6_size h')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_total_under_inv_public_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_public k ->
    k <> K9Empty ->
    exists k' x, kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x).
Proof.
  intros fuel X [|b|h m t] Hinv Hne; [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_eject_xbase9 X b Hb Hxb) as [b' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [_ [Ht [_ [Hxt _]]]].
    assert (Ht1 : buf6_size_ge 1 t).
    { eapply buf6_size_ge_weaken; [|exact Ht]. lia. }
    destruct (buf6_eject_xbase9 X t Ht1 Hxt) as [t' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (Nat.leb 5 (buf6_size t')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_inv_boundaries_under_inv_public_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_public k ->
    kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k') ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros fuel X [|b|h m t] x k' Hinv Hpop;
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
  - discriminate.
  - destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Hpop as Hx Hk'; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Ht [_ [_ [_ _]]]]].
    destruct (buf6_pop h) as [[e h']|] eqn:Hph; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    assert (Hh'4 : buf6_size_ge 4 h').
    { unfold buf6_size_ge in Hh |- *.
      apply buf6_pop_size_some in Hph. lia. }
    assert (Hh'1 : buf6_size_ge 1 h').
    { eapply buf6_size_ge_weaken; [|exact Hh'4]. lia. }
    assert (Ht1 : buf6_size_ge 1 t).
    { eapply buf6_size_ge_weaken; [|exact Ht]. lia. }
    destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp;
      injection Hpop as Hx Hk'; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries]. split; assumption.
    + apply refill_h_K9Triple_fuel_inv_boundaries_present; assumption.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_inv_boundaries_under_inv_public_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_public k ->
    kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x) ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros fuel X [|b|h m t] k' x Hinv Heject;
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
  - discriminate.
  - destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Heject as Hk' Hx; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Ht [_ [_ [_ _]]]]].
    destruct (buf6_eject t) as [[t' e]|] eqn:Het; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    assert (Ht'4 : buf6_size_ge 4 t').
    { unfold buf6_size_ge in Ht |- *.
      apply buf6_eject_size_some in Het. lia. }
    assert (Ht'1 : buf6_size_ge 1 t').
    { eapply buf6_size_ge_weaken; [|exact Ht'4]. lia. }
    assert (Hh1 : buf6_size_ge 1 h).
    { eapply buf6_size_ge_weaken; [|exact Hh]. lia. }
    destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp;
      injection Heject as Hk' Hx; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries]. split; assumption.
    + apply refill_t_K9Triple_fuel_inv_boundaries_present; assumption.
Qed.

Definition inv_kcad9_ocaml_ready_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Empty =>
      True
  | K9Simple b =>
      buf6_size_ge 1 b /\ all_xbase9 b
  | K9Triple h m t =>
      buf6_size_ge 1 h /\
      all_xbase9 h /\
      buf6_size_ge 1 t /\
      all_xbase9 t /\
      front_ready_middle9_depth depth m /\
      back_ready_middle9_depth depth m
  end.

Definition inv_kcad9_ocaml_ready_or_empty_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Empty =>
      True
  | K9Simple b =>
      buf6_size_ge 1 b /\ all_xbase9 b
  | K9Triple h m t =>
      buf6_size_ge 1 h /\
      all_xbase9 h /\
      buf6_size_ge 1 t /\
      all_xbase9 t /\
      front_ready_or_empty_middle9_depth depth m /\
      back_ready_or_empty_middle9_depth depth m
  end.

Definition inv_kcad9_ocaml_reachable_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_ready_or_empty_depth depth k /\
  inv_kcad9_ocaml_deep_xbase k.

Fixpoint stored_middle_depth_le {X : Type}
  (depth : nat) (s : Stored9 X) {struct s} : Prop :=
  match s with
  | StoredSmall9 _ =>
      True
  | StoredBig9 _ sm _ =>
      (fix go (l : list (Stored9 X)) : Prop :=
         match l with
         | [] => True
         | s' :: ss => stored_middle_depth_le depth s' /\ go ss
         end) (buf6_elems sm)
  | StoredMiddle9 sm =>
      match depth with
      | O => False
      | S depth' =>
          (fix go (l : list (Stored9 X)) : Prop :=
             match l with
             | [] => True
             | s' :: ss => stored_middle_depth_le depth' s' /\ go ss
             end) (buf6_elems sm)
      end
  end.

Definition middle9_depth_le {X : Type}
  (depth : nat) (m : Buf6 (Stored9 X)) : Prop :=
  (fix go (l : list (Stored9 X)) : Prop :=
     match l with
     | [] => True
     | s :: ss => stored_middle_depth_le depth s /\ go ss
     end) (buf6_elems m).

Definition inv_kcad9_ocaml_middle_depth_bound {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Empty => True
  | K9Simple _ => True
  | K9Triple _ m _ => middle9_depth_le depth m
  end.

Fixpoint stored_refill_depth_le {X : Type}
  (depth : nat) (s : Stored9 X) {struct s} : Prop :=
  match s with
  | StoredSmall9 _ =>
      True
  | StoredBig9 _ sm _ =>
      match depth with
      | O => buf6_is_empty sm = true
      | S depth' =>
          (fix go (l : list (Stored9 X)) : Prop :=
             match l with
             | [] => True
             | s' :: ss => stored_refill_depth_le depth' s' /\ go ss
             end) (buf6_elems sm)
      end
  | StoredMiddle9 sm =>
      match depth with
      | O => False
      | S depth' =>
          (fix go (l : list (Stored9 X)) : Prop :=
             match l with
             | [] => True
             | s' :: ss => stored_refill_depth_le depth' s' /\ go ss
             end) (buf6_elems sm)
      end
  end.

Definition middle9_refill_depth_le {X : Type}
  (depth : nat) (m : Buf6 (Stored9 X)) : Prop :=
  (fix go (l : list (Stored9 X)) : Prop :=
     match l with
     | [] => True
     | s :: ss => stored_refill_depth_le depth s /\ go ss
     end) (buf6_elems m).

Definition inv_kcad9_ocaml_refill_depth_bound {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Empty => True
  | K9Simple _ => True
  | K9Triple _ m _ => middle9_refill_depth_le depth m
  end.

Lemma stored_middle_depth_le_small :
