Lemma stored_middle_depth_le_succ :
  forall (depth : nat) (X : Type) (s : Stored9 X),
    stored_middle_depth_le depth s ->
    stored_middle_depth_le (S depth) s.
Proof.
  fix IH 3.
  intros depth X [b|pre [xs] suf|[xs]] Hs;
    cbn [stored_middle_depth_le buf6_elems] in *.
  - exact I.
  - induction xs as [|cell rest IHxs]; cbn in *.
    + exact I.
    + destruct Hs as [Hcell Hrest].
      split.
      * apply IH. exact Hcell.
      * apply IHxs. exact Hrest.
  - destruct depth as [|depth']; [contradiction|].
    induction xs as [|cell rest IHxs]; cbn in *.
    + exact I.
    + destruct Hs as [Hcell Hrest].
      split.
      * apply IH. exact Hcell.
      * apply IHxs. exact Hrest.
Qed.

