      * exact I.
      * destruct Hs as [Hcell Hrest].
        split.
        -- apply stored_middle_depth_le_succ.
           apply IH. exact Hcell.
        -- apply IHxs. exact Hrest.
  - destruct depth as [|depth']; [contradiction|].
    destruct sm as [xs]. cbn [buf6_elems] in *.
    induction xs as [|cell rest IHxs]; cbn in *.
    + exact I.
    + destruct Hs as [Hcell Hrest].
