Definition front_refill_residual_ready_middle9_depth {X : Type}
  (depth : nat) (m : Buf6 (Stored9 X)) : Prop :=
  match buf6_pop m with
  | None => True
  | Some (StoredSmall9 b, m_rest) =>
      buf6_size_ge 1 b /\
      front_ready_or_empty_middle9_depth depth m_rest
  | Some (StoredBig9 pre sm suf, m_rest) =>
      buf6_size_ge 1 pre /\
      front_ready_or_empty_middle9_depth depth
        (k9_middle_push sm (buf6_push (StoredSmall9 suf) m_rest))
  | Some (StoredMiddle9 sm, m_rest) =>
      front_ready_or_empty_middle9_depth depth (k9_middle_push sm m_rest)
  end.

Definition back_refill_residual_ready_middle9_depth {X : Type}
  (depth : nat) (m : Buf6 (Stored9 X)) : Prop :=
  match buf6_eject m with
  | None => True
  | Some (m_rest, StoredSmall9 b) =>
      back_ready_or_empty_middle9_depth depth m_rest /\
      buf6_size_ge 1 b
  | Some (m_rest, StoredBig9 pre sm suf) =>
      back_ready_or_empty_middle9_depth depth
        (k9_middle_inject
          (buf6_inject m_rest (StoredSmall9 pre))
          sm) /\
      buf6_size_ge 1 suf
  | Some (m_rest, StoredMiddle9 sm) =>
      back_ready_or_empty_middle9_depth depth (k9_middle_inject m_rest sm)
  end.

Definition kcad9_ocaml_refill_residual_ready_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Triple _ m _ =>
      front_refill_residual_ready_middle9_depth depth m /\
      back_refill_residual_ready_middle9_depth depth m
  | _ => True
  end.

Definition inv_kcad9_ocaml_residual_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_reachable_depth depth k /\
  kcad9_ocaml_refill_residual_ready_depth depth k.

Fixpoint front_refill_continuation_ready_middle9_fuel {X : Type}
  (fuel depth : nat) (m : Buf6 (Stored9 X)) {struct fuel} : Prop :=
  front_ready_or_empty_middle9_depth depth m /\
  match fuel with
  | O => True
  | S fuel' =>
      match buf6_pop m with
      | None => True
      | Some (StoredSmall9 b, m_rest) =>
          buf6_size_ge 1 b /\
          front_refill_continuation_ready_middle9_fuel fuel' depth m_rest
      | Some (StoredBig9 pre sm suf, m_rest) =>
          buf6_size_ge 1 pre /\
          front_refill_continuation_ready_middle9_fuel fuel' depth
            (k9_middle_push sm (buf6_push (StoredSmall9 suf) m_rest))
      | Some (StoredMiddle9 sm, m_rest) =>
          match buf6_pop sm with
          | None =>
              front_refill_continuation_ready_middle9_fuel fuel' depth m_rest
          | Some (front_cell, sm_rest) =>
              front_refill_continuation_ready_middle9_fuel fuel' depth
                (buf6_push front_cell (k9_middle_push sm_rest m_rest))
          end
      end
  end.

Fixpoint back_refill_continuation_ready_middle9_fuel {X : Type}
  (fuel depth : nat) (m : Buf6 (Stored9 X)) {struct fuel} : Prop :=
  back_ready_or_empty_middle9_depth depth m /\
  match fuel with
  | O => True
  | S fuel' =>
      match buf6_eject m with
      | None => True
      | Some (m_rest, StoredSmall9 b) =>
          back_refill_continuation_ready_middle9_fuel fuel' depth m_rest /\
          buf6_size_ge 1 b
      | Some (m_rest, StoredBig9 pre sm suf) =>
          back_refill_continuation_ready_middle9_fuel fuel' depth
            (k9_middle_inject
              (buf6_inject m_rest (StoredSmall9 pre))
              sm) /\
          buf6_size_ge 1 suf
      | Some (m_rest, StoredMiddle9 sm) =>
          match buf6_eject sm with
          | None =>
              back_refill_continuation_ready_middle9_fuel fuel' depth m_rest
          | Some (sm_rest, back_cell) =>
              back_refill_continuation_ready_middle9_fuel fuel' depth
                (buf6_inject (k9_middle_inject m_rest sm_rest) back_cell)
          end
      end
  end.

Definition kcad9_ocaml_refill_continuation_ready_fuel_depth {X : Type}
  (fuel depth : nat) (k : KCadeque9 X) : Prop :=
  match k with
  | K9Triple _ m _ =>
      front_refill_continuation_ready_middle9_fuel fuel depth m /\
      back_refill_continuation_ready_middle9_fuel fuel depth m
  | _ => True
  end.

Definition inv_kcad9_ocaml_continuation_depth {X : Type}
  (fuel depth : nat) (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_reachable_depth depth k /\
  kcad9_ocaml_refill_continuation_ready_fuel_depth fuel depth k.

Definition front_refill_step_middle9 {X : Type}
  (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)) : Buf6 (Stored9 X) :=
  match cell with
  | StoredSmall9 b =>
      buf6_push (StoredSmall9 b) m_rest
  | StoredBig9 pre sm suf =>
      buf6_push (StoredSmall9 pre)
        (k9_middle_push sm
          (buf6_push (StoredSmall9 suf) m_rest))
  | StoredMiddle9 sm =>
      k9_middle_push sm m_rest
  end.

Definition back_refill_step_middle9 {X : Type}
  (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X) : Buf6 (Stored9 X) :=
  match cell with
  | StoredSmall9 b =>
      buf6_inject m_rest (StoredSmall9 b)
  | StoredBig9 pre sm suf =>
      buf6_inject
        (k9_middle_inject
          (buf6_inject m_rest (StoredSmall9 pre))
          sm)
        (StoredSmall9 suf)
  | StoredMiddle9 sm =>
      k9_middle_inject m_rest sm
  end.

Definition front_normalize_step_middle9 {X : Type}
  (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)) : Buf6 (Stored9 X) :=
  match cell with
  | StoredSmall9 _ =>
      m_rest
  | StoredBig9 _ sm suf =>
      k9_middle_push sm (buf6_push (StoredSmall9 suf) m_rest)
  | StoredMiddle9 sm =>
      match buf6_pop sm with
      | Some (front_cell, sm_rest) =>
          buf6_push front_cell (k9_middle_push sm_rest m_rest)
      | None =>
          m_rest
      end
  end.

Definition back_normalize_step_middle9 {X : Type}
  (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X) : Buf6 (Stored9 X) :=
  match cell with
  | StoredSmall9 _ =>
      m_rest
  | StoredBig9 pre sm _ =>
      k9_middle_inject (buf6_inject m_rest (StoredSmall9 pre)) sm
  | StoredMiddle9 sm =>
      match buf6_eject sm with
      | Some (sm_rest, back_cell) =>
          buf6_inject (k9_middle_inject m_rest sm_rest) back_cell
      | None =>
          m_rest
      end
  end.

Lemma middle9_refill_depth_le_front_refill_step :
  forall (depth : nat) (X : Type)
         (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)),
    stored_refill_depth_le depth cell ->
    middle9_refill_depth_le depth m_rest ->
    middle9_refill_depth_le depth (front_refill_step_middle9 cell m_rest).
Proof.
  intros depth X [b|pre sm suf|sm] m_rest Hcell Hrest;
    cbn [front_refill_step_middle9] in *.
  - apply middle9_refill_depth_le_push;
      [apply stored_refill_depth_le_small|exact Hrest].
  - destruct depth as [|depth'].
    + unfold k9_middle_push. rewrite Hcell.
      apply middle9_refill_depth_le_push.
      * apply stored_refill_depth_le_small.
      * apply middle9_refill_depth_le_push;
          [apply stored_refill_depth_le_small|exact Hrest].
    + apply middle9_refill_depth_le_push.
      * apply stored_refill_depth_le_small.
      * apply middle9_refill_depth_le_k9_middle_push.
        -- exact Hcell.
        -- apply middle9_refill_depth_le_push;
             [apply stored_refill_depth_le_small|exact Hrest].
  - destruct depth as [|depth']; [contradiction|].
    apply middle9_refill_depth_le_k9_middle_push; assumption.
Qed.

Lemma middle9_refill_depth_le_back_refill_step :
  forall (depth : nat) (X : Type)
         (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    middle9_refill_depth_le depth m_rest ->
    stored_refill_depth_le depth cell ->
    middle9_refill_depth_le depth (back_refill_step_middle9 m_rest cell).
Proof.
  intros depth X m_rest [b|pre sm suf|sm] Hrest Hcell;
    cbn [back_refill_step_middle9] in *.
  - apply middle9_refill_depth_le_inject;
      [exact Hrest|apply stored_refill_depth_le_small].
  - destruct depth as [|depth'].
    + unfold k9_middle_inject. rewrite Hcell.
      apply middle9_refill_depth_le_inject.
      * apply middle9_refill_depth_le_inject;
          [exact Hrest|apply stored_refill_depth_le_small].
      * apply stored_refill_depth_le_small.
    + apply middle9_refill_depth_le_inject.
      * apply middle9_refill_depth_le_k9_middle_inject.
        -- apply middle9_refill_depth_le_inject;
             [exact Hrest|apply stored_refill_depth_le_small].
        -- exact Hcell.
      * apply stored_refill_depth_le_small.
  - destruct depth as [|depth']; [contradiction|].
    apply middle9_refill_depth_le_k9_middle_inject; assumption.
Qed.

Lemma middle9_refill_depth_le_front_normalize_step :
  forall (depth : nat) (X : Type)
         (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)),
    stored_refill_depth_le depth cell ->
    middle9_refill_depth_le depth m_rest ->
    middle9_refill_depth_le depth (front_normalize_step_middle9 cell m_rest).
Proof.
  intros depth X [b|pre sm suf|sm] m_rest Hcell Hrest;
    cbn [front_normalize_step_middle9] in *.
  - exact Hrest.
  - destruct depth as [|depth'].
    + unfold k9_middle_push. rewrite Hcell.
      apply middle9_refill_depth_le_push;
        [apply stored_refill_depth_le_small|exact Hrest].
    + apply middle9_refill_depth_le_k9_middle_push.
      * exact Hcell.
      * apply middle9_refill_depth_le_push;
          [apply stored_refill_depth_le_small|exact Hrest].
  - destruct depth as [|depth']; [contradiction|].
    destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hpop.
    + destruct (middle9_refill_depth_le_pop
                  depth' X sm sm_rest front_cell Hcell Hpop)
        as [Hfront Hsm_rest].
      apply middle9_refill_depth_le_push.
      * apply stored_refill_depth_le_succ. exact Hfront.
      * apply middle9_refill_depth_le_k9_middle_push; assumption.
    + exact Hrest.
Qed.

Lemma middle9_refill_depth_le_back_normalize_step :
  forall (depth : nat) (X : Type)
         (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    middle9_refill_depth_le depth m_rest ->
    stored_refill_depth_le depth cell ->
    middle9_refill_depth_le depth (back_normalize_step_middle9 m_rest cell).
Proof.
  intros depth X m_rest [b|pre sm suf|sm] Hrest Hcell;
    cbn [back_normalize_step_middle9] in *.
  - exact Hrest.
  - destruct depth as [|depth'].
    + unfold k9_middle_inject. rewrite Hcell.
      apply middle9_refill_depth_le_inject;
        [exact Hrest|apply stored_refill_depth_le_small].
    + apply middle9_refill_depth_le_k9_middle_inject.
      * apply middle9_refill_depth_le_inject;
          [exact Hrest|apply stored_refill_depth_le_small].
      * exact Hcell.
  - destruct depth as [|depth']; [contradiction|].
    destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Heject.
    + destruct (middle9_refill_depth_le_eject
                  depth' X sm sm_rest back_cell Hcell Heject)
        as [Hsm_rest Hback].
      apply middle9_refill_depth_le_inject.
      * apply middle9_refill_depth_le_k9_middle_inject; assumption.
      * apply stored_refill_depth_le_succ. exact Hback.
    + exact Hrest.
Qed.

Theorem k9_with_fuel_refill_depth_bound_pair :
  forall fuel : nat,
    (forall (depth : nat) (X : Type)
            (h : Buf6 (KElem9 X))
            (m : Buf6 (Stored9 X))
            (t : Buf6 (KElem9 X)),
        middle9_refill_depth_le depth m ->
        inv_kcad9_ocaml_refill_depth_bound
          depth (k9_with_front_fuel fuel h m t)) /\
    (forall (depth : nat) (X : Type)
            (h : Buf6 (KElem9 X))
            (m : Buf6 (Stored9 X))
            (t : Buf6 (KElem9 X)),
        middle9_refill_depth_le depth m ->
        inv_kcad9_ocaml_refill_depth_bound
          depth (k9_with_back_fuel fuel h m t)).
Proof.
  induction fuel as [|fuel [IHfront IHback]].
  - split; intros depth X h m t Hm;
      cbn [k9_with_front_fuel k9_with_back_fuel
           inv_kcad9_ocaml_refill_depth_bound];
      exact Hm.
  - split; intros depth X h m t Hm.
    + cbn [k9_with_front_fuel].
      destruct (buf6_is_empty h) eqn:Hh_empty.
      * destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
        -- destruct (middle9_refill_depth_le_pop
                      depth X m m_rest cell Hm Hpop)
             as [Hcell Hm_rest].
           destruct cell as [b|pre sm suf|sm].
           ++ destruct (buf6_is_empty b) eqn:Hb_empty.
              ** apply IHfront. exact Hm_rest.
              ** cbn [inv_kcad9_ocaml_refill_depth_bound].
                 exact Hm_rest.
           ++ pose proof
                (middle9_refill_depth_le_front_normalize_step
                   depth X (StoredBig9 pre sm suf) m_rest Hcell Hm_rest)
                as Hnew.
              cbn [front_normalize_step_middle9] in Hnew.
              destruct (buf6_is_empty pre) eqn:Hpre_empty.
              ** apply IHfront. exact Hnew.
              ** cbn [inv_kcad9_ocaml_refill_depth_bound].
                 exact Hnew.
           ++ pose proof
                (middle9_refill_depth_le_front_normalize_step
                   depth X (StoredMiddle9 sm) m_rest Hcell Hm_rest)
                as Hnew.
              destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm_pop;
                cbn [front_normalize_step_middle9] in Hnew;
                rewrite Hsm_pop in Hnew;
                apply IHfront; exact Hnew.
        -- destruct (buf6_is_empty t);
             cbn [inv_kcad9_ocaml_refill_depth_bound]; exact I.
      * destruct (buf6_is_empty t) eqn:Ht_empty.
        -- apply IHback. exact Hm.
        -- cbn [inv_kcad9_ocaml_refill_depth_bound]. exact Hm.
    + cbn [k9_with_back_fuel].
      destruct (buf6_is_empty t) eqn:Ht_empty.
      * destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
        -- destruct (middle9_refill_depth_le_eject
                      depth X m m_rest cell Hm Heject)
             as [Hm_rest Hcell].
           destruct cell as [b|pre sm suf|sm].
           ++ destruct (buf6_is_empty b) eqn:Hb_empty.
              ** apply IHback. exact Hm_rest.
              ** cbn [inv_kcad9_ocaml_refill_depth_bound].
                 exact Hm_rest.
           ++ pose proof
                (middle9_refill_depth_le_back_normalize_step
                   depth X m_rest (StoredBig9 pre sm suf) Hm_rest Hcell)
                as Hnew.
              cbn [back_normalize_step_middle9] in Hnew.
              destruct (buf6_is_empty suf) eqn:Hsuf_empty.
              ** apply IHback. exact Hnew.
              ** cbn [inv_kcad9_ocaml_refill_depth_bound].
                 exact Hnew.
           ++ pose proof
                (middle9_refill_depth_le_back_normalize_step
                   depth X m_rest (StoredMiddle9 sm) Hm_rest Hcell)
                as Hnew.
              destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Hsm_eject;
                cbn [back_normalize_step_middle9] in Hnew;
                rewrite Hsm_eject in Hnew;
                apply IHback; exact Hnew.
        -- destruct (buf6_is_empty h);
             cbn [inv_kcad9_ocaml_refill_depth_bound]; exact I.
      * destruct (buf6_is_empty h) eqn:Hh_empty.
        -- apply IHfront. exact Hm.
        -- cbn [inv_kcad9_ocaml_refill_depth_bound]. exact Hm.
Qed.

Theorem k9_with_front_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_refill_depth_le depth m ->
    inv_kcad9_ocaml_refill_depth_bound
      depth (k9_with_front_fuel fuel h m t).
Proof.
  intros fuel. exact (proj1 (k9_with_fuel_refill_depth_bound_pair fuel)).
Qed.

Theorem k9_with_back_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_refill_depth_le depth m ->
    inv_kcad9_ocaml_refill_depth_bound
      depth (k9_with_back_fuel fuel h m t).
Proof.
  intros fuel. exact (proj2 (k9_with_fuel_refill_depth_bound_pair fuel)).
Qed.

Theorem refill_h_K9Triple_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h' : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_refill_depth_le depth m ->
    inv_kcad9_ocaml_refill_depth_bound
      depth (refill_h_K9Triple_fuel fuel h' m t).
Proof.
  intros fuel depth X h' m t Hm.
  unfold refill_h_K9Triple_fuel.
  destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
  - destruct (middle9_refill_depth_le_pop depth X m m_rest cell Hm Hpop)
      as [Hcell Hm_rest].
    destruct cell as [b|pre sm suf|sm];
      apply k9_with_front_fuel_refill_depth_bound_thm.
    + pose proof
        (middle9_refill_depth_le_front_refill_step
           depth X (StoredSmall9 b) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_refill_depth_le_front_refill_step
           depth X (StoredBig9 pre sm suf) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_refill_depth_le_front_refill_step
           depth X (StoredMiddle9 sm) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
  - apply k9_with_front_fuel_refill_depth_bound_thm.
    apply middle9_refill_depth_le_empty.
Qed.

Theorem refill_t_K9Triple_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t' : Buf6 (KElem9 X)),
    middle9_refill_depth_le depth m ->
    inv_kcad9_ocaml_refill_depth_bound
      depth (refill_t_K9Triple_fuel fuel h m t').
Proof.
  intros fuel depth X h m t' Hm.
  unfold refill_t_K9Triple_fuel.
  destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
  - destruct (middle9_refill_depth_le_eject depth X m m_rest cell Hm Heject)
      as [Hm_rest Hcell].
    destruct cell as [b|pre sm suf|sm];
      apply k9_with_back_fuel_refill_depth_bound_thm.
    + pose proof
        (middle9_refill_depth_le_back_refill_step
           depth X m_rest (StoredSmall9 b) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_refill_depth_le_back_refill_step
           depth X m_rest (StoredBig9 pre sm suf) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_refill_depth_le_back_refill_step
           depth X m_rest (StoredMiddle9 sm) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
  - apply k9_with_back_fuel_refill_depth_bound_thm.
    apply middle9_refill_depth_le_empty.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k') ->
    inv_kcad9_ocaml_refill_depth_bound depth k'.
Proof.
  intros fuel depth X [|b|h m t] x k' Hinv Hpop;
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
  - discriminate.
  - destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Hpop as Hx Hk'; subst x k';
      exact I.
  - destruct (buf6_pop h) as [[e h']|] eqn:Hph; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp;
      injection Hpop as Hx Hk'; subst x k'.
    + cbn [inv_kcad9_ocaml_refill_depth_bound]. exact Hinv.
    + apply refill_h_K9Triple_fuel_refill_depth_bound_thm.
      exact Hinv.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x) ->
    inv_kcad9_ocaml_refill_depth_bound depth k'.
Proof.
  intros fuel depth X [|b|h m t] k' x Hinv Heject;
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
  - discriminate.
  - destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Heject as Hk' Hx; subst k' x;
      exact I.
  - destruct (buf6_eject t) as [[t' e]|] eqn:Het; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp;
      injection Heject as Hk' Hx; subst k' x.
    + cbn [inv_kcad9_ocaml_refill_depth_bound]. exact Hinv.
    + apply refill_t_K9Triple_fuel_refill_depth_bound_thm.
      exact Hinv.
Qed.

Theorem inv_kcad9_ocaml_refill_depth_bound_succ_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    inv_kcad9_ocaml_refill_depth_bound (S depth) k.
Proof.
  intros depth X [|b|h m t] Hinv; cbn in *; auto.
  apply middle9_refill_depth_le_succ. exact Hinv.
Qed.

Theorem empty_kcad9_ocaml_refill_depth_bound_thm :
  forall (depth : nat) (X : Type),
    inv_kcad9_ocaml_refill_depth_bound depth (@kcad9_empty X).
Proof. intros depth X. exact I. Qed.

Theorem singleton_kcad9_ocaml_refill_depth_bound_thm :
  forall (depth : nat) (X : Type) (x : X),
    inv_kcad9_ocaml_refill_depth_bound depth (kcad9_singleton x).
Proof. intros depth X x. exact I. Qed.

Theorem kcad9_push_ocaml_refill_depth_bound_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    inv_kcad9_ocaml_refill_depth_bound depth (kcad9_push x k).
Proof.
  intros depth X x [|b|h m t] Hinv;
    cbn [inv_kcad9_ocaml_refill_depth_bound kcad9_push] in *;
    exact Hinv.
Qed.

Theorem kcad9_inject_ocaml_refill_depth_bound_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    inv_kcad9_ocaml_refill_depth_bound depth (kcad9_inject k x).
Proof.
  intros depth X [|b|h m t] x Hinv;
    cbn [inv_kcad9_ocaml_refill_depth_bound kcad9_inject] in *;
    exact Hinv.
Qed.

Theorem kcad9_concat_ocaml_shape_refill_depth_split_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound (S depth) a ->
    inv_kcad9_ocaml_refill_depth_bound depth b ->
    inv_kcad9_ocaml_refill_depth_bound
      (S depth) (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [inv_kcad9_ocaml_refill_depth_bound kcad9_concat_ocaml_shape] in *.
  - exact I.
  - exact I.
  - apply middle9_refill_depth_le_succ. exact Hb.
  - exact I.
  - apply middle9_refill_depth_le_empty.
  - apply middle9_refill_depth_le_push.
    + apply stored_refill_depth_le_small.
    + apply middle9_refill_depth_le_succ. exact Hb.
  - exact Ha.
  - apply middle9_refill_depth_le_inject.
    + exact Ha.
    + apply stored_refill_depth_le_small.
  - destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct (middle9_refill_depth_le_eject
                  depth X m2 m2_rest back_cell Hb Heject)
        as [Hm2_rest Hback_cell].
      apply middle9_refill_depth_le_inject.
      * apply middle9_refill_depth_le_inject.
        -- exact Ha.
        -- cbn [stored_refill_depth_le].
           apply middle9_refill_depth_le_push.
           ++ apply stored_refill_depth_le_small.
           ++ exact Hm2_rest.
      * apply stored_refill_depth_le_succ. exact Hback_cell.
    + apply middle9_refill_depth_le_inject.
      * exact Ha.
      * cbn [stored_refill_depth_le].
        apply middle9_refill_depth_le_empty.
Qed.

Fixpoint refill_depth_exact_witness (depth : nat) : Stored9 nat :=
  match depth with
  | O => StoredSmall9 (mkBuf6 [XBase9 99])
  | S depth' =>
      StoredMiddle9 (mkBuf6 [refill_depth_exact_witness depth'])
  end.

Lemma stored_refill_depth_exact_witness_le :
  forall depth : nat,
    stored_refill_depth_le depth (refill_depth_exact_witness depth).
Proof.
  induction depth as [|depth IH].
  - exact I.
  - cbn [refill_depth_exact_witness stored_refill_depth_le buf6_elems].
    split; [exact IH|exact I].
Qed.

Lemma stored_refill_depth_exact_witness_too_shallow :
  forall depth : nat,
    ~ stored_refill_depth_le depth (refill_depth_exact_witness (S depth)).
Proof.
  induction depth as [|depth IH]; intro Hbad.
  - exact Hbad.
  - cbn [refill_depth_exact_witness stored_refill_depth_le buf6_elems]
      in Hbad.
    destruct Hbad as [Hbad _].
    exact (IH Hbad).
Qed.

Theorem kcad9_concat_ocaml_shape_refill_depth_same_depth_counterexample_thm :
  forall depth : nat,
    exists (a b : KCadeque9 nat),
      inv_kcad9_ocaml_refill_depth_bound depth a /\
      inv_kcad9_ocaml_refill_depth_bound depth b /\
      ~ inv_kcad9_ocaml_refill_depth_bound
          depth (kcad9_concat_ocaml_shape a b).
Proof.
  intro depth.
  exists
    (K9Triple
      (mkBuf6 [XBase9 0])
      (@buf6_empty (Stored9 nat))
      (mkBuf6 [XBase9 1])).
  exists
    (K9Triple
      (mkBuf6 [XBase9 2])
      (mkBuf6
        [refill_depth_exact_witness depth;
         StoredSmall9 (mkBuf6 [XBase9 4])])
      (mkBuf6 [XBase9 3])).
  split.
  - exact I.
  - split.
    + cbn [inv_kcad9_ocaml_refill_depth_bound middle9_refill_depth_le
           buf6_elems].
      split.
      * apply stored_refill_depth_exact_witness_le.
      * split; exact I.
    + intro Hbad.
      destruct depth as [|depth].
      * cbn [inv_kcad9_ocaml_refill_depth_bound middle9_refill_depth_le
             kcad9_concat_ocaml_shape stored_refill_depth_le
             refill_depth_exact_witness buf6_eject buf6_inject buf6_push
             buf6_empty buf6_is_empty buf6_elems] in Hbad.
        destruct Hbad as [Hcontra _].
        discriminate Hcontra.
      * cbn [inv_kcad9_ocaml_refill_depth_bound middle9_refill_depth_le
             kcad9_concat_ocaml_shape stored_refill_depth_le
             refill_depth_exact_witness buf6_eject buf6_inject buf6_push
             buf6_empty buf6_is_empty buf6_elems] in Hbad.
        destruct Hbad as [[_ [Htoo_shallow _]] _].
        exact (stored_refill_depth_exact_witness_too_shallow
                 depth Htoo_shallow).
Qed.

Definition inv_kcad9_ocaml_refill_concat_left_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_refill_depth_bound (S depth) k.

Definition inv_kcad9_ocaml_refill_concat_right_depth {X : Type}
  (depth : nat) (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_refill_depth_bound depth k.

Theorem inv_kcad9_ocaml_refill_concat_right_left_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_refill_concat_right_depth depth k ->
    inv_kcad9_ocaml_refill_concat_left_depth depth k.
Proof.
  intros depth X k Hright.
  unfold inv_kcad9_ocaml_refill_concat_left_depth,
    inv_kcad9_ocaml_refill_concat_right_depth in *.
  apply inv_kcad9_ocaml_refill_depth_bound_succ_thm. exact Hright.
Qed.

Theorem kcad9_push_ocaml_refill_concat_left_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_refill_concat_left_depth depth k ->
    inv_kcad9_ocaml_refill_concat_left_depth depth (kcad9_push x k).
Proof.
  intros depth X x k Hleft.
  unfold inv_kcad9_ocaml_refill_concat_left_depth in *.
  apply kcad9_push_ocaml_refill_depth_bound_thm. exact Hleft.
Qed.

Theorem kcad9_push_ocaml_refill_concat_right_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_refill_concat_right_depth depth k ->
    inv_kcad9_ocaml_refill_concat_right_depth depth (kcad9_push x k).
Proof.
  intros depth X x k Hright.
  unfold inv_kcad9_ocaml_refill_concat_right_depth in *.
  apply kcad9_push_ocaml_refill_depth_bound_thm. exact Hright.
Qed.

