Theorem kcad9_concat_ocaml_shape_refill_concat_left_right_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_refill_concat_left_depth depth a ->
    inv_kcad9_ocaml_refill_concat_right_depth depth b ->
    inv_kcad9_ocaml_refill_concat_left_depth
      depth (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X a b Hleft Hright.
  unfold inv_kcad9_ocaml_refill_concat_left_depth,
    inv_kcad9_ocaml_refill_concat_right_depth in *.
  eapply kcad9_concat_ocaml_shape_refill_depth_split_thm;
    eassumption.
Qed.

Theorem kcad9_concat_ocaml_shape_refill_concat_not_right_counterexample_thm :
  forall depth : nat,
    exists (a b : KCadeque9 nat),
      inv_kcad9_ocaml_refill_concat_left_depth depth a /\
      inv_kcad9_ocaml_refill_concat_right_depth depth b /\
      ~ inv_kcad9_ocaml_refill_concat_right_depth
          depth (kcad9_concat_ocaml_shape a b).
Proof.
  intro depth.
  destruct (kcad9_concat_ocaml_shape_refill_depth_same_depth_counterexample_thm
              depth) as (a & b & Ha & Hb & Hbad).
  exists a, b.
  unfold inv_kcad9_ocaml_refill_concat_left_depth,
    inv_kcad9_ocaml_refill_concat_right_depth.
  repeat split.
  - apply inv_kcad9_ocaml_refill_depth_bound_succ_thm. exact Ha.
  - exact Hb.
  - exact Hbad.
Qed.

Fixpoint kcad9_concat_ocaml_shape_left_fold {X : Type}
  (acc : KCadeque9 X) (ks : list (KCadeque9 X)) : KCadeque9 X :=
  match ks with
  | [] => acc
  | k :: ks' =>
      kcad9_concat_ocaml_shape_left_fold
        (kcad9_concat_ocaml_shape acc k) ks'
  end.

Fixpoint all_kcad9_ocaml_refill_concat_right_depth {X : Type}
  (depth : nat) (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_refill_concat_right_depth depth k /\
      all_kcad9_ocaml_refill_concat_right_depth depth ks'
  end.

Theorem kcad9_concat_ocaml_shape_left_fold_refill_concat_left_thm :
  forall (depth : nat) (X : Type)
         (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_refill_concat_left_depth depth acc ->
    all_kcad9_ocaml_refill_concat_right_depth depth ks ->
    inv_kcad9_ocaml_refill_concat_left_depth
      depth (kcad9_concat_ocaml_shape_left_fold acc ks).
Proof.
  intros depth X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hleft Hall.
  - exact Hleft.
  - cbn [kcad9_concat_ocaml_shape_left_fold
         all_kcad9_ocaml_refill_concat_right_depth] in *.
    destruct Hall as [Hk Hks].
    apply IH; [|exact Hks].
    eapply kcad9_concat_ocaml_shape_refill_concat_left_right_thm;
      eassumption.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_refill_depth_one_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_refill_depth_bound 1 acc ->
    all_kcad9_ocaml_refill_concat_right_depth 0 ks ->
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_ocaml_shape_left_fold acc ks).
Proof.
  intros X acc ks Hacc Hks.
  exact (kcad9_concat_ocaml_shape_left_fold_refill_concat_left_thm
           0 X acc ks Hacc Hks).
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_refill_base_depth_one_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_refill_depth_bound 0 acc ->
    all_kcad9_ocaml_refill_concat_right_depth 0 ks ->
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_ocaml_shape_left_fold acc ks).
Proof.
  intros X acc ks Hacc Hks.
  apply kcad9_concat_ocaml_shape_left_fold_refill_depth_one_thm.
  - apply inv_kcad9_ocaml_refill_depth_bound_succ_thm. exact Hacc.
  - exact Hks.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_seq_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    kcad9_to_list (kcad9_concat_ocaml_shape_left_fold acc ks) =
    kcad9_to_list acc ++ concat (map kcad9_to_list ks).
Proof.
  intros X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intro acc.
  - cbn [kcad9_concat_ocaml_shape_left_fold map concat].
    rewrite app_nil_r. reflexivity.
  - cbn [kcad9_concat_ocaml_shape_left_fold map concat].
    rewrite IH.
    rewrite kcad9_concat_ocaml_shape_seq.
    rewrite app_assoc. reflexivity.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_refill_base_depth_one_seq_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_refill_depth_bound 0 acc ->
    all_kcad9_ocaml_refill_concat_right_depth 0 ks ->
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_ocaml_shape_left_fold acc ks) /\
    kcad9_to_list (kcad9_concat_ocaml_shape_left_fold acc ks) =
      kcad9_to_list acc ++ concat (map kcad9_to_list ks).
Proof.
  intros X acc ks Hacc Hks.
  split.
  - apply kcad9_concat_ocaml_shape_left_fold_refill_base_depth_one_thm;
      assumption.
  - apply kcad9_concat_ocaml_shape_left_fold_seq_thm.
Qed.

Theorem all_kcad9_ocaml_refill_concat_right_depth_singletons_thm :
  forall (X : Type) (xs : list X),
    all_kcad9_ocaml_refill_concat_right_depth
      0 (map kcad9_singleton xs).
Proof.
  intros X xs.
  induction xs as [|x xs IH].
  - exact I.
  - cbn [map all_kcad9_ocaml_refill_concat_right_depth].
    split.
    + apply singleton_kcad9_ocaml_refill_depth_bound_thm.
    + exact IH.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm :
  forall (X : Type) (xs : list X),
    kcad9_to_list
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) = xs.
Proof.
  intros X xs.
  rewrite kcad9_concat_ocaml_shape_left_fold_seq_thm.
  rewrite empty_to_list9. cbn [app].
  induction xs as [|x xs IH].
  - reflexivity.
  - cbn [map concat].
    rewrite singleton_to_list9.
    rewrite IH. reflexivity.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_refill_depth_one_seq_thm :
  forall (X : Type) (xs : list X),
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) /\
    kcad9_to_list
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) = xs.
Proof.
  intros X xs.
  split.
  - apply kcad9_concat_ocaml_shape_left_fold_refill_base_depth_one_thm.
    + apply empty_kcad9_ocaml_refill_depth_bound_thm.
    + apply all_kcad9_ocaml_refill_concat_right_depth_singletons_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm.
Qed.

Lemma middle9_depth_le_front_refill_step_succ :
  forall (depth : nat) (X : Type)
         (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)),
    stored_middle_depth_le depth cell ->
    middle9_depth_le depth m_rest ->
    middle9_depth_le (S depth) (front_refill_step_middle9 cell m_rest).
Proof.
  intros depth X [b|pre sm suf|sm] m_rest Hcell Hrest;
    cbn [front_refill_step_middle9] in *.
  - apply middle9_depth_le_push.
    + apply stored_middle_depth_le_small.
    + apply middle9_depth_le_succ. exact Hrest.
  - apply middle9_depth_le_push.
    + apply stored_middle_depth_le_small.
    + apply middle9_depth_le_k9_middle_push_succ.
      * exact Hcell.
      * apply middle9_depth_le_push.
        -- apply stored_middle_depth_le_small.
        -- apply middle9_depth_le_succ. exact Hrest.
  - destruct depth as [|depth']; [contradiction|].
    apply middle9_depth_le_succ.
    apply middle9_depth_le_k9_middle_push_succ; assumption.
Qed.

Lemma middle9_depth_le_back_refill_step_succ :
  forall (depth : nat) (X : Type)
         (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    middle9_depth_le depth m_rest ->
    stored_middle_depth_le depth cell ->
    middle9_depth_le (S depth) (back_refill_step_middle9 m_rest cell).
Proof.
  intros depth X m_rest [b|pre sm suf|sm] Hrest Hcell;
    cbn [back_refill_step_middle9] in *.
  - apply middle9_depth_le_inject.
    + apply middle9_depth_le_succ. exact Hrest.
    + apply stored_middle_depth_le_small.
  - apply middle9_depth_le_inject.
    + apply middle9_depth_le_k9_middle_inject_succ.
      * apply middle9_depth_le_inject.
        -- apply middle9_depth_le_succ. exact Hrest.
        -- apply stored_middle_depth_le_small.
      * exact Hcell.
    + apply stored_middle_depth_le_small.
  - destruct depth as [|depth']; [contradiction|].
    apply middle9_depth_le_succ.
    apply middle9_depth_le_k9_middle_inject_succ; assumption.
Qed.

Lemma middle9_depth_le_front_normalize_step_succ :
  forall (depth : nat) (X : Type)
         (cell : Stored9 X) (m_rest : Buf6 (Stored9 X)),
    stored_middle_depth_le depth cell ->
    middle9_depth_le depth m_rest ->
    middle9_depth_le (S depth) (front_normalize_step_middle9 cell m_rest).
Proof.
  intros depth X [b|pre sm suf|sm] m_rest Hcell Hrest;
    cbn [front_normalize_step_middle9] in *.
  - apply middle9_depth_le_succ. exact Hrest.
  - apply middle9_depth_le_k9_middle_push_succ.
    + exact Hcell.
    + apply middle9_depth_le_push.
      * apply stored_middle_depth_le_small.
      * apply middle9_depth_le_succ. exact Hrest.
  - destruct depth as [|depth']; [contradiction|].
    destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hpop.
    + destruct (middle9_depth_le_pop depth' X sm sm_rest front_cell
                  Hcell Hpop) as [Hfront Hsm_rest].
      apply middle9_depth_le_push.
      * apply stored_middle_depth_le_succ.
        apply stored_middle_depth_le_succ. exact Hfront.
      * apply middle9_depth_le_succ.
        apply middle9_depth_le_k9_middle_push_succ; assumption.
    + apply middle9_depth_le_succ. exact Hrest.
Qed.

Lemma middle9_depth_le_back_normalize_step_succ :
  forall (depth : nat) (X : Type)
         (m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    middle9_depth_le depth m_rest ->
    stored_middle_depth_le depth cell ->
    middle9_depth_le (S depth) (back_normalize_step_middle9 m_rest cell).
Proof.
  intros depth X m_rest [b|pre sm suf|sm] Hrest Hcell;
    cbn [back_normalize_step_middle9] in *.
  - apply middle9_depth_le_succ. exact Hrest.
  - apply middle9_depth_le_k9_middle_inject_succ.
    + apply middle9_depth_le_inject.
      * apply middle9_depth_le_succ. exact Hrest.
      * apply stored_middle_depth_le_small.
    + exact Hcell.
  - destruct depth as [|depth']; [contradiction|].
    destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Heject.
    + destruct (middle9_depth_le_eject depth' X sm sm_rest back_cell
                  Hcell Heject) as [Hsm_rest Hback].
      apply middle9_depth_le_inject.
      * apply middle9_depth_le_succ.
        apply middle9_depth_le_k9_middle_inject_succ; assumption.
      * apply stored_middle_depth_le_succ.
        apply stored_middle_depth_le_succ. exact Hback.
    + apply middle9_depth_le_succ. exact Hrest.
Qed.

Theorem k9_with_fuel_middle_depth_bound_pair :
  forall fuel : nat,
    (forall (depth : nat) (X : Type)
            (h : Buf6 (KElem9 X))
            (m : Buf6 (Stored9 X))
            (t : Buf6 (KElem9 X)),
        middle9_depth_le depth m ->
        inv_kcad9_ocaml_middle_depth_bound
          (fuel + depth) (k9_with_front_fuel fuel h m t)) /\
    (forall (depth : nat) (X : Type)
            (h : Buf6 (KElem9 X))
            (m : Buf6 (Stored9 X))
            (t : Buf6 (KElem9 X)),
        middle9_depth_le depth m ->
        inv_kcad9_ocaml_middle_depth_bound
          (fuel + depth) (k9_with_back_fuel fuel h m t)).
Proof.
  induction fuel as [|fuel [IHfront IHback]].
  - split; intros depth X h m t Hm;
      cbn [k9_with_front_fuel k9_with_back_fuel
           inv_kcad9_ocaml_middle_depth_bound];
      exact Hm.
  - split; intros depth X h m t Hm.
    + cbn [k9_with_front_fuel].
      destruct (buf6_is_empty h) eqn:Hh_empty.
      * destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
        -- destruct (middle9_depth_le_pop depth X m m_rest cell Hm Hpop)
             as [Hcell Hm_rest].
           destruct cell as [b|pre sm suf|sm].
           ++ destruct (buf6_is_empty b) eqn:Hb_empty.
              ** replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply IHfront. apply middle9_depth_le_succ. exact Hm_rest.
              ** cbn [inv_kcad9_ocaml_middle_depth_bound].
                 apply middle9_depth_le_add_l. exact Hm_rest.
           ++ pose proof
                (middle9_depth_le_front_normalize_step_succ
                   depth X (StoredBig9 pre sm suf) m_rest Hcell Hm_rest)
                as Hnew.
              cbn [front_normalize_step_middle9] in Hnew.
              destruct (buf6_is_empty pre) eqn:Hpre_empty.
              ** replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply IHfront. exact Hnew.
              ** cbn [inv_kcad9_ocaml_middle_depth_bound].
                 replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply middle9_depth_le_add_l. exact Hnew.
           ++ pose proof
                (middle9_depth_le_front_normalize_step_succ
                   depth X (StoredMiddle9 sm) m_rest Hcell Hm_rest)
                as Hnew.
              destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm_pop;
                cbn [front_normalize_step_middle9] in Hnew;
                rewrite Hsm_pop in Hnew;
                replace (S fuel + depth) with (fuel + S depth) by lia;
                apply IHfront; exact Hnew.
        -- destruct (buf6_is_empty t);
             cbn [inv_kcad9_ocaml_middle_depth_bound]; exact I.
      * destruct (buf6_is_empty t) eqn:Ht_empty.
        -- replace (S fuel + depth) with (fuel + S depth) by lia.
           apply IHback. apply middle9_depth_le_succ. exact Hm.
        -- cbn [inv_kcad9_ocaml_middle_depth_bound].
           apply middle9_depth_le_add_l. exact Hm.
    + cbn [k9_with_back_fuel].
      destruct (buf6_is_empty t) eqn:Ht_empty.
      * destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
        -- destruct (middle9_depth_le_eject depth X m m_rest cell Hm Heject)
             as [Hm_rest Hcell].
           destruct cell as [b|pre sm suf|sm].
           ++ destruct (buf6_is_empty b) eqn:Hb_empty.
              ** replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply IHback. apply middle9_depth_le_succ. exact Hm_rest.
              ** cbn [inv_kcad9_ocaml_middle_depth_bound].
                 apply middle9_depth_le_add_l. exact Hm_rest.
           ++ pose proof
                (middle9_depth_le_back_normalize_step_succ
                   depth X m_rest (StoredBig9 pre sm suf) Hm_rest Hcell)
                as Hnew.
              cbn [back_normalize_step_middle9] in Hnew.
              destruct (buf6_is_empty suf) eqn:Hsuf_empty.
              ** replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply IHback. exact Hnew.
              ** cbn [inv_kcad9_ocaml_middle_depth_bound].
                 replace (S fuel + depth) with (fuel + S depth) by lia.
                 apply middle9_depth_le_add_l. exact Hnew.
           ++ pose proof
                (middle9_depth_le_back_normalize_step_succ
                   depth X m_rest (StoredMiddle9 sm) Hm_rest Hcell)
                as Hnew.
              destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Hsm_eject;
                cbn [back_normalize_step_middle9] in Hnew;
                rewrite Hsm_eject in Hnew;
                replace (S fuel + depth) with (fuel + S depth) by lia;
                apply IHback; exact Hnew.
        -- destruct (buf6_is_empty h);
             cbn [inv_kcad9_ocaml_middle_depth_bound]; exact I.
      * destruct (buf6_is_empty h) eqn:Hh_empty.
        -- replace (S fuel + depth) with (fuel + S depth) by lia.
           apply IHfront. apply middle9_depth_le_succ. exact Hm.
        -- cbn [inv_kcad9_ocaml_middle_depth_bound].
           apply middle9_depth_le_add_l. exact Hm.
Qed.

Theorem k9_with_front_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_depth_le depth m ->
    inv_kcad9_ocaml_middle_depth_bound
      (fuel + depth) (k9_with_front_fuel fuel h m t).
Proof.
  intros fuel. exact (proj1 (k9_with_fuel_middle_depth_bound_pair fuel)).
Qed.

Theorem k9_with_back_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_depth_le depth m ->
    inv_kcad9_ocaml_middle_depth_bound
      (fuel + depth) (k9_with_back_fuel fuel h m t).
Proof.
  intros fuel. exact (proj2 (k9_with_fuel_middle_depth_bound_pair fuel)).
Qed.

Theorem refill_h_K9Triple_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h' : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)),
    middle9_depth_le depth m ->
    inv_kcad9_ocaml_middle_depth_bound
      (fuel + S depth) (refill_h_K9Triple_fuel fuel h' m t).
Proof.
  intros fuel depth X h' m t Hm.
  unfold refill_h_K9Triple_fuel.
  destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
  - destruct (middle9_depth_le_pop depth X m m_rest cell Hm Hpop)
      as [Hcell Hm_rest].
    destruct cell as [b|pre sm suf|sm];
      apply k9_with_front_fuel_middle_depth_bound_thm.
    + pose proof
        (middle9_depth_le_front_refill_step_succ
           depth X (StoredSmall9 b) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_depth_le_front_refill_step_succ
           depth X (StoredBig9 pre sm suf) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_depth_le_front_refill_step_succ
           depth X (StoredMiddle9 sm) m_rest Hcell Hm_rest) as Hstep.
      cbn [front_refill_step_middle9] in Hstep. exact Hstep.
  - apply k9_with_front_fuel_middle_depth_bound_thm.
    apply middle9_depth_le_empty.
Qed.

Theorem refill_t_K9Triple_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X))
         (m : Buf6 (Stored9 X))
         (t' : Buf6 (KElem9 X)),
    middle9_depth_le depth m ->
    inv_kcad9_ocaml_middle_depth_bound
      (fuel + S depth) (refill_t_K9Triple_fuel fuel h m t').
Proof.
  intros fuel depth X h m t' Hm.
  unfold refill_t_K9Triple_fuel.
  destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
  - destruct (middle9_depth_le_eject depth X m m_rest cell Hm Heject)
      as [Hm_rest Hcell].
    destruct cell as [b|pre sm suf|sm];
      apply k9_with_back_fuel_middle_depth_bound_thm.
    + pose proof
        (middle9_depth_le_back_refill_step_succ
           depth X m_rest (StoredSmall9 b) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_depth_le_back_refill_step_succ
           depth X m_rest (StoredBig9 pre sm suf) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
    + pose proof
        (middle9_depth_le_back_refill_step_succ
           depth X m_rest (StoredMiddle9 sm) Hm_rest Hcell) as Hstep.
      cbn [back_refill_step_middle9] in Hstep. exact Hstep.
  - apply k9_with_back_fuel_middle_depth_bound_thm.
    apply middle9_depth_le_empty.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_ocaml_middle_depth_bound depth k ->
    kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k') ->
    inv_kcad9_ocaml_middle_depth_bound (fuel + S depth) k'.
Proof.
  intros fuel depth X [|b|h m t] x k' Hinv Hpop;
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
  - discriminate.
  - destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Hpop as Hx Hk'; subst x k';
      exact I.
  - destruct (buf6_pop h) as [[e h']|] eqn:Hph; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp;
      injection Hpop as Hx Hk'; subst x k'.
    + cbn [inv_kcad9_ocaml_middle_depth_bound].
      apply middle9_depth_le_add_l.
      apply middle9_depth_le_succ. exact Hinv.
    + apply refill_h_K9Triple_fuel_middle_depth_bound_thm.
      exact Hinv.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_middle_depth_bound depth k ->
    kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x) ->
    inv_kcad9_ocaml_middle_depth_bound (fuel + S depth) k'.
Proof.
  intros fuel depth X [|b|h m t] k' x Hinv Heject;
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
  - discriminate.
  - destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Heject as Hk' Hx; subst k' x;
      exact I.
  - destruct (buf6_eject t) as [[t' e]|] eqn:Het; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp;
      injection Heject as Hk' Hx; subst k' x.
    + cbn [inv_kcad9_ocaml_middle_depth_bound].
      apply middle9_depth_le_add_l.
      apply middle9_depth_le_succ. exact Hinv.
    + apply refill_t_K9Triple_fuel_middle_depth_bound_thm.
      exact Hinv.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_middle_depth_same_depth_counterexample_thm :
  exists (k k' : KCadeque9 nat),
    inv_kcad9_ocaml_middle_depth_bound 0 k /\
    kcad9_pop_ocaml_shape_fuel 0 k = Some (0, k') /\
    ~ inv_kcad9_ocaml_middle_depth_bound 0 k'.
Proof.
  exists
    (K9Triple
      (mkBuf6 [XBase9 0])
      (mkBuf6
        [StoredBig9
          (@buf6_empty (KElem9 nat))
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 1])])
          (@buf6_empty (KElem9 nat))])
      (@buf6_empty (KElem9 nat))).
  eexists. split.
  - cbn [inv_kcad9_ocaml_middle_depth_bound middle9_depth_le
         stored_middle_depth_le buf6_elems].
    repeat split.
  - split.
    + cbn [kcad9_pop_ocaml_shape_fuel refill_h_K9Triple_fuel
           k9_with_front_fuel k9_middle_push buf6_pop buf6_is_empty
           buf6_size Nat.leb buf6_push buf6_empty buf6_elems].
      reflexivity.
    + intro Hbad.
      cbn [inv_kcad9_ocaml_middle_depth_bound middle9_depth_le
           stored_middle_depth_le k9_middle_push buf6_push buf6_is_empty
           buf6_empty buf6_elems] in Hbad.
      destruct Hbad as [_ [Hcontra _]]. exact Hcontra.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_middle_depth_same_depth_counterexample_thm :
  exists (k k' : KCadeque9 nat),
    inv_kcad9_ocaml_middle_depth_bound 0 k /\
    kcad9_eject_ocaml_shape_fuel 0 k = Some (k', 0) /\
    ~ inv_kcad9_ocaml_middle_depth_bound 0 k'.
Proof.
  exists
    (K9Triple
      (@buf6_empty (KElem9 nat))
      (mkBuf6
        [StoredBig9
          (@buf6_empty (KElem9 nat))
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 1])])
          (@buf6_empty (KElem9 nat))])
      (mkBuf6 [XBase9 0])).
  eexists. split.
  - cbn [inv_kcad9_ocaml_middle_depth_bound middle9_depth_le
         stored_middle_depth_le buf6_elems].
    repeat split.
  - split.
    + cbn [kcad9_eject_ocaml_shape_fuel refill_t_K9Triple_fuel
           k9_with_back_fuel k9_middle_inject buf6_eject buf6_is_empty
           buf6_size Nat.leb buf6_inject buf6_empty buf6_elems].
      reflexivity.
    + intro Hbad.
      cbn [inv_kcad9_ocaml_middle_depth_bound middle9_depth_le
           stored_middle_depth_le k9_middle_inject buf6_inject buf6_is_empty
           buf6_empty buf6_elems] in Hbad.
      destruct Hbad as [_ [Hcontra _]]. exact Hcontra.
Qed.

