Theorem front_refill_residual_ready_middle9_depth_succ_thm :
  forall (depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    front_refill_residual_ready_middle9_depth depth m ->
    front_refill_residual_ready_middle9_depth (S depth) m.
Proof.
  intros depth X m Hres.
  unfold front_refill_residual_ready_middle9_depth in *.
  destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop; [|exact I].
  destruct cell as [b|pre sm suf|sm].
  - destruct Hres as [Hb Hrest]. split; [exact Hb|].
    apply front_ready_or_empty_middle9_depth_succ. exact Hrest.
  - destruct Hres as [Hpre Hrest]. split; [exact Hpre|].
    apply front_ready_or_empty_middle9_depth_succ. exact Hrest.
  - apply front_ready_or_empty_middle9_depth_succ. exact Hres.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_succ_thm :
  forall (fuel depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    front_refill_continuation_ready_middle9_fuel fuel depth m ->
    front_refill_continuation_ready_middle9_fuel fuel (S depth) m.
Proof.
  induction fuel as [|fuel IH]; intros depth X m Hcont.
  - destruct Hcont as [Hready _]. split.
    + apply front_ready_or_empty_middle9_depth_succ. exact Hready.
    + exact I.
  - cbn [front_refill_continuation_ready_middle9_fuel] in *.
    destruct Hcont as [Hready Htail]. split.
    + apply front_ready_or_empty_middle9_depth_succ. exact Hready.
    + destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop; [|exact I].
      destruct cell as [b|pre sm suf|sm].
      * destruct Htail as [Hb Hrest]. split; [exact Hb|].
        apply IH. exact Hrest.
      * destruct Htail as [Hpre Hrest]. split; [exact Hpre|].
        apply IH. exact Hrest.
      * destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm;
          apply IH; exact Htail.
Qed.

Theorem back_refill_residual_ready_middle9_depth_succ_thm :
