    back_refill_residual_ready_middle9_depth depth m ->
    back_refill_residual_ready_middle9_depth (S depth) m.
Proof.
  intros depth X m Hres.
  unfold back_refill_residual_ready_middle9_depth in *.
  destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject; [|exact I].
  destruct cell as [b|pre sm suf|sm].
  - destruct Hres as [Hrest Hb]. split.
    + apply back_ready_or_empty_middle9_depth_succ. exact Hrest.
    + exact Hb.
  - destruct Hres as [Hrest Hsuf]. split.
    + apply back_ready_or_empty_middle9_depth_succ. exact Hrest.
    + exact Hsuf.
  - apply back_ready_or_empty_middle9_depth_succ. exact Hres.
Qed.

