Theorem inv_kcad9_ocaml_continuation_depth_fuel_weaken_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth (S fuel) depth k ->
