Theorem front_ready_or_empty_middle9_depth_after_front_refill_step :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    front_ready_or_empty_middle9_depth depth m ->
    front_ready_or_empty_middle9_depth depth
      match cell with
      | StoredSmall9 b =>
          buf6_push (StoredSmall9 b) m_rest
      | StoredBig9 pre sm suf =>
          buf6_push (StoredSmall9 pre)
            (k9_middle_push sm
              (buf6_push (StoredSmall9 suf) m_rest))
      | StoredMiddle9 sm =>
          k9_middle_push sm m_rest
      end.
Proof.
  intros depth X m m_rest cell Hpop Hfront.
  assert (Hcell :
            front_ready_stored9_depth depth cell).
  { destruct Hfront as [Hempty|Hready].
    - rewrite Hpop in Hempty. discriminate.
    - destruct Hready as (front_cell & rest & Hpop_m & Hready_cell).
      rewrite Hpop in Hpop_m. injection Hpop_m as Hcell_eq _.
      subst front_cell. exact Hready_cell. }
  destruct cell as [b|pre sm suf|sm].
  - right. apply buf6_push_front_ready_stored9_depth. exact Hcell.
  - right. apply buf6_push_front_ready_stored9_depth.
    destruct depth; cbn in Hcell |- *; exact Hcell.
  - right.
    destruct depth as [|depth']; [contradiction|].
    cbn in Hcell.
    destruct Hcell as (front_cell & sm_rest & Hsm & Hinner).
    exists (StoredMiddle9 sm), m_rest. split.
    + eapply k9_middle_push_pop. exact Hsm.
    + cbn. exists front_cell, sm_rest. split; assumption.
Qed.

Theorem back_ready_or_empty_middle9_depth_after_back_refill_step :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    back_ready_or_empty_middle9_depth depth m ->
    back_ready_or_empty_middle9_depth depth
      match cell with
      | StoredSmall9 b =>
          buf6_inject m_rest (StoredSmall9 b)
      | StoredBig9 pre sm suf =>
          buf6_inject
            (k9_middle_inject
              (buf6_inject m_rest (StoredSmall9 pre))
              sm)
            (StoredSmall9 suf)
      | StoredMiddle9 sm =>
          k9_middle_inject m_rest sm
      end.
Proof.
  intros depth X m m_rest cell Heject Hback.
  assert (Hcell :
            back_ready_stored9_depth depth cell).
  { destruct Hback as [Hempty|Hready].
    - rewrite Heject in Hempty. discriminate.
    - destruct Hready as (rest & back_cell & Heject_m & Hready_cell).
      rewrite Heject in Heject_m. injection Heject_m as _ Hcell_eq.
      subst back_cell. exact Hready_cell. }
  destruct cell as [b|pre sm suf|sm].
  - right. apply buf6_inject_back_ready_stored9_depth. exact Hcell.
  - right. apply buf6_inject_back_ready_stored9_depth.
    destruct depth; cbn in Hcell |- *; exact Hcell.
  - right.
    destruct depth as [|depth']; [contradiction|].
    cbn in Hcell.
    destruct Hcell as (sm_rest & back_cell & Hsm & Hinner).
    exists m_rest, (StoredMiddle9 sm). split.
    + eapply k9_middle_inject_eject. exact Hsm.
    + cbn. exists sm_rest, back_cell. split; assumption.
Qed.

Lemma buf6_pop_inject_some :
  forall (X : Type) (m rest : Buf6 X) (front cell : X),
    buf6_pop m = Some (front, rest) ->
    buf6_pop (buf6_inject m cell) =
      Some (front, buf6_inject rest cell).
Proof.
  intros X [xs] rest front cell Hpop.
  cbn [buf6_pop buf6_inject buf6_elems] in *.
  destruct xs as [|x xs]; [discriminate|].
  injection Hpop as Hfront Hrest. subst front rest.
  reflexivity.
Qed.

Lemma buf6_pop_inject_none :
  forall (X : Type) (m : Buf6 X) (cell : X),
    buf6_pop m = None ->
    buf6_pop (buf6_inject m cell) = Some (cell, buf6_empty).
Proof.
  intros X [xs] cell Hpop.
  cbn [buf6_pop buf6_inject buf6_empty buf6_elems] in *.
  destruct xs as [|x xs]; [reflexivity|discriminate].
Qed.

Lemma buf6_push_inject_comm :
  forall (X : Type) (front back : X) (m : Buf6 X),
    buf6_push front (buf6_inject m back) =
    buf6_inject (buf6_push front m) back.
Proof.
  intros X front back [xs].
  reflexivity.
Qed.

Lemma buf6_pop_some_push_eq :
  forall (X : Type) (m rest : Buf6 X) (front : X),
    buf6_pop m = Some (front, rest) ->
    m = buf6_push front rest.
Proof.
  intros X [xs] rest front Hpop.
  cbn [buf6_pop buf6_push buf6_elems] in *.
  destruct xs as [|x xs]; [discriminate|].
  injection Hpop as Hfront Hrest. subst front rest.
  reflexivity.
Qed.

Lemma buf6_eject_some_inject_eq :
  forall (X : Type) (m rest : Buf6 X) (back : X),
    buf6_eject m = Some (rest, back) ->
    m = buf6_inject rest back.
Proof.
  intros X [xs] rest back Heject.
  apply buf6_eject_seq_some in Heject.
  unfold buf6_to_list in Heject. cbn [buf6_elems] in Heject.
  destruct rest as [rs].
  cbn [buf6_inject buf6_elems].
  subst xs. reflexivity.
Qed.

Lemma buf6_eject_front_refill_step_some :
  forall (X : Type) (cell last : Stored9 X)
         (m rest : Buf6 (Stored9 X)),
    buf6_eject m = Some (rest, last) ->
    buf6_eject (front_refill_step_middle9 cell m) =
      Some (front_refill_step_middle9 cell rest, last).
Proof.
  intros X [b|pre sm suf|sm] last m rest Heject;
    cbn [front_refill_step_middle9].
  - apply buf6_eject_push_some. exact Heject.
  - apply buf6_eject_push_some.
    unfold k9_middle_push.
    destruct (buf6_is_empty sm).
    + apply buf6_eject_push_some. exact Heject.
    + apply buf6_eject_push_some.
      apply buf6_eject_push_some. exact Heject.
  - unfold k9_middle_push.
    destruct (buf6_is_empty sm).
    + exact Heject.
    + apply buf6_eject_push_some. exact Heject.
Qed.

Lemma buf6_pop_back_refill_step_some :
  forall (X : Type) (front cell : Stored9 X)
         (m rest : Buf6 (Stored9 X)),
    buf6_pop m = Some (front, rest) ->
    buf6_pop (back_refill_step_middle9 m cell) =
      Some (front, back_refill_step_middle9 rest cell).
Proof.
  intros X front [b|pre sm suf|sm] m rest Hpop;
    cbn [back_refill_step_middle9].
  - apply buf6_pop_inject_some. exact Hpop.
  - apply buf6_pop_inject_some.
    unfold k9_middle_inject.
    destruct (buf6_is_empty sm).
    + apply buf6_pop_inject_some. exact Hpop.
    + apply buf6_pop_inject_some.
      apply buf6_pop_inject_some. exact Hpop.
  - unfold k9_middle_inject.
    destruct (buf6_is_empty sm).
    + exact Hpop.
    + apply buf6_pop_inject_some. exact Hpop.
Qed.

Lemma front_refill_step_middle9_inject :
  forall (X : Type) (cell back : Stored9 X)
         (m : Buf6 (Stored9 X)),
    front_refill_step_middle9 cell (buf6_inject m back) =
