Lemma buf6_eject_open_front_middle_some :
  forall (X : Type) (front_cell last : Stored9 X)
         (sm_rest m rest : Buf6 (Stored9 X)),
    buf6_eject m = Some (rest, last) ->
    buf6_eject (buf6_push front_cell (k9_middle_push sm_rest m)) =
