Proof.
  intros X front_cell last sm_rest m rest Heject.
  unfold k9_middle_push.
  destruct (buf6_is_empty sm_rest).
  - apply buf6_eject_push_some. exact Heject.
  - apply buf6_eject_push_some.
    apply buf6_eject_push_some. exact Heject.
Qed.

Lemma buf6_pop_open_back_middle_some :
  forall (X : Type) (front back_cell : Stored9 X)
