Lemma k9_middle_push_push_open_back_middle_comm :
  forall (X : Type) (front back : Stored9 X)
         (sm_front rest sm_back : Buf6 (Stored9 X)),
    k9_middle_push sm_front
      (buf6_push front
        (buf6_inject (k9_middle_inject rest sm_back) back)) =
