      (k9_middle_inject
        (k9_middle_push sm_front (buf6_push front rest))
        sm_back)
      back.
Proof.
  intros X front back [fronts] [rs] [backs].
  unfold k9_middle_push, k9_middle_inject, buf6_is_empty,
    buf6_push, buf6_inject, buf6_elems.
  destruct fronts as [|f fs]; destruct backs as [|b bs]; reflexivity.
Qed.

Theorem back_ready_or_empty_middle9_depth_after_pop :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    back_ready_or_empty_middle9_depth depth m ->
    back_ready_or_empty_middle9_depth depth m_rest.
Proof.
  intros depth X [xs] m_rest cell Hpop Hback.
  destruct xs as [|front xs]; [discriminate|].
  cbn [buf6_pop buf6_elems] in Hpop.
  injection Hpop as Hcell Hrest. subst front m_rest.
  destruct xs as [|next rest].
  - left. reflexivity.
  - right.
    destruct Hback as [Hempty|Hready].
    + apply buf6_eject_seq_none in Hempty. unfold buf6_to_list in Hempty.
      cbn [buf6_elems] in Hempty. discriminate.
    + destruct Hready as (full_rest & last & Hfull & Hlast).
      assert (Htail_ge : buf6_size_ge 1 (mkBuf6 (next :: rest))).
      { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
      destruct (buf6_eject_of_size_ge_S
                  (Stored9 X) 0 (mkBuf6 (next :: rest)) Htail_ge)
        as (tail_rest & tail_last & Htail).
      pose proof
        (buf6_eject_push_some
           (Stored9 X) cell (mkBuf6 (next :: rest))
           tail_rest tail_last Htail)
        as Hfull_expected.
      change (buf6_eject (buf6_push cell (mkBuf6 (next :: rest))) =
                Some (full_rest, last)) in Hfull.
      rewrite Hfull_expected in Hfull.
      injection Hfull as _ Hlast_eq. subst last.
      exists tail_rest, tail_last. split; assumption.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_pop_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    back_refill_continuation_ready_middle9_fuel fuel depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  induction fuel as [|fuel IH]; intros depth X m m_rest cell Hpop Hcont.
  - destruct Hcont as [Hready _]. split.
    + eapply back_ready_or_empty_middle9_depth_after_pop; eassumption.
    + exact I.
  - pose proof (buf6_pop_some_push_eq
                  (Stored9 X) m m_rest cell Hpop) as Hm.
    subst m.
    cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + eapply back_ready_or_empty_middle9_depth_after_pop.
      * apply buf6_pop_push.
      * exact Hready.
    + destruct (buf6_eject m_rest) as [[rest last]|] eqn:Hrest_eject.
      * rewrite (buf6_eject_push_some
                   (Stored9 X) cell m_rest rest last Hrest_eject) in Htail.
        destruct last as [b|pre sm suf|sm_last].
        -- destruct Htail as [Hprefix Hb]. split; [|exact Hb].
           exact
             (IH depth X (buf6_push cell rest) rest cell
                (buf6_pop_push (Stored9 X) cell rest) Hprefix).
	        -- destruct Htail as [Hprefix Hsuf]. split; [|exact Hsuf].
	           exact
	             (IH depth X
	                (k9_middle_inject
	                   (buf6_inject (buf6_push cell rest) (StoredSmall9 pre))
	                   sm)
	                (k9_middle_inject
	                   (buf6_inject rest (StoredSmall9 pre)) sm)
	                cell
	                ltac:(unfold k9_middle_inject;
	                      destruct (buf6_is_empty sm);
	                      repeat apply buf6_pop_inject_some;
	                      apply buf6_pop_push)
	                Hprefix).
	        -- destruct (buf6_eject sm_last) as [[sm_rest back_cell]|] eqn:Hsm.
	           ++ exact
	                (IH depth X
	                   (buf6_inject
	                      (k9_middle_inject (buf6_push cell rest) sm_rest)
	                      back_cell)
	                   (buf6_inject
	                      (k9_middle_inject rest sm_rest)
	                      back_cell)
	                   cell
	                   ltac:(apply buf6_pop_inject_some;
	                         unfold k9_middle_inject;
	                         destruct (buf6_is_empty sm_rest);
	                         repeat apply buf6_pop_inject_some;
	                         apply buf6_pop_push)
	                   Htail).
           ++ exact
                (IH depth X (buf6_push cell rest) rest cell
                   (buf6_pop_push (Stored9 X) cell rest) Htail).
      * apply buf6_eject_seq_none in Hrest_eject.
        unfold buf6_to_list in Hrest_eject.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_eject. subst rs.
        exact I.
Qed.

Theorem back_ready_or_empty_middle9_depth_open_front_middle :
  forall (depth : nat) (X : Type)
         (sm sm_rest : Buf6 (Stored9 X)) (front_cell : Stored9 X)
         (m_rest : Buf6 (Stored9 X)),
    buf6_pop sm = Some (front_cell, sm_rest) ->
    back_ready_or_empty_middle9_depth depth
      (buf6_push (StoredMiddle9 sm) m_rest) ->
    back_ready_or_empty_middle9_depth depth
      (buf6_push front_cell (k9_middle_push sm_rest m_rest)).
Proof.
  intros depth X sm sm_rest front_cell m_rest Hsm Hready.
  pose proof
    (buf6_pop_some_push_eq (Stored9 X) sm sm_rest front_cell Hsm) as Hsm_eq.
  subst sm.
  assert (Hm_rest_ready_or_empty :
            back_ready_or_empty_middle9_depth depth m_rest).
  { pose proof
      (back_refill_continuation_ready_middle9_fuel_after_pop_thm
         0 depth X
         (buf6_push (StoredMiddle9 (buf6_push front_cell sm_rest)) m_rest)
         m_rest (StoredMiddle9 (buf6_push front_cell sm_rest))
         (buf6_pop_push (Stored9 X)
            (StoredMiddle9 (buf6_push front_cell sm_rest)) m_rest)
         (conj Hready I)) as Hrest.
    exact (proj1 Hrest). }
  destruct Hm_rest_ready_or_empty as [Hm_empty|Hm_ready].
  - apply buf6_eject_seq_none in Hm_empty.
    unfold buf6_to_list in Hm_empty.
    destruct m_rest as [m_elems]. cbn [buf6_elems] in Hm_empty. subst m_elems.
    destruct Hready as [Hempty_source|Hsource_ready].
    + cbn [buf6_eject buf6_push buf6_empty buf6_elems] in Hempty_source.
      discriminate.
    + destruct Hsource_ready as (source_rest & source_cell & Hsource_eject & Hstored).
      cbn [buf6_eject buf6_push buf6_empty buf6_elems rev] in Hsource_eject.
      injection Hsource_eject as Hsource_rest Hsource_cell.
      subst source_rest source_cell.
      destruct sm_rest as [sm_elems].
      destruct sm_elems as [|next sm_tail].
      * right. exists buf6_empty, front_cell.
        cbn [k9_middle_push buf6_is_empty buf6_push buf6_empty buf6_eject
             buf6_elems].
        split; [reflexivity|].
        destruct depth as [|depth']; [contradiction|].
        cbn [back_ready_stored9_depth] in Hstored.
        destruct Hstored as (inner_rest & inner_cell & Hinner_eject & Hinner).
        cbn [buf6_eject buf6_push buf6_empty buf6_elems rev] in Hinner_eject.
        injection Hinner_eject as Hinner_rest Hinner_cell.
        subst inner_rest inner_cell.
        apply back_ready_stored9_depth_succ. exact Hinner.
      * right.
        exists (buf6_push front_cell buf6_empty),
          (StoredMiddle9 (mkBuf6 (next :: sm_tail))).
        cbn [k9_middle_push buf6_is_empty buf6_push buf6_empty buf6_eject
             buf6_elems rev].
        split; [reflexivity|].
        destruct depth as [|depth']; [contradiction|].
        cbn [back_ready_stored9_depth] in Hstored |- *.
        destruct Hstored as (inner_rest & inner_cell & Hinner_eject & Hinner).
        assert (Hinner_ready :
                  back_ready_or_empty_middle9_depth depth'
                    (mkBuf6 (next :: sm_tail))).
        { exact
            (back_ready_or_empty_middle9_depth_after_pop
               depth' X
               (buf6_push front_cell (mkBuf6 (next :: sm_tail)))
               (mkBuf6 (next :: sm_tail)) front_cell
               (buf6_pop_push (Stored9 X) front_cell
                  (mkBuf6 (next :: sm_tail)))
               (or_intror
                  (ex_intro _ inner_rest
                    (ex_intro _ inner_cell
                      (conj Hinner_eject Hinner))))). }
        destruct Hinner_ready as [Hinner_empty|Hinner_ready].
        -- apply buf6_eject_seq_none in Hinner_empty.
           unfold buf6_to_list in Hinner_empty.
           cbn [buf6_elems] in Hinner_empty. discriminate.
        -- exact Hinner_ready.
  - right.
    unfold k9_middle_push.
    destruct (buf6_is_empty sm_rest).
    + apply back_ready_middle9_depth_push_preserve. exact Hm_ready.
    + apply back_ready_middle9_depth_push_preserve.
      apply back_ready_middle9_depth_push_preserve. exact Hm_ready.
Qed.

Theorem back_ready_or_empty_middle9_depth_after_front_normalize_step :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    back_ready_or_empty_middle9_depth depth m ->
    back_ready_or_empty_middle9_depth depth
      (front_normalize_step_middle9 cell m_rest).
Proof.
  intros depth X m m_rest cell Hpop Hready.
  destruct cell as [b|pre sm suf|sm].
  - cbn [front_normalize_step_middle9].
    eapply back_ready_or_empty_middle9_depth_after_pop; eassumption.
  - cbn [front_normalize_step_middle9].
    pose proof
      (back_ready_or_empty_middle9_depth_after_front_refill_step
         depth X m m_rest (StoredBig9 pre sm suf) Hpop Hready)
      as Hstep.
    eapply back_ready_or_empty_middle9_depth_after_pop.
    + apply buf6_pop_push.
    + exact Hstep.
  - cbn [front_normalize_step_middle9].
    destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm.
    + pose proof
        (back_ready_or_empty_middle9_depth_after_front_refill_step
           depth X m m_rest (StoredMiddle9 sm) Hpop Hready)
        as Hstep.
      cbn [front_refill_step_middle9] in Hstep.
      unfold k9_middle_push in Hstep.
      rewrite (buf6_is_empty_false_of_pop_some
                 (Stored9 X) sm front_cell sm_rest Hsm) in Hstep.
      eapply back_ready_or_empty_middle9_depth_open_front_middle;
        eassumption.
    + eapply back_ready_or_empty_middle9_depth_after_pop; eassumption.
Qed.

Theorem front_ready_or_empty_middle9_depth_after_eject :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    front_ready_or_empty_middle9_depth depth m ->
    front_ready_or_empty_middle9_depth depth m_rest.
Proof.
  intros depth X m m_rest cell Heject Hfront.
  destruct m as [xs]. destruct m_rest as [rs].
  apply buf6_eject_seq_some in Heject.
  unfold buf6_to_list in Heject. cbn [buf6_elems] in Heject. subst xs.
  destruct rs as [|front rest].
  - left. reflexivity.
  - right.
    destruct Hfront as [Hempty|Hready].
    + cbn [front_ready_or_empty_middle9_depth buf6_pop buf6_elems] in Hempty.
      discriminate.
    + destruct Hready as (front_cell & full_rest & Hpop & Hcell).
      cbn [buf6_pop buf6_elems] in Hpop.
      injection Hpop as Hfront_cell Hfull_rest.
      subst front_cell full_rest.
      exists front, (mkBuf6 rest). cbn [buf6_pop buf6_elems].
      split; [reflexivity|exact Hcell].
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_eject_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    front_refill_continuation_ready_middle9_fuel fuel depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  induction fuel as [|fuel IH]; intros depth X m m_rest cell Heject Hcont.
  - destruct Hcont as [Hready _]. split.
    + eapply front_ready_or_empty_middle9_depth_after_eject; eassumption.
    + exact I.
  - pose proof (buf6_eject_some_inject_eq
                  (Stored9 X) m m_rest cell Heject) as Hm.
    subst m.
    cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + eapply front_ready_or_empty_middle9_depth_after_eject.
      * apply buf6_eject_inject.
      * exact Hready.
    + destruct (buf6_pop m_rest) as [[front rest]|] eqn:Hrest_pop.
      * rewrite (buf6_pop_inject_some
                   (Stored9 X) m_rest rest front cell Hrest_pop) in Htail.
        destruct front as [b|pre sm suf|sm_front].
        -- destruct Htail as [Hb Hsuffix]. split; [exact Hb|].
           exact
             (IH depth X (buf6_inject rest cell) rest cell
                (buf6_eject_inject (Stored9 X) rest cell) Hsuffix).
        -- destruct Htail as [Hpre Hsuffix]. split; [exact Hpre|].
           exact
             (IH depth X
                (k9_middle_push sm
                   (buf6_push (StoredSmall9 suf)
                     (buf6_inject rest cell)))
                (k9_middle_push sm
                   (buf6_push (StoredSmall9 suf) rest))
                cell
                ltac:(unfold k9_middle_push;
                      destruct (buf6_is_empty sm);
                      repeat apply buf6_eject_push_some;
                      apply buf6_eject_inject)
                Hsuffix).
        -- destruct (buf6_pop sm_front) as [[front_cell sm_rest]|] eqn:Hsm.
           ++ exact
                (IH depth X
                   (buf6_push front_cell
                      (k9_middle_push sm_rest (buf6_inject rest cell)))
                   (buf6_push front_cell
                      (k9_middle_push sm_rest rest))
                   cell
                   ltac:(apply buf6_eject_push_some;
                         unfold k9_middle_push;
                         destruct (buf6_is_empty sm_rest);
                         repeat apply buf6_eject_push_some;
                         apply buf6_eject_inject)
                   Htail).
           ++ exact
                (IH depth X (buf6_inject rest cell) rest cell
                   (buf6_eject_inject (Stored9 X) rest cell) Htail).
      * apply buf6_pop_seq_none in Hrest_pop.
        unfold buf6_to_list in Hrest_pop.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_pop. subst rs.
        exact I.
Qed.

Theorem front_ready_or_empty_middle9_depth_open_back_middle :
  forall (depth : nat) (X : Type)
         (sm sm_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X)
         (m_rest : Buf6 (Stored9 X)),
    buf6_eject sm = Some (sm_rest, back_cell) ->
    front_ready_or_empty_middle9_depth depth
      (buf6_inject m_rest (StoredMiddle9 sm)) ->
    front_ready_or_empty_middle9_depth depth
      (buf6_inject (k9_middle_inject m_rest sm_rest) back_cell).
Proof.
  intros depth X sm sm_rest back_cell m_rest Hsm Hready.
  pose proof
    (buf6_eject_some_inject_eq (Stored9 X) sm sm_rest back_cell Hsm)
    as Hsm_eq.
  subst sm.
  assert (Hm_rest_ready_or_empty :
            front_ready_or_empty_middle9_depth depth m_rest).
  { pose proof
      (front_refill_continuation_ready_middle9_fuel_after_eject_thm
         0 depth X
         (buf6_inject m_rest (StoredMiddle9 (buf6_inject sm_rest back_cell)))
         m_rest (StoredMiddle9 (buf6_inject sm_rest back_cell))
         (buf6_eject_inject (Stored9 X) m_rest
            (StoredMiddle9 (buf6_inject sm_rest back_cell)))
         (conj Hready I)) as Hrest.
    exact (proj1 Hrest). }
  destruct Hm_rest_ready_or_empty as [Hm_empty|Hm_ready].
  - apply buf6_pop_seq_none in Hm_empty.
    unfold buf6_to_list in Hm_empty.
    destruct m_rest as [m_elems]. cbn [buf6_elems] in Hm_empty. subst m_elems.
    destruct Hready as [Hempty_source|Hsource_ready].
    + cbn [buf6_pop buf6_inject buf6_empty buf6_elems] in Hempty_source.
      discriminate.
    + destruct Hsource_ready as (source_cell & source_rest & Hsource_pop & Hstored).
      cbn [buf6_pop buf6_inject buf6_empty buf6_elems] in Hsource_pop.
      injection Hsource_pop as Hsource_cell Hsource_rest.
      subst source_cell source_rest.
      destruct sm_rest as [sm_elems].
      destruct sm_elems as [|front sm_tail].
      * right. exists back_cell, buf6_empty.
        cbn [k9_middle_inject buf6_is_empty buf6_inject buf6_empty buf6_pop
             buf6_elems].
        split; [reflexivity|].
        destruct depth as [|depth']; [contradiction|].
        cbn [front_ready_stored9_depth] in Hstored.
        destruct Hstored as (inner_cell & inner_rest & Hinner_pop & Hinner).
        cbn [buf6_pop buf6_inject buf6_empty buf6_elems] in Hinner_pop.
        injection Hinner_pop as Hinner_cell Hinner_rest.
        subst inner_cell inner_rest.
        apply front_ready_stored9_depth_succ. exact Hinner.
      * right.
        exists (StoredMiddle9 (mkBuf6 (front :: sm_tail))),
          (buf6_inject buf6_empty back_cell).
        cbn [k9_middle_inject buf6_is_empty buf6_inject buf6_empty buf6_pop
             buf6_elems].
        split; [reflexivity|].
        destruct depth as [|depth']; [contradiction|].
        cbn [front_ready_stored9_depth] in Hstored |- *.
        destruct Hstored as (inner_cell & inner_rest & Hinner_pop & Hinner).
        assert (Hinner_ready :
                  front_ready_or_empty_middle9_depth depth'
                    (mkBuf6 (front :: sm_tail))).
        { exact
            (front_ready_or_empty_middle9_depth_after_eject
               depth' X
               (buf6_inject (mkBuf6 (front :: sm_tail)) back_cell)
               (mkBuf6 (front :: sm_tail)) back_cell
               (buf6_eject_inject (Stored9 X)
                  (mkBuf6 (front :: sm_tail)) back_cell)
               (or_intror
                  (ex_intro _ inner_cell
                    (ex_intro _ inner_rest
                      (conj Hinner_pop Hinner))))). }
        destruct Hinner_ready as [Hinner_empty|Hinner_ready].
        -- cbn [buf6_pop buf6_elems] in Hinner_empty. discriminate.
        -- exact Hinner_ready.
  - right.
    unfold k9_middle_inject.
    destruct (buf6_is_empty sm_rest).
    + apply front_ready_middle9_depth_inject_preserve. exact Hm_ready.
    + apply front_ready_middle9_depth_inject_preserve.
      apply front_ready_middle9_depth_inject_preserve. exact Hm_ready.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      match cell with
      | StoredSmall9 b =>
          buf6_push (StoredSmall9 b) m_rest
      | StoredBig9 pre sm suf =>
          buf6_push (StoredSmall9 pre)
            (k9_middle_push sm
              (buf6_push (StoredSmall9 suf) m_rest))
      | StoredMiddle9 sm =>
          k9_middle_push sm m_rest
      end.
Proof.
  intros fuel depth X m m_rest cell Hpop Hcont.
  cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
  destruct Hcont as [Hready Htail].
  rewrite Hpop in Htail.
  pose proof
    (front_ready_or_empty_middle9_depth_after_front_refill_step
       depth X m m_rest cell Hpop Hready)
    as Hready_step.
  destruct fuel as [|fuel].
  - split; [exact Hready_step|exact I].
  - split; [exact Hready_step|].
    destruct cell as [b|pre sm suf|sm].
    + cbn [front_refill_continuation_ready_middle9_fuel buf6_pop buf6_push
           buf6_elems].
      destruct Htail as [Hb Hrest]. split; [exact Hb|].
      apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
      exact Hrest.
    + cbn [front_refill_continuation_ready_middle9_fuel buf6_pop buf6_push
           buf6_elems].
      destruct Htail as [Hpre Hrest]. split; [exact Hpre|].
      apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
      exact Hrest.
    + destruct sm as [[|front_cell sm_tail]].
      * cbn [k9_middle_push buf6_is_empty buf6_pop buf6_elems] in *.
        destruct Htail as [_ Htail]. exact Htail.
      * cbn [k9_middle_push buf6_is_empty buf6_pop buf6_push buf6_elems] in *.
        destruct m_rest as [mrest_elems]. cbn [buf6_elems] in *.
        apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
        exact Htail.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_front_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      (front_normalize_step_middle9 cell m_rest).
Proof.
  intros fuel depth X m m_rest cell Hpop Hcont.
  cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
  destruct Hcont as [_ Htail].
  rewrite Hpop in Htail.
  destruct cell as [b|pre sm suf|sm].
  - cbn [front_normalize_step_middle9]. destruct Htail as [_ Htail].
    exact Htail.
  - cbn [front_normalize_step_middle9]. destruct Htail as [_ Htail].
    exact Htail.
  - cbn [front_normalize_step_middle9].
    destruct (buf6_pop sm) as [[front_cell sm_rest]|]; exact Htail.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      (front_refill_step_middle9 cell m_rest).
Proof.
  induction fuel as [|fuel IH]; intros depth X m m_rest cell Hpop Hcont.
  - destruct Hcont as [Hready _]. split.
    + unfold front_refill_step_middle9.
      eapply back_ready_or_empty_middle9_depth_after_front_refill_step;
        eassumption.
    + exact I.
  - pose proof (buf6_pop_some_push_eq
                  (Stored9 X) m m_rest cell Hpop) as Hm.
    subst m.
    cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + unfold front_refill_step_middle9.
      eapply back_ready_or_empty_middle9_depth_after_front_refill_step.
      * apply buf6_pop_push.
      * exact Hready.
    + destruct (buf6_eject m_rest) as [[rest last]|] eqn:Hrest_eject.
      * rewrite (buf6_eject_push_some
                   (Stored9 X) cell m_rest rest last Hrest_eject) in Htail.
        rewrite (buf6_eject_front_refill_step_some
                   X cell last m_rest rest Hrest_eject).
        destruct last as [b|pre sm suf|sm_last].
        -- destruct Htail as [Hprefix Hb]. split; [|exact Hb].
           exact
             (IH depth X (buf6_push cell rest) rest cell
                (buf6_pop_push (Stored9 X) cell rest) Hprefix).
        -- destruct Htail as [Hprefix Hsuf]. split; [|exact Hsuf].
           pose proof
             (IH depth X
                (k9_middle_inject
                   (buf6_inject (buf6_push cell rest) (StoredSmall9 pre))
                   sm)
                (k9_middle_inject
                   (buf6_inject rest (StoredSmall9 pre))
                   sm)
                cell
                ltac:(unfold k9_middle_inject;
                      destruct (buf6_is_empty sm);
                      repeat apply buf6_pop_inject_some;
                      apply buf6_pop_push)
                Hprefix) as Hprefix'.
           rewrite front_refill_step_middle9_k9_middle_inject in Hprefix'.
           rewrite front_refill_step_middle9_inject in Hprefix'.
           exact Hprefix'.
        -- destruct (buf6_eject sm_last) as [[sm_rest back_cell]|] eqn:Hsm.
           ++ pose proof
                (IH depth X
                   (buf6_inject
                      (k9_middle_inject (buf6_push cell rest) sm_rest)
                      back_cell)
                   (buf6_inject
                      (k9_middle_inject rest sm_rest)
                      back_cell)
                   cell
                   ltac:(apply buf6_pop_inject_some;
                         unfold k9_middle_inject;
                         destruct (buf6_is_empty sm_rest);
                         repeat apply buf6_pop_inject_some;
                         apply buf6_pop_push)
                   Htail) as Hprefix'.
              rewrite front_refill_step_middle9_inject in Hprefix'.
              rewrite front_refill_step_middle9_k9_middle_inject in Hprefix'.
              exact Hprefix'.
           ++ exact
                (IH depth X (buf6_push cell rest) rest cell
                   (buf6_pop_push (Stored9 X) cell rest) Htail).
      * apply buf6_eject_seq_none in Hrest_eject.
        unfold buf6_to_list in Hrest_eject.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_eject. subst rs.
        destruct cell as [b|pre sm suf|sm].
        -- cbn [front_refill_step_middle9
                back_refill_continuation_ready_middle9_fuel
                buf6_push buf6_empty buf6_eject buf6_elems rev] in *.
           destruct Htail as [Hempty Hb]. split; [|exact Hb].
           apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
           exact Hempty.
        -- cbn [buf6_push buf6_empty buf6_eject buf6_elems rev] in Htail |- *.
           replace
             (front_refill_step_middle9
                (StoredBig9 pre sm suf) {| buf6_elems := [] |})
             with
             (buf6_inject
                (k9_middle_inject
                  (buf6_inject buf6_empty (StoredSmall9 pre)) sm)
                (StoredSmall9 suf)).
           change
             (back_refill_continuation_ready_middle9_fuel (S fuel) depth
                (k9_middle_inject
                  (buf6_inject buf6_empty (StoredSmall9 pre)) sm) /\
              buf6_size_ge 1 suf) in Htail.
           rewrite buf6_eject_inject.
           change
             (back_refill_continuation_ready_middle9_fuel fuel depth
                (k9_middle_inject
                  (buf6_inject buf6_empty (StoredSmall9 pre)) sm) /\
              buf6_size_ge 1 suf).
           destruct Htail as [Hprefix Hsuf]. split; [|exact Hsuf].
           apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
           exact Hprefix.
           unfold front_refill_step_middle9, k9_middle_push, k9_middle_inject.
           destruct (buf6_is_empty sm); reflexivity.
        -- unfold front_refill_step_middle9, k9_middle_push in *.
           destruct sm as [sm_elems].
           destruct sm_elems as [|front sm_tail].
           ++ cbn [buf6_is_empty back_refill_continuation_ready_middle9_fuel
                   buf6_empty buf6_eject buf6_elems] in *.
              exact I.
	           ++ cbn [buf6_is_empty
	                   back_refill_continuation_ready_middle9_fuel
	                   buf6_push buf6_empty buf6_eject buf6_elems rev] in *.
              change
                (match buf6_eject (mkBuf6 (front :: sm_tail)) with
                 | Some (sm_rest, back_cell) =>
                     back_refill_continuation_ready_middle9_fuel (S fuel) depth
                       (buf6_inject
                          (k9_middle_inject
                            (@buf6_empty (Stored9 X)) sm_rest)
                          back_cell)
                 | None =>
                     back_refill_continuation_ready_middle9_fuel (S fuel) depth
                       (@buf6_empty (Stored9 X))
                 end) in Htail.
	              change
	                (match buf6_eject (mkBuf6 (front :: sm_tail)) with
	                 | Some (sm_rest, back_cell) =>
	                     back_refill_continuation_ready_middle9_fuel fuel depth
	                       (buf6_inject
	                          (k9_middle_inject
                                    (@buf6_empty (Stored9 X)) sm_rest)
                                  back_cell)
	                 | None =>
	                     back_refill_continuation_ready_middle9_fuel fuel depth
	                       (@buf6_empty (Stored9 X))
	                 end).
              destruct (buf6_eject (mkBuf6 (front :: sm_tail)))
                as [[sm_rest back_cell]|].
              ** apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
                 exact Htail.
              ** apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
                 exact Htail.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_small_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (b : Buf6 (KElem9 X)),
    buf6_pop m = Some (StoredSmall9 b, m_rest) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  intros fuel depth X m m_rest b Hpop Hcont.
  apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
  eapply back_refill_continuation_ready_middle9_fuel_after_pop_thm;
    eassumption.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_big_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (pre suf : Buf6 (KElem9 X)) (sm : Buf6 (Stored9 X)),
    buf6_pop m = Some (StoredBig9 pre sm suf, m_rest) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      (k9_middle_push sm (buf6_push (StoredSmall9 suf) m_rest)).
Proof.
  intros fuel depth X m m_rest pre suf sm Hpop Hcont.
  pose proof
    (back_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm
       fuel depth X m m_rest (StoredBig9 pre sm suf) Hpop Hcont)
    as Hstep.
  cbn [front_refill_step_middle9] in Hstep.
  eapply back_refill_continuation_ready_middle9_fuel_after_pop_thm.
  - apply buf6_pop_push.
  - exact Hstep.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_empty_middle_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest sm : Buf6 (Stored9 X)),
    buf6_pop m = Some (StoredMiddle9 sm, m_rest) ->
    buf6_pop sm = None ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  intros fuel depth X m m_rest sm Hpop _ Hcont.
  apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
  eapply back_refill_continuation_ready_middle9_fuel_after_pop_thm;
    eassumption.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_open_middle_normalize_step_thm :
  forall (fuel depth : nat) (X : Type)
         (m m_rest sm sm_rest : Buf6 (Stored9 X))
         (front_cell : Stored9 X),
    buf6_pop m = Some (StoredMiddle9 sm, m_rest) ->
    buf6_pop sm = Some (front_cell, sm_rest) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      (buf6_push front_cell (k9_middle_push sm_rest m_rest)).
Proof.
  induction fuel as [|fuel IH];
    intros depth X m m_rest sm sm_rest front_cell Hpop Hsm Hcont.
  - destruct Hcont as [Hready _]. split.
    + pose proof (buf6_pop_some_push_eq
                    (Stored9 X) m m_rest (StoredMiddle9 sm) Hpop) as Hm.
      subst m.
      eapply back_ready_or_empty_middle9_depth_open_front_middle;
        eassumption.
    + exact I.
  - pose proof (buf6_pop_some_push_eq
                  (Stored9 X) m m_rest (StoredMiddle9 sm) Hpop) as Hm.
    pose proof (buf6_pop_some_push_eq
                  (Stored9 X) sm sm_rest front_cell Hsm) as Hsm_eq.
    subst m sm.
    cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + eapply back_ready_or_empty_middle9_depth_open_front_middle.
      * apply buf6_pop_push.
      * exact Hready.
    + destruct (buf6_eject m_rest) as [[rest last]|] eqn:Hrest_eject.
      * rewrite (buf6_eject_push_some
                   (Stored9 X)
                   (StoredMiddle9 (buf6_push front_cell sm_rest))
                   m_rest rest last Hrest_eject) in Htail.
        rewrite (buf6_eject_open_front_middle_some
                   X front_cell last sm_rest m_rest rest Hrest_eject).
        destruct last as [b|pre sm_back suf|sm_back].
        -- destruct Htail as [Hprefix Hb]. split; [|exact Hb].
           exact
             (IH depth X
                (buf6_push (StoredMiddle9 (buf6_push front_cell sm_rest))
                   rest)
                rest (buf6_push front_cell sm_rest) sm_rest front_cell
                (buf6_pop_push (Stored9 X)
                   (StoredMiddle9 (buf6_push front_cell sm_rest)) rest)
                (buf6_pop_push (Stored9 X) front_cell sm_rest)
                Hprefix).
        -- destruct Htail as [Hprefix Hsuf]. split; [|exact Hsuf].
           rewrite k9_middle_inject_push_comm in Hprefix.
           pose proof
             (IH depth X
                (buf6_push (StoredMiddle9 (buf6_push front_cell sm_rest))
                   (k9_middle_inject
                     (buf6_inject rest (StoredSmall9 pre)) sm_back))
                (k9_middle_inject
                  (buf6_inject rest (StoredSmall9 pre)) sm_back)
                (buf6_push front_cell sm_rest) sm_rest front_cell
                (buf6_pop_push (Stored9 X)
                   (StoredMiddle9 (buf6_push front_cell sm_rest))
                   (k9_middle_inject
                     (buf6_inject rest (StoredSmall9 pre)) sm_back))
                (buf6_pop_push (Stored9 X) front_cell sm_rest)
                Hprefix) as Hprefix'.
           rewrite k9_middle_inject_open_front_middle_comm.
           exact Hprefix'.
        -- destruct (buf6_eject sm_back)
             as [[sm_back_rest back_cell]|] eqn:Hsm_back.
           ++ rewrite buf6_inject_k9_middle_inject_push_comm in Htail.
              pose proof
                (IH depth X
                   (buf6_push (StoredMiddle9 (buf6_push front_cell sm_rest))
                      (buf6_inject
                        (k9_middle_inject rest sm_back_rest) back_cell))
                   (buf6_inject
                     (k9_middle_inject rest sm_back_rest) back_cell)
                   (buf6_push front_cell sm_rest) sm_rest front_cell
                   (buf6_pop_push (Stored9 X)
                      (StoredMiddle9 (buf6_push front_cell sm_rest))
                      (buf6_inject
                        (k9_middle_inject rest sm_back_rest) back_cell))
                   (buf6_pop_push (Stored9 X) front_cell sm_rest)
                   Htail) as Htail'.
              rewrite buf6_inject_open_front_middle_comm.
              exact Htail'.
           ++ exact
                (IH depth X
                   (buf6_push (StoredMiddle9 (buf6_push front_cell sm_rest))
                      rest)
                   rest (buf6_push front_cell sm_rest) sm_rest front_cell
                   (buf6_pop_push (Stored9 X)
                      (StoredMiddle9 (buf6_push front_cell sm_rest)) rest)
                   (buf6_pop_push (Stored9 X) front_cell sm_rest)
                   Htail).
      * apply buf6_eject_seq_none in Hrest_eject.
        unfold buf6_to_list in Hrest_eject.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_eject. subst rs.
        change {| buf6_elems := [] |} with (@buf6_empty (Stored9 X)) in Htail.
        rewrite (buf6_eject_push_empty
                   (Stored9 X)
                   (StoredMiddle9 (buf6_push front_cell sm_rest))) in Htail.
        destruct (buf6_eject sm_rest)
          as [[sm_tail back_cell]|] eqn:Hsm_tail.
        -- rewrite (buf6_eject_push_some
                     (Stored9 X) front_cell sm_rest sm_tail back_cell
                     Hsm_tail) in Htail.
           change
             (back_refill_continuation_ready_middle9_fuel (S fuel) depth
                (buf6_push
                  (StoredMiddle9 (buf6_push front_cell sm_tail))
                  (buf6_inject (@buf6_empty (Stored9 X)) back_cell)))
             in Htail.
           pose proof
             (IH depth X
                (buf6_push
                  (StoredMiddle9 (buf6_push front_cell sm_tail))
                  (buf6_inject (@buf6_empty (Stored9 X)) back_cell))
                (buf6_inject (@buf6_empty (Stored9 X)) back_cell)
                (buf6_push front_cell sm_tail) sm_tail front_cell
                (buf6_pop_push (Stored9 X)
                  (StoredMiddle9 (buf6_push front_cell sm_tail))
                  (buf6_inject (@buf6_empty (Stored9 X)) back_cell))
                (buf6_pop_push (Stored9 X) front_cell sm_tail)
                Htail) as Htail'.
           rewrite k9_middle_push_inject_comm in Htail'.
           rewrite k9_middle_push_empty_k9_middle_inject_empty in Htail'.
           unfold k9_middle_push.
           rewrite (buf6_is_empty_false_of_eject_some
                      (Stored9 X) sm_rest sm_tail back_cell Hsm_tail).
           change {| buf6_elems := [] |} with (@buf6_empty (Stored9 X)).
           rewrite (buf6_eject_push_some
                      (Stored9 X) front_cell
                      (buf6_push (StoredMiddle9 sm_rest)
                        (@buf6_empty (Stored9 X)))
                      (@buf6_empty (Stored9 X)) (StoredMiddle9 sm_rest)
                        (buf6_eject_push_empty
                        (Stored9 X) (StoredMiddle9 sm_rest))).
           rewrite Hsm_tail.
           rewrite buf6_inject_k9_middle_inject_push_comm.
           exact Htail'.
        -- apply buf6_eject_seq_none in Hsm_tail.
           unfold buf6_to_list in Hsm_tail.
           destruct sm_rest as [ss].
           cbn [buf6_elems] in Hsm_tail. subst ss.
           cbn [k9_middle_push k9_middle_inject buf6_is_empty buf6_empty
                buf6_eject buf6_push buf6_inject buf6_elems rev] in Htail |- *.
           destruct Htail as [_ Htail]. exact Htail.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_front_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      (front_normalize_step_middle9 cell m_rest).
Proof.
  intros fuel depth X m m_rest cell Hpop Hcont.
  destruct cell as [b|pre sm suf|sm].
  - eapply back_refill_continuation_ready_middle9_fuel_after_front_small_normalize_step_thm;
      eassumption.
  - eapply back_refill_continuation_ready_middle9_fuel_after_front_big_normalize_step_thm;
      eassumption.
  - cbn [front_normalize_step_middle9].
    destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm.
    + eapply back_refill_continuation_ready_middle9_fuel_after_front_open_middle_normalize_step_thm;
        eassumption.
    + eapply back_refill_continuation_ready_middle9_fuel_after_front_empty_middle_normalize_step_thm;
        eassumption.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_back_refill_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      match cell with
      | StoredSmall9 b =>
          buf6_inject m_rest (StoredSmall9 b)
      | StoredBig9 pre sm suf =>
          buf6_inject
            (k9_middle_inject
              (buf6_inject m_rest (StoredSmall9 pre))
              sm)
            (StoredSmall9 suf)
      | StoredMiddle9 sm =>
          k9_middle_inject m_rest sm
      end.
Proof.
  intros fuel depth X m m_rest cell Heject Hcont.
  cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
  destruct Hcont as [Hready Htail].
  rewrite Heject in Htail.
  pose proof
    (back_ready_or_empty_middle9_depth_after_back_refill_step
       depth X m m_rest cell Heject Hready)
    as Hready_step.
  destruct fuel as [|fuel].
  - split; [exact Hready_step|exact I].
  - split; [exact Hready_step|].
    destruct cell as [b|pre sm suf|sm].
    + cbn [back_refill_continuation_ready_middle9_fuel].
      rewrite buf6_eject_inject.
      destruct Htail as [Hrest Hb]. split; [|exact Hb].
      apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
      exact Hrest.
    + cbn [back_refill_continuation_ready_middle9_fuel].
      rewrite buf6_eject_inject.
      destruct Htail as [Hrest Hsuf]. split; [|exact Hsuf].
      apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
      exact Hrest.
    + destruct sm as [sm_elems].
      destruct (buf6_eject (mkBuf6 sm_elems))
        as [[sm_rest back_cell]|] eqn:Hsm.
      * cbn [back_refill_continuation_ready_middle9_fuel].
        rewrite (k9_middle_inject_eject
                   X m_rest (mkBuf6 sm_elems) sm_rest back_cell Hsm).
        rewrite Hsm.
        apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
        exact Htail.
      * apply buf6_eject_seq_none in Hsm.
        unfold buf6_to_list in Hsm. cbn [buf6_elems] in Hsm. subst sm_elems.
        cbn [k9_middle_inject buf6_is_empty buf6_eject buf6_elems] in *.
        destruct Htail as [_ Htail]. exact Htail.
Qed.

Theorem back_refill_continuation_ready_middle9_fuel_after_back_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    back_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    back_refill_continuation_ready_middle9_fuel fuel depth
      (back_normalize_step_middle9 m_rest cell).
Proof.
  intros fuel depth X m m_rest cell Heject Hcont.
  cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
  destruct Hcont as [_ Htail].
  rewrite Heject in Htail.
  destruct cell as [b|pre sm suf|sm].
  - cbn [back_normalize_step_middle9]. destruct Htail as [Htail _].
    exact Htail.
  - cbn [back_normalize_step_middle9]. destruct Htail as [Htail _].
    exact Htail.
  - cbn [back_normalize_step_middle9].
    destruct (buf6_eject sm) as [[sm_rest back_cell]|]; exact Htail.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_refill_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      (back_refill_step_middle9 m_rest cell).
Proof.
  induction fuel as [|fuel IH]; intros depth X m m_rest cell Heject Hcont.
  - destruct Hcont as [Hready _]. split.
    + unfold back_refill_step_middle9.
      eapply front_ready_or_empty_middle9_depth_after_back_refill_step;
        eassumption.
    + exact I.
  - pose proof (buf6_eject_some_inject_eq
                  (Stored9 X) m m_rest cell Heject) as Hm.
    subst m.
    cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + unfold back_refill_step_middle9.
      eapply front_ready_or_empty_middle9_depth_after_back_refill_step.
      * apply buf6_eject_inject.
      * exact Hready.
    + destruct (buf6_pop m_rest) as [[front rest]|] eqn:Hrest_pop.
      * rewrite (buf6_pop_inject_some
                   (Stored9 X) m_rest rest front cell Hrest_pop) in Htail.
        rewrite (buf6_pop_back_refill_step_some
                   X front cell m_rest rest Hrest_pop).
        destruct front as [b|pre sm suf|sm_front].
        -- destruct Htail as [Hb Hprefix]. split; [exact Hb|].
           exact
             (IH depth X (buf6_inject rest cell) rest cell
                (buf6_eject_inject (Stored9 X) rest cell) Hprefix).
        -- destruct Htail as [Hpre Hprefix]. split; [exact Hpre|].
           pose proof
             (IH depth X
                (k9_middle_push sm
                   (buf6_push (StoredSmall9 suf)
                     (buf6_inject rest cell)))
                (k9_middle_push sm
                   (buf6_push (StoredSmall9 suf) rest))
                cell
                ltac:(unfold k9_middle_push;
                      destruct (buf6_is_empty sm);
                      repeat apply buf6_eject_push_some;
                      apply buf6_eject_inject)
                Hprefix) as Hprefix'.
           rewrite back_refill_step_middle9_k9_middle_push in Hprefix'.
           rewrite back_refill_step_middle9_push in Hprefix'.
           exact Hprefix'.
        -- destruct (buf6_pop sm_front) as [[front_cell sm_rest]|] eqn:Hsm.
           ++ pose proof
                (IH depth X
                   (buf6_push front_cell
                      (k9_middle_push sm_rest (buf6_inject rest cell)))
                   (buf6_push front_cell
                      (k9_middle_push sm_rest rest))
                   cell
                   ltac:(apply buf6_eject_push_some;
                         unfold k9_middle_push;
                         destruct (buf6_is_empty sm_rest);
                         repeat apply buf6_eject_push_some;
                         apply buf6_eject_inject)
                   Htail) as Hprefix'.
              rewrite back_refill_step_middle9_push in Hprefix'.
              rewrite back_refill_step_middle9_k9_middle_push in Hprefix'.
              exact Hprefix'.
           ++ exact
                (IH depth X (buf6_inject rest cell) rest cell
                   (buf6_eject_inject (Stored9 X) rest cell) Htail).
      * apply buf6_pop_seq_none in Hrest_pop.
        unfold buf6_to_list in Hrest_pop.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_pop. subst rs.
        destruct cell as [b|pre sm suf|sm].
        -- cbn [back_refill_step_middle9
                front_refill_continuation_ready_middle9_fuel
                buf6_inject buf6_empty buf6_pop buf6_elems] in *.
           destruct Htail as [Hb Hempty]. split; [exact Hb|].
           apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
           exact Hempty.
        -- cbn [buf6_inject buf6_empty buf6_pop buf6_elems] in Htail |- *.
           replace
             (back_refill_step_middle9 {| buf6_elems := [] |}
                (StoredBig9 pre sm suf))
             with
             (buf6_push (StoredSmall9 pre)
                (k9_middle_push sm
                  (buf6_push (StoredSmall9 suf) buf6_empty))).
           rewrite buf6_pop_push.
           change
             (buf6_size_ge 1 pre /\
              front_refill_continuation_ready_middle9_fuel fuel depth
                (k9_middle_push sm
                  (buf6_push (StoredSmall9 suf) buf6_empty))).
           change
             (buf6_size_ge 1 pre /\
              front_refill_continuation_ready_middle9_fuel (S fuel) depth
                (k9_middle_push sm
                  (buf6_push (StoredSmall9 suf) buf6_empty))) in Htail.
           destruct Htail as [Hpre Hprefix]. split; [exact Hpre|].
           apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
           exact Hprefix.
           unfold back_refill_step_middle9, k9_middle_push, k9_middle_inject.
           destruct (buf6_is_empty sm); reflexivity.
        -- unfold back_refill_step_middle9, k9_middle_inject in *.
           destruct sm as [sm_elems].
           destruct sm_elems as [|front sm_tail].
           ++ cbn [buf6_is_empty front_refill_continuation_ready_middle9_fuel
                   buf6_empty buf6_pop buf6_elems] in *.
              exact I.
           ++ cbn [buf6_is_empty
                   front_refill_continuation_ready_middle9_fuel
                   buf6_inject buf6_empty buf6_pop buf6_elems] in *.
              change
                (match buf6_pop (mkBuf6 (front :: sm_tail)) with
                 | Some (front_cell, sm_rest) =>
                     front_refill_continuation_ready_middle9_fuel (S fuel)
                       depth
                       (buf6_push front_cell
                          (k9_middle_push sm_rest
                            (@buf6_empty (Stored9 X))))
                 | None =>
                     front_refill_continuation_ready_middle9_fuel (S fuel)
                       depth (@buf6_empty (Stored9 X))
                 end) in Htail.
              change
                (match buf6_pop (mkBuf6 (front :: sm_tail)) with
                 | Some (front_cell, sm_rest) =>
                     front_refill_continuation_ready_middle9_fuel fuel depth
                       (buf6_push front_cell
                          (k9_middle_push sm_rest
                            (@buf6_empty (Stored9 X))))
                 | None =>
                     front_refill_continuation_ready_middle9_fuel fuel depth
                       (@buf6_empty (Stored9 X))
                 end).
              destruct (buf6_pop (mkBuf6 (front :: sm_tail)))
                as [[front_cell sm_rest]|].
              ** apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
                 exact Htail.
              ** apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
                 exact Htail.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_small_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (b : Buf6 (KElem9 X)),
    buf6_eject m = Some (m_rest, StoredSmall9 b) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  intros fuel depth X m m_rest b Heject Hcont.
  apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
  eapply front_refill_continuation_ready_middle9_fuel_after_eject_thm;
    eassumption.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_big_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (pre suf : Buf6 (KElem9 X)) (sm : Buf6 (Stored9 X)),
    buf6_eject m = Some (m_rest, StoredBig9 pre sm suf) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      (k9_middle_inject (buf6_inject m_rest (StoredSmall9 pre)) sm).
Proof.
  intros fuel depth X m m_rest pre suf sm Heject Hcont.
  pose proof
    (front_refill_continuation_ready_middle9_fuel_after_back_refill_step_thm
       fuel depth X m m_rest (StoredBig9 pre sm suf) Heject Hcont)
    as Hstep.
  cbn [back_refill_step_middle9] in Hstep.
  eapply front_refill_continuation_ready_middle9_fuel_after_eject_thm.
  - apply buf6_eject_inject.
  - exact Hstep.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_empty_middle_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest sm : Buf6 (Stored9 X)),
    buf6_eject m = Some (m_rest, StoredMiddle9 sm) ->
    buf6_eject sm = None ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth m_rest.
Proof.
  intros fuel depth X m m_rest sm Heject _ Hcont.
  apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
  eapply front_refill_continuation_ready_middle9_fuel_after_eject_thm;
    eassumption.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_open_middle_normalize_step_thm :
  forall (fuel depth : nat) (X : Type)
         (m m_rest sm sm_rest : Buf6 (Stored9 X))
         (back_cell : Stored9 X),
    buf6_eject m = Some (m_rest, StoredMiddle9 sm) ->
    buf6_eject sm = Some (sm_rest, back_cell) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      (buf6_inject (k9_middle_inject m_rest sm_rest) back_cell).
Proof.
  induction fuel as [|fuel IH];
    intros depth X m m_rest sm sm_rest back_cell Heject Hsm Hcont.
  - destruct Hcont as [Hready _]. split.
    + pose proof (buf6_eject_some_inject_eq
                    (Stored9 X) m m_rest (StoredMiddle9 sm) Heject) as Hm.
      subst m.
      eapply front_ready_or_empty_middle9_depth_open_back_middle;
        eassumption.
    + exact I.
  - pose proof (buf6_eject_some_inject_eq
                  (Stored9 X) m m_rest (StoredMiddle9 sm) Heject) as Hm.
    pose proof (buf6_eject_some_inject_eq
                  (Stored9 X) sm sm_rest back_cell Hsm) as Hsm_eq.
    subst m sm.
    cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
    destruct Hcont as [Hready Htail]. split.
    + eapply front_ready_or_empty_middle9_depth_open_back_middle.
      * apply buf6_eject_inject.
      * exact Hready.
    + destruct (buf6_pop m_rest) as [[front rest]|] eqn:Hrest_pop.
      * rewrite (buf6_pop_inject_some
                   (Stored9 X) m_rest rest front
                   (StoredMiddle9 (buf6_inject sm_rest back_cell))
                   Hrest_pop) in Htail.
        rewrite (buf6_pop_open_back_middle_some
                   X front back_cell m_rest rest sm_rest Hrest_pop).
        destruct front as [b|pre sm_front suf|sm_front].
        -- destruct Htail as [Hb Hsuffix]. split; [exact Hb|].
           exact
             (IH depth X
                (buf6_inject rest
                  (StoredMiddle9 (buf6_inject sm_rest back_cell)))
                rest (buf6_inject sm_rest back_cell) sm_rest back_cell
                (buf6_eject_inject (Stored9 X) rest
                  (StoredMiddle9 (buf6_inject sm_rest back_cell)))
                (buf6_eject_inject (Stored9 X) sm_rest back_cell)
                Hsuffix).
        -- destruct Htail as [Hpre Hsuffix]. split; [exact Hpre|].
           pose proof
             (IH depth X
                (k9_middle_push sm_front
                  (buf6_push (StoredSmall9 suf)
                    (buf6_inject rest
                      (StoredMiddle9
                        (buf6_inject sm_rest back_cell)))))
                (k9_middle_push sm_front
                  (buf6_push (StoredSmall9 suf) rest))
                (buf6_inject sm_rest back_cell) sm_rest back_cell
                ltac:(unfold k9_middle_push;
                      destruct (buf6_is_empty sm_front);
                      repeat apply buf6_eject_push_some;
                      apply buf6_eject_inject)
                (buf6_eject_inject (Stored9 X) sm_rest back_cell)
                Hsuffix) as Hsuffix'.
           rewrite k9_middle_push_push_open_back_middle_comm.
           exact Hsuffix'.
        -- destruct (buf6_pop sm_front)
             as [[front_cell sm_front_rest]|] eqn:Hsm_front.
           ++ pose proof
                (IH depth X
                   (buf6_push front_cell
                     (k9_middle_push sm_front_rest
                       (buf6_inject rest
                         (StoredMiddle9
                           (buf6_inject sm_rest back_cell)))))
                   (buf6_push front_cell
                     (k9_middle_push sm_front_rest rest))
                   (buf6_inject sm_rest back_cell) sm_rest back_cell
                   ltac:(apply buf6_eject_push_some;
                         unfold k9_middle_push;
                         destruct (buf6_is_empty sm_front_rest);
                         repeat apply buf6_eject_push_some;
                         apply buf6_eject_inject)
                   (buf6_eject_inject (Stored9 X) sm_rest back_cell)
                   Htail) as Htail'.
              rewrite <- buf6_inject_open_front_middle_comm.
              exact Htail'.
           ++ exact
                (IH depth X
                   (buf6_inject rest
                     (StoredMiddle9 (buf6_inject sm_rest back_cell)))
                   rest (buf6_inject sm_rest back_cell) sm_rest back_cell
                   (buf6_eject_inject (Stored9 X) rest
                     (StoredMiddle9 (buf6_inject sm_rest back_cell)))
                   (buf6_eject_inject (Stored9 X) sm_rest back_cell)
                   Htail).
      * apply buf6_pop_seq_none in Hrest_pop.
        unfold buf6_to_list in Hrest_pop.
        destruct m_rest as [rs]. cbn [buf6_elems] in Hrest_pop. subst rs.
        change {| buf6_elems := [] |} with (@buf6_empty (Stored9 X)) in Htail.
        rewrite (buf6_pop_inject_empty
                   (Stored9 X)
                   (StoredMiddle9 (buf6_inject sm_rest back_cell))) in Htail.
        destruct (buf6_pop sm_rest)
          as [[front sm_tail]|] eqn:Hsm_tail.
        -- rewrite (buf6_pop_inject_some
                     (Stored9 X) sm_rest sm_tail front back_cell
                     Hsm_tail) in Htail.
           change
             (front_refill_continuation_ready_middle9_fuel (S fuel) depth
                (buf6_push front
                  (k9_middle_push
                    (buf6_inject sm_tail back_cell)
                    (@buf6_empty (Stored9 X)))))
             in Htail.
           pose proof
             (IH depth X
                (buf6_push front
                  (k9_middle_push
                    (buf6_inject sm_tail back_cell)
                    (@buf6_empty (Stored9 X))))
                (buf6_push front (@buf6_empty (Stored9 X)))
                (buf6_inject sm_tail back_cell) sm_tail back_cell
                ltac:(unfold k9_middle_push;
                      rewrite (buf6_is_empty_false_of_eject_some
                                 (Stored9 X)
                                 (buf6_inject sm_tail back_cell)
                                 sm_tail back_cell
                                 (buf6_eject_inject
                                    (Stored9 X) sm_tail back_cell));
                      apply buf6_eject_push_some;
                      apply buf6_eject_push_empty)
                (buf6_eject_inject (Stored9 X) sm_tail back_cell)
                Htail) as Htail'.
           rewrite buf6_inject_k9_middle_inject_push_comm in Htail'.
           rewrite <- k9_middle_push_empty_k9_middle_inject_empty in Htail'.
           rewrite <- k9_middle_push_inject_comm in Htail'.
           unfold k9_middle_inject.
           rewrite (buf6_is_empty_false_of_pop_some
                      (Stored9 X) sm_rest front sm_tail Hsm_tail).
           change {| buf6_elems := [] |} with (@buf6_empty (Stored9 X)).
           rewrite (buf6_pop_inject_some
                      (Stored9 X)
                      (buf6_inject (@buf6_empty (Stored9 X))
                        (StoredMiddle9 sm_rest))
                      (@buf6_empty (Stored9 X))
                      (StoredMiddle9 sm_rest) back_cell
                      (buf6_pop_inject_empty
                        (Stored9 X) (StoredMiddle9 sm_rest))).
           rewrite Hsm_tail.
           exact Htail'.
        -- apply buf6_pop_seq_none in Hsm_tail.
           unfold buf6_to_list in Hsm_tail.
           destruct sm_rest as [ss].
           cbn [buf6_elems] in Hsm_tail. subst ss.
           cbn [k9_middle_push k9_middle_inject buf6_is_empty buf6_empty
                buf6_pop buf6_push buf6_inject buf6_elems] in Htail |- *.
           destruct Htail as [_ Htail]. exact Htail.
Qed.

Theorem front_refill_continuation_ready_middle9_fuel_after_back_normalize_step_thm :
  forall (fuel depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    front_refill_continuation_ready_middle9_fuel (S fuel) depth m ->
    front_refill_continuation_ready_middle9_fuel fuel depth
      (back_normalize_step_middle9 m_rest cell).
Proof.
  intros fuel depth X m m_rest cell Heject Hcont.
  destruct cell as [b|pre sm suf|sm].
  - eapply front_refill_continuation_ready_middle9_fuel_after_back_small_normalize_step_thm;
      eassumption.
  - eapply front_refill_continuation_ready_middle9_fuel_after_back_big_normalize_step_thm;
      eassumption.
  - cbn [back_normalize_step_middle9].
    destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Hsm.
    + eapply front_refill_continuation_ready_middle9_fuel_after_back_open_middle_normalize_step_thm;
        eassumption.
    + eapply front_refill_continuation_ready_middle9_fuel_after_back_empty_middle_normalize_step_thm;
        eassumption.
Qed.

Theorem front_ready_or_empty_middle9_depth_after_back_normalize_step :
  forall (depth : nat) (X : Type) (m m_rest : Buf6 (Stored9 X))
         (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    front_ready_or_empty_middle9_depth depth m ->
    front_ready_or_empty_middle9_depth depth
      (back_normalize_step_middle9 m_rest cell).
Proof.
  intros depth X m m_rest cell Heject Hready.
  destruct cell as [b|pre sm suf|sm].
  - cbn [back_normalize_step_middle9].
    eapply front_ready_or_empty_middle9_depth_after_eject; eassumption.
  - cbn [back_normalize_step_middle9].
    pose proof
      (front_ready_or_empty_middle9_depth_after_back_refill_step
         depth X m m_rest (StoredBig9 pre sm suf) Heject Hready)
      as Hstep.
    eapply front_ready_or_empty_middle9_depth_after_eject.
    + apply buf6_eject_inject.
    + exact Hstep.
  - cbn [back_normalize_step_middle9].
    destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Hsm.
    + pose proof
        (front_ready_or_empty_middle9_depth_after_back_refill_step
           depth X m m_rest (StoredMiddle9 sm) Heject Hready)
        as Hstep.
      cbn [back_refill_step_middle9] in Hstep.
      unfold k9_middle_inject in Hstep.
      rewrite (buf6_is_empty_false_of_eject_some
                 (Stored9 X) sm sm_rest back_cell Hsm) in Hstep.
      eapply front_ready_or_empty_middle9_depth_open_back_middle;
        eassumption.
    + eapply front_ready_or_empty_middle9_depth_after_eject; eassumption.
Qed.

Theorem k9_with_front_fuel_front_continuation_thm :
  forall (fuel sched depth : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (t : Buf6 (KElem9 X))
         (k : KCadeque9 X),
    front_refill_continuation_ready_middle9_fuel
      (fuel + sched) depth m ->
    k9_with_front_fuel fuel (@buf6_empty (KElem9 X)) m t = k ->
    match k with
    | K9Triple _ m' _ =>
        front_refill_continuation_ready_middle9_fuel sched depth m'
    | _ => True
    end.
Proof.
  induction fuel as [|fuel IH]; intros sched depth X m t k Hcont Hres.
  - cbn [k9_with_front_fuel] in Hres. subst k. exact Hcont.
  - cbn [Nat.add] in Hcont.
    cbn [k9_with_front_fuel buf6_is_empty buf6_empty] in Hres.
    destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
    + cbn [front_refill_continuation_ready_middle9_fuel] in Hcont.
      destruct Hcont as [_ Htail]. rewrite Hpop in Htail.
      destruct cell as [b|pre sm suf|sm].
      * destruct Htail as [Hb Hrest].
        destruct (buf6_is_empty b) eqn:Hb_empty.
        -- exact (IH sched depth X m_rest t k Hrest Hres).
        -- subst k.
           eapply front_refill_continuation_ready_middle9_fuel_drop_prefix_thm.
           exact Hrest.
      * destruct Htail as [Hpre Hrest].
        destruct (buf6_is_empty pre) eqn:Hpre_empty.
        -- exact
             (IH sched depth X
                (k9_middle_push sm (buf6_push (StoredSmall9 suf) m_rest))
                t k Hrest Hres).
        -- subst k.
           eapply front_refill_continuation_ready_middle9_fuel_drop_prefix_thm.
           exact Hrest.
      * destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm.
        -- exact
             (IH sched depth X
                (buf6_push front_cell (k9_middle_push sm_rest m_rest))
                t k Htail Hres).
        -- exact (IH sched depth X m_rest t k Htail Hres).
    + destruct (buf6_is_empty t); subst k; exact I.
Qed.

Theorem k9_with_back_fuel_back_continuation_thm :
  forall (fuel sched depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (k : KCadeque9 X),
    back_refill_continuation_ready_middle9_fuel
      (fuel + sched) depth m ->
    k9_with_back_fuel fuel h m (@buf6_empty (KElem9 X)) = k ->
    match k with
