  induction fuel as [|fuel IH]; intros sched depth X h m k Hcont Hres.
  - cbn [k9_with_back_fuel] in Hres. subst k. exact Hcont.
  - cbn [Nat.add] in Hcont.
    cbn [k9_with_back_fuel buf6_is_empty buf6_empty] in Hres.
    destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
    + cbn [back_refill_continuation_ready_middle9_fuel] in Hcont.
      destruct Hcont as [_ Htail]. rewrite Heject in Htail.
      destruct cell as [b|pre sm suf|sm].
      * destruct Htail as [Hrest Hb].
        destruct (buf6_is_empty b) eqn:Hb_empty.
        -- exact (IH sched depth X h m_rest k Hrest Hres).
        -- subst k.
           eapply back_refill_continuation_ready_middle9_fuel_drop_prefix_thm.
           exact Hrest.
      * destruct Htail as [Hrest Hsuf].
        destruct (buf6_is_empty suf) eqn:Hsuf_empty.
        -- exact
             (IH sched depth X h
                (k9_middle_inject
                  (buf6_inject m_rest (StoredSmall9 pre)) sm)
                k Hrest Hres).
        -- subst k.
           eapply back_refill_continuation_ready_middle9_fuel_drop_prefix_thm.
           exact Hrest.
      * destruct (buf6_eject sm) as [[sm_rest back_cell]|] eqn:Hsm.
        -- exact
             (IH sched depth X h
                (buf6_inject (k9_middle_inject m_rest sm_rest) back_cell)
                k Htail Hres).
        -- exact (IH sched depth X h m_rest k Htail Hres).
    + destruct (buf6_is_empty h); subst k; exact I.
Qed.

