Theorem inv_kcad9_ocaml_ready_depth_ready_or_empty_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_depth depth k ->
    inv_kcad9_ocaml_ready_or_empty_depth depth k.
Proof.
  intros depth X [|b|h m t] Hinv; cbn in *; auto.
  destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  repeat split; try assumption; right; assumption.
Qed.

Theorem inv_kcad9_ocaml_ready_or_empty_depth_succ_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    inv_kcad9_ocaml_ready_or_empty_depth (S depth) k.
Proof.
  intros depth X [|b|h m t] Hinv; cbn in *; auto.
  destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  repeat split; try assumption.
  - apply front_ready_or_empty_middle9_depth_succ. exact Hfront.
  - apply back_ready_or_empty_middle9_depth_succ. exact Hback.
Qed.

Theorem kcad9_push_ocaml_ready_or_empty_depth_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    inv_kcad9_ocaml_ready_or_empty_depth depth (kcad9_push x k).
Proof.
  intros depth X x [|b|h m t] Hinv;
    cbn [inv_kcad9_ocaml_ready_or_empty_depth kcad9_push] in *.
  - split.
    + unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
    + constructor; [exact I|constructor].
  - destruct Hinv as [Hb Hxb].
    split.
    + apply buf6_size_ge_push_preserve. exact Hb.
    + apply all_xbase9_push_base. exact Hxb.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    repeat split; try assumption.
    + apply buf6_size_ge_push_preserve. exact Hh.
    + apply all_xbase9_push_base. exact Hxh.
Qed.

Theorem kcad9_inject_ocaml_ready_or_empty_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    inv_kcad9_ocaml_ready_or_empty_depth depth (kcad9_inject k x).
Proof.
  intros depth X [|b|h m t] x Hinv;
    cbn [inv_kcad9_ocaml_ready_or_empty_depth kcad9_inject] in *.
  - split.
    + unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
    + constructor; [exact I|constructor].
  - destruct Hinv as [Hb Hxb].
    split.
    + apply buf6_size_ge_inject_preserve. exact Hb.
    + apply all_xbase9_inject_base. exact Hxb.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    repeat split; try assumption.
    + apply buf6_size_ge_inject_preserve. exact Ht.
    + apply all_xbase9_inject_base. exact Hxt.
Qed.

Theorem kcad9_push_ocaml_middle_depth_bound_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_middle_depth_bound depth k ->
