  intros depth X x [|b|h m t] Hinv;
    cbn [inv_kcad9_ocaml_middle_depth_bound kcad9_push] in *;
    exact Hinv.
Qed.

Theorem kcad9_inject_ocaml_middle_depth_bound_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_middle_depth_bound depth k ->
    inv_kcad9_ocaml_middle_depth_bound depth (kcad9_inject k x).
