Theorem kcad9_concat_ocaml_shape_middle_depth_bound_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_middle_depth_bound depth a ->
    inv_kcad9_ocaml_middle_depth_bound depth b ->
    inv_kcad9_ocaml_middle_depth_bound
      depth (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [inv_kcad9_ocaml_middle_depth_bound kcad9_concat_ocaml_shape] in *.
  - exact I.
  - exact Hb.
  - exact Hb.
  - exact Ha.
  - apply middle9_depth_le_empty.
  - apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hb].
  - exact Ha.
  - apply middle9_depth_le_inject; [exact Ha|apply stored_middle_depth_le_small].
  - destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct (middle9_depth_le_eject depth X m2 m2_rest back_cell Hb Heject)
        as [Hm2_rest Hback_cell].
      apply middle9_depth_le_inject; [|exact Hback_cell].
      apply middle9_depth_le_inject; [exact Ha|].
      apply stored_middle_depth_le_big.
      apply middle9_depth_le_push.
      * apply stored_middle_depth_le_small.
      * exact Hm2_rest.
    + apply middle9_depth_le_inject; [exact Ha|].
      apply stored_middle_depth_le_big.
      apply middle9_depth_le_empty.
Qed.

Theorem kcad9_concat_ocaml_shape_inv_ready_or_empty_depth_same_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth a ->
    inv_kcad9_ocaml_ready_or_empty_depth depth b ->
    inv_kcad9_ocaml_ready_or_empty_depth
      depth (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [kcad9_concat_ocaml_shape].
  - exact I.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Hb.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Hb.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Ha.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hba Hxba]. destruct Hb as [Hbb Hxbb].
    repeat split; try assumption; left; reflexivity.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hba Hxba].
    destruct Hb as [Hh2 [Hxh2 [Ht2 [Hxt2 [Hfront2 Hback2]]]]].
    repeat split; try assumption.
    + right. apply buf6_push_front_ready_stored9_depth.
      apply front_ready_stored9_depth_small. exact Hh2.
    + right. eapply back_ready_middle9_depth_push_or_ready.
      * apply back_ready_stored9_depth_small. exact Hh2.
      * exact Hback2.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Ha.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hh1 [Hxh1 [Ht1 [Hxt1 [Hfront1 Hback1]]]]].
    destruct Hb as [Hbb Hxbb].
    repeat split; try assumption.
    + right. eapply front_ready_middle9_depth_inject_or_ready.
      * exact Hfront1.
      * apply front_ready_stored9_depth_small. exact Ht1.
    + right. apply buf6_inject_back_ready_stored9_depth.
      apply back_ready_stored9_depth_small. exact Ht1.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hh1 [Hxh1 [Ht1 [Hxt1 [Hfront1 Hback1]]]]].
    destruct Hb as [Hh2 [Hxh2 [Ht2 [Hxt2 [Hfront2 Hback2]]]]].
    repeat split; try assumption.
    + destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
      * right. apply front_ready_middle9_depth_inject_preserve.
        eapply front_ready_middle9_depth_inject_or_ready.
        -- exact Hfront1.
        -- apply front_ready_stored9_depth_big. exact Ht1.
      * right.
        eapply front_ready_middle9_depth_inject_or_ready.
        -- exact Hfront1.
        -- apply front_ready_stored9_depth_big. exact Ht1.
    + right. destruct Hback2 as [Hm2empty|Hback2].
      * apply buf6_eject_seq_none in Hm2empty. unfold buf6_to_list in Hm2empty.
        destruct m2 as [xs]. cbn [buf6_elems] in Hm2empty. subst xs.
        apply buf6_inject_back_ready_stored9_depth.
        apply back_ready_stored9_depth_big. exact Hh2.
      * pose proof
          (kcad9_concat_ocaml_shape_tt_back_ready_depth
             depth X h1 m1 t1 h2 m2 t2 Hback2)
          as Hready.
        cbn [kcad9_concat_ocaml_shape] in Hready.
        exact Hready.
Qed.

Theorem kcad9_concat_ocaml_shape_inv_ready_or_empty_depth_bump_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth a ->
    inv_kcad9_ocaml_ready_or_empty_depth depth b ->
    inv_kcad9_ocaml_ready_or_empty_depth
      (S depth) (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X a b Ha Hb.
  apply inv_kcad9_ocaml_ready_or_empty_depth_succ_thm.
  eapply kcad9_concat_ocaml_shape_inv_ready_or_empty_depth_same_thm;
    eassumption.
Qed.

