Theorem inv_kcad9_ocaml_residual_depth_succ_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_residual_depth depth k ->
    inv_kcad9_ocaml_residual_depth (S depth) k.
Proof.
  intros depth X [|b|h m t] [Hreach Hres].
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + exact I.
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + exact I.
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + cbn [kcad9_ocaml_refill_residual_ready_depth] in *.
      destruct Hres as [Hfront Hback]. split.
      * apply front_refill_residual_ready_middle9_depth_succ_thm. exact Hfront.
      * apply back_refill_residual_ready_middle9_depth_succ_thm. exact Hback.
Qed.

Theorem inv_kcad9_ocaml_continuation_depth_succ_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth fuel depth k ->
    inv_kcad9_ocaml_continuation_depth fuel (S depth) k.
Proof.
  intros fuel depth X [|b|h m t] [Hreach Hcont].
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + exact I.
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + exact I.
  - split.
    + apply inv_kcad9_ocaml_reachable_depth_succ_thm. exact Hreach.
    + cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth] in *.
      destruct Hcont as [Hfront Hback]. split.
      * apply front_refill_continuation_ready_middle9_fuel_succ_thm.
        exact Hfront.
      * apply back_refill_continuation_ready_middle9_fuel_succ_thm.
        exact Hback.
Qed.

Theorem kcad9_push_ocaml_reachable_depth_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth depth k ->
    inv_kcad9_ocaml_reachable_depth depth (kcad9_push x k).
Proof.
  intros depth X x k [Hready Hdeep]. split.
  - apply kcad9_push_ocaml_ready_or_empty_depth_thm. exact Hready.
  - apply kcad9_push_ocaml_deep_xbase. exact Hdeep.
Qed.

Theorem kcad9_inject_ocaml_reachable_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_reachable_depth depth k ->
    inv_kcad9_ocaml_reachable_depth depth (kcad9_inject k x).
Proof.
  intros depth X k x [Hready Hdeep]. split.
  - apply kcad9_inject_ocaml_ready_or_empty_depth_thm. exact Hready.
  - apply kcad9_inject_ocaml_deep_xbase. exact Hdeep.
Qed.

Theorem kcad9_push_ocaml_residual_depth_thm :
  forall (depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_residual_depth depth k ->
    inv_kcad9_ocaml_residual_depth depth (kcad9_push x k).
Proof.
  intros depth X x k [Hreach Hres]. split.
  - apply kcad9_push_ocaml_reachable_depth_thm. exact Hreach.
  - destruct k as [|b|h m t];
      cbn [kcad9_push kcad9_ocaml_refill_residual_ready_depth] in *;
      exact Hres.
Qed.

Theorem kcad9_inject_ocaml_residual_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_residual_depth depth k ->
    inv_kcad9_ocaml_residual_depth depth (kcad9_inject k x).
Proof.
  intros depth X k x [Hreach Hres]. split.
  - apply kcad9_inject_ocaml_reachable_depth_thm. exact Hreach.
  - destruct k as [|b|h m t];
      cbn [kcad9_inject kcad9_ocaml_refill_residual_ready_depth] in *;
      exact Hres.
Qed.

Theorem kcad9_push_ocaml_continuation_depth_thm :
  forall (fuel depth : nat) (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth fuel depth k ->
    inv_kcad9_ocaml_continuation_depth fuel depth (kcad9_push x k).
Proof.
  intros fuel depth X x k [Hreach Hcont]. split.
  - apply kcad9_push_ocaml_reachable_depth_thm. exact Hreach.
  - destruct k as [|b|h m t];
      cbn [kcad9_push kcad9_ocaml_refill_continuation_ready_fuel_depth] in *;
      exact Hcont.
Qed.

Theorem kcad9_inject_ocaml_continuation_depth_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_continuation_depth fuel depth k ->
    inv_kcad9_ocaml_continuation_depth fuel depth (kcad9_inject k x).
Proof.
  intros fuel depth X k x [Hreach Hcont]. split.
  - apply kcad9_inject_ocaml_reachable_depth_thm. exact Hreach.
  - destruct k as [|b|h m t];
      cbn [kcad9_inject kcad9_ocaml_refill_continuation_ready_fuel_depth] in *;
      exact Hcont.
Qed.

Theorem kcad9_concat_ocaml_shape_inv_reachable_depth_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth depth a ->
    inv_kcad9_ocaml_reachable_depth depth b ->
    inv_kcad9_ocaml_reachable_depth depth (kcad9_concat_ocaml_shape a b).
Proof.
  intros depth X a b [Ha_ready Ha_deep] [Hb_ready Hb_deep]. split.
  - eapply kcad9_concat_ocaml_shape_inv_ready_or_empty_depth_same_thm;
      eassumption.
  - eapply kcad9_concat_ocaml_shape_inv_deep_xbase; eassumption.
Qed.

Fixpoint all_kcad9_ocaml_reachable_depth {X : Type}
  (depth : nat) (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_reachable_depth depth k /\
      all_kcad9_ocaml_reachable_depth depth ks'
  end.

Theorem kcad9_concat_ocaml_shape_left_fold_reachable_depth_thm :
  forall (depth : nat) (X : Type)
         (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_reachable_depth depth acc ->
    all_kcad9_ocaml_reachable_depth depth ks ->
    inv_kcad9_ocaml_reachable_depth depth
      (kcad9_concat_ocaml_shape_left_fold acc ks).
Proof.
  intros depth X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hacc Hall.
  - exact Hacc.
  - cbn [kcad9_concat_ocaml_shape_left_fold
         all_kcad9_ocaml_reachable_depth] in *.
    destruct Hall as [Hk Hks].
    apply IH; [|exact Hks].
    eapply kcad9_concat_ocaml_shape_inv_reachable_depth_thm;
      eassumption.
Qed.

Theorem all_kcad9_ocaml_reachable_depth_singletons_thm :
  forall (depth : nat) (X : Type) (xs : list X),
    all_kcad9_ocaml_reachable_depth
      depth (map kcad9_singleton xs).
Proof.
  intros depth X xs.
  induction xs as [|x xs IH].
  - exact I.
  - cbn [map all_kcad9_ocaml_reachable_depth].
    split.
    + apply singleton_kcad9_ocaml_reachable_depth_thm.
    + exact IH.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm :
  forall (X : Type) (xs : list X),
    inv_kcad9_ocaml_reachable_depth 1
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) /\
    kcad9_to_list
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) = xs.
Proof.
  intros X xs.
  split.
  - apply kcad9_concat_ocaml_shape_left_fold_reachable_depth_thm.
    + apply empty_kcad9_ocaml_reachable_depth_thm.
    + apply all_kcad9_ocaml_reachable_depth_singletons_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm.
Qed.

Definition stored9_small_nonempty {X : Type} (s : Stored9 X) : Prop :=
  match s with
  | StoredSmall9 b => buf6_size_ge 1 b
  | _ => False
  end.

Definition middle9_small_nonempty {X : Type}
  (m : Buf6 (Stored9 X)) : Prop :=
  Forall stored9_small_nonempty (buf6_elems m).

Definition kcad9_ocaml_middle_small_nonempty {X : Type}
  (k : KCadeque9 X) : Prop :=
  match k with
  | K9Triple _ m _ => middle9_small_nonempty m
  | _ => True
  end.

Lemma stored9_small_nonempty_front_ready_depth :
  forall (depth : nat) (X : Type) (s : Stored9 X),
    stored9_small_nonempty s ->
    front_ready_stored9_depth depth s.
Proof.
  intros [|depth] X [b|pre sm suf|sm] Hsmall;
    cbn [stored9_small_nonempty front_ready_stored9_depth
         front_ready_stored9] in *;
    try contradiction; exact Hsmall.
Qed.

Lemma stored9_small_nonempty_back_ready_depth :
  forall (depth : nat) (X : Type) (s : Stored9 X),
    stored9_small_nonempty s ->
    back_ready_stored9_depth depth s.
Proof.
  intros [|depth] X [b|pre sm suf|sm] Hsmall;
    cbn [stored9_small_nonempty back_ready_stored9_depth
         back_ready_stored9] in *;
    try contradiction; exact Hsmall.
Qed.

Lemma middle9_small_nonempty_pop :
  forall (X : Type) (m m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    buf6_pop m = Some (cell, m_rest) ->
    middle9_small_nonempty m ->
    stored9_small_nonempty cell /\ middle9_small_nonempty m_rest.
Proof.
  intros X [xs] [rs] cell Hpop Hsmall.
  unfold middle9_small_nonempty in *.
  cbn [buf6_pop buf6_elems] in Hpop.
  destruct xs as [|front rest]; [discriminate|].
  injection Hpop as Hcell Hrest. subst cell rs.
  inversion Hsmall; subst. split; assumption.
Qed.

Lemma middle9_small_nonempty_eject :
  forall (X : Type) (m m_rest : Buf6 (Stored9 X)) (cell : Stored9 X),
    buf6_eject m = Some (m_rest, cell) ->
    middle9_small_nonempty m ->
    middle9_small_nonempty m_rest /\ stored9_small_nonempty cell.
Proof.
  intros X [xs] [rs] cell Heject Hsmall.
  unfold middle9_small_nonempty in *.
  apply buf6_eject_seq_some in Heject.
  unfold buf6_to_list in Heject. cbn [buf6_elems] in Heject.
  subst xs.
  apply Forall_app in Hsmall as [Hrs Hcell].
  inversion Hcell; subst. split; assumption.
Qed.

Lemma middle9_small_nonempty_inject_small :
  forall (X : Type) (m : Buf6 (Stored9 X)) (b : Buf6 (KElem9 X)),
    middle9_small_nonempty m ->
    buf6_size_ge 1 b ->
    middle9_small_nonempty (buf6_inject m (StoredSmall9 b)).
Proof.
  intros X [xs] b Hsmall Hb.
  unfold middle9_small_nonempty in *.
  cbn [buf6_inject buf6_elems].
  apply Forall_app. split; [exact Hsmall|].
  constructor; [exact Hb|constructor].
Qed.

Lemma front_ready_or_empty_middle9_depth_small_nonempty :
  forall (depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    middle9_small_nonempty m ->
    front_ready_or_empty_middle9_depth depth m.
Proof.
  intros depth X m Hsmall.
  destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
  - right. exists cell, m_rest. split; [exact Hpop|].
    destruct (middle9_small_nonempty_pop X m m_rest cell Hpop Hsmall)
      as [Hcell _].
    apply stored9_small_nonempty_front_ready_depth. exact Hcell.
  - left. exact Hpop.
Qed.

Lemma back_ready_or_empty_middle9_depth_small_nonempty :
  forall (depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    middle9_small_nonempty m ->
    back_ready_or_empty_middle9_depth depth m.
Proof.
  intros depth X m Hsmall.
  destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject.
  - right. exists m_rest, cell. split; [exact Heject|].
    destruct (middle9_small_nonempty_eject X m m_rest cell Heject Hsmall)
      as [_ Hcell].
    apply stored9_small_nonempty_back_ready_depth. exact Hcell.
  - left. exact Heject.
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_small_nonempty :
  forall (fuel depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    middle9_small_nonempty m ->
    front_refill_continuation_ready_middle9_fuel fuel depth m.
Proof.
  induction fuel as [|fuel IH]; intros depth X m Hsmall.
  - split.
    + apply front_ready_or_empty_middle9_depth_small_nonempty. exact Hsmall.
    + exact I.
  - split.
    + apply front_ready_or_empty_middle9_depth_small_nonempty. exact Hsmall.
    + destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop; [|exact I].
      destruct (middle9_small_nonempty_pop X m m_rest cell Hpop Hsmall)
        as [Hcell Hrest].
      destruct cell as [b|pre sm suf|sm];
        cbn [stored9_small_nonempty] in Hcell; try contradiction.
      split; [exact Hcell|].
      apply IH. exact Hrest.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_small_nonempty :
  forall (fuel depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    middle9_small_nonempty m ->
    back_refill_continuation_ready_middle9_fuel fuel depth m.
Proof.
  induction fuel as [|fuel IH]; intros depth X m Hsmall.
  - split.
    + apply back_ready_or_empty_middle9_depth_small_nonempty. exact Hsmall.
    + exact I.
  - split.
    + apply back_ready_or_empty_middle9_depth_small_nonempty. exact Hsmall.
    + destruct (buf6_eject m) as [[m_rest cell]|] eqn:Heject; [|exact I].
      destruct (middle9_small_nonempty_eject X m m_rest cell Heject Hsmall)
        as [Hrest Hcell].
      destruct cell as [b|pre sm suf|sm];
        cbn [stored9_small_nonempty] in Hcell; try contradiction.
      split; [|exact Hcell].
      apply IH. exact Hrest.
Qed.

Lemma front_ready_or_empty_middle9_depth_inject_small :
  forall (depth : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (b : Buf6 (KElem9 X)),
    front_ready_or_empty_middle9_depth depth m ->
    buf6_size_ge 1 b ->
    front_ready_or_empty_middle9_depth depth
      (buf6_inject m (StoredSmall9 b)).
Proof.
  intros depth X m b Hfront Hb.
  destruct Hfront as [Hempty|Hfront].
  - right. exists (StoredSmall9 b), buf6_empty. split.
    + apply buf6_pop_inject_none. exact Hempty.
    + destruct depth; cbn; exact Hb.
  - destruct Hfront as (cell & rest & Hpop & Hcell).
    right. exists cell, (buf6_inject rest (StoredSmall9 b)).
    split.
    + apply buf6_pop_inject_some. exact Hpop.
    + exact Hcell.
Qed.

Lemma back_ready_or_empty_middle9_depth_inject_small :
  forall (depth : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (b : Buf6 (KElem9 X)),
    buf6_size_ge 1 b ->
    back_ready_or_empty_middle9_depth depth
      (buf6_inject m (StoredSmall9 b)).
Proof.
  intros depth X m b Hb.
  right. exists m, (StoredSmall9 b). split.
  - apply buf6_eject_inject.
  - destruct depth; cbn; exact Hb.
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_inject_small :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (b : Buf6 (KElem9 X)),
    front_refill_continuation_ready_middle9_fuel fuel 1 m ->
    buf6_size_ge 1 b ->
    front_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredSmall9 b)).
Proof.
  induction fuel as [|fuel IH]; intros X m b Hcont Hb.
  - destruct Hcont as [Hfront _].
    split.
    + apply front_ready_or_empty_middle9_depth_inject_small; assumption.
    + exact I.
  - destruct Hcont as [Hfront Hstep].
    split.
    + apply front_ready_or_empty_middle9_depth_inject_small; assumption.
    + cbn [front_refill_continuation_ready_middle9_fuel] in Hstep |- *.
      destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
      * rewrite (buf6_pop_inject_some (Stored9 X) m m_rest cell
                   (StoredSmall9 b) Hpop).
        destruct cell as [b0|pre sm suf|sm].
        -- destruct Hstep as [Hb0 Hrest].
           split; [exact Hb0|].
           apply IH; assumption.
        -- destruct Hstep as [Hpre Hrest].
           split; [exact Hpre|].
           rewrite buf6_push_inject_comm.
           rewrite k9_middle_push_inject_comm.
           apply IH; assumption.
        -- destruct (buf6_pop sm) as [[front_cell sm_rest]|] eqn:Hsm.
           ++ rewrite k9_middle_push_inject_comm.
              rewrite buf6_push_inject_comm.
              apply IH; assumption.
           ++ apply IH; assumption.
      * rewrite (buf6_pop_inject_none (Stored9 X) m (StoredSmall9 b) Hpop).
        split; [exact Hb|].
        apply front_refill_continuation_ready_middle9_fuel_empty_thm.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_inject_small :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (b : Buf6 (KElem9 X)),
    back_refill_continuation_ready_middle9_fuel fuel 1 m ->
    buf6_size_ge 1 b ->
    back_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredSmall9 b)).
Proof.
  intros [|fuel] X m b Hcont Hb.
  - destruct Hcont as [_ _].
    split.
    + apply back_ready_or_empty_middle9_depth_inject_small. exact Hb.
    + exact I.
  - pose proof Hcont as Hcont_full.
    destruct Hcont as [_ _].
    split.
    + apply back_ready_or_empty_middle9_depth_inject_small. exact Hb.
    + cbn [back_refill_continuation_ready_middle9_fuel].
      rewrite buf6_eject_inject. split.
      * apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
        exact Hcont_full.
      * exact Hb.
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_push_small :
  forall (fuel : nat) (X : Type)
         (b : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X)),
    buf6_size_ge 1 b ->
    front_refill_continuation_ready_middle9_fuel fuel 1 m ->
    front_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_push (StoredSmall9 b) m).
Proof.
  intros [|fuel] X b m Hb Hcont.
  - split.
    + right. exists (StoredSmall9 b), m. split.
      * apply buf6_pop_push.
      * cbn. exact Hb.
    + exact I.
  - split.
    + right. exists (StoredSmall9 b), m. split.
      * apply buf6_pop_push.
      * cbn. exact Hb.
    + cbn [front_refill_continuation_ready_middle9_fuel].
      rewrite buf6_pop_push. split.
      * exact Hb.
      * apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
        exact Hcont.
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_k9_middle_push_small_cont :
  forall (fuel : nat) (X : Type)
         (sm rest : Buf6 (Stored9 X)),
    middle9_small_nonempty sm ->
    front_refill_continuation_ready_middle9_fuel fuel 1 rest ->
    front_refill_continuation_ready_middle9_fuel fuel 1
      (k9_middle_push sm rest).
Proof.
  induction fuel as [|fuel IH]; intros X [sms] rest Hsm Hrest.
  - destruct sms as [|cell sms'].
    + cbn [k9_middle_push buf6_is_empty buf6_elems]. exact Hrest.
    + split.
      * cbn [k9_middle_push buf6_is_empty buf6_elems
             front_ready_or_empty_middle9_depth front_ready_middle9_depth].
        right.
        exists (StoredMiddle9 {| buf6_elems := cell :: sms' |}), rest.
        split; [apply buf6_pop_push|].
        cbn [front_ready_stored9_depth front_ready_middle9_depth].
        exists cell, {| buf6_elems := sms' |}. split; [reflexivity|].
        inversion Hsm; subst.
        exact (stored9_small_nonempty_front_ready_depth 0 X cell H1).
      * exact I.
  - destruct sms as [|cell sms'].
    + cbn [k9_middle_push buf6_is_empty buf6_elems]. exact Hrest.
    + cbn [k9_middle_push buf6_is_empty buf6_elems
           front_refill_continuation_ready_middle9_fuel].
      split.
      * cbn [front_ready_or_empty_middle9_depth front_ready_middle9_depth].
        right.
        exists (StoredMiddle9 {| buf6_elems := cell :: sms' |}), rest.
        split; [apply buf6_pop_push|].
        cbn [front_ready_stored9_depth front_ready_middle9_depth].
        exists cell, {| buf6_elems := sms' |}. split; [reflexivity|].
        inversion Hsm; subst.
        exact (stored9_small_nonempty_front_ready_depth 0 X cell H1).
      * rewrite buf6_pop_push.
        cbn [buf6_pop buf6_elems].
        inversion Hsm; subst.
        destruct cell as [b|pre sm0 suf|sm0];
          cbn [stored9_small_nonempty] in H1; try contradiction.
        apply front_refill_continuation_ready_middle9_fuel_push_small.
        -- exact H1.
        -- apply IH.
           ++ exact H2.
           ++ apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
              exact Hrest.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_k9_middle_inject_small_cont :
  forall (fuel : nat) (X : Type)
         (rest sm : Buf6 (Stored9 X)),
    back_refill_continuation_ready_middle9_fuel fuel 1 rest ->
    middle9_small_nonempty sm ->
    back_refill_continuation_ready_middle9_fuel fuel 1
      (k9_middle_inject rest sm).
Proof.
  induction fuel as [|fuel IH]; intros X rest [sms] Hrest Hsm.
  - destruct sms as [|cell sms'].
    + cbn [k9_middle_inject buf6_is_empty buf6_elems]. exact Hrest.
    + split.
      * cbn [k9_middle_inject buf6_is_empty buf6_elems
             back_ready_or_empty_middle9_depth back_ready_middle9_depth].
        right.
        exists rest, (StoredMiddle9 {| buf6_elems := cell :: sms' |}).
        split; [apply buf6_eject_inject|].
        cbn [back_ready_stored9_depth back_ready_middle9_depth].
        destruct
          (buf6_eject_of_size_ge_S (Stored9 X) 0
            {| buf6_elems := cell :: sms' |}) as (sm_rest & back_cell & Heject).
        { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
        exists sm_rest, back_cell. split; [exact Heject|].
        destruct
          (middle9_small_nonempty_eject X _ _ _ Heject Hsm) as [_ Hcell].
        exact (stored9_small_nonempty_back_ready_depth 0 X back_cell Hcell).
      * exact I.
  - destruct sms as [|cell sms'].
    + cbn [k9_middle_inject buf6_is_empty buf6_elems]. exact Hrest.
    + cbn [k9_middle_inject buf6_is_empty buf6_elems
           back_refill_continuation_ready_middle9_fuel].
      split.
      * cbn [back_ready_or_empty_middle9_depth back_ready_middle9_depth].
        right.
        exists rest, (StoredMiddle9 {| buf6_elems := cell :: sms' |}).
        split; [apply buf6_eject_inject|].
        cbn [back_ready_stored9_depth back_ready_middle9_depth].
        destruct
          (buf6_eject_of_size_ge_S (Stored9 X) 0
            {| buf6_elems := cell :: sms' |}) as (sm_rest & back_cell & Heject).
        { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
        exists sm_rest, back_cell. split; [exact Heject|].
        destruct
          (middle9_small_nonempty_eject X _ _ _ Heject Hsm) as [_ Hcell].
        exact (stored9_small_nonempty_back_ready_depth 0 X back_cell Hcell).
      * rewrite buf6_eject_inject.
        destruct
          (buf6_eject_of_size_ge_S (Stored9 X) 0
            {| buf6_elems := cell :: sms' |}) as (sm_rest & back_cell & Heject).
        { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
        rewrite Heject.
        destruct
          (middle9_small_nonempty_eject X _ _ _ Heject Hsm)
          as [Hsm_rest Hback_cell].
        destruct back_cell as [b|pre sm0 suf|sm0];
          cbn [stored9_small_nonempty] in Hback_cell; try contradiction.
        apply back_refill_continuation_ready_middle9_fuel_inject_small.
        -- apply IH.
           ++ apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
              exact Hrest.
           ++ exact Hsm_rest.
        -- exact Hback_cell.
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_inject_big_small :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (pre : Buf6 (KElem9 X))
         (sm : Buf6 (Stored9 X)) (suf : Buf6 (KElem9 X)),
    front_refill_continuation_ready_middle9_fuel fuel 1 m ->
    buf6_size_ge 1 pre ->
    middle9_small_nonempty sm ->
    buf6_size_ge 1 suf ->
    front_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredBig9 pre sm suf)).
Proof.
  induction fuel as [|fuel IH]; intros X m pre sm suf Hcont Hpre Hsm Hsuf.
  - destruct Hcont as [Hfront _].
    split.
    + destruct Hfront as [Hempty|Hfront].
      * right. exists (StoredBig9 pre sm suf), buf6_empty. split.
        -- apply buf6_pop_inject_none. exact Hempty.
        -- cbn. exact Hpre.
      * destruct Hfront as (cell & rest & Hpop & Hcell).
        right. exists cell, (buf6_inject rest (StoredBig9 pre sm suf)).
        split.
        -- apply buf6_pop_inject_some. exact Hpop.
        -- exact Hcell.
    + exact I.
  - destruct Hcont as [Hfront Hstep].
    split.
    + destruct Hfront as [Hempty|Hfront].
      * right. exists (StoredBig9 pre sm suf), buf6_empty. split.
        -- apply buf6_pop_inject_none. exact Hempty.
        -- cbn. exact Hpre.
      * destruct Hfront as (cell & rest & Hpop & Hcell).
        right. exists cell, (buf6_inject rest (StoredBig9 pre sm suf)).
        split.
        -- apply buf6_pop_inject_some. exact Hpop.
        -- exact Hcell.
    + cbn [front_refill_continuation_ready_middle9_fuel] in Hstep |- *.
      destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hpop.
      * rewrite (buf6_pop_inject_some (Stored9 X) m m_rest cell
                   (StoredBig9 pre sm suf) Hpop).
        destruct cell as [b0|pre0 sm0 suf0|sm0].
        -- destruct Hstep as [Hb0 Hrest].
           split; [exact Hb0|].
           apply IH; assumption.
        -- destruct Hstep as [Hpre0 Hrest].
           split; [exact Hpre0|].
           rewrite buf6_push_inject_comm.
           rewrite k9_middle_push_inject_comm.
           apply IH; assumption.
        -- destruct (buf6_pop sm0) as [[front_cell sm_rest]|] eqn:Hsm0.
           ++ rewrite k9_middle_push_inject_comm.
              rewrite buf6_push_inject_comm.
              apply IH; assumption.
           ++ apply IH; assumption.
      * rewrite (buf6_pop_inject_none
                   (Stored9 X) m (StoredBig9 pre sm suf) Hpop).
        split; [exact Hpre|].
        apply front_refill_continuation_ready_middle9_fuel_k9_middle_push_small_cont.
        -- exact Hsm.
        -- apply front_refill_continuation_ready_middle9_fuel_push_small.
           ++ exact Hsuf.
           ++ apply front_refill_continuation_ready_middle9_fuel_empty_thm.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_inject_big_small :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (pre : Buf6 (KElem9 X))
         (sm : Buf6 (Stored9 X)) (suf : Buf6 (KElem9 X)),
    back_refill_continuation_ready_middle9_fuel fuel 1 m ->
    buf6_size_ge 1 pre ->
    middle9_small_nonempty sm ->
    buf6_size_ge 1 suf ->
    back_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredBig9 pre sm suf)).
Proof.
  intros [|fuel] X m pre sm suf Hcont Hpre Hsm Hsuf.
  - split.
    + cbn [back_ready_or_empty_middle9_depth back_ready_middle9_depth].
      right. exists m, (StoredBig9 pre sm suf).
      split; [apply buf6_eject_inject|].
      cbn. exact Hsuf.
    + exact I.
  - split.
    + cbn [back_ready_or_empty_middle9_depth back_ready_middle9_depth].
      right. exists m, (StoredBig9 pre sm suf).
      split; [apply buf6_eject_inject|].
      cbn. exact Hsuf.
    + cbn [back_refill_continuation_ready_middle9_fuel].
      rewrite buf6_eject_inject. split.
      * apply back_refill_continuation_ready_middle9_fuel_k9_middle_inject_small_cont.
        -- apply back_refill_continuation_ready_middle9_fuel_inject_small.
           ++ apply back_refill_continuation_ready_middle9_fuel_weaken_thm.
              exact Hcont.
           ++ exact Hpre.
        -- exact Hsm.
      * exact Hsuf.
Qed.

Lemma middle9_small_nonempty_push_small :
  forall (X : Type) (b : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X)),
