Lemma front_ready_or_empty_middle9_depth_k9_middle_push_small :
  forall (X : Type) (sm rest : Buf6 (Stored9 X)),
    middle9_small_nonempty sm ->
    middle9_small_nonempty rest ->
    front_ready_or_empty_middle9_depth 1 (k9_middle_push sm rest).
Proof.
  intros X [sms] rest Hsm Hrest.
  destruct sms as [|cell sms'].
  - cbn [k9_middle_push buf6_is_empty buf6_elems].
    apply front_ready_or_empty_middle9_depth_small_nonempty. exact Hrest.
  - cbn [k9_middle_push buf6_is_empty buf6_elems].
    right.
    exists (StoredMiddle9 {| buf6_elems := cell :: sms' |}). exists rest.
    split; [apply buf6_pop_push|].
    cbn [front_ready_stored9_depth front_ready_middle9_depth
         buf6_pop buf6_elems].
    exists cell. exists {| buf6_elems := sms' |}. split; [reflexivity|].
    inversion Hsm; subst.
    exact (stored9_small_nonempty_front_ready_depth 0 X cell H1).
Qed.

Lemma back_ready_or_empty_middle9_depth_k9_middle_inject_small :
  forall (X : Type) (rest sm : Buf6 (Stored9 X)),
    middle9_small_nonempty rest ->
    middle9_small_nonempty sm ->
    back_ready_or_empty_middle9_depth 1 (k9_middle_inject rest sm).
Proof.
  intros X rest [sms] Hrest Hsm.
  destruct sms as [|cell sms'].
  - cbn [k9_middle_inject buf6_is_empty buf6_elems].
    apply back_ready_or_empty_middle9_depth_small_nonempty. exact Hrest.
  - cbn [k9_middle_inject buf6_is_empty buf6_elems].
    right.
    exists rest, (StoredMiddle9 {| buf6_elems := cell :: sms' |}).
    split; [apply buf6_eject_inject|].
    cbn [back_ready_stored9_depth back_ready_middle9_depth].
    destruct
      (buf6_eject_of_size_ge_S (Stored9 X) 0
        {| buf6_elems := cell :: sms' |})
      as (sm_rest & back_cell & Heject).
    { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
    exists sm_rest, back_cell. split; [exact Heject|].
    destruct (middle9_small_nonempty_eject X _ _ _ Heject Hsm)
      as [_ Hcell].
    exact (stored9_small_nonempty_back_ready_depth 0 X back_cell Hcell).
Qed.

Lemma front_refill_continuation_ready_middle9_fuel_k9_middle_push_small_pair :
  forall fuel : nat,
    (forall (X : Type) (sm rest : Buf6 (Stored9 X)),
      middle9_small_nonempty sm ->
      middle9_small_nonempty rest ->
      front_refill_continuation_ready_middle9_fuel fuel 1
        (k9_middle_push sm rest)) /\
    (forall (X : Type) (cell : Stored9 X) (sm rest : Buf6 (Stored9 X)),
      stored9_small_nonempty cell ->
      middle9_small_nonempty sm ->
      middle9_small_nonempty rest ->
      front_refill_continuation_ready_middle9_fuel fuel 1
        (buf6_push cell (k9_middle_push sm rest))).
Proof.
  induction fuel as [|fuel [IHmain IHpush]].
  - split.
    + intros X sm rest Hsm Hrest.
      split.
      * apply front_ready_or_empty_middle9_depth_k9_middle_push_small;
          assumption.
      * exact I.
    + intros X cell sm rest Hcell Hsm Hrest.
      split.
      * cbn [front_ready_or_empty_middle9_depth front_ready_middle9_depth].
        right. exists cell, (k9_middle_push sm rest).
        split; [apply buf6_pop_push|].
        exact (stored9_small_nonempty_front_ready_depth 1 X cell Hcell).
      * exact I.
  - split.
    + intros X [sms] rest Hsm Hrest.
      destruct sms as [|cell sms'].
      * cbn [k9_middle_push buf6_is_empty buf6_elems].
        apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
        exact Hrest.
      * cbn [k9_middle_push buf6_is_empty buf6_elems
             front_refill_continuation_ready_middle9_fuel].
        split.
        -- cbn [front_ready_or_empty_middle9_depth front_ready_middle9_depth].
           right.
           exists (StoredMiddle9 {| buf6_elems := cell :: sms' |}), rest.
           split; [apply buf6_pop_push|].
           cbn [front_ready_stored9_depth front_ready_middle9_depth].
           exists cell, {| buf6_elems := sms' |}.
           split; [reflexivity|].
           inversion Hsm; subst.
           exact (stored9_small_nonempty_front_ready_depth 0 X cell H1).
        -- rewrite buf6_pop_push.
           inversion Hsm; subst.
           exact (IHpush X cell {| buf6_elems := sms' |} rest H1 H2 Hrest).
    + intros X cell sm rest Hcell Hsm Hrest.
      cbn [front_refill_continuation_ready_middle9_fuel].
      split.
      * cbn [front_ready_or_empty_middle9_depth front_ready_middle9_depth].
        right. exists cell, (k9_middle_push sm rest).
        split; [apply buf6_pop_push|].
        exact (stored9_small_nonempty_front_ready_depth 1 X cell Hcell).
      * rewrite buf6_pop_push.
        destruct cell as [b|pre sm0 suf|sm0];
          cbn [stored9_small_nonempty] in Hcell; try contradiction.
        split; [exact Hcell|].
        exact (IHmain X sm rest Hsm Hrest).
Qed.

