Lemma front_refill_continuation_ready_middle9_fuel_small_prefix_bridge :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (pre : Buf6 (KElem9 X))
         (sm : Buf6 (Stored9 X)) (suf : Buf6 (KElem9 X)),
    middle9_small_nonempty m ->
    buf6_size_ge 1 pre ->
    middle9_small_nonempty sm ->
    buf6_size_ge 1 suf ->
    front_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredBig9 pre sm suf)).
Proof.
  induction fuel as [|fuel IH]; intros X [ms] pre sm suf Hm Hpre Hsm Hsuf.
  - cbn [front_refill_continuation_ready_middle9_fuel].
    split.
    + destruct ms as [|cell ms'].
      * cbn [buf6_inject front_ready_or_empty_middle9_depth
             front_ready_middle9_depth front_ready_stored9_depth
             front_ready_stored9 buf6_pop buf6_elems].
        right. exists (StoredBig9 pre sm suf), (mkBuf6 []).
        split; [reflexivity|exact Hpre].
      * cbn [buf6_inject front_ready_or_empty_middle9_depth
             front_ready_middle9_depth buf6_pop buf6_elems].
        right. exists cell, (mkBuf6 (ms' ++ [StoredBig9 pre sm suf])).
        split; [reflexivity|].
        inversion Hm; subst.
        exact (stored9_small_nonempty_front_ready_depth 1 X cell H1).
    + exact I.
  - cbn [front_refill_continuation_ready_middle9_fuel].
    split.
    + destruct ms as [|cell ms'].
      * cbn [buf6_inject front_ready_or_empty_middle9_depth
             front_ready_middle9_depth front_ready_stored9_depth
             front_ready_stored9 buf6_pop buf6_elems].
        right. exists (StoredBig9 pre sm suf), (mkBuf6 []).
        split; [reflexivity|exact Hpre].
      * cbn [buf6_inject front_ready_or_empty_middle9_depth
             front_ready_middle9_depth buf6_pop buf6_elems].
        right. exists cell, (mkBuf6 (ms' ++ [StoredBig9 pre sm suf])).
        split; [reflexivity|].
        inversion Hm; subst.
        exact (stored9_small_nonempty_front_ready_depth 1 X cell H1).
    + destruct ms as [|cell ms'].
      * cbn [buf6_inject buf6_pop buf6_elems].
        split; [exact Hpre|].
        apply front_refill_continuation_ready_middle9_fuel_k9_middle_push_small.
        -- exact Hsm.
        -- apply middle9_small_nonempty_push_small; assumption.
      * cbn [buf6_inject buf6_pop buf6_elems].
        inversion Hm; subst.
        destruct cell as [b|pre0 sm0 suf0|sm0];
          cbn [stored9_small_nonempty] in H1; try contradiction.
        split; [exact H1|].
        change (front_refill_continuation_ready_middle9_fuel fuel 1
          (buf6_inject {| buf6_elems := ms' |} (StoredBig9 pre sm suf))).
        apply IH; assumption.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_small_prefix_bridge :
  forall (fuel : nat) (X : Type)
         (m : Buf6 (Stored9 X)) (pre : Buf6 (KElem9 X))
         (sm : Buf6 (Stored9 X)) (suf : Buf6 (KElem9 X)),
    middle9_small_nonempty m ->
    buf6_size_ge 1 pre ->
    middle9_small_nonempty sm ->
    buf6_size_ge 1 suf ->
    back_refill_continuation_ready_middle9_fuel fuel 1
      (buf6_inject m (StoredBig9 pre sm suf)).
Proof.
  induction fuel as [|fuel _]; intros X m pre sm suf Hm Hpre Hsm Hsuf.
  - cbn [back_refill_continuation_ready_middle9_fuel
         back_ready_or_empty_middle9_depth back_ready_middle9_depth].
    split.
    + right. exists m, (StoredBig9 pre sm suf).
      split; [apply buf6_eject_inject|].
      cbn [back_ready_stored9_depth back_ready_stored9]. exact Hsuf.
    + exact I.
  - cbn [back_refill_continuation_ready_middle9_fuel
         back_ready_or_empty_middle9_depth back_ready_middle9_depth].
    split.
    + right. exists m, (StoredBig9 pre sm suf).
      split; [apply buf6_eject_inject|].
      cbn [back_ready_stored9_depth back_ready_stored9]. exact Hsuf.
    + rewrite buf6_eject_inject. split.
      * apply back_refill_continuation_ready_middle9_fuel_k9_middle_inject_small.
        -- apply middle9_small_nonempty_inject_small; assumption.
        -- exact Hsm.
      * exact Hsuf.
Qed.

Lemma kcad9_singleton_inv_ocaml_boundaries :
  forall (X : Type) (x : X),
    inv_kcad9_ocaml_boundaries (kcad9_singleton x).
Proof.
  intros X x.
  cbn [kcad9_singleton inv_kcad9_ocaml_boundaries].
  unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
Qed.

Lemma kcad9_concat_ocaml_shape_singleton_middle_small_nonempty :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_boundaries k ->
    kcad9_ocaml_middle_small_nonempty k ->
    kcad9_ocaml_middle_small_nonempty
      (kcad9_concat_ocaml_shape k (kcad9_singleton x)).
Proof.
  intros X [|b|h m t] x Hbounds Hsmall.
  - exact I.
  - cbn [kcad9_concat_ocaml_shape kcad9_singleton
         kcad9_ocaml_middle_small_nonempty middle9_small_nonempty
         buf6_empty buf6_elems].
    constructor.
  - cbn [kcad9_concat_ocaml_shape kcad9_singleton
         kcad9_ocaml_middle_small_nonempty] in *.
    destruct Hbounds as [_ Ht].
    apply middle9_small_nonempty_inject_small; assumption.
Qed.

Lemma kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty :
  forall (X : Type) (acc : KCadeque9 X) (xs : list X),
    inv_kcad9_ocaml_boundaries acc ->
    kcad9_ocaml_middle_small_nonempty acc ->
    inv_kcad9_ocaml_boundaries
      (kcad9_concat_ocaml_shape_left_fold acc (map kcad9_singleton xs)) /\
    kcad9_ocaml_middle_small_nonempty
      (kcad9_concat_ocaml_shape_left_fold acc (map kcad9_singleton xs)).
Proof.
  intros X acc xs.
  revert acc.
  induction xs as [|x xs IH]; intros acc Hbounds Hsmall.
  - split; assumption.
  - cbn [map kcad9_concat_ocaml_shape_left_fold].
    apply IH.
    + apply kcad9_concat_ocaml_shape_inv_boundaries.
      * exact Hbounds.
      * apply kcad9_singleton_inv_ocaml_boundaries.
    + apply kcad9_concat_ocaml_shape_singleton_middle_small_nonempty;
        assumption.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_continuation_depth_thm :
  forall (fuel depth : nat) (X : Type) (xs : list X),
    inv_kcad9_ocaml_continuation_depth fuel depth
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)).
Proof.
  intros fuel depth X xs.
  set (k :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton xs)).
  assert (Hreach : inv_kcad9_ocaml_reachable_depth depth k).
  { subst k.
    apply kcad9_concat_ocaml_shape_left_fold_reachable_depth_thm.
    - apply empty_kcad9_ocaml_reachable_depth_thm.
    - apply all_kcad9_ocaml_reachable_depth_singletons_thm. }
  assert (Hsmall : kcad9_ocaml_middle_small_nonempty k).
  { subst k.
    destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
         X (@kcad9_empty X) xs I I) as [_ Hsmall].
    exact Hsmall. }
  split; [exact Hreach|].
  destruct k as [|b|h m t];
    cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
