      Some (x, K9Triple h' m t) /\
    inv_kcad9_ocaml_reachable_depth depth (K9Triple h' m t).
Proof.
  intros fuel depth X h m t x h' [Hready Hdeep] Hpop Hsize.
  cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready.
  cbn [inv_kcad9_ocaml_deep_xbase] in Hdeep.
  destruct Hready as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  destruct Hdeep as [Hxh_deep [Hm_deep Hxt_deep]].
  destruct (all_xbase9_pop X h h' (XBase9 x) Hxh Hpop) as [_ Hxh'].
  destruct (all_xbase9_pop X h h' (XBase9 x) Hxh_deep Hpop)
    as [_ Hxh'_deep].
  split.
  - cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    apply PeanoNat.Nat.leb_le in Hsize. rewrite Hsize.
    reflexivity.
  - split.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth].
      repeat split; try assumption.
      unfold buf6_size_ge. lia.
    + cbn [inv_kcad9_ocaml_deep_xbase].
