Theorem kcad9_pop_ocaml_shape_fuel_front_continuation_present_refill_thm :
  forall (fuel sched depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)) (x : X) (h' : Buf6 (KElem9 X)),
    inv_kcad9_ocaml_continuation_depth (S sched) depth (K9Triple h m t) ->
    buf6_pop h = Some (XBase9 x, h') ->
    buf6_size_ge 1 h' ->
    exists m',
      kcad9_pop_ocaml_shape_fuel fuel (K9Triple h m t) =
        Some (x, K9Triple h' m' t) /\
      front_refill_continuation_ready_middle9_fuel sched depth m'.
Proof.
  intros fuel sched depth X h m t x h' [[Hready _] Hcont] Hpop Hh'.
  cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready.
  destruct Hready as [_ [_ [Ht [_ _]]]].
  cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth] in Hcont.
  destruct Hcont as [Hfront _].
  cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
  destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp.
  - exists m. split; [reflexivity|].
    apply front_refill_continuation_ready_middle9_fuel_weaken_thm.
    exact Hfront.
  - unfold refill_h_K9Triple_fuel.
    destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hmpop.
    + destruct cell as [b|pre sm suf|sm].
      * exists (buf6_push (StoredSmall9 b) m_rest).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        exact
          (front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm
             sched depth X m m_rest (StoredSmall9 b) Hmpop Hfront).
      * exists
          (buf6_push (StoredSmall9 pre)
             (k9_middle_push sm
                (buf6_push (StoredSmall9 suf) m_rest))).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        exact
          (front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm
             sched depth X m m_rest (StoredBig9 pre sm suf) Hmpop Hfront).
      * exists (k9_middle_push sm m_rest).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        exact
          (front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm
             sched depth X m m_rest (StoredMiddle9 sm) Hmpop Hfront).
    + exists buf6_empty.
      rewrite (k9_with_front_fuel_present_boundaries
                 fuel X h' _ t Hh' Ht).
      split; [reflexivity|].
      destruct sched.
      * cbn [front_refill_continuation_ready_middle9_fuel].
        split; [left; reflexivity|exact I].
      * cbn [front_refill_continuation_ready_middle9_fuel buf6_pop
             buf6_empty buf6_elems].
        split; [left; reflexivity|exact I].
Qed.

