Theorem kcad9_pop_ocaml_shape_fuel_front_continuation_empty_refill_thm :
  forall (fuel sched depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)) (x : X) (h' : Buf6 (KElem9 X)),
    inv_kcad9_ocaml_continuation_depth
      (S (fuel + sched)) depth (K9Triple h m t) ->
    buf6_pop h = Some (XBase9 x, h') ->
    buf6_is_empty h' = true ->
    exists k',
      kcad9_pop_ocaml_shape_fuel fuel (K9Triple h m t) =
        Some (x, k') /\
      match k' with
      | K9Triple _ m' _ =>
          front_refill_continuation_ready_middle9_fuel sched depth m'
      | _ => True
      end.
Proof.
  intros fuel sched depth X h m t x h' [_ Hcont] Hpop Hempty.
  cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth] in Hcont.
  destruct Hcont as [Hfront _].
  apply buf6_eq_empty_of_is_empty in Hempty. subst h'.
  cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
  unfold refill_h_K9Triple_fuel.
  destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hmpop.
  - destruct cell as [b|pre sm suf|sm].
    + exists
        (k9_with_front_fuel fuel (@buf6_empty (KElem9 X))
           (buf6_push (StoredSmall9 b) m_rest) t).
      split; [reflexivity|].
      eapply k9_with_front_fuel_front_continuation_thm.
      * eapply front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm;
          eassumption.
      * reflexivity.
    + exists
        (k9_with_front_fuel fuel (@buf6_empty (KElem9 X))
           (buf6_push (StoredSmall9 pre)
             (k9_middle_push sm
               (buf6_push (StoredSmall9 suf) m_rest))) t).
      split; [reflexivity|].
      eapply k9_with_front_fuel_front_continuation_thm.
      * eapply front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm;
          eassumption.
      * reflexivity.
    + exists
        (k9_with_front_fuel fuel (@buf6_empty (KElem9 X))
           (k9_middle_push sm m_rest) t).
      split; [reflexivity|].
      eapply k9_with_front_fuel_front_continuation_thm.
      * eapply front_refill_continuation_ready_middle9_fuel_after_front_refill_step_thm;
          eassumption.
      * reflexivity.
  - exists
      (k9_with_front_fuel fuel (@buf6_empty (KElem9 X))
         (@buf6_empty (Stored9 X)) t).
    split; [reflexivity|].
    eapply k9_with_front_fuel_front_continuation_thm.
    + apply front_refill_continuation_ready_middle9_fuel_empty_thm.
    + reflexivity.
Qed.

