Theorem kcad9_pop_ocaml_shape_fuel_front_ready_present_refill_thm :
  forall (fuel depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)) (x : X) (h' : Buf6 (KElem9 X)),
    inv_kcad9_ocaml_reachable_depth depth (K9Triple h m t) ->
    buf6_pop h = Some (XBase9 x, h') ->
    buf6_size_ge 1 h' ->
    exists m',
      kcad9_pop_ocaml_shape_fuel fuel (K9Triple h m t) =
        Some (x, K9Triple h' m' t) /\
      front_ready_or_empty_middle9_depth depth m'.
Proof.
  intros fuel depth X h m t x h' [Hready _] Hpop Hh'.
  cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready.
  destruct Hready as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  assert (Hfront_cell :
            forall cell m_rest,
              buf6_pop m = Some (cell, m_rest) ->
              front_ready_stored9_depth depth cell).
  { intros cell m_rest Hmpop.
    destruct Hfront as [Hempty|Hready].
    - rewrite Hmpop in Hempty. discriminate.
    - destruct Hready as (front_cell & rest & Hpop_m & Hcell).
      rewrite Hmpop in Hpop_m. injection Hpop_m as Hcell_eq _.
      subst front_cell. exact Hcell. }
  cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
  destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp.
  - exists m. split; [reflexivity|exact Hfront].
  -
    unfold refill_h_K9Triple_fuel.
    destruct (buf6_pop m) as [[cell m_rest]|] eqn:Hmpop.
    + pose proof (Hfront_cell cell m_rest eq_refl) as Hcell.
      destruct cell as [b|pre sm suf|sm].
      * exists (buf6_push (StoredSmall9 b) m_rest).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        right. apply buf6_push_front_ready_stored9_depth. exact Hcell.
      * exists
          (buf6_push (StoredSmall9 pre)
             (k9_middle_push sm
                (buf6_push (StoredSmall9 suf) m_rest))).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        right. apply buf6_push_front_ready_stored9_depth.
        destruct depth; cbn in Hcell |- *; exact Hcell.
      * exists (k9_middle_push sm m_rest).
        rewrite (k9_with_front_fuel_present_boundaries
                   fuel X h' _ t Hh' Ht).
        split; [reflexivity|].
        right.
        destruct depth as [|depth']; [contradiction|].
        cbn in Hcell.
        destruct Hcell as (front_cell & sm_rest & Hsm & Hinner).
        exists (StoredMiddle9 sm), m_rest.
        split.
        -- eapply k9_middle_push_pop. exact Hsm.
        -- cbn. exists front_cell, sm_rest. split; assumption.
    + exists buf6_empty.
      rewrite (k9_with_front_fuel_present_boundaries
                 fuel X h' _ t Hh' Ht).
      split; [reflexivity|left; reflexivity].
Qed.

