        Some (x, K9Triple h' m' t) /\
      inv_kcad9_ocaml_continuation_depth sched depth
        (K9Triple h' m' t).
Proof.
  intros fuel sched depth X h m t x h' [Hreach Hcont] Hpop Hh'.
  pose proof (conj Hreach Hcont) as Hinv.
  destruct
    (kcad9_pop_ocaml_shape_fuel_reachable_depth_present_refill_thm
       fuel depth X h m t x h' Hreach Hpop Hh')
    as (m_reach & Hres_reach & Hreach').
  destruct
    (kcad9_pop_ocaml_shape_fuel_front_continuation_present_refill_thm
       fuel sched depth X h m t x h' Hinv Hpop Hh')
    as (m_front & Hres_front & Hfront').
  rewrite Hres_reach in Hres_front.
  inversion Hres_front. subst m_front. clear Hres_front.
  destruct
    (kcad9_pop_ocaml_shape_fuel_back_continuation_present_refill_thm
       fuel sched depth X h m t x h' Hinv Hpop Hh')
    as (m_back & Hres_back & Hback').
  rewrite Hres_reach in Hres_back.
  inversion Hres_back. subst m_back. clear Hres_back.
  exists m_reach. split; [exact Hres_reach|].
  split; [exact Hreach'|].
  cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth].
  split; assumption.
Qed.

