Theorem kcad9_pop_ocaml_shape_fuel_reachable_depth_empty_refill_counterexample_thm :
  exists k k' : KCadeque9 nat,
    inv_kcad9_ocaml_reachable_depth 0 k /\
    kcad9_pop_ocaml_shape_fuel 1 k = Some (0, k') /\
    ~ inv_kcad9_ocaml_reachable_depth 0 k'.
Proof.
  pose (h := mkBuf6 [XBase9 0]).
  pose (b1 := mkBuf6 [XBase9 1]).
  pose (bad := @buf6_empty (Stored9 nat)).
  pose (b2 := mkBuf6 [XBase9 2]).
  pose (m := mkBuf6 [StoredSmall9 b1; StoredMiddle9 bad; StoredSmall9 b2]).
  pose (t := mkBuf6 [XBase9 3]).
  pose (k := K9Triple h m t).
  pose (k' := K9Triple b1 (mkBuf6 [StoredMiddle9 bad; StoredSmall9 b2]) t).
  exists k, k'. split.
  - split.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth h b1 bad b2 m t k].
      repeat split; try (unfold buf6_size_ge, buf6_size, buf6_elems; cbn; lia);
        try (constructor; [exact I|constructor]).
      * right. exists (StoredSmall9 b1),
          (mkBuf6 [StoredMiddle9 bad; StoredSmall9 b2]).
        cbn [front_ready_middle9_depth buf6_pop buf6_elems].
        split; [reflexivity|].
        cbn [front_ready_stored9_depth front_ready_stored9 b1].
        unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
      * right. exists (mkBuf6 [StoredSmall9 b1; StoredMiddle9 bad]),
          (StoredSmall9 b2).
        cbn [back_ready_middle9_depth buf6_eject buf6_elems].
        split; [reflexivity|].
        cbn [back_ready_stored9_depth back_ready_stored9 b2].
        unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
    + cbn [inv_kcad9_ocaml_deep_xbase h b1 bad b2 m t k xbase_middle9_deep
           xbase_stored9_deep].
      repeat split; try (constructor; [exact I|constructor]).
      * constructor.
        -- cbn [xbase_stored9_deep all_xbase9 buf6_elems].
           constructor; [exact I|constructor].
        -- constructor.
           ++ cbn [xbase_stored9_deep bad buf6_empty buf6_elems].
              exact I.
           ++ constructor.
              ** cbn [xbase_stored9_deep all_xbase9 buf6_elems].
                 constructor; [exact I|constructor].
              ** constructor.
  - split.
    + cbn [kcad9_pop_ocaml_shape_fuel refill_h_K9Triple_fuel k9_with_front_fuel
           h b1 bad b2 m t k k' buf6_pop buf6_is_empty buf6_size buf6_elems].
      reflexivity.
    + intros [Hready _].
      cbn [inv_kcad9_ocaml_ready_or_empty_depth k' b1 bad b2 t] in Hready.
      destruct Hready as [_ [_ [_ [_ [Hfront _]]]]].
      destruct Hfront as [Hempty|Hfront].
      * cbn [buf6_pop buf6_elems] in Hempty. discriminate.
      * destruct Hfront as (cell & rest & Hpop & Hcell).
        cbn [front_ready_middle9_depth buf6_pop buf6_elems] in Hpop.
        injection Hpop as Hcell_eq _. subst cell.
        cbn [front_ready_stored9_depth front_ready_stored9] in Hcell.
        exact Hcell.
Qed.

