  - split.
    + split.
      * cbn [inv_kcad9_ocaml_ready_or_empty_depth h b1 bad b2 sm m t k].
        repeat split; try (unfold buf6_size_ge, buf6_size, buf6_elems; cbn; lia);
          try (constructor; [exact I|constructor]).
        -- right. exists (StoredMiddle9 sm), buf6_empty.
           cbn [front_ready_middle9_depth buf6_pop buf6_empty buf6_elems].
           split; [reflexivity|].
           cbn [front_ready_stored9_depth sm b1 buf6_pop buf6_elems].
           exists (StoredSmall9 b1), (mkBuf6 [StoredMiddle9 bad; StoredSmall9 b2]).
           split; [reflexivity|].
           cbn [front_ready_stored9_depth front_ready_stored9 b1].
           unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
        -- right. exists buf6_empty, (StoredMiddle9 sm).
           cbn [back_ready_middle9_depth buf6_eject buf6_empty buf6_elems].
           split; [reflexivity|].
           cbn [back_ready_stored9_depth sm b2 buf6_eject buf6_elems].
           exists (mkBuf6 [StoredSmall9 b1; StoredMiddle9 bad]), (StoredSmall9 b2).
           split; [reflexivity|].
           cbn [back_ready_stored9_depth back_ready_stored9 b2].
           unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
      * cbn [inv_kcad9_ocaml_deep_xbase h b1 bad b2 sm m t k
             xbase_middle9_deep xbase_stored9_deep].
        repeat constructor; exact I.
    + cbn [kcad9_ocaml_refill_residual_ready_depth
           front_refill_residual_ready_middle9_depth
           back_refill_residual_ready_middle9_depth
           k sm m b1 b2 bad buf6_pop buf6_eject buf6_empty buf6_elems
           k9_middle_push k9_middle_inject buf6_is_empty].
      split.
      * right. exists (StoredMiddle9 sm), buf6_empty.
        cbn [front_ready_middle9_depth buf6_pop buf6_empty buf6_elems].
        split; [reflexivity|].
        cbn [front_ready_stored9_depth sm b1 buf6_pop buf6_elems].
        exists (StoredSmall9 b1), (mkBuf6 [StoredMiddle9 bad; StoredSmall9 b2]).
        split; [reflexivity|].
        cbn [front_ready_stored9_depth front_ready_stored9 b1].
        unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
      * right. exists buf6_empty, (StoredMiddle9 sm).
        cbn [back_ready_middle9_depth buf6_eject buf6_empty buf6_elems].
        split; [reflexivity|].
        cbn [back_ready_stored9_depth sm b2 buf6_eject buf6_elems].
        exists (mkBuf6 [StoredSmall9 b1; StoredMiddle9 bad]), (StoredSmall9 b2).
        split; [reflexivity|].
        cbn [back_ready_stored9_depth back_ready_stored9 b2].
        unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
  - intros [_ Hcont].
    cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
         front_refill_continuation_ready_middle9_fuel
         k sm m b1 b2 bad buf6_pop buf6_elems k9_middle_push
         buf6_is_empty buf6_empty] in Hcont.
    destruct Hcont as [Hfront _].
    destruct Hfront as [_ Hafter_outer].
    destruct Hafter_outer as [_ Hafter_small].
    destruct Hafter_small as [_ Hrest].
    destruct Hrest as [Hrest_ready _].
    destruct Hrest_ready as [Hempty|Hready].
    + cbn [buf6_pop buf6_elems] in Hempty. discriminate.
    + destruct Hready as (cell & rest & Hpop & Hcell).
      cbn [front_ready_middle9_depth buf6_pop buf6_elems] in Hpop.
      injection Hpop as Hcell_eq _. subst cell.
      cbn [front_ready_stored9_depth buf6_pop buf6_elems] in Hcell.
      destruct Hcell as (front_cell & sm_rest & Hsm & Hinner).
      cbn [buf6_pop buf6_elems] in Hsm.
      injection Hsm as Hfront_cell_eq _. subst front_cell.
      cbn [front_ready_stored9_depth front_ready_stored9] in Hinner.
      exact Hinner.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_total_under_ready_or_empty_depth_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    k <> K9Empty ->
    exists x k', kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k').
Proof.
  intros fuel depth X [|b|h m t] Hinv Hne;
    [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_pop_xbase9 X b Hb Hxb) as [x [b' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [Hh [Hxh _]].
    destruct (buf6_pop_xbase9 X h Hh Hxh) as [x [h' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (Nat.leb 5 (buf6_size h')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_total_under_ready_or_empty_depth_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    k <> K9Empty ->
    exists k' x, kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x).
Proof.
  intros fuel depth X [|b|h m t] Hinv Hne;
    [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_eject_xbase9 X b Hb Hxb) as [b' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [_ [_ [Ht [Hxt _]]]].
    destruct (buf6_eject_xbase9 X t Ht Hxt) as [t' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (Nat.leb 5 (buf6_size t')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_inv_boundaries_under_ready_or_empty_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    kcad9_pop_ocaml_shape_fuel (S depth) k = Some (x, k') ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros depth X [|b|h m t] x k' Hinv Hpop;
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
  - discriminate.
  - destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Hpop as Hx Hk'; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    destruct (buf6_pop h) as [[e h']|] eqn:Hph; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp;
      injection Hpop as Hx Hk'; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries].
      apply PeanoNat.Nat.leb_le in Hcmp. split; [|exact Ht].
      unfold buf6_size_ge. lia.
    + destruct (buf6_is_empty h') eqn:Hempty.
      * destruct Hfront as [Hmemtpy|Hfront].
        -- apply buf6_eq_empty_of_is_empty in Hempty. subst h'.
           unfold refill_h_K9Triple_fuel. rewrite Hmemtpy.
           cbn [k9_with_front_fuel].
           rewrite (buf6_size_ge_S_not_empty (KElem9 X) 0 t Ht).
           cbn [inv_kcad9_ocaml_boundaries]. exact Ht.
        -- destruct (refill_h_K9Triple_fuel_front_ready_depth
                      depth X h' m t Hempty Hfront)
             as (h'' & m' & Hrefill & Hh'').
           rewrite Hrefill. cbn [inv_kcad9_ocaml_boundaries].
           split; assumption.
      * apply refill_h_K9Triple_fuel_inv_boundaries_present.
        -- apply buf6_is_empty_false_size_ge_1. exact Hempty.
        -- exact Ht.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_inv_boundaries_under_ready_or_empty_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_ready_or_empty_depth depth k ->
    kcad9_eject_ocaml_shape_fuel (S depth) k = Some (k', x) ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros depth X [|b|h m t] k' x Hinv Heject;
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
  - discriminate.
  - destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Heject as Hk' Hx; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    destruct (buf6_eject t) as [[t' e]|] eqn:Het; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp;
      injection Heject as Hk' Hx; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries].
      apply PeanoNat.Nat.leb_le in Hcmp. split; [exact Hh|].
      unfold buf6_size_ge. lia.
    + destruct (buf6_is_empty t') eqn:Hempty.
      * destruct Hback as [Hmemtpy|Hback].
        -- apply buf6_eq_empty_of_is_empty in Hempty. subst t'.
           unfold refill_t_K9Triple_fuel. rewrite Hmemtpy.
           cbn [k9_with_back_fuel].
           rewrite (buf6_size_ge_S_not_empty (KElem9 X) 0 h Hh).
           cbn [inv_kcad9_ocaml_boundaries]. exact Hh.
        -- destruct (refill_t_K9Triple_fuel_back_ready_depth
                      depth X h m t' Hempty Hback)
             as (m' & t'' & Hrefill & Ht'').
           rewrite Hrefill. cbn [inv_kcad9_ocaml_boundaries].
           split; assumption.
      * apply refill_t_K9Triple_fuel_inv_boundaries_present.
        -- exact Hh.
        -- apply buf6_is_empty_false_size_ge_1. exact Hempty.
Qed.

