Theorem kcad9_pop_ocaml_shape_fuel_total_under_left_fold_singletons_thm :
  forall (fuel : nat) (X : Type) (x : X) (xs : list X),
    exists y k',
      kcad9_pop_ocaml_shape_fuel fuel
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (x :: xs))) =
      Some (y, k').
Proof.
  intros fuel X x xs.
  eapply kcad9_pop_ocaml_shape_fuel_total_under_reachable_depth_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_nonempty_thm.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_total_under_left_fold_singletons_thm :
  forall (fuel : nat) (X : Type) (x : X) (xs : list X),
    exists k' y,
      kcad9_eject_ocaml_shape_fuel fuel
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (x :: xs))) =
      Some (k', y).
Proof.
  intros fuel X x xs.
  eapply kcad9_eject_ocaml_shape_fuel_total_under_reachable_depth_thm.
