Theorem kcad9_pop_ocaml_shape_fuel_left_fold_singletons_seq_thm :
  forall (fuel : nat) (X : Type) (x y : X) (xs : list X)
         (k' : KCadeque9 X),
    kcad9_pop_ocaml_shape_fuel fuel
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton (x :: xs))) =
    Some (y, k') ->
    y = x /\ kcad9_to_list k' = xs.
Proof.
  intros fuel X x y xs k' Hpop.
  pose proof
    (kcad9_pop_ocaml_shape_fuel_seq_thm
       fuel X
       (kcad9_concat_ocaml_shape_left_fold
         (@kcad9_empty X) (map kcad9_singleton (x :: xs)))
       y k' Hpop) as Hseq.
  rewrite
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm X (x :: xs))
    in Hseq.
  injection Hseq as Hy Htail.
  subst y. split; [reflexivity|symmetry; exact Htail].
Qed.

Lemma app_singleton_inj :
  forall (X : Type) (xs ys : list X) (x y : X),
    xs ++ [x] = ys ++ [y] ->
    xs = ys /\ x = y.
Proof.
  induction xs as [|xh xs IH]; intros ys x y Happ.
  - destruct ys as [|yh ys].
    + cbn in Happ. injection Happ as Hxy. subst x. split; reflexivity.
    + cbn in Happ. injection Happ as Hhead Htail.
      destruct ys as [|y2 ys].
      * cbn in Htail. discriminate Htail.
      * discriminate Htail.
  - destruct ys as [|yh ys].
    + cbn in Happ. injection Happ as Hhead Htail.
      destruct xs as [|x2 xs].
      * cbn in Htail. discriminate Htail.
      * discriminate Htail.
    + cbn in Happ. injection Happ as Hhead Htail.
      destruct (IH ys x y Htail) as [Hxs Hxy].
      subst yh. subst xs. subst x.
      split; reflexivity.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_expected_under_boundary_deep_seq_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (xs : list X),
    inv_kcad9_ocaml_boundary_deep k ->
    kcad9_to_list k = x :: xs ->
    exists k',
      kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k') /\
      kcad9_to_list k' = xs.
Proof.
  intros fuel X k x xs Hinv Hseq_in.
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    discriminate Hseq_in. }
  destruct
    (kcad9_pop_ocaml_shape_fuel_total_under_boundary_deep_thm
       fuel X k Hinv Hne) as (y & k' & Hpop).
  pose proof
    (kcad9_pop_ocaml_shape_fuel_seq_thm fuel X k y k' Hpop)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  injection Hseq_out as Hy Htail.
  subst y. exists k'. split; [exact Hpop|symmetry; exact Htail].
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_expected_under_boundary_deep_seq_thm :
  forall (fuel : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X) (x : X),
    inv_kcad9_ocaml_boundary_deep k ->
    kcad9_to_list k = xs ++ [x] ->
    exists k',
      kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x) /\
      kcad9_to_list k' = xs.
Proof.
  intros fuel X k xs x Hinv Hseq_in.
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    destruct xs as [|xh xs]; discriminate Hseq_in. }
  destruct
    (kcad9_eject_ocaml_shape_fuel_total_under_boundary_deep_thm
       fuel X k Hinv Hne) as (k' & y & Heject).
  pose proof
    (kcad9_eject_ocaml_shape_fuel_seq_thm fuel X k k' y Heject)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  destruct (app_singleton_inj X xs (kcad9_to_list k') x y Hseq_out)
    as [Htail Hy].
  subst y. exists k'. split; [exact Heject|symmetry; exact Htail].
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_left_fold_singletons_snoc_seq_thm :
  forall (fuel : nat) (X : Type) (xs : list X) (x y : X)
