Theorem kcad9_pop_ocaml_shape_fuel_expected_refill_left_under_left_fold_singletons_thm :
  forall (fuel : nat) (X : Type) (x : X) (xs : list X),
    exists k',
      kcad9_pop_ocaml_shape_fuel fuel
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (x :: xs))) =
      Some (x, k') /\
      kcad9_to_list k' = xs /\
      inv_kcad9_ocaml_refill_concat_left_depth 0 k'.
Proof.
  intros fuel X x xs.
  destruct
    (kcad9_pop_ocaml_shape_fuel_expected_under_left_fold_singletons_thm
       fuel X x xs) as (k' & Hpop & Hseq).
  exists k'. repeat split; try assumption.
  eapply kcad9_pop_ocaml_shape_fuel_refill_concat_left_thm.
  - exact
      (proj1
         (kcad9_concat_ocaml_shape_left_fold_singletons_refill_depth_one_seq_thm
            X (x :: xs))).
  - exact Hpop.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_snoc_nonempty_thm :
  forall (X : Type) (xs : list X) (x : X),
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton (xs ++ [x])) <> K9Empty.
Proof.
  intros X xs x Hempty.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm
       X (xs ++ [x])) as Hseq.
  rewrite Hempty in Hseq.
  rewrite empty_to_list9 in Hseq.
  destruct xs as [|xh xs].
  - cbn in Hseq. discriminate Hseq.
  - discriminate Hseq.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_total_under_left_fold_singletons_snoc_thm :
  forall (fuel : nat) (X : Type) (xs : list X) (x : X),
    exists k' y,
      kcad9_eject_ocaml_shape_fuel fuel
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (xs ++ [x]))) =
      Some (k', y).
Proof.
  intros fuel X xs x.
  eapply kcad9_eject_ocaml_shape_fuel_total_under_reachable_depth_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm.
  - apply kcad9_concat_ocaml_shape_left_fold_singletons_snoc_nonempty_thm.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_expected_under_left_fold_singletons_snoc_thm :
  forall (fuel : nat) (X : Type) (xs : list X) (x : X),
