        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (xs ++ [x]))) =
      Some (k', x) /\
      kcad9_to_list k' = xs.
Proof.
  intros fuel X xs x.
  destruct
    (kcad9_eject_ocaml_shape_fuel_total_under_left_fold_singletons_snoc_thm
       fuel X xs x) as (k' & y & Heject).
  destruct
    (kcad9_eject_ocaml_shape_fuel_left_fold_singletons_snoc_seq_thm
       fuel X xs x y k' Heject) as [Hy Htail].
  subst y. exists k'. split; assumption.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_expected_refill_left_under_left_fold_singletons_snoc_thm :
  forall (fuel : nat) (X : Type) (xs : list X) (x : X),
