Theorem kcad9_pop_ocaml_shape_fuel_two_boundary_deep_left_not_boundary_deep_counterexample_thm :
  exists k k' : KCadeque9 nat,
    inv_kcad9_ocaml_boundary_deep k /\
    inv_kcad9_ocaml_refill_concat_left_depth 0 k /\
    kcad9_to_list k = [0; 1] /\
    kcad9_pop_ocaml_shape_fuel 2 k = Some (0, k') /\
    kcad9_to_list k' = [1] /\
    ~ inv_kcad9_ocaml_boundary_deep k'.
Proof.
  pose (empty_cell := StoredSmall9 (@buf6_empty (KElem9 nat))).
  pose (h := mkBuf6 [XBase9 0]).
  pose (m := mkBuf6 [empty_cell; empty_cell; empty_cell]).
  pose (t := mkBuf6 [XBase9 1]).
  pose (k := K9Triple h m t).
  pose (k' := K9Triple (@buf6_empty (KElem9 nat))
              (mkBuf6 [empty_cell]) t).
  exists k, k'. split.
  - split.
    + unfold k.
      cbn [inv_kcad9_ocaml_boundaries].
      unfold h, t, buf6_size_ge, buf6_size, buf6_elems.
      cbn.
      split; lia.
    + unfold k, h, m, t, empty_cell.
      cbn [inv_kcad9_ocaml_deep_xbase
           xbase_middle9_deep xbase_stored9_deep all_xbase9
           buf6_elems buf6_empty].
      repeat constructor.
  - split.
    + unfold inv_kcad9_ocaml_refill_concat_left_depth.
      unfold k, m, empty_cell.
      cbn [inv_kcad9_ocaml_refill_depth_bound middle9_refill_depth_le
           stored_refill_depth_le buf6_elems].
      repeat split; exact I.
    + split.
      * unfold k, h, m, t, empty_cell.
        cbn [kcad9_to_list stored9_to_list
             kelem9_to_list buf6_elems buf6_empty].
        reflexivity.
      * split.
        -- unfold k, k', h, m, t, empty_cell.
           cbn [kcad9_pop_ocaml_shape_fuel refill_h_K9Triple_fuel
                k9_with_front_fuel buf6_pop
                buf6_is_empty buf6_size buf6_elems buf6_empty].
           reflexivity.
        -- split.
           ++ unfold k', t, empty_cell.
              cbn [kcad9_to_list stored9_to_list
                   kelem9_to_list buf6_elems buf6_empty].
              reflexivity.
           ++ intros [Hbounds _].
              unfold k' in Hbounds.
              cbn [inv_kcad9_ocaml_boundaries] in Hbounds.
              unfold buf6_size_ge, buf6_size, buf6_empty, buf6_elems
                in Hbounds.
              cbn in Hbounds.
              destruct Hbounds as [Hempty _]. lia.
Qed.

