Theorem inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_boundary_deep k ->
    kcad9_ocaml_refill_continuation_ready_fuel_depth fuel depth k ->
    inv_kcad9_ocaml_reachable_depth depth k.
Proof.
  intros fuel depth X [|b|h m t] [Hboundary Hdeep] Hcont.
  - split; exact I.
  - split.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth]. split; assumption.
    + exact Hdeep.
  - cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth] in Hcont.
    destruct Hboundary as [Hh Ht].
    destruct Hdeep as [Hxh [Hm Hxt]].
    destruct Hcont as [Hfront_cont Hback_cont].
    destruct fuel as [|fuel'];
    cbn [front_refill_continuation_ready_middle9_fuel
         back_refill_continuation_ready_middle9_fuel]
      in Hfront_cont, Hback_cont.
    all: destruct Hfront_cont as [Hfront _];
      destruct Hback_cont as [Hback _];
      split.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth].
      repeat split; assumption.
    + cbn [inv_kcad9_ocaml_deep_xbase].
      repeat split; assumption.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth].
      repeat split; assumption.
    + cbn [inv_kcad9_ocaml_deep_xbase].
      repeat split; assumption.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_continuation_depth_empty_refill_thm :
  forall (sched depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)) (x : X) (h' : Buf6 (KElem9 X)),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth (K9Triple h m t) ->
    buf6_pop h = Some (XBase9 x, h') ->
    buf6_is_empty h' = true ->
    exists k',
      kcad9_pop_ocaml_shape_fuel (S depth) (K9Triple h m t) =
        Some (x, k') /\
      inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros sched depth X h m t x h' [Hreach Hcont] Hpop Hempty.
  pose proof (conj Hreach Hcont) as Hinv.
  destruct
    (kcad9_pop_ocaml_shape_fuel_front_continuation_empty_refill_thm
       (S depth) sched depth X h m t x h' Hinv Hpop Hempty)
    as (k_front & Hres_front & Hfront).
  destruct
    (kcad9_pop_ocaml_shape_fuel_back_continuation_empty_refill_thm
       (S depth) sched depth X h m t x h' Hinv Hpop Hempty)
    as (k_back & Hres_back & Hback).
  rewrite Hres_front in Hres_back.
  inversion Hres_back. subst k_back. clear Hres_back.
  pose proof
    (kcad9_pop_ocaml_shape_fuel_boundary_deep_under_reachable_depth_thm
       depth X (K9Triple h m t) x k_front Hreach Hres_front)
    as Hboundary_deep.
  assert (Hcont' :
            kcad9_ocaml_refill_continuation_ready_fuel_depth
              sched depth k_front).
  { destruct k_front as [|b|h2 m2 t2]; cbn in *.
    - exact I.
    - exact I.
    - split; assumption. }
  exists k_front. split; [exact Hres_front|].
  split.
  - eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
      eassumption.
  - exact Hcont'.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_continuation_depth_empty_refill_thm :
  forall (sched depth : nat) (X : Type)
         (h : Buf6 (KElem9 X)) (m : Buf6 (Stored9 X))
         (t : Buf6 (KElem9 X)) (t' : Buf6 (KElem9 X)) (x : X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth (K9Triple h m t) ->
    buf6_eject t = Some (t', XBase9 x) ->
    buf6_is_empty t' = true ->
    exists k',
      kcad9_eject_ocaml_shape_fuel (S depth) (K9Triple h m t) =
        Some (k', x) /\
      inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros sched depth X h m t t' x [Hreach Hcont] Heject Hempty.
  pose proof (conj Hreach Hcont) as Hinv.
  destruct
    (kcad9_eject_ocaml_shape_fuel_front_continuation_empty_refill_thm
       (S depth) sched depth X h m t t' x Hinv Heject Hempty)
    as (k_front & Hres_front & Hfront).
  destruct
    (kcad9_eject_ocaml_shape_fuel_back_continuation_empty_refill_thm
       (S depth) sched depth X h m t t' x Hinv Heject Hempty)
    as (k_back & Hres_back & Hback).
  rewrite Hres_front in Hres_back.
  inversion Hres_back. subst k_back. clear Hres_back.
  pose proof
    (kcad9_eject_ocaml_shape_fuel_boundary_deep_under_reachable_depth_thm
       depth X (K9Triple h m t) k_front x Hreach Hres_front)
    as Hboundary_deep.
  assert (Hcont' :
            kcad9_ocaml_refill_continuation_ready_fuel_depth
              sched depth k_front).
  { destruct k_front as [|b|h2 m2 t2]; cbn in *.
    - exact I.
    - exact I.
    - split; assumption. }
  exists k_front. split; [exact Hres_front|].
  split.
  - eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
      eassumption.
  - exact Hcont'.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_continuation_depth_thm :
  forall (sched depth : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth k ->
    kcad9_pop_ocaml_shape_fuel (S depth) k = Some (x, k') ->
    inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros sched depth X [|b|h m t] x k' Hinv Hpop.
  - cbn [kcad9_pop_ocaml_shape_fuel] in Hpop. discriminate.
  - destruct Hinv as [[Hready Hdeep] _].
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
    cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready.
    destruct Hready as [_ Hxb].
    destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (all_xbase9_pop X b b' (XBase9 y) Hxb Hpb) as [_ Hxb'].
    destruct (all_xbase9_pop X b b' (XBase9 y) Hdeep Hpb)
      as [_ Hdeep'].
    destruct (buf6_is_empty b') eqn:Hempty;
      inversion Hpop; subst; clear Hpop.
    + apply empty_kcad9_ocaml_continuation_depth_thm.
    + split.
      * split.
        -- cbn [inv_kcad9_ocaml_ready_or_empty_depth].
           split.
           ++ apply buf6_is_empty_false_size_ge_1. exact Hempty.
           ++ exact Hxb'.
        -- cbn [inv_kcad9_ocaml_deep_xbase]. exact Hdeep'.
      * exact I.
  - destruct (buf6_pop h) as [[e h']|] eqn:Hph.
    + destruct e as [y|s]; [|cbn [kcad9_pop_ocaml_shape_fuel] in Hpop;
                              rewrite Hph in Hpop; discriminate].
      destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp.
      * assert (Hinv_sched :
                  inv_kcad9_ocaml_continuation_depth sched depth
                    (K9Triple h m t)).
        { exact
            (inv_kcad9_ocaml_continuation_depth_fuel_drop_prefix_thm
               (S (S depth)) sched depth X (K9Triple h m t) Hinv). }
        apply PeanoNat.Nat.leb_le in Hcmp.
        destruct
          (kcad9_pop_ocaml_shape_fuel_continuation_depth_no_refill_thm
             (S depth) sched depth X h m t y h'
             Hinv_sched Hph Hcmp) as [Hresult Hout].
        rewrite Hresult in Hpop. inversion Hpop; subst. exact Hout.
      * destruct (buf6_is_empty h') eqn:Hempty.
        -- destruct
             (kcad9_pop_ocaml_shape_fuel_continuation_depth_empty_refill_thm
                sched depth X h m t y h' Hinv Hph Hempty)
             as (k_empty & Hresult & Hout).
           rewrite Hresult in Hpop. inversion Hpop; subst. exact Hout.
        -- assert (Hinv_present :
                    inv_kcad9_ocaml_continuation_depth (S sched) depth
                      (K9Triple h m t)).
           { replace (S (S depth + sched)) with (S depth + S sched) in Hinv
             by lia.
             exact
               (inv_kcad9_ocaml_continuation_depth_fuel_drop_prefix_thm
                  (S depth) (S sched) depth X (K9Triple h m t) Hinv). }
           destruct
             (kcad9_pop_ocaml_shape_fuel_continuation_depth_present_refill_thm
                (S depth) sched depth X h m t y h' Hinv_present Hph
                (buf6_is_empty_false_size_ge_1 _ _ Hempty))
             as (m' & Hresult & Hout).
           rewrite Hresult in Hpop. inversion Hpop; subst. exact Hout.
    + cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
      rewrite Hph in Hpop. discriminate.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_continuation_depth_thm :
  forall (sched depth : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth k ->
    kcad9_eject_ocaml_shape_fuel (S depth) k = Some (k', x) ->
    inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros sched depth X [|b|h m t] k' x Hinv Heject.
  - cbn [kcad9_eject_ocaml_shape_fuel] in Heject. discriminate.
  - destruct Hinv as [[Hready Hdeep] _].
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
    cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready.
    destruct Hready as [_ Hxb].
    destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (all_xbase9_eject X b b' (XBase9 y) Hxb Heb) as [Hxb' _].
    destruct (all_xbase9_eject X b b' (XBase9 y) Hdeep Heb)
      as [Hdeep' _].
    destruct (buf6_is_empty b') eqn:Hempty;
      inversion Heject; subst; clear Heject.
    + apply empty_kcad9_ocaml_continuation_depth_thm.
    + split.
      * split.
        -- cbn [inv_kcad9_ocaml_ready_or_empty_depth].
           split.
           ++ apply buf6_is_empty_false_size_ge_1. exact Hempty.
           ++ exact Hxb'.
        -- cbn [inv_kcad9_ocaml_deep_xbase]. exact Hdeep'.
      * exact I.
  - destruct (buf6_eject t) as [[t' e]|] eqn:Het.
    + destruct e as [y|s]; [|cbn [kcad9_eject_ocaml_shape_fuel] in Heject;
                              rewrite Het in Heject; discriminate].
      destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp.
      * assert (Hinv_sched :
                  inv_kcad9_ocaml_continuation_depth sched depth
                    (K9Triple h m t)).
        { exact
            (inv_kcad9_ocaml_continuation_depth_fuel_drop_prefix_thm
               (S (S depth)) sched depth X (K9Triple h m t) Hinv). }
        apply PeanoNat.Nat.leb_le in Hcmp.
        destruct
          (kcad9_eject_ocaml_shape_fuel_continuation_depth_no_refill_thm
             (S depth) sched depth X h m t t' y
             Hinv_sched Het Hcmp) as [Hresult Hout].
        rewrite Hresult in Heject. inversion Heject; subst. exact Hout.
      * destruct (buf6_is_empty t') eqn:Hempty.
        -- destruct
             (kcad9_eject_ocaml_shape_fuel_continuation_depth_empty_refill_thm
                sched depth X h m t t' y Hinv Het Hempty)
             as (k_empty & Hresult & Hout).
           rewrite Hresult in Heject. inversion Heject; subst. exact Hout.
        -- assert (Hinv_present :
                    inv_kcad9_ocaml_continuation_depth (S sched) depth
                      (K9Triple h m t)).
           { replace (S (S depth + sched)) with (S depth + S sched) in Hinv
             by lia.
             exact
               (inv_kcad9_ocaml_continuation_depth_fuel_drop_prefix_thm
                  (S depth) (S sched) depth X (K9Triple h m t) Hinv). }
           destruct
             (kcad9_eject_ocaml_shape_fuel_continuation_depth_present_refill_thm
                (S depth) sched depth X h m t t' y Hinv_present Het
                (buf6_is_empty_false_size_ge_1 _ _ Hempty))
             as (m' & Hresult & Hout).
           rewrite Hresult in Heject. inversion Heject; subst. exact Hout.
    + cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
      rewrite Het in Heject. discriminate.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (xs : list X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth k ->
    kcad9_to_list k = x :: xs ->
    exists k',
      kcad9_pop_ocaml_shape_fuel (S depth) k = Some (x, k') /\
      kcad9_to_list k' = xs /\
      inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros depth sched X k x xs Hinv Hseq_in.
  assert (Hreach : inv_kcad9_ocaml_reachable_depth depth k).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hinv. }
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    discriminate Hseq_in. }
  destruct
    (kcad9_pop_ocaml_shape_fuel_total_under_reachable_depth_thm
       (S depth) depth X k Hreach Hne) as (y & k' & Hpop).
  pose proof
    (kcad9_pop_ocaml_shape_fuel_seq_thm (S depth) X k y k' Hpop)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  injection Hseq_out as Hy Htail.
  subst y. exists k'.
  split; [exact Hpop|].
  split; [symmetry; exact Htail|].
  eapply kcad9_pop_ocaml_shape_fuel_continuation_depth_thm;
    eassumption.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X) (x : X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + sched)) depth k ->
    kcad9_to_list k = xs ++ [x] ->
    exists k',
      kcad9_eject_ocaml_shape_fuel (S depth) k = Some (k', x) /\
      kcad9_to_list k' = xs /\
      inv_kcad9_ocaml_continuation_depth sched depth k'.
Proof.
  intros depth sched X k xs x Hinv Hseq_in.
  assert (Hreach : inv_kcad9_ocaml_reachable_depth depth k).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hinv. }
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    destruct xs as [|xh xs]; discriminate Hseq_in. }
  destruct
    (kcad9_eject_ocaml_shape_fuel_total_under_reachable_depth_thm
       (S depth) depth X k Hreach Hne) as (k' & y & Heject).
  pose proof
    (kcad9_eject_ocaml_shape_fuel_seq_thm (S depth) X k k' y Heject)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  destruct (app_singleton_inj X xs (kcad9_to_list k') x y Hseq_out)
    as [Htail Hy].
  subst y. exists k'.
  split; [exact Heject|].
  split; [symmetry; exact Htail|].
  eapply kcad9_eject_ocaml_shape_fuel_continuation_depth_thm;
    eassumption.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_then_pop_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (x y : X) (xs : list X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + S (S depth + sched))) depth k ->
    kcad9_to_list k = x :: y :: xs ->
    exists k1 k2,
      kcad9_pop_ocaml_shape_fuel (S depth) k = Some (x, k1) /\
      kcad9_to_list k1 = y :: xs /\
      inv_kcad9_ocaml_continuation_depth
        (S (S depth + sched)) depth k1 /\
      kcad9_pop_ocaml_shape_fuel (S depth) k1 = Some (y, k2) /\
      kcad9_to_list k2 = xs /\
      inv_kcad9_ocaml_continuation_depth sched depth k2.
Proof.
  intros depth sched X k x y xs Hinv Hseq.
  destruct
    (kcad9_pop_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
       depth (S (S depth + sched)) X k x (y :: xs) Hinv Hseq)
    as (k1 & Hpop1 & Hseq1 & Hcont1).
  destruct
    (kcad9_pop_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
       depth sched X k1 y xs Hcont1 Hseq1)
    as (k2 & Hpop2 & Hseq2 & Hcont2).
  exists k1, k2.
  split; [exact Hpop1|].
  split; [exact Hseq1|].
  split; [exact Hcont1|].
  split; [exact Hpop2|].
  split; [exact Hseq2|exact Hcont2].
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_then_eject_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X) (y x : X),
    inv_kcad9_ocaml_continuation_depth
      (S (S depth + S (S depth + sched))) depth k ->
    kcad9_to_list k = xs ++ [y; x] ->
    exists k1 k2,
      kcad9_eject_ocaml_shape_fuel (S depth) k = Some (k1, x) /\
      kcad9_to_list k1 = xs ++ [y] /\
      inv_kcad9_ocaml_continuation_depth
        (S (S depth + sched)) depth k1 /\
      kcad9_eject_ocaml_shape_fuel (S depth) k1 = Some (k2, y) /\
      kcad9_to_list k2 = xs /\
      inv_kcad9_ocaml_continuation_depth sched depth k2.
Proof.
  intros depth sched X k xs y x Hinv Hseq.
  replace (xs ++ [y; x]) with ((xs ++ [y]) ++ [x]) in Hseq
    by (change [y; x] with ([y] ++ [x]); rewrite <- app_assoc; reflexivity).
  destruct
    (kcad9_eject_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
       depth (S (S depth + sched)) X k (xs ++ [y]) x Hinv Hseq)
    as (k1 & Heject1 & Hseq1 & Hcont1).
  destruct
    (kcad9_eject_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
       depth sched X k1 xs y Hcont1 Hseq1)
    as (k2 & Heject2 & Hseq2 & Hcont2).
  exists k1, k2.
  split; [exact Heject1|].
  split; [exact Hseq1|].
  split; [exact Hcont1|].
  split; [exact Heject2|].
  split; [exact Hseq2|exact Hcont2].
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_two_then_pop_expected_continuation_under_left_fold_singletons_thm :
  forall (X : Type) (x y : X) (xs : list X),
    exists k1 k2,
      kcad9_pop_ocaml_shape_fuel 2
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (x :: y :: xs))) =
        Some (x, k1) /\
      kcad9_to_list k1 = y :: xs /\
      inv_kcad9_ocaml_continuation_depth 3 1 k1 /\
      kcad9_pop_ocaml_shape_fuel 2 k1 = Some (y, k2) /\
      kcad9_to_list k2 = xs /\
      inv_kcad9_ocaml_continuation_depth 0 1 k2.
Proof.
  intros X x y xs.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_continuation_depth_thm
       (S (S 1 + S (S 1 + 0))) 1 X (x :: y :: xs)) as Hcont.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm
       X (x :: y :: xs)) as Hseq.
  destruct
    (kcad9_pop_ocaml_shape_fuel_then_pop_expected_under_continuation_depth_seq_thm
       1 0 X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (x :: y :: xs)))
       x y xs Hcont Hseq)
    as (k1 & k2 & Hpop1 & Hseq1 & Hcont1 & Hpop2 & Hseq2 & Hcont2).
  exists k1, k2.
  split; [exact Hpop1|].
  split; [exact Hseq1|].
  split; [exact Hcont1|].
  split; [exact Hpop2|].
  split; [exact Hseq2|exact Hcont2].
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_two_then_eject_expected_continuation_under_left_fold_singletons_snoc_thm :
  forall (X : Type) (xs : list X) (y x : X),
    exists k1 k2,
