    (kcad9_eject_ocaml_shape_fuel_then_eject_expected_under_continuation_depth_seq_thm
       1 0 X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton (xs ++ [y; x])))
