Fixpoint kcad9_endpoint_budget_for_list
  (depth sched : nat) {X : Type} (xs : list X) : nat :=
  match xs with
  | [] => sched
  | _ :: xs' =>
      S (S depth + kcad9_endpoint_budget_for_list depth sched xs')
  end.

Fixpoint kcad9_pop_ocaml_shape_fuel_drain_expected {X : Type}
  (fuel : nat) (k : KCadeque9 X) (xs : list X)
  (k_final : KCadeque9 X) : Prop :=
  match xs with
  | [] => k_final = k
  | x :: xs' =>
      exists k1,
        kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k1) /\
        kcad9_pop_ocaml_shape_fuel_drain_expected fuel k1 xs' k_final
  end.

Fixpoint kcad9_eject_ocaml_shape_fuel_drain_expected {X : Type}
  (fuel : nat) (k : KCadeque9 X) (xs : list X)
  (k_final : KCadeque9 X) : Prop :=
  match xs with
  | [] => k_final = k
  | x :: xs' =>
      exists k1,
        kcad9_eject_ocaml_shape_fuel fuel k = Some (k1, x) /\
        kcad9_eject_ocaml_shape_fuel_drain_expected fuel k1 xs' k_final
  end.

Theorem kcad9_pop_ocaml_shape_fuel_drain_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X),
    inv_kcad9_ocaml_continuation_depth
      (kcad9_endpoint_budget_for_list depth sched xs) depth k ->
    kcad9_to_list k = xs ->
    exists k_final,
      kcad9_pop_ocaml_shape_fuel_drain_expected
        (S depth) k xs k_final /\
      kcad9_to_list k_final = [] /\
      inv_kcad9_ocaml_continuation_depth sched depth k_final.
Proof.
  intros depth sched X k xs.
  revert k.
  induction xs as [|x xs IH]; intros k Hcont Hseq.
  - exists k.
    split; [reflexivity|].
    split; [exact Hseq|exact Hcont].
  - cbn [kcad9_endpoint_budget_for_list] in Hcont.
    destruct
      (kcad9_pop_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
         depth (kcad9_endpoint_budget_for_list depth sched xs)
         X k x xs Hcont Hseq)
      as (k1 & Hpop & Hseq1 & Hcont1).
    destruct (IH k1 Hcont1 Hseq1)
      as (k_final & Hdrain & Hseq_final & Hcont_final).
    exists k_final.
    split.
    + cbn [kcad9_pop_ocaml_shape_fuel_drain_expected].
      exists k1. split; [exact Hpop|exact Hdrain].
    + split; [exact Hseq_final|exact Hcont_final].
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_drain_expected_under_continuation_depth_rev_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X),
    inv_kcad9_ocaml_continuation_depth
      (kcad9_endpoint_budget_for_list depth sched xs) depth k ->
    kcad9_to_list k = rev xs ->
    exists k_final,
      kcad9_eject_ocaml_shape_fuel_drain_expected
        (S depth) k xs k_final /\
      kcad9_to_list k_final = [] /\
      inv_kcad9_ocaml_continuation_depth sched depth k_final.
Proof.
  intros depth sched X k xs.
  revert k.
  induction xs as [|x xs IH]; intros k Hcont Hseq.
  - exists k.
    split; [reflexivity|].
    split; [exact Hseq|exact Hcont].
  - cbn [kcad9_endpoint_budget_for_list] in Hcont.
    cbn [rev] in Hseq.
    destruct
      (kcad9_eject_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
         depth (kcad9_endpoint_budget_for_list depth sched xs)
         X k (rev xs) x Hcont Hseq)
      as (k1 & Heject & Hseq1 & Hcont1).
    destruct (IH k1 Hcont1 Hseq1)
      as (k_final & Hdrain & Hseq_final & Hcont_final).
    exists k_final.
    split.
    + cbn [kcad9_eject_ocaml_shape_fuel_drain_expected].
      exists k1. split; [exact Heject|exact Hdrain].
    + split; [exact Hseq_final|exact Hcont_final].
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_two_drain_expected_under_left_fold_singletons_thm :
  forall (X : Type) (xs : list X),
    exists k_final,
      kcad9_pop_ocaml_shape_fuel_drain_expected 2
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
        xs k_final /\
      kcad9_to_list k_final = [] /\
      inv_kcad9_ocaml_continuation_depth 0 1 k_final.
Proof.
  intros X xs.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_continuation_depth_thm
       (kcad9_endpoint_budget_for_list 1 0 xs) 1 X xs) as Hcont.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm X xs) as Hseq.
  exact
    (kcad9_pop_ocaml_shape_fuel_drain_expected_under_continuation_depth_seq_thm
       1 0 X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
       xs Hcont Hseq).
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_two_drain_expected_under_left_fold_singletons_rev_thm :
  forall (X : Type) (xs : list X),
    exists k_final,
      kcad9_eject_ocaml_shape_fuel_drain_expected 2
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
        (rev xs) k_final /\
      kcad9_to_list k_final = [] /\
      inv_kcad9_ocaml_continuation_depth 0 1 k_final.
Proof.
  intros X xs.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_continuation_depth_thm
       (kcad9_endpoint_budget_for_list 1 0 (rev xs)) 1 X xs) as Hcont.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm X xs) as Hseq.
  assert (Hseq_rev :
            kcad9_to_list
              (kcad9_concat_ocaml_shape_left_fold
                (@kcad9_empty X) (map kcad9_singleton xs)) =
            rev (rev xs)).
  { rewrite rev_involutive. exact Hseq. }
  exact
    (kcad9_eject_ocaml_shape_fuel_drain_expected_under_continuation_depth_rev_seq_thm
       1 0 X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
       (rev xs) Hcont Hseq_rev).
Qed.

Inductive KCad9EndpointSide : Type :=
| KCad9EndpointFront
| KCad9EndpointBack.

Definition list_unsnoc {X : Type} (xs : list X) : option (list X * X) :=
  match rev xs with
  | [] => None
  | x :: rev_prefix => Some (rev rev_prefix, x)
  end.

Lemma list_unsnoc_some_app :
  forall (X : Type) (xs prefix : list X) (x : X),
    list_unsnoc xs = Some (prefix, x) ->
    xs = prefix ++ [x].
Proof.
  intros X xs prefix x Hunsnoc.
  unfold list_unsnoc in Hunsnoc.
  destruct (rev xs) as [|last rev_prefix] eqn:Hrev; [discriminate|].
  injection Hunsnoc as Hprefix Hx. subst prefix x.
  rewrite <- (rev_involutive xs).
  rewrite Hrev. cbn [rev]. reflexivity.
Qed.

Lemma list_unsnoc_app_singleton :
  forall (X : Type) (xs : list X) (x : X),
    list_unsnoc (xs ++ [x]) = Some (xs, x).
Proof.
  intros X xs x.
  unfold list_unsnoc.
  rewrite rev_app_distr. cbn [rev app].
  rewrite rev_involutive.
  reflexivity.
Qed.

Fixpoint kcad9_endpoint_budget_for_script
  (depth sched : nat) (ops : list KCad9EndpointSide) : nat :=
  match ops with
  | [] => sched
  | _ :: ops' =>
      S (S depth + kcad9_endpoint_budget_for_script depth sched ops')
  end.

Fixpoint kcad9_endpoint_script_model {X : Type}
  (xs : list X) (ops : list KCad9EndpointSide) : option (list X) :=
  match ops with
  | [] => Some xs
  | KCad9EndpointFront :: ops' =>
      match xs with
      | [] => None
      | _ :: xs' => kcad9_endpoint_script_model xs' ops'
      end
  | KCad9EndpointBack :: ops' =>
      match list_unsnoc xs with
      | Some (xs', _) => kcad9_endpoint_script_model xs' ops'
      | None => None
      end
  end.

Fixpoint kcad9_endpoint_script_expected {X : Type}
  (fuel : nat) (k : KCadeque9 X) (xs : list X)
  (ops : list KCad9EndpointSide) (k_final : KCadeque9 X)
  (xs_final : list X) : Prop :=
  match ops with
  | [] => k_final = k /\ xs_final = xs
  | KCad9EndpointFront :: ops' =>
      match xs with
      | [] => False
      | x :: xs' =>
          exists k1,
            kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k1) /\
            kcad9_endpoint_script_expected
              fuel k1 xs' ops' k_final xs_final
      end
  | KCad9EndpointBack :: ops' =>
      match list_unsnoc xs with
      | Some (xs', x) =>
          exists k1,
            kcad9_eject_ocaml_shape_fuel fuel k = Some (k1, x) /\
            kcad9_endpoint_script_expected
              fuel k1 xs' ops' k_final xs_final
      | None => False
      end
  end.

Theorem kcad9_endpoint_script_expected_refill_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X) (ops : list KCad9EndpointSide)
         (k_final : KCadeque9 X) (xs_final : list X),
    inv_kcad9_ocaml_refill_depth_bound depth k ->
    kcad9_endpoint_script_expected
      fuel k xs ops k_final xs_final ->
    inv_kcad9_ocaml_refill_depth_bound depth k_final.
Proof.
  intros fuel depth X k xs ops.
  revert k xs.
  induction ops as [|op ops IH]; intros k xs k_final xs_final Hdepth Hscript.
  - cbn [kcad9_endpoint_script_expected] in Hscript.
    destruct Hscript as [Hk_final _]. subst k_final.
    exact Hdepth.
  - destruct op.
    + destruct xs as [|x xs']; [contradiction|].
      cbn [kcad9_endpoint_script_expected] in Hscript.
      destruct Hscript as (k1 & Hpop & Hscript).
      eapply IH.
      * eapply kcad9_pop_ocaml_shape_fuel_refill_depth_bound_thm;
          eassumption.
      * exact Hscript.
    + destruct (list_unsnoc xs) as [[xs' x]|] eqn:Hunsnoc.
      * cbn [kcad9_endpoint_script_expected] in Hscript.
        rewrite Hunsnoc in Hscript.
        destruct Hscript as (k1 & Heject & Hscript).
        eapply IH.
        -- eapply kcad9_eject_ocaml_shape_fuel_refill_depth_bound_thm;
             eassumption.
        -- exact Hscript.
      * cbn [kcad9_endpoint_script_expected] in Hscript.
        rewrite Hunsnoc in Hscript.
        contradiction.
Qed.

Theorem kcad9_endpoint_script_expected_under_continuation_depth_seq_thm :
  forall (depth sched : nat) (X : Type) (k : KCadeque9 X)
         (xs : list X) (ops : list KCad9EndpointSide)
         (xs_final : list X),
    inv_kcad9_ocaml_continuation_depth
      (kcad9_endpoint_budget_for_script depth sched ops) depth k ->
    kcad9_to_list k = xs ->
    kcad9_endpoint_script_model xs ops = Some xs_final ->
    exists k_final,
      kcad9_endpoint_script_expected
        (S depth) k xs ops k_final xs_final /\
      kcad9_to_list k_final = xs_final /\
      inv_kcad9_ocaml_continuation_depth sched depth k_final.
Proof.
  intros depth sched X k xs ops.
  revert k xs.
  induction ops as [|op ops IH]; intros k xs xs_final Hcont Hseq Hmodel.
  - cbn [kcad9_endpoint_script_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists k.
    split; [split; reflexivity|].
    split; [exact Hseq|exact Hcont].
  - cbn [kcad9_endpoint_budget_for_script] in Hcont.
    destruct op.
    + destruct xs as [|x xs']; [discriminate|].
      cbn [kcad9_endpoint_script_model] in Hmodel.
      destruct
        (kcad9_pop_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
           depth (kcad9_endpoint_budget_for_script depth sched ops)
           X k x xs' Hcont Hseq)
        as (k1 & Hpop & Hseq1 & Hcont1).
      destruct (IH k1 xs' xs_final Hcont1 Hseq1 Hmodel)
        as (k_final & Hscript & Hseq_final & Hcont_final).
      exists k_final.
      split.
      * cbn [kcad9_endpoint_script_expected].
        exists k1. split; [exact Hpop|exact Hscript].
      * split; [exact Hseq_final|exact Hcont_final].
    + destruct (list_unsnoc xs) as [[xs' x]|] eqn:Hunsnoc.
      cbn [kcad9_endpoint_script_model] in Hmodel.
      rewrite Hunsnoc in Hmodel.
      assert (Hseq_eject : kcad9_to_list k = xs' ++ [x]).
      { rewrite Hseq.
        apply list_unsnoc_some_app. exact Hunsnoc. }
      destruct
        (kcad9_eject_ocaml_shape_fuel_expected_under_continuation_depth_seq_thm
           depth (kcad9_endpoint_budget_for_script depth sched ops)
           X k xs' x Hcont Hseq_eject)
        as (k1 & Heject & Hseq1 & Hcont1).
      destruct (IH k1 xs' xs_final Hcont1 Hseq1 Hmodel)
        as (k_final & Hscript & Hseq_final & Hcont_final).
      exists k_final.
      split.
      * cbn [kcad9_endpoint_script_expected].
        rewrite Hunsnoc.
        exists k1. split; [exact Heject|exact Hscript].
      * split; [exact Hseq_final|exact Hcont_final].
      * cbn [kcad9_endpoint_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel. discriminate.
Qed.

Theorem kcad9_endpoint_script_expected_fuel_two_under_left_fold_singletons_thm :
  forall (X : Type) (xs : list X) (ops : list KCad9EndpointSide)
         (xs_final : list X),
    kcad9_endpoint_script_model xs ops = Some xs_final ->
    exists k_final,
      kcad9_endpoint_script_expected 2
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
        xs ops k_final xs_final /\
      kcad9_to_list k_final = xs_final /\
      inv_kcad9_ocaml_continuation_depth 0 1 k_final.
Proof.
  intros X xs ops xs_final Hmodel.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_continuation_depth_thm
       (kcad9_endpoint_budget_for_script 1 0 ops) 1 X xs) as Hcont.
  pose proof
    (kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm X xs) as Hseq.
  exact
    (kcad9_endpoint_script_expected_under_continuation_depth_seq_thm
       1 0 X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
       xs ops xs_final Hcont Hseq Hmodel).
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singleton_chunks_not_continuation_depth_thm :
  let a :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [0;1;2]) in
  let b :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [3;4;5]) in
  let k := kcad9_concat_ocaml_shape a b in
  kcad9_to_list k = [0;1;2;3;4;5] /\
  ~ inv_kcad9_ocaml_continuation_depth 2 1 k.
Proof.
  cbv [map kcad9_concat_ocaml_shape_left_fold kcad9_empty kcad9_singleton
       kcad9_concat_ocaml_shape kcad9_to_list stored9_to_list
       kelem9_to_list stored9_flat_list kelem9_flat_list
       inv_kcad9_ocaml_continuation_depth inv_kcad9_ocaml_reachable_depth
       inv_kcad9_ocaml_ready_or_empty_depth inv_kcad9_ocaml_deep_xbase
       kcad9_ocaml_refill_continuation_ready_fuel_depth
       front_refill_continuation_ready_middle9_fuel
       back_refill_continuation_ready_middle9_fuel
       front_ready_or_empty_middle9_depth back_ready_or_empty_middle9_depth
       front_ready_middle9_depth back_ready_middle9_depth
       front_ready_stored9_depth back_ready_stored9_depth
       front_ready_stored9 back_ready_stored9
       xbase_middle9_deep xbase_stored9_deep all_xbase9
       k9_middle_push k9_middle_inject
       buf6_empty buf6_inject buf6_eject buf6_push buf6_pop buf6_is_empty
       buf6_elems buf6_size_ge buf6_size length rev app].
  split; [reflexivity|].
  intros Hcont. firstorder lia.
Qed.

Definition kcad9_concat_absorb_back_bridge_cell {X : Type}
  (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
  (back_cell : Stored9 X) : Stored9 X :=
  match back_cell with
  | StoredSmall9 b =>
      StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) b
  | StoredBig9 pre sm suf =>
      StoredBig9 t1
        (k9_middle_inject
          (buf6_inject (buf6_push (StoredSmall9 h2) m2_rest)
            (StoredSmall9 pre))
          sm)
        suf
  | StoredMiddle9 sm =>
      StoredBig9 t1
        (k9_middle_inject (buf6_push (StoredSmall9 h2) m2_rest) sm)
        buf6_empty
  end.

Lemma kcad9_concat_absorb_back_bridge_cell_seq :
  forall (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    stored9_to_list
      (kcad9_concat_absorb_back_bridge_cell t1 h2 m2_rest back_cell) =
    kelem9_flat_list (buf6_elems t1) ++
    kelem9_flat_list (buf6_elems h2) ++
    stored9_flat_list (buf6_elems m2_rest) ++
    stored9_to_list back_cell.
Proof.
  intros X t1 h2 m2_rest [b|pre sm suf|sm];
    cbn [kcad9_concat_absorb_back_bridge_cell].
  - rewrite stored9_to_list_big, stored9_flat_list_push, stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - rewrite stored9_to_list_big, k9_middle_inject_seq.
    rewrite stored9_flat_list_inject, stored9_flat_list_push.
    rewrite !stored9_to_list_small, stored9_to_list_big.
    rewrite <- !app_assoc. reflexivity.
  - rewrite stored9_to_list_big, k9_middle_inject_seq.
    rewrite stored9_flat_list_push, stored9_to_list_small, stored9_to_list_middle.
    cbn [kelem9_flat_list buf6_elems]. rewrite app_nil_r.
    rewrite <- !app_assoc. reflexivity.
Qed.

Definition kcad9_concat_absorb_back_shape {X : Type}
  (a b : KCadeque9 X) : KCadeque9 X :=
  match a, b with
  | K9Empty, _ => b
  | _, K9Empty => a
  | K9Simple ba, K9Simple bb =>
      K9Triple ba buf6_empty bb
  | K9Simple ba, K9Triple h2 m2 t2 =>
      K9Triple ba (buf6_push (StoredSmall9 h2) m2) t2
  | K9Triple h1 m1 t1, K9Simple bb =>
      K9Triple h1 (buf6_inject m1 (StoredSmall9 t1)) bb
  | K9Triple h1 m1 t1, K9Triple h2 m2 t2 =>
      let m_new :=
        match buf6_eject m2 with
        | Some (m2_rest, back_cell) =>
            buf6_inject m1
              (kcad9_concat_absorb_back_bridge_cell t1 h2 m2_rest back_cell)
        | None =>
            let cell := StoredBig9 t1 buf6_empty h2 in
            buf6_inject m1 cell
        end in
      K9Triple h1 m_new t2
  end.

Theorem kcad9_concat_absorb_back_shape_seq_thm :
  forall (X : Type) (a b : KCadeque9 X),
    kcad9_to_list (kcad9_concat_absorb_back_shape a b) =
    kcad9_to_list a ++ kcad9_to_list b.
Proof.
  intros X [|ba|h1 m1 t1] [|bb|h2 m2 t2];
    cbn [kcad9_concat_absorb_back_shape].
  - reflexivity.
  - reflexivity.
  - reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_triple, !kcad9_to_list_simple.
    cbn [stored9_flat_list buf6_elems]. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_push. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_inject. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - rewrite !kcad9_to_list_triple.
    destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + assert (Hm2 := Heject). apply stored9_flat_list_eject_some in Hm2.
      rewrite stored9_flat_list_inject.
      rewrite kcad9_concat_absorb_back_bridge_cell_seq.
      rewrite Hm2. rewrite <- !app_assoc. reflexivity.
    + assert (Hm2flat := stored9_flat_list_empty_of_eject_none X m2 Heject).
      rewrite stored9_flat_list_inject. rewrite stored9_to_list_big.
      rewrite Hm2flat. cbn [stored9_flat_list buf6_elems].
      rewrite <- !app_assoc. reflexivity.
Qed.

Theorem kcad9_concat_absorb_back_shape_left_fold_singleton_chunks_continuation_depth_thm :
  let a :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [0;1;2]) in
  let b :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [3;4;5]) in
  let k := kcad9_concat_absorb_back_shape a b in
  kcad9_to_list k = [0;1;2;3;4;5] /\
  inv_kcad9_ocaml_continuation_depth 2 1 k.
Proof.
  vm_compute.
  split; [reflexivity|].
  repeat match goal with
  | |- _ /\ _ => split
  | |- _ \/ _ => right
  | |- exists _, _ => eexists
  | |- Some _ = Some _ => reflexivity
  | |- _ >= _ => lia
  | |- Forall _ _ => constructor
  | |- True => exact I
  end;
    cbn; try lia; try (repeat constructor).
  - eexists; eexists; split; [reflexivity|cbn; lia].
  - eexists; eexists; split; [reflexivity|cbn; lia].
Qed.

Theorem kcad9_concat_absorb_back_shape_stored_middle_back_cell_not_continuation_depth_thm :
  let h1 := mkBuf6 [XBase9 0] in
  let t1 := mkBuf6 [XBase9 1] in
  let h2 := mkBuf6 [XBase9 2] in
  let inner := mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])] in
  let m2 := mkBuf6 [StoredMiddle9 inner] in
  let t2 := mkBuf6 [XBase9 4] in
  let a := K9Triple h1 buf6_empty t1 in
  let b := K9Triple h2 m2 t2 in
  let k := kcad9_concat_absorb_back_shape a b in
  inv_kcad9_ocaml_continuation_depth 1 1 b /\
  kcad9_to_list k = [0;1;2;3;4] /\
  ~ inv_kcad9_ocaml_continuation_depth 0 1 k.
Proof.
  vm_compute.
  split.
  - repeat (cbn; repeat match goal with
    | |- _ /\ _ => split
    | |- _ \/ _ => right
    | |- exists _, _ => eexists
    | |- Some _ = Some _ => reflexivity
    | |- _ <= _ => lia
    | |- _ >= _ => lia
    | |- Forall _ _ => constructor
    | |- True => exact I
    end); try lia; try (repeat constructor); try reflexivity.
  - split; [reflexivity|].
    intros [[Hready _] _].
    destruct Hready as [_ [_ [_ [_ [_ Hback]]]]].
    destruct Hback as [Hnone|Hready_back].
    + discriminate Hnone.
    + destruct Hready_back as (m_rest & cell & Heject & Hcell).
      injection Heject as Hm_rest Hcell_eq. subst m_rest cell.
      cbn in Hcell. lia.
Qed.

Definition kcad9_concat_absorb_open_back_bridge_cell {X : Type}
  (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
  (back_cell : Stored9 X) : Stored9 X :=
  match back_cell with
  | StoredMiddle9 sm =>
      match buf6_eject sm with
      | Some (sm_rest, inner_back) =>
          kcad9_concat_absorb_back_bridge_cell t1 h2
            (k9_middle_inject m2_rest sm_rest) inner_back
      | None =>
          StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) buf6_empty
      end
  | _ => kcad9_concat_absorb_back_bridge_cell t1 h2 m2_rest back_cell
  end.

Lemma kcad9_concat_absorb_open_back_bridge_cell_seq :
  forall (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    stored9_to_list
      (kcad9_concat_absorb_open_back_bridge_cell t1 h2 m2_rest back_cell) =
    kelem9_flat_list (buf6_elems t1) ++
    kelem9_flat_list (buf6_elems h2) ++
    stored9_flat_list (buf6_elems m2_rest) ++
    stored9_to_list back_cell.
Proof.
  intros X t1 h2 m2_rest [b|pre sm suf|sm];
    cbn [kcad9_concat_absorb_open_back_bridge_cell].
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + rewrite kcad9_concat_absorb_back_bridge_cell_seq.
      rewrite k9_middle_inject_seq.
      assert (Hsm := Heject). apply stored9_flat_list_eject_some in Hsm.
      rewrite stored9_to_list_middle, Hsm.
      rewrite <- !app_assoc. reflexivity.
    + rewrite stored9_to_list_big, stored9_flat_list_push, stored9_to_list_small.
      assert (Hsm := Heject). apply stored9_flat_list_empty_of_eject_none in Hsm.
      rewrite stored9_to_list_middle, Hsm.
      cbn [kelem9_flat_list buf6_elems]. rewrite app_nil_r.
      rewrite app_nil_r. reflexivity.
Qed.

Definition kcad9_concat_absorb_open_back_shape {X : Type}
  (a b : KCadeque9 X) : KCadeque9 X :=
  match a, b with
  | K9Empty, _ => b
  | _, K9Empty => a
  | K9Simple ba, K9Simple bb =>
      K9Triple ba buf6_empty bb
  | K9Simple ba, K9Triple h2 m2 t2 =>
      K9Triple ba (buf6_push (StoredSmall9 h2) m2) t2
  | K9Triple h1 m1 t1, K9Simple bb =>
      K9Triple h1 (buf6_inject m1 (StoredSmall9 t1)) bb
  | K9Triple h1 m1 t1, K9Triple h2 m2 t2 =>
      let m_new :=
        match buf6_eject m2 with
        | Some (m2_rest, back_cell) =>
            buf6_inject m1
              (kcad9_concat_absorb_open_back_bridge_cell
                t1 h2 m2_rest back_cell)
        | None =>
            let cell := StoredBig9 t1 buf6_empty h2 in
            buf6_inject m1 cell
        end in
      K9Triple h1 m_new t2
  end.

Theorem kcad9_concat_absorb_open_back_shape_seq_thm :
  forall (X : Type) (a b : KCadeque9 X),
    kcad9_to_list (kcad9_concat_absorb_open_back_shape a b) =
    kcad9_to_list a ++ kcad9_to_list b.
Proof.
  intros X [|ba|h1 m1 t1] [|bb|h2 m2 t2];
    cbn [kcad9_concat_absorb_open_back_shape].
  - reflexivity.
  - reflexivity.
  - reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_triple, !kcad9_to_list_simple.
    cbn [stored9_flat_list buf6_elems]. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_push. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_inject. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - rewrite !kcad9_to_list_triple.
    destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + assert (Hm2 := Heject). apply stored9_flat_list_eject_some in Hm2.
      rewrite stored9_flat_list_inject.
      rewrite kcad9_concat_absorb_open_back_bridge_cell_seq.
      rewrite Hm2. rewrite <- !app_assoc. reflexivity.
    + assert (Hm2flat := stored9_flat_list_empty_of_eject_none X m2 Heject).
      rewrite stored9_flat_list_inject. rewrite stored9_to_list_big.
      rewrite Hm2flat. cbn [stored9_flat_list buf6_elems].
      rewrite <- !app_assoc. reflexivity.
Qed.

Lemma kcad9_concat_absorb_back_bridge_cell_deep_xbase :
  forall (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    all_xbase9 t1 ->
    all_xbase9 h2 ->
    xbase_middle9_deep m2_rest ->
    xbase_stored9_deep back_cell ->
    xbase_stored9_deep
      (kcad9_concat_absorb_back_bridge_cell t1 h2 m2_rest back_cell).
Proof.
  intros X t1 h2 m2_rest [b|pre sm suf|sm] Ht1 Hh2 Hm2 Hback;
    cbn [kcad9_concat_absorb_back_bridge_cell] in *.
  - apply xbase_stored9_deep_big.
    + exact Ht1.
    + apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
    + exact Hback.
  - apply xbase_stored9_deep_big_iff in Hback.
    destruct Hback as [Hpre [Hsuf Hsm]].
    apply xbase_stored9_deep_big.
    + exact Ht1.
    + apply xbase_middle9_deep_k9_middle_inject; [|exact Hsm].
      apply xbase_middle9_deep_inject.
      * apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
      * exact Hpre.
    + exact Hsuf.
  - apply xbase_stored9_deep_middle_iff in Hback.
    apply xbase_stored9_deep_big.
    + exact Ht1.
    + apply xbase_middle9_deep_k9_middle_inject; [|exact Hback].
      apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
    + apply all_xbase9_empty.
Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_deep_xbase :
  forall (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    all_xbase9 t1 ->
    all_xbase9 h2 ->
    xbase_middle9_deep m2_rest ->
    xbase_stored9_deep back_cell ->
    xbase_stored9_deep
      (kcad9_concat_absorb_open_back_bridge_cell t1 h2 m2_rest back_cell).
Proof.
  intros X t1 h2 m2_rest [b|pre sm suf|sm] Ht1 Hh2 Hm2 Hback;
    cbn [kcad9_concat_absorb_open_back_bridge_cell] in *.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply xbase_stored9_deep_middle_iff in Hback.
    destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + destruct (xbase_middle9_deep_eject X sm sm_rest inner_back Hback Heject)
        as [Hsm_rest Hinner].
      apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; try assumption.
      apply xbase_middle9_deep_k9_middle_inject; assumption.
    + apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
      * apply all_xbase9_empty.
Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_front_ready_depth :
  forall (depth : nat) (X : Type)
         (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
         (back_cell : Stored9 X),
    buf6_size_ge 1 t1 ->
    front_ready_stored9_depth depth
      (kcad9_concat_absorb_open_back_bridge_cell t1 h2 m2_rest back_cell).
Proof.
  intros depth X t1 h2 m2_rest [b|pre sm suf|sm] Ht1;
    cbn [kcad9_concat_absorb_open_back_bridge_cell].
  - apply front_ready_stored9_depth_big. exact Ht1.
  - apply front_ready_stored9_depth_big. exact Ht1.
  - destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + destruct inner_back as [b|pre sm' suf|sm'];
        cbn [kcad9_concat_absorb_back_bridge_cell];
        apply front_ready_stored9_depth_big; exact Ht1.
    + apply front_ready_stored9_depth_big. exact Ht1.
Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_back_ready_depth_one :
  forall (depth : nat) (X : Type)
         (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
         (back_cell : Stored9 X),
    back_ready_stored9_depth 1 back_cell ->
    back_ready_stored9_depth depth
      (kcad9_concat_absorb_open_back_bridge_cell t1 h2 m2_rest back_cell).
Proof.
  intros depth X t1 h2 m2_rest [b|pre sm suf|sm] Hready;
    cbn [kcad9_concat_absorb_open_back_bridge_cell] in *.
  - apply back_ready_stored9_depth_big. exact Hready.
  - apply back_ready_stored9_depth_big. exact Hready.
  - destruct Hready as (sm_rest0 & inner_back0 & Heject0 & Hinner).
    destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + injection Heject0 as Hrest Hcell.
      subst sm_rest0 inner_back0.
      destruct inner_back as [b|pre sm' suf|sm'];
        cbn [kcad9_concat_absorb_back_bridge_cell
             back_ready_stored9_depth back_ready_stored9] in *.
      * apply back_ready_stored9_depth_big. exact Hinner.
      * apply back_ready_stored9_depth_big. exact Hinner.
      * contradiction.
    + discriminate.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_inv_ready_or_empty_depth_one_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_ready_or_empty_depth 1 a ->
    inv_kcad9_ocaml_ready_or_empty_depth 1 b ->
    inv_kcad9_ocaml_ready_or_empty_depth 1
      (kcad9_concat_absorb_open_back_shape a b).
Proof.
  intros X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [kcad9_concat_absorb_open_back_shape].
  - exact I.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Hb.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Hb.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Ha.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hba Hxba]. destruct Hb as [Hbb Hxbb].
    repeat split; try assumption; left; reflexivity.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hba Hxba].
    destruct Hb as [Hh2 [Hxh2 [Ht2 [Hxt2 [Hfront2 Hback2]]]]].
    repeat split; try assumption.
    + right. apply buf6_push_front_ready_stored9_depth.
      apply front_ready_stored9_depth_small. exact Hh2.
    + right. eapply back_ready_middle9_depth_push_or_ready.
      * apply back_ready_stored9_depth_small. exact Hh2.
      * exact Hback2.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *. exact Ha.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hh1 [Hxh1 [Ht1 [Hxt1 [Hfront1 Hback1]]]]].
    destruct Hb as [Hbb Hxbb].
    repeat split; try assumption.
    + right. eapply front_ready_middle9_depth_inject_or_ready.
      * exact Hfront1.
      * apply front_ready_stored9_depth_small. exact Ht1.
    + right. apply buf6_inject_back_ready_stored9_depth.
      apply back_ready_stored9_depth_small. exact Ht1.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth] in *.
    destruct Ha as [Hh1 [Hxh1 [Ht1 [Hxt1 [Hfront1 Hback1]]]]].
    destruct Hb as [Hh2 [Hxh2 [Ht2 [Hxt2 [Hfront2 Hback2]]]]].
    repeat split; try assumption.
    + destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
      * right. eapply front_ready_middle9_depth_inject_or_ready.
        -- exact Hfront1.
        -- apply kcad9_concat_absorb_open_back_bridge_cell_front_ready_depth.
           exact Ht1.
      * right. eapply front_ready_middle9_depth_inject_or_ready.
        -- exact Hfront1.
        -- apply front_ready_stored9_depth_big. exact Ht1.
    + right.
      destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
      * apply buf6_inject_back_ready_stored9_depth.
        apply kcad9_concat_absorb_open_back_bridge_cell_back_ready_depth_one.
        destruct Hback2 as [Hempty|Hready].
        -- rewrite Hempty in Heject. discriminate.
        -- destruct Hready as (m2_rest' & back_cell' & Heject' & Hback_cell).
           rewrite Heject in Heject'. injection Heject' as Hrest Hcell.
           subst m2_rest' back_cell'. exact Hback_cell.
      * apply buf6_inject_back_ready_stored9_depth.
        apply back_ready_stored9_depth_big. exact Hh2.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_inv_deep_xbase_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_deep_xbase a ->
    inv_kcad9_ocaml_deep_xbase b ->
    inv_kcad9_ocaml_deep_xbase
      (kcad9_concat_absorb_open_back_shape a b).
Proof.
  intros X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [inv_kcad9_ocaml_deep_xbase
         kcad9_concat_absorb_open_back_shape] in *.
  - exact I.
  - exact Hb.
  - exact Hb.
  - exact Ha.
  - repeat split; try assumption.
    apply xbase_middle9_deep_empty.
  - destruct Hb as [Hh2 [Hm2 Ht2]].
    repeat split; try assumption.
    apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
  - exact Ha.
  - destruct Ha as [Hh1 [Hm1 Ht1]].
    repeat split; try assumption.
    apply xbase_middle9_deep_inject; [exact Hm1|exact Ht1].
  - destruct Ha as [Hh1 [Hm1 Ht1]].
    destruct Hb as [Hh2 [Hm2 Ht2]].
    repeat split; try assumption.
    destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct (xbase_middle9_deep_eject X m2 m2_rest back_cell Hm2 Heject)
        as [Hm2_rest Hback_cell].
      apply xbase_middle9_deep_inject; [exact Hm1|].
      eapply kcad9_concat_absorb_open_back_bridge_cell_deep_xbase;
        eassumption.
    + apply xbase_middle9_deep_inject; [exact Hm1|].
      apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_empty.
      * exact Hh2.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_inv_reachable_depth_one_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth 1 a ->
    inv_kcad9_ocaml_reachable_depth 1 b ->
    inv_kcad9_ocaml_reachable_depth 1
      (kcad9_concat_absorb_open_back_shape a b).
Proof.
  intros X a b [Ha_ready Ha_deep] [Hb_ready Hb_deep].
  split.
  - eapply kcad9_concat_absorb_open_back_shape_inv_ready_or_empty_depth_one_thm;
      eassumption.
  - eapply kcad9_concat_absorb_open_back_shape_inv_deep_xbase_thm;
      eassumption.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_continuation_depth_zero_one_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth 0 1 a ->
    inv_kcad9_ocaml_continuation_depth 0 1 b ->
    inv_kcad9_ocaml_continuation_depth 0 1
      (kcad9_concat_absorb_open_back_shape a b).
Proof.
  intros X a b Ha Hb.
  assert (Ha_reach : inv_kcad9_ocaml_reachable_depth 1 a).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Ha. }
  assert (Hb_reach : inv_kcad9_ocaml_reachable_depth 1 b).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hb. }
  set (k := kcad9_concat_absorb_open_back_shape a b).
  assert (Hreach : inv_kcad9_ocaml_reachable_depth 1 k).
  { subst k. eapply kcad9_concat_absorb_open_back_shape_inv_reachable_depth_one_thm;
      eassumption. }
  split; [exact Hreach|].
  destruct Hreach as [Hready _].
  destruct k as [|bk|h m t]; cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
                                     front_refill_continuation_ready_middle9_fuel
                                     back_refill_continuation_ready_middle9_fuel] in *;
    try exact I.
  destruct Hready as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  split.
  - split; [exact Hfront|exact I].
  - split; [exact Hback|exact I].
Qed.

Fixpoint kcad9_concat_absorb_open_back_bridge_cell_fuel {X : Type}
  (fuel : nat) (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
  (back_cell : Stored9 X) {struct fuel} : Stored9 X :=
  match fuel, back_cell with
  | S fuel', StoredMiddle9 sm =>
      match buf6_eject sm with
      | Some (sm_rest, inner_back) =>
          kcad9_concat_absorb_open_back_bridge_cell_fuel fuel'
            t1 h2 (k9_middle_inject m2_rest sm_rest) inner_back
      | None =>
          StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) buf6_empty
      end
  | _, _ =>
      kcad9_concat_absorb_back_bridge_cell t1 h2 m2_rest back_cell
  end.

Lemma kcad9_concat_absorb_open_back_bridge_cell_fuel_seq :
  forall (fuel : nat) (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    stored9_to_list
      (kcad9_concat_absorb_open_back_bridge_cell_fuel
        fuel t1 h2 m2_rest back_cell) =
    kelem9_flat_list (buf6_elems t1) ++
    kelem9_flat_list (buf6_elems h2) ++
    stored9_flat_list (buf6_elems m2_rest) ++
    stored9_to_list back_cell.
Proof.
  induction fuel as [|fuel IH]; intros X t1 h2 m2_rest [b|pre sm suf|sm];
    cbn [kcad9_concat_absorb_open_back_bridge_cell_fuel].
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - apply kcad9_concat_absorb_back_bridge_cell_seq.
  - destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + rewrite IH. rewrite k9_middle_inject_seq.
      assert (Hsm := Heject). apply stored9_flat_list_eject_some in Hsm.
      rewrite stored9_to_list_middle, Hsm.
      rewrite <- !app_assoc. reflexivity.
    + rewrite stored9_to_list_big, stored9_flat_list_push, stored9_to_list_small.
      assert (Hsm := Heject). apply stored9_flat_list_empty_of_eject_none in Hsm.
      rewrite stored9_to_list_middle, Hsm.
      cbn [kelem9_flat_list buf6_elems]. rewrite app_nil_r.
      rewrite app_nil_r. reflexivity.
Qed.

Definition kcad9_concat_absorb_open_back_shape_fuel {X : Type}
  (fuel : nat) (a b : KCadeque9 X) : KCadeque9 X :=
  match a, b with
  | K9Empty, _ => b
  | _, K9Empty => a
  | K9Simple ba, K9Simple bb =>
      K9Triple ba buf6_empty bb
  | K9Simple ba, K9Triple h2 m2 t2 =>
      K9Triple ba (buf6_push (StoredSmall9 h2) m2) t2
  | K9Triple h1 m1 t1, K9Simple bb =>
      K9Triple h1 (buf6_inject m1 (StoredSmall9 t1)) bb
  | K9Triple h1 m1 t1, K9Triple h2 m2 t2 =>
      let m_new :=
        match buf6_eject m2 with
        | Some (m2_rest, back_cell) =>
            buf6_inject m1
              (kcad9_concat_absorb_open_back_bridge_cell_fuel
                fuel t1 h2 m2_rest back_cell)
        | None =>
            let cell := StoredBig9 t1 buf6_empty h2 in
            buf6_inject m1 cell
        end in
      K9Triple h1 m_new t2
  end.

Theorem kcad9_concat_absorb_open_back_shape_fuel_seq_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
    kcad9_to_list (kcad9_concat_absorb_open_back_shape_fuel fuel a b) =
    kcad9_to_list a ++ kcad9_to_list b.
Proof.
  intros fuel X [|ba|h1 m1 t1] [|bb|h2 m2 t2];
    cbn [kcad9_concat_absorb_open_back_shape_fuel].
  - reflexivity.
  - reflexivity.
  - reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_triple, !kcad9_to_list_simple.
    cbn [stored9_flat_list buf6_elems]. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_push. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - cbn [kcad9_to_list]. rewrite app_nil_r. reflexivity.
  - rewrite kcad9_to_list_simple, !kcad9_to_list_triple.
    rewrite stored9_flat_list_inject. rewrite stored9_to_list_small.
    rewrite <- !app_assoc. reflexivity.
  - rewrite !kcad9_to_list_triple.
    destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + assert (Hm2 := Heject). apply stored9_flat_list_eject_some in Hm2.
      rewrite stored9_flat_list_inject.
      rewrite kcad9_concat_absorb_open_back_bridge_cell_fuel_seq.
      rewrite Hm2. rewrite <- !app_assoc. reflexivity.
    + assert (Hm2flat := stored9_flat_list_empty_of_eject_none X m2 Heject).
      rewrite stored9_flat_list_inject. rewrite stored9_to_list_big.
      rewrite Hm2flat. cbn [stored9_flat_list buf6_elems].
      rewrite <- !app_assoc. reflexivity.
Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_fuel_deep_xbase :
  forall (fuel : nat) (X : Type) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (back_cell : Stored9 X),
    all_xbase9 t1 ->
    all_xbase9 h2 ->
    xbase_middle9_deep m2_rest ->
    xbase_stored9_deep back_cell ->
    xbase_stored9_deep
      (kcad9_concat_absorb_open_back_bridge_cell_fuel
        fuel t1 h2 m2_rest back_cell).
Proof.
  induction fuel as [|fuel IH]; intros X t1 h2 m2_rest [b|pre sm suf|sm]
    Ht1 Hh2 Hm2 Hback; cbn [kcad9_concat_absorb_open_back_bridge_cell_fuel] in *.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply kcad9_concat_absorb_back_bridge_cell_deep_xbase; assumption.
  - apply xbase_stored9_deep_middle_iff in Hback.
    destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + destruct (xbase_middle9_deep_eject X sm sm_rest inner_back Hback Heject)
        as [Hsm_rest Hinner].
      apply IH; try assumption.
      apply xbase_middle9_deep_k9_middle_inject; assumption.
    + apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
      * apply all_xbase9_empty.
Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_fuel_front_ready_depth :
  forall (fuel depth : nat) (X : Type)
         (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
         (back_cell : Stored9 X),
