Qed.

Lemma kcad9_concat_absorb_open_back_bridge_cell_fuel_back_ready_depth :
  forall (fuel depth : nat) (X : Type)
         (t1 h2 : Buf6 (KElem9 X)) (m2_rest : Buf6 (Stored9 X))
         (back_cell : Stored9 X),
