Theorem kcad9_concat_absorb_open_back_shape_fuel_continuation_depth_zero_thm :
  forall (depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_continuation_depth 0 depth a ->
    inv_kcad9_ocaml_continuation_depth 0 depth b ->
    inv_kcad9_ocaml_continuation_depth 0 depth
      (kcad9_concat_absorb_open_back_shape_fuel depth a b).
Proof.
  intros depth X a b Ha Hb.
  assert (Ha_reach : inv_kcad9_ocaml_reachable_depth depth a).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Ha. }
  assert (Hb_reach : inv_kcad9_ocaml_reachable_depth depth b).
  { eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hb. }
  set (k := kcad9_concat_absorb_open_back_shape_fuel depth a b).
  assert (Hreach : inv_kcad9_ocaml_reachable_depth depth k).
  { subst k. eapply kcad9_concat_absorb_open_back_shape_fuel_inv_reachable_depth_thm;
      eassumption. }
  split; [exact Hreach|].
  destruct Hreach as [Hready _].
  destruct k as [|bk|h m t]; cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
                                     front_refill_continuation_ready_middle9_fuel
                                     back_refill_continuation_ready_middle9_fuel] in *;
    try exact I.
  destruct Hready as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
  split.
  - split; [exact Hfront|exact I].
  - split; [exact Hback|exact I].
Qed.

