    unfold inv_kcad9_ocaml_open_back_update_const in Hinv;
    pose proof
      (inv_kcad9_ocaml_continuation_depth_reachable_thm 0 1 X _ Hinv)
      as [Hready Hdeep];
    cbn [inv_kcad9_ocaml_boundary_deep inv_kcad9_ocaml_boundaries
         inv_kcad9_ocaml_deep_xbase inv_kcad9_ocaml_ready_or_empty_depth]
      in *.
  - split; exact I.
