Theorem kcad9_pop_ocaml_shape_fuel_two_expected_boundary_deep_under_open_back_update_const_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X) (xs : list X),
    inv_kcad9_ocaml_open_back_update_const k ->
    kcad9_to_list k = x :: xs ->
    exists k',
      kcad9_pop_ocaml_shape_fuel 2 k = Some (x, k') /\
      kcad9_to_list k' = xs /\
      inv_kcad9_ocaml_boundary_deep k'.
Proof.
  intros X k x xs Hinv Hseq_in.
  assert (Hreach : inv_kcad9_ocaml_reachable_depth 1 k).
  { unfold inv_kcad9_ocaml_open_back_update_const in Hinv.
    eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hinv. }
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    discriminate Hseq_in. }
  destruct
    (kcad9_pop_ocaml_shape_fuel_total_under_reachable_depth_thm
       2 1 X k Hreach Hne) as (y & k' & Hpop).
  pose proof
    (kcad9_pop_ocaml_shape_fuel_seq_thm 2 X k y k' Hpop)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  injection Hseq_out as Hy Htail.
  subst y. exists k'.
  split; [exact Hpop|].
  split; [symmetry; exact Htail|].
  eapply kcad9_pop_ocaml_shape_fuel_boundary_deep_under_reachable_depth_thm;
    eassumption.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_two_expected_boundary_deep_under_open_back_update_const_thm :
  forall (X : Type) (k : KCadeque9 X) (xs : list X) (x : X),
    inv_kcad9_ocaml_open_back_update_const k ->
    kcad9_to_list k = xs ++ [x] ->
    exists k',
      kcad9_eject_ocaml_shape_fuel 2 k = Some (k', x) /\
      kcad9_to_list k' = xs /\
      inv_kcad9_ocaml_boundary_deep k'.
Proof.
  intros X k xs x Hinv Hseq_in.
  assert (Hreach : inv_kcad9_ocaml_reachable_depth 1 k).
  { unfold inv_kcad9_ocaml_open_back_update_const in Hinv.
    eapply inv_kcad9_ocaml_continuation_depth_reachable_thm; exact Hinv. }
  assert (Hne : k <> K9Empty).
  { intros Hempty.
    rewrite Hempty in Hseq_in. rewrite empty_to_list9 in Hseq_in.
    destruct xs as [|xh xs]; discriminate Hseq_in. }
  destruct
    (kcad9_eject_ocaml_shape_fuel_total_under_reachable_depth_thm
       2 1 X k Hreach Hne) as (k' & y & Heject).
  pose proof
    (kcad9_eject_ocaml_shape_fuel_seq_thm 2 X k k' y Heject)
    as Hseq_out.
  rewrite Hseq_in in Hseq_out.
  destruct (app_singleton_inj X xs (kcad9_to_list k') x y Hseq_out)
    as [Htail Hy].
  subst y. exists k'.
  split; [exact Heject|].
  split; [symmetry; exact Htail|].
  eapply kcad9_eject_ocaml_shape_fuel_boundary_deep_under_reachable_depth_thm;
    eassumption.
Qed.

