Theorem kcad9_endpoint_script_expected_fuel_two_under_open_back_reusable_const_thm :
  forall (X : Type) (k : KCadeque9 X) (xs : list X)
         (ops : list KCad9EndpointSide) (xs_final : list X),
    inv_kcad9_ocaml_open_back_reusable_const k ->
    kcad9_to_list k = xs ->
    kcad9_endpoint_script_model xs ops = Some xs_final ->
    exists k_final,
      kcad9_endpoint_script_expected 2 k xs ops k_final xs_final /\
      kcad9_to_list k_final = xs_final /\
      inv_kcad9_ocaml_open_back_reusable_const k_final.
Proof.
  intros X k xs ops.
  revert k xs.
  induction ops as [|op ops IH]; intros k xs xs_final Hinv Hseq Hmodel.
  - cbn [kcad9_endpoint_script_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists k. split; [split; reflexivity|].
    split; [exact Hseq|exact Hinv].
  - destruct op.
    + destruct xs as [|x xs']; [discriminate|].
      cbn [kcad9_endpoint_script_model] in Hmodel.
      destruct
        (kcad9_pop_ocaml_shape_fuel_two_expected_under_open_back_reusable_const_thm
           X k x xs' Hinv Hseq)
        as (k1 & Hpop & Hseq1 & Hinv1).
      destruct (IH k1 xs' xs_final Hinv1 Hseq1 Hmodel)
        as (k_final & Hscript & Hseq_final & Hinv_final).
      exists k_final.
      split.
      * cbn [kcad9_endpoint_script_expected].
        exists k1. split; [exact Hpop|exact Hscript].
      * split; [exact Hseq_final|exact Hinv_final].
    + destruct (list_unsnoc xs) as [[xs' x]|] eqn:Hunsnoc.
      * cbn [kcad9_endpoint_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel.
        assert (Hseq_eject : kcad9_to_list k = xs' ++ [x]).
        { rewrite Hseq. apply list_unsnoc_some_app. exact Hunsnoc. }
        destruct
          (kcad9_eject_ocaml_shape_fuel_two_expected_under_open_back_reusable_const_thm
             X k xs' x Hinv Hseq_eject)
          as (k1 & Heject & Hseq1 & Hinv1).
        destruct (IH k1 xs' xs_final Hinv1 Hseq1 Hmodel)
          as (k_final & Hscript & Hseq_final & Hinv_final).
        exists k_final.
        split.
        -- cbn [kcad9_endpoint_script_expected].
           rewrite Hunsnoc.
           exists k1. split; [exact Heject|exact Hscript].
        -- split; [exact Hseq_final|exact Hinv_final].
      * cbn [kcad9_endpoint_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel. discriminate.
Qed.

Theorem kcad9_endpoint_script_expected_fuel_two_under_open_back_reusable_const_refill_depth_one_thm :
  forall (X : Type) (k : KCadeque9 X) (xs : list X)
         (ops : list KCad9EndpointSide) (xs_final : list X),
    inv_kcad9_ocaml_open_back_reusable_const k ->
    inv_kcad9_ocaml_refill_depth_bound 1 k ->
    kcad9_to_list k = xs ->
    kcad9_endpoint_script_model xs ops = Some xs_final ->
    exists k_final,
      kcad9_endpoint_script_expected 2 k xs ops k_final xs_final /\
      kcad9_to_list k_final = xs_final /\
      inv_kcad9_ocaml_open_back_reusable_const k_final /\
      inv_kcad9_ocaml_refill_depth_bound 1 k_final /\
      inv_kcad9_ocaml_middle_depth_bound 1 k_final.
Proof.
  intros X k xs ops xs_final Hreusable Hrefill Hseq Hmodel.
  destruct
    (kcad9_endpoint_script_expected_fuel_two_under_open_back_reusable_const_thm
       X k xs ops xs_final Hreusable Hseq Hmodel)
    as (k_final & Hscript & Hseq_final & Hreusable_final).
  assert (Hrefill_final :
    inv_kcad9_ocaml_refill_depth_bound 1 k_final).
  { eapply kcad9_endpoint_script_expected_refill_depth_bound_thm;
      eassumption. }
  exists k_final.
  split; [exact Hscript|].
  split; [exact Hseq_final|].
  split; [exact Hreusable_final|].
  split; [exact Hrefill_final|].
  apply inv_kcad9_ocaml_refill_depth_bound_middle_depth_bound_thm.
  exact Hrefill_final.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_open_back_reusable_const_thm :
  forall (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 : Buf6 (KElem9 X)) (m2 : Buf6 (Stored9 X))
         (t2 : Buf6 (KElem9 X)),
    buf6_size_ge 1 h1 ->
    all_xbase9 h1 ->
    middle9_small_nonempty m1 ->
    xbase_middle9_deep m1 ->
    buf6_size_ge 1 t1 ->
    all_xbase9 t1 ->
    buf6_size_ge 1 h2 ->
    all_xbase9 h2 ->
    middle9_small_nonempty m2 ->
    xbase_middle9_deep m2 ->
    buf6_size_ge 1 t2 ->
    all_xbase9 t2 ->
    kcad9_to_list
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (K9Triple h1 m1 t1) (K9Triple h2 m2 t2)) =
      kcad9_to_list (K9Triple h1 m1 t1) ++
      kcad9_to_list (K9Triple h2 m2 t2) /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (K9Triple h1 m1 t1) (K9Triple h2 m2 t2)).
Proof.
  intros X h1 m1 t1 h2 m2 t2
    Hh1 Hxh1 Hm1 Hxm1 Ht1 Hxt1 Hh2 Hxh2 Hm2 Hxm2 Ht2 Hxt2.
  split.
  - apply kcad9_concat_absorb_open_back_shape_fuel_one_seq_thm.
  - intros fuel.
    assert (Ha : inv_kcad9_ocaml_reachable_depth 1 (K9Triple h1 m1 t1)).
    { split.
      - cbn [inv_kcad9_ocaml_ready_or_empty_depth].
        repeat split; try assumption.
        + apply front_ready_or_empty_middle9_depth_small_nonempty. exact Hm1.
        + apply back_ready_or_empty_middle9_depth_small_nonempty. exact Hm1.
      - cbn [inv_kcad9_ocaml_deep_xbase].
        repeat split; assumption. }
    assert (Hb : inv_kcad9_ocaml_reachable_depth 1 (K9Triple h2 m2 t2)).
    { split.
      - cbn [inv_kcad9_ocaml_ready_or_empty_depth].
        repeat split; try assumption.
        + apply front_ready_or_empty_middle9_depth_small_nonempty. exact Hm2.
        + apply back_ready_or_empty_middle9_depth_small_nonempty. exact Hm2.
      - cbn [inv_kcad9_ocaml_deep_xbase].
        repeat split; assumption. }
    split.
    + eapply kcad9_concat_absorb_open_back_shape_fuel_inv_reachable_depth_thm;
        eassumption.
    + cbn [kcad9_concat_absorb_open_back_shape_fuel
           kcad9_ocaml_refill_continuation_ready_fuel_depth].
      destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
      * destruct (middle9_small_nonempty_eject X m2 m2_rest back_cell
                    Heject Hm2) as [Hm2_rest Hback_cell].
        destruct back_cell as [b|pre sm suf|sm];
          cbn [stored9_small_nonempty] in Hback_cell; try contradiction.
        split.
        -- apply front_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
           ++ exact Hm1.
           ++ exact Ht1.
           ++ apply middle9_small_nonempty_push_small; assumption.
           ++ exact Hback_cell.
        -- apply back_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
           ++ exact Hm1.
           ++ exact Ht1.
           ++ apply middle9_small_nonempty_push_small; assumption.
           ++ exact Hback_cell.
      * split.
        -- apply front_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
           ++ exact Hm1.
           ++ exact Ht1.
           ++ cbn [middle9_small_nonempty buf6_empty buf6_elems]. constructor.
           ++ exact Hh2.
        -- apply back_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
           ++ exact Hm1.
           ++ exact Ht1.
           ++ cbn [middle9_small_nonempty buf6_empty buf6_elems]. constructor.
           ++ exact Hh2.
Qed.

Theorem kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm :
  forall (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth 1 k ->
    kcad9_ocaml_middle_small_nonempty k ->
    inv_kcad9_ocaml_open_back_reusable_const k.
Proof.
  intros X [|b|h m t] Hreach Hsmall fuel.
  - apply empty_kcad9_ocaml_continuation_depth_thm.
  - split; [exact Hreach|exact I].
  - split; [exact Hreach|].
    cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
         kcad9_ocaml_middle_small_nonempty] in Hsmall.
    split.
    + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
      exact Hsmall.
    + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
      exact Hsmall.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_public_open_back_reusable_const_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth 1 a ->
    inv_kcad9_ocaml_reachable_depth 1 b ->
    kcad9_ocaml_middle_small_nonempty a ->
    kcad9_ocaml_middle_small_nonempty b ->
    kcad9_to_list
      (kcad9_concat_absorb_open_back_shape_fuel 1 a b) =
      kcad9_to_list a ++ kcad9_to_list b /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_absorb_open_back_shape_fuel 1 a b).
Proof.
  intros X a b Ha Hb Hsmall_a Hsmall_b.
  split.
  - apply kcad9_concat_absorb_open_back_shape_fuel_one_seq_thm.
  - destruct a as [|ba|h1 m1 t1]; destruct b as [|bb|h2 m2 t2].
    + exact (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
        X K9Empty Hb I).
    + exact (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
        X (K9Simple bb) Hb I).
    + exact (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
        X (K9Triple h2 m2 t2) Hb Hsmall_b).
    + exact (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
        X (K9Simple ba) Ha I).
    + assert (Hres :
        inv_kcad9_ocaml_reachable_depth 1
          (kcad9_concat_absorb_open_back_shape_fuel
             1 (K9Simple ba) (K9Simple bb))).
      { eapply kcad9_concat_absorb_open_back_shape_fuel_inv_reachable_depth_thm;
          eassumption. }
      eapply kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm.
      * exact Hres.
      * cbn [kcad9_concat_absorb_open_back_shape_fuel
             kcad9_ocaml_middle_small_nonempty
             middle9_small_nonempty buf6_empty buf6_elems].
        constructor.
    + assert (Hres :
        inv_kcad9_ocaml_reachable_depth 1
          (kcad9_concat_absorb_open_back_shape_fuel
             1 (K9Simple ba) (K9Triple h2 m2 t2))).
      { eapply kcad9_concat_absorb_open_back_shape_fuel_inv_reachable_depth_thm;
          eassumption. }
      cbn [inv_kcad9_ocaml_reachable_depth inv_kcad9_ocaml_ready_or_empty_depth]
        in Hb.
      destruct Hb as [[Hh2 _] _].
      eapply kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm.
      * exact Hres.
      * cbn [kcad9_concat_absorb_open_back_shape_fuel
             kcad9_ocaml_middle_small_nonempty].
        apply middle9_small_nonempty_push_small; [exact Hh2|exact Hsmall_b].
    + exact (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
        X (K9Triple h1 m1 t1) Ha Hsmall_a).
    + assert (Hres :
        inv_kcad9_ocaml_reachable_depth 1
          (kcad9_concat_absorb_open_back_shape_fuel
             1 (K9Triple h1 m1 t1) (K9Simple bb))).
      { eapply kcad9_concat_absorb_open_back_shape_fuel_inv_reachable_depth_thm;
          eassumption. }
      cbn [inv_kcad9_ocaml_reachable_depth inv_kcad9_ocaml_ready_or_empty_depth]
        in Ha.
      destruct Ha as [[_ [_ [Ht1 _]]] _].
      eapply kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm.
      * exact Hres.
      * cbn [kcad9_concat_absorb_open_back_shape_fuel
             kcad9_ocaml_middle_small_nonempty].
        apply middle9_small_nonempty_inject_small; [exact Hsmall_a|exact Ht1].
    + cbn [inv_kcad9_ocaml_reachable_depth inv_kcad9_ocaml_ready_or_empty_depth
           inv_kcad9_ocaml_deep_xbase kcad9_ocaml_middle_small_nonempty] in *.
      destruct Ha as [Hready_a Hdeep_a].
      destruct Hready_a as [Hh1 [Hxh1 [Ht1 [Hxt1 _]]]].
      destruct Hdeep_a as [Hh1_deep [Hm1_deep Ht1_deep]].
      destruct Hb as [Hready_b Hdeep_b].
      destruct Hready_b as [Hh2 [Hxh2 [Ht2 [Hxt2 _]]]].
      destruct Hdeep_b as [Hh2_deep [Hm2_deep Ht2_deep]].
      eapply kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_open_back_reusable_const_thm;
        eassumption.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_fuel_one_left_fold_singletons_open_back_reusable_const_thm :
  forall (X : Type) (xs ys : list X),
    kcad9_to_list
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton ys))) =
      xs ++ ys /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton ys))).
Proof.
  intros X xs ys.
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm
       X xs) as [Hreach_xs Hseq_xs].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm
       X ys) as [Hreach_ys Hseq_ys].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
       X (@kcad9_empty X) xs I I) as [_ Hsmall_xs].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
       X (@kcad9_empty X) ys I I) as [_ Hsmall_ys].
  destruct
    (kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_public_open_back_reusable_const_thm
       X
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))
       (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton ys))
       Hreach_xs Hreach_ys Hsmall_xs Hsmall_ys)
    as [Hseq Hinv].
  split.
  - rewrite Hseq. rewrite Hseq_xs, Hseq_ys. reflexivity.
  - exact Hinv.
Qed.

