Lemma kcad9_concat_ocaml_full_split_open_back_middle_fuel_tail_boundary :
  forall (fuel : nat) (X : Type)
         (m1 : Buf6 (Stored9 X)) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (t2 : Buf6 (KElem9 X))
         (back_cell : Stored9 X),
    buf6_size_ge 1 t2 ->
    let '(_, t_new) :=
      kcad9_concat_ocaml_full_split_open_back_middle_fuel
        fuel m1 t1 h2 m2_rest t2 back_cell in
    buf6_size_ge 1 t_new.
Proof.
  induction fuel as [|fuel IH]; intros X m1 t1 h2 m2_rest t2
    [b|pre sm suf|sm] Ht2;
    cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
         kcad9_concat_ocaml_full_split_open_back_base] in *.
  - exact Ht2.
  - apply buf6_size_ge_concat_r. exact Ht2.
  - exact Ht2.
  - exact Ht2.
  - apply buf6_size_ge_concat_r. exact Ht2.
  - destruct (buf6_eject sm) as [[sm_rest inner_back]|].
    + apply IH. exact Ht2.
    + exact Ht2.
Qed.

