Lemma kcad9_concat_ocaml_full_split_open_back_middle_fuel_deep_xbase :
  forall (fuel : nat) (X : Type)
         (m1 : Buf6 (Stored9 X)) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (t2 : Buf6 (KElem9 X))
         (back_cell : Stored9 X),
    xbase_middle9_deep m1 ->
    all_xbase9 t1 ->
    all_xbase9 h2 ->
    xbase_middle9_deep m2_rest ->
    all_xbase9 t2 ->
    xbase_stored9_deep back_cell ->
    let '(m_new, t_new) :=
      kcad9_concat_ocaml_full_split_open_back_middle_fuel
        fuel m1 t1 h2 m2_rest t2 back_cell in
    xbase_middle9_deep m_new /\ all_xbase9 t_new.
Proof.
  induction fuel as [|fuel IH]; intros X m1 t1 h2 m2_rest t2
    [b|pre sm suf|sm] Hm1 Ht1 Hh2 Hm2 Ht2 Hback;
    cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
         kcad9_concat_ocaml_full_split_open_back_base] in *.
  - split.
    + apply xbase_middle9_deep_inject; [exact Hm1|].
      apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
      * exact Hback.
    + exact Ht2.
  - apply xbase_stored9_deep_big_iff in Hback.
    destruct Hback as [Hpre [Hsuf Hsm]].
    split.
    + apply xbase_middle9_deep_concat.
      * apply xbase_middle9_deep_inject.
        -- apply xbase_middle9_deep_inject; [exact Hm1|].
           apply xbase_stored9_deep_big.
           ++ exact Ht1.
           ++ apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
           ++ apply all_xbase9_empty.
        -- exact Hpre.
      * exact Hsm.
    + apply all_xbase9_concat; assumption.
  - apply xbase_stored9_deep_middle_iff in Hback.
    split.
    + apply xbase_middle9_deep_inject.
      * apply xbase_middle9_deep_inject; [exact Hm1|].
        apply xbase_stored9_deep_big.
        -- exact Ht1.
        -- apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
        -- apply all_xbase9_empty.
      * apply xbase_stored9_deep_middle. exact Hback.
    + exact Ht2.
  - split.
    + apply xbase_middle9_deep_inject; [exact Hm1|].
      apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
      * exact Hback.
    + exact Ht2.
  - apply xbase_stored9_deep_big_iff in Hback.
    destruct Hback as [Hpre [Hsuf Hsm]].
    split.
    + apply xbase_middle9_deep_concat.
      * apply xbase_middle9_deep_inject.
        -- apply xbase_middle9_deep_inject; [exact Hm1|].
           apply xbase_stored9_deep_big.
           ++ exact Ht1.
           ++ apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
           ++ apply all_xbase9_empty.
        -- exact Hpre.
      * exact Hsm.
    + apply all_xbase9_concat; assumption.
  - apply xbase_stored9_deep_middle_iff in Hback.
    destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + destruct (xbase_middle9_deep_eject X sm sm_rest inner_back Hback Heject)
        as [Hsm_rest Hinner_back].
      eapply IH; try eassumption.
      apply xbase_middle9_deep_k9_middle_inject; assumption.
    + split.
      * apply xbase_middle9_deep_inject; [exact Hm1|].
        apply xbase_stored9_deep_big.
        -- exact Ht1.
        -- apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
        -- apply all_xbase9_empty.
      * exact Ht2.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_inv_boundaries_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_boundaries a ->
    inv_kcad9_ocaml_boundaries b ->
    inv_kcad9_ocaml_boundaries
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel fuel a b).
Proof.
  intros fuel X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
         inv_kcad9_ocaml_boundaries] in *.
  - exact I.
  - exact Hb.
  - exact Hb.
  - exact Ha.
  - split; assumption.
  - destruct Hb as [_ Ht2]. split; assumption.
  - exact Ha.
  - destruct Ha as [Hh1 _]. split; assumption.
  - destruct Ha as [Hh1 _]. destruct Hb as [_ Ht2].
    destruct (buf6_eject m2) as [[m2_rest back_cell]|].
    + pose proof
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel_tail_boundary
           fuel X m1 t1 h2 m2_rest t2 back_cell Ht2) as Htail.
      destruct
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel
          fuel m1 t1 h2 m2_rest t2 back_cell)
        as [m_new t_new].
      split; [exact Hh1|exact Htail].
    + split; assumption.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_inv_deep_xbase_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_deep_xbase a ->
    inv_kcad9_ocaml_deep_xbase b ->
    inv_kcad9_ocaml_deep_xbase
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel fuel a b).
Proof.
  intros fuel X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
         inv_kcad9_ocaml_deep_xbase] in *.
  - exact I.
  - exact Hb.
  - exact Hb.
  - exact Ha.
  - repeat split; try assumption.
    apply xbase_middle9_deep_empty.
  - destruct Hb as [Hh2 [Hm2 Ht2]].
    repeat split; try assumption.
    apply xbase_middle9_deep_push; [exact Hh2|exact Hm2].
  - exact Ha.
  - destruct Ha as [Hh1 [Hm1 Ht1]].
    repeat split; try assumption.
    apply xbase_middle9_deep_inject; [exact Hm1|exact Ht1].
  - destruct Ha as [Hh1 [Hm1 Ht1]].
    destruct Hb as [Hh2 [Hm2 Ht2]].
    destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct (xbase_middle9_deep_eject X m2 m2_rest back_cell Hm2 Heject)
        as [Hm2_rest Hback_cell].
      pose proof
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel_deep_xbase
           fuel X m1 t1 h2 m2_rest t2 back_cell
           Hm1 Ht1 Hh2 Hm2_rest Ht2 Hback_cell) as Hout.
      destruct
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel
          fuel m1 t1 h2 m2_rest t2 back_cell)
        as [m_new t_new].
      destruct Hout as [Hm_new Ht_new].
      cbn [inv_kcad9_ocaml_deep_xbase].
      repeat split; assumption.
    + repeat split; try assumption.
      apply xbase_middle9_deep_inject; [exact Hm1|].
      apply xbase_stored9_deep_big.
      * exact Ht1.
      * apply xbase_middle9_deep_empty.
      * exact Hh2.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
