Theorem kcad9_pop_ocaml_shape_fuel_two_expected_under_full_split_boundary_deep_concat_thm :
  forall (concat_fuel : nat) (X : Type) (a b : KCadeque9 X)
         (x : X) (xs : list X),
    inv_kcad9_ocaml_boundary_deep a ->
    inv_kcad9_ocaml_boundary_deep b ->
    kcad9_to_list a ++ kcad9_to_list b = x :: xs ->
    exists k',
      kcad9_pop_ocaml_shape_fuel 2
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel concat_fuel a b) =
      Some (x, k') /\
      kcad9_to_list k' = xs.
Proof.
  intros concat_fuel X a b x xs Ha Hb Hseq.
  pose proof
    (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
       concat_fuel X a b Ha Hb) as Hboundary.
  apply kcad9_pop_ocaml_shape_fuel_expected_under_boundary_deep_seq_thm
    with
      (k := kcad9_concat_ocaml_full_split_open_back_shape_fuel
              concat_fuel a b).
  - exact Hboundary.
  - rewrite kcad9_concat_ocaml_full_split_open_back_shape_fuel_seq_thm.
    exact Hseq.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_two_expected_under_full_split_boundary_deep_concat_thm :
  forall (concat_fuel : nat) (X : Type) (a b : KCadeque9 X)
