    exists k',
      kcad9_eject_ocaml_shape_fuel 2
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel concat_fuel a b) =
      Some (k', x) /\
      kcad9_to_list k' = xs.
Proof.
  intros concat_fuel X a b xs x Ha Hb Hseq.
  pose proof
    (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
       concat_fuel X a b Ha Hb) as Hboundary.
  apply kcad9_eject_ocaml_shape_fuel_expected_under_boundary_deep_seq_thm
    with
