Theorem kcad9_pop_ocaml_shape_fuel_two_full_split_left_const_not_full_split_left_const_counterexample_thm :
  exists k k' : KCadeque9 nat,
    inv_kcad9_ocaml_full_split_left_const k /\
    kcad9_to_list k = [0; 1] /\
    kcad9_pop_ocaml_shape_fuel 2 k = Some (0, k') /\
    kcad9_to_list k' = [1] /\
    ~ inv_kcad9_ocaml_full_split_left_const k'.
Proof.
  destruct
    kcad9_pop_ocaml_shape_fuel_two_boundary_deep_left_not_boundary_deep_counterexample_thm
    as (k & k' & Hboundary & Hleft & Hseq & Hpop & Hseq' & Hnot_boundary).
  exists k, k'.
  split.
  - split; [exact Hboundary|].
    unfold inv_kcad9_ocaml_refill_concat_left_depth in Hleft.
    exact Hleft.
  - split; [exact Hseq|].
    split; [exact Hpop|].
    split; [exact Hseq'|].
    intros [Hboundary' _].
    exact (Hnot_boundary Hboundary').
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_two_full_split_left_const_not_full_split_left_const_counterexample_thm :
  exists k k' : KCadeque9 nat,
    inv_kcad9_ocaml_full_split_left_const k /\
    kcad9_to_list k = [0; 1] /\
    kcad9_eject_ocaml_shape_fuel 2 k = Some (k', 1) /\
