Proof.
  destruct
    kcad9_eject_ocaml_shape_fuel_two_boundary_deep_left_not_boundary_deep_counterexample_thm
    as (k & k' & Hboundary & Hleft & Hseq & Heject & Hseq' & Hnot_boundary).
  exists k, k'.
  split.
  - split; [exact Hboundary|].
    unfold inv_kcad9_ocaml_refill_concat_left_depth in Hleft.
    exact Hleft.
  - split; [exact Hseq|].
    split; [exact Heject|].
    split; [exact Hseq'|].
    intros [Hboundary' _].
    exact (Hnot_boundary Hboundary').
Qed.

