Fixpoint stored9_full_split_suffix_empty {X : Type}
  (s : Stored9 X) {struct s} : Prop :=
  match s with
  | StoredSmall9 _ =>
      True
  | StoredBig9 _ sm suf =>
      (fix go (l : list (Stored9 X)) : Prop :=
         match l with
         | [] => True
         | s' :: ss => stored9_full_split_suffix_empty s' /\ go ss
         end) (buf6_elems sm) /\
      buf6_is_empty suf = true
  | StoredMiddle9 sm =>
      (fix go (l : list (Stored9 X)) : Prop :=
         match l with
         | [] => True
         | s' :: ss => stored9_full_split_suffix_empty s' /\ go ss
         end) (buf6_elems sm)
  end.

Definition middle9_full_split_suffix_empty {X : Type}
  (m : Buf6 (Stored9 X)) : Prop :=
  (fix go (l : list (Stored9 X)) : Prop :=
     match l with
     | [] => True
     | s :: ss => stored9_full_split_suffix_empty s /\ go ss
     end) (buf6_elems m).

Definition inv_kcad9_ocaml_full_split_suffix_empty {X : Type}
  (k : KCadeque9 X) : Prop :=
  match k with
  | K9Empty => True
  | K9Simple _ => True
  | K9Triple _ m _ => middle9_full_split_suffix_empty m
  end.

Lemma middle9_full_split_suffix_empty_empty :
  forall X : Type,
    middle9_full_split_suffix_empty (@buf6_empty (Stored9 X)).
Proof.
  intros X.
  unfold middle9_full_split_suffix_empty, buf6_empty, buf6_elems.
  exact I.
Qed.

Lemma middle9_full_split_suffix_empty_inject :
  forall (X : Type) (m : Buf6 (Stored9 X)) (s : Stored9 X),
    middle9_full_split_suffix_empty m ->
    stored9_full_split_suffix_empty s ->
    middle9_full_split_suffix_empty (buf6_inject m s).
Proof.
  intros X [xs] s Hm Hs.
  unfold middle9_full_split_suffix_empty, buf6_inject, buf6_elems in *.
  induction xs as [|cell rest IH]; cbn in *.
  - split; [exact Hs|exact I].
  - destruct Hm as [Hcell Hrest].
    split; [exact Hcell|].
    apply IH. exact Hrest.
Qed.

Lemma middle9_full_split_suffix_empty_eject :
  forall (X : Type) (m m_rest : Buf6 (Stored9 X)) (s : Stored9 X),
    middle9_full_split_suffix_empty m ->
    buf6_eject m = Some (m_rest, s) ->
    middle9_full_split_suffix_empty m_rest /\
    stored9_full_split_suffix_empty s.
Proof.
  intros X [xs] m_rest s Hm Heject.
  unfold middle9_full_split_suffix_empty, buf6_eject, buf6_elems in *.
  destruct (rev xs) as [|last rev_rest] eqn:Hrev; [discriminate|].
  injection Heject as Hrest Hlast. subst m_rest s.
  apply (f_equal (@rev (Stored9 X))) in Hrev.
  rewrite rev_involutive in Hrev.
  cbn in Hrev. rewrite Hrev in Hm.
  unfold middle9_full_split_suffix_empty, buf6_elems.
  set (ys := rev rev_rest) in *.
  clearbody ys. clear xs rev_rest Hrev.
  induction ys as [|cell rest IH]; cbn in Hm.
  - destruct Hm as [Hlast _].
    split; [exact I|exact Hlast].
  - destruct Hm as [Hcell Hrest].
    destruct (IH Hrest) as [Hrest_mid Hlast].
    split.
    + cbn. split; assumption.
    + exact Hlast.
Qed.

Lemma buf6_concat_empty_r :
  forall (X : Type) (b : Buf6 X),
    buf6_concat b buf6_empty = b.
Proof.
  intros X [xs].
  unfold buf6_concat, buf6_empty, buf6_elems.
  rewrite app_nil_r. reflexivity.
Qed.

Lemma buf6_concat_empty_l :
  forall (X : Type) (b : Buf6 X),
    buf6_concat buf6_empty b = b.
Proof.
  intros X [xs].
  unfold buf6_concat, buf6_empty, buf6_elems.
  reflexivity.
Qed.

Definition kcad9_concat_ocaml_full_split_open_back_zero_splice_base {X : Type}
  (m1 : Buf6 (Stored9 X)) (t1 h2 : Buf6 (KElem9 X))
  (m2_rest : Buf6 (Stored9 X)) (t2 : Buf6 (KElem9 X))
  (back_cell : Stored9 X) : Buf6 (Stored9 X) * Buf6 (KElem9 X) :=
  match back_cell with
  | StoredSmall9 b =>
      let cell := StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) b in
      (buf6_inject m1 cell, t2)
  | StoredMiddle9 sm =>
      let cell :=
        StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) buf6_empty in
      (buf6_inject (buf6_inject m1 cell) (StoredMiddle9 sm), t2)
  | StoredBig9 pre _ _ =>
      let bridge :=
        StoredBig9 t1 (buf6_push (StoredSmall9 h2) m2_rest) buf6_empty in
      (buf6_inject (buf6_inject m1 bridge) (StoredSmall9 pre), t2)
  end.

Definition kcad9_concat_ocaml_full_split_open_back_zero_splice_shape {X : Type}
  (a b : KCadeque9 X) : KCadeque9 X :=
  match a, b with
  | K9Empty, _ => b
  | _, K9Empty => a
  | K9Simple ba, K9Simple bb =>
      K9Triple ba buf6_empty bb
  | K9Simple ba, K9Triple h2 m2 t2 =>
      K9Triple ba (buf6_push (StoredSmall9 h2) m2) t2
  | K9Triple h1 m1 t1, K9Simple bb =>
      K9Triple h1 (buf6_inject m1 (StoredSmall9 t1)) bb
  | K9Triple h1 m1 t1, K9Triple h2 m2 t2 =>
      match buf6_eject m2 with
      | Some (m2_rest, back_cell) =>
          let '(m_new, t_new) :=
            kcad9_concat_ocaml_full_split_open_back_zero_splice_base
              m1 t1 h2 m2_rest t2 back_cell in
          K9Triple h1 m_new t_new
      | None =>
          let cell := StoredBig9 t1 buf6_empty h2 in
          K9Triple h1 (buf6_inject m1 cell) t2
      end
  end.

Lemma kcad9_concat_ocaml_full_split_open_back_base_zero_splice_eq :
  forall (X : Type) (m1 : Buf6 (Stored9 X))
         (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (t2 : Buf6 (KElem9 X))
         (back_cell : Stored9 X),
    stored_refill_depth_le 0 back_cell ->
    stored9_full_split_suffix_empty back_cell ->
    kcad9_concat_ocaml_full_split_open_back_base
      m1 t1 h2 m2_rest t2 back_cell =
    kcad9_concat_ocaml_full_split_open_back_zero_splice_base
      m1 t1 h2 m2_rest t2 back_cell.
Proof.
  intros X m1 t1 h2 m2_rest t2 [b|pre sm suf|sm] Hdepth Hsuffix;
    cbn [kcad9_concat_ocaml_full_split_open_back_base
         kcad9_concat_ocaml_full_split_open_back_zero_splice_base
         stored_refill_depth_le stored9_full_split_suffix_empty] in *.
  - reflexivity.
  - destruct Hsuffix as [_ Hsuf].
    apply buf6_eq_empty_of_is_empty in Hdepth.
    apply buf6_eq_empty_of_is_empty in Hsuf.
    subst sm suf.
    rewrite buf6_concat_empty_r, buf6_concat_empty_l.
    reflexivity.
  - contradiction.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_zero_splice_eq_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound 0 b ->
    inv_kcad9_ocaml_full_split_suffix_empty b ->
    kcad9_concat_ocaml_full_split_open_back_shape_fuel fuel a b =
    kcad9_concat_ocaml_full_split_open_back_zero_splice_shape a b.
Proof.
  intros fuel X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Hdepth Hsuffix;
    cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
         kcad9_concat_ocaml_full_split_open_back_zero_splice_shape
         inv_kcad9_ocaml_refill_depth_bound
         inv_kcad9_ocaml_full_split_suffix_empty] in *;
    try reflexivity.
  destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject;
    [|reflexivity].
  destruct
    (middle9_refill_depth_le_eject 0 X m2 m2_rest back_cell
       Hdepth Heject) as [Hm2_rest Hback_depth].
  destruct
    (middle9_full_split_suffix_empty_eject X m2 m2_rest back_cell
       Hsuffix Heject) as [Hm2_rest_suffix Hback_suffix].
  destruct back_cell as [b|pre sm suf|sm];
    cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
         kcad9_concat_ocaml_full_split_open_back_base
         kcad9_concat_ocaml_full_split_open_back_zero_splice_base
         stored_refill_depth_le stored9_full_split_suffix_empty] in *.
  - destruct fuel; reflexivity.
  - destruct Hback_suffix as [_ Hsuf].
    apply buf6_eq_empty_of_is_empty in Hback_depth.
    apply buf6_eq_empty_of_is_empty in Hsuf.
    subst sm suf.
    destruct fuel;
      cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
           kcad9_concat_ocaml_full_split_open_back_base
           kcad9_concat_ocaml_full_split_open_back_zero_splice_base].
    + rewrite buf6_concat_empty_r, buf6_concat_empty_l.
      reflexivity.
    + rewrite buf6_concat_empty_r, buf6_concat_empty_l.
      reflexivity.
  - contradiction.
Qed.

Theorem empty_kcad9_ocaml_full_split_suffix_empty_thm :
  forall X : Type,
    inv_kcad9_ocaml_full_split_suffix_empty (@kcad9_empty X).
Proof. intros X. exact I. Qed.

