Theorem kcad9_concat_ocaml_shape_singleton_right_full_split_suffix_empty_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_full_split_suffix_empty k ->
    inv_kcad9_ocaml_full_split_suffix_empty
      (kcad9_concat_ocaml_shape k (kcad9_singleton x)).
Proof.
  intros X [|b|h m t] x Hsuffix;
    cbn [kcad9_concat_ocaml_shape kcad9_singleton
         inv_kcad9_ocaml_full_split_suffix_empty] in *.
  - exact I.
  - apply middle9_full_split_suffix_empty_empty.
  - apply middle9_full_split_suffix_empty_inject;
      [exact Hsuffix|exact I].
Qed.

Lemma kcad9_concat_ocaml_shape_left_fold_singletons_full_split_suffix_empty_from_suffix :
  forall (X : Type) (acc : KCadeque9 X) (xs : list X),
    inv_kcad9_ocaml_full_split_suffix_empty acc ->
    inv_kcad9_ocaml_full_split_suffix_empty
      (kcad9_concat_ocaml_shape_left_fold
        acc (map kcad9_singleton xs)).
Proof.
  intros X acc xs.
  revert acc.
  induction xs as [|x xs IH]; intros acc Hsuffix.
  - exact Hsuffix.
  - cbn [map kcad9_concat_ocaml_shape_left_fold].
    apply IH.
    apply kcad9_concat_ocaml_shape_singleton_right_full_split_suffix_empty_thm.
    exact Hsuffix.
Qed.

Lemma middle9_depth_le_concat :
  forall (depth : nat) (X : Type)
         (a b : Buf6 (Stored9 X)),
    middle9_depth_le depth a ->
    middle9_depth_le depth b ->
