Lemma kcad9_concat_ocaml_full_split_open_back_middle_fuel_middle_depth_bound :
  forall (fuel depth : nat) (X : Type)
         (m1 : Buf6 (Stored9 X)) (t1 h2 : Buf6 (KElem9 X))
         (m2_rest : Buf6 (Stored9 X)) (t2 : Buf6 (KElem9 X))
         (back_cell : Stored9 X),
    middle9_depth_le depth m1 ->
    middle9_depth_le depth m2_rest ->
    stored_middle_depth_le depth back_cell ->
    let '(m_new, _) :=
      kcad9_concat_ocaml_full_split_open_back_middle_fuel
        fuel m1 t1 h2 m2_rest t2 back_cell in
    middle9_depth_le depth m_new.
Proof.
  induction fuel as [|fuel IH]; intros depth X m1 t1 h2 m2_rest t2
    [b|pre sm suf|sm] Hm1 Hm2 Hback;
    cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
         kcad9_concat_ocaml_full_split_open_back_base] in *.
  - apply middle9_depth_le_inject; [exact Hm1|].
    apply stored_middle_depth_le_big.
    apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hm2].
  - apply middle9_depth_le_concat.
    + apply middle9_depth_le_inject.
      * apply middle9_depth_le_inject.
        -- exact Hm1.
        -- apply stored_middle_depth_le_big.
           apply middle9_depth_le_push;
             [apply stored_middle_depth_le_small|exact Hm2].
      * apply stored_middle_depth_le_small.
    + exact Hback.
  - apply middle9_depth_le_inject.
    + apply middle9_depth_le_inject.
      * exact Hm1.
      * apply stored_middle_depth_le_big.
        apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hm2].
    + exact Hback.
  - apply middle9_depth_le_inject; [exact Hm1|].
    apply stored_middle_depth_le_big.
    apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hm2].
  - apply middle9_depth_le_concat.
    + apply middle9_depth_le_inject.
      * apply middle9_depth_le_inject.
        -- exact Hm1.
        -- apply stored_middle_depth_le_big.
           apply middle9_depth_le_push;
             [apply stored_middle_depth_le_small|exact Hm2].
      * apply stored_middle_depth_le_small.
    + exact Hback.
  - destruct depth as [|depth']; [contradiction|].
    cbn [stored_middle_depth_le] in Hback.
    destruct (buf6_eject sm) as [[sm_rest inner_back]|] eqn:Heject.
    + destruct
        (middle9_depth_le_eject depth' X sm sm_rest inner_back Hback Heject)
        as [Hsm_rest Hinner_back].
      eapply IH.
      * exact Hm1.
      * apply middle9_depth_le_k9_middle_inject_succ; assumption.
      * apply stored_middle_depth_le_succ. exact Hinner_back.
    + apply middle9_depth_le_inject; [exact Hm1|].
      apply stored_middle_depth_le_big.
      apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hm2].
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_middle_depth_bound_thm :
  forall (fuel depth : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_middle_depth_bound depth a ->
    inv_kcad9_ocaml_middle_depth_bound depth b ->
