  intros fuel depth X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Ha Hb;
    cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
         inv_kcad9_ocaml_middle_depth_bound] in *.
  - exact I.
  - exact I.
  - exact Hb.
  - exact I.
  - apply middle9_depth_le_empty.
  - apply middle9_depth_le_push; [apply stored_middle_depth_le_small|exact Hb].
  - exact Ha.
  - apply middle9_depth_le_inject; [exact Ha|apply stored_middle_depth_le_small].
  - destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct
        (middle9_depth_le_eject depth X m2 m2_rest back_cell Hb Heject)
        as [Hm2_rest Hback_cell].
      pose proof
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel_middle_depth_bound
           fuel depth X m1 t1 h2 m2_rest t2 back_cell
           Ha Hm2_rest Hback_cell) as Hout.
      destruct
        (kcad9_concat_ocaml_full_split_open_back_middle_fuel
          fuel m1 t1 h2 m2_rest t2 back_cell)
        as [m_new t_new].
      exact Hout.
    + apply middle9_depth_le_inject; [exact Ha|].
      apply stored_middle_depth_le_big. apply middle9_depth_le_empty.
Qed.

