    cbn [stored_refill_depth_le].
    apply middle9_refill_depth_le_push;
      [apply stored_refill_depth_le_small|exact Hm2].
  - apply middle9_refill_depth_le_concat.
    + apply middle9_refill_depth_le_inject.
