Fixpoint all_kcad9_ocaml_full_split_right_const {X : Type}
  (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_full_split_right_const k /\
      all_kcad9_ocaml_full_split_right_const ks'
  end.

Fixpoint all_kcad9_ocaml_full_split_right_const_suffix_empty {X : Type}
  (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_full_split_right_const k /\
      inv_kcad9_ocaml_full_split_suffix_empty k /\
      all_kcad9_ocaml_full_split_right_const_suffix_empty ks'
  end.

Fixpoint kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold {X : Type}
  (fuel : nat) (acc : KCadeque9 X) (ks : list (KCadeque9 X))
    : KCadeque9 X :=
  match ks with
  | [] => acc
  | k :: ks' =>
      kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
        fuel
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel fuel acc k)
        ks'
  end.

Fixpoint kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold {X : Type}
  (acc : KCadeque9 X) (ks : list (KCadeque9 X)) : KCadeque9 X :=
