Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_zero_splice_eq_thm :
  forall (fuel : nat) (X : Type) (acc : KCadeque9 X)
         (ks : list (KCadeque9 X)),
    all_kcad9_ocaml_full_split_right_const_suffix_empty ks ->
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
