Theorem all_kcad9_ocaml_full_split_right_const_singletons_thm :
  forall (X : Type) (xs : list X),
    all_kcad9_ocaml_full_split_right_const (map kcad9_singleton xs).
Proof.
  intros X xs.
  induction xs as [|x xs IH].
  - exact I.
  - cbn [map all_kcad9_ocaml_full_split_right_const].
    split.
    + apply singleton_kcad9_ocaml_full_split_right_const_thm.
    + exact IH.
Qed.

Theorem all_kcad9_ocaml_full_split_right_const_suffix_empty_singletons_thm :
  forall (X : Type) (xs : list X),
    all_kcad9_ocaml_full_split_right_const_suffix_empty
      (map kcad9_singleton xs).
Proof.
  intros X xs.
  induction xs as [|x xs IH].
  - exact I.
  - cbn [map all_kcad9_ocaml_full_split_right_const_suffix_empty].
    split.
    + apply singleton_kcad9_ocaml_full_split_right_const_thm.
    + split.
      * apply singleton_kcad9_ocaml_full_split_suffix_empty_thm.
      * exact IH.
Qed.

