Theorem kcad9_concat_ocaml_shape_singleton_right_full_split_right_const_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_full_split_right_const k ->
    inv_kcad9_ocaml_full_split_right_const
      (kcad9_concat_ocaml_shape k (kcad9_singleton x)).
Proof.
  intros X k x [Hboundary_deep Hdepth].
  destruct Hboundary_deep as [Hboundary Hdeep].
  destruct
    (singleton_kcad9_ocaml_full_split_right_const_thm X x)
    as [[Hsingleton_boundary Hsingleton_deep] _].
  split.
  - split.
    + eapply kcad9_concat_ocaml_shape_inv_boundaries;
        eassumption.
    + eapply kcad9_concat_ocaml_shape_inv_deep_xbase_thm;
        eassumption.
  - destruct k as [|b|h m t];
      cbn [kcad9_concat_ocaml_shape kcad9_singleton
           inv_kcad9_ocaml_refill_depth_bound] in *.
    + exact I.
    + apply middle9_refill_depth_le_empty.
    + apply middle9_refill_depth_le_inject.
      * exact Hdepth.
      * apply stored_refill_depth_le_small.
Qed.

