Definition buf6_splice_payload_count {X : Type} (b : Buf6 X) : nat :=
  if buf6_is_empty b then 0 else 1.

Lemma buf6_splice_payload_count_zero :
  forall (X : Type) (b : Buf6 X),
    buf6_is_empty b = true ->
    buf6_splice_payload_count b = 0.
Proof.
  intros X b Hempty.
  unfold buf6_splice_payload_count.
  rewrite Hempty. reflexivity.
Qed.

Definition kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count
  {X : Type} (back_cell : Stored9 X) : nat :=
  match back_cell with
  | StoredSmall9 _ => 0
  | StoredBig9 _ sm suf =>
      buf6_splice_payload_count sm + buf6_splice_payload_count suf
  | StoredMiddle9 sm => buf6_splice_payload_count sm
  end.

Fixpoint kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count
  {X : Type} (fuel : nat) (back_cell : Stored9 X) : nat :=
  match fuel, back_cell with
  | S fuel', StoredMiddle9 sm =>
      match buf6_eject sm with
      | Some (_, inner_back) =>
          kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count
            fuel' inner_back
      | None => 0
      end
  | _, _ =>
      kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count
        back_cell
  end.

Definition kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
  {X : Type} (fuel : nat) (a b : KCadeque9 X) : nat :=
  match a, b with
  | K9Triple _ _ _, K9Triple _ m2 _ =>
      match buf6_eject m2 with
      | Some (_, back_cell) =>
          kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count
            fuel back_cell
      | None => 0
      end
  | _, _ => 0
  end.

Fixpoint kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
  {X : Type} (fuel : nat) (acc : KCadeque9 X)
  (ks : list (KCadeque9 X)) : nat :=
  match ks with
  | [] => 0
  | k :: ks' =>
      kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
        fuel acc k +
      kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
        fuel
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel fuel acc k)
        ks'
  end.

Lemma kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count_zero :
  forall (X : Type) (back_cell : Stored9 X),
    stored_refill_depth_le 0 back_cell ->
    stored9_full_split_suffix_empty back_cell ->
    kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count
      back_cell = 0.
Proof.
  intros X [b|pre sm suf|sm] Hdepth Hsuffix;
    cbn [kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count
         stored_refill_depth_le stored9_full_split_suffix_empty] in *.
  - reflexivity.
  - destruct Hsuffix as [_ Hsuf].
    rewrite (buf6_splice_payload_count_zero _ sm Hdepth).
    rewrite (buf6_splice_payload_count_zero _ suf Hsuf).
    reflexivity.
  - contradiction.
Qed.

Lemma kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count_zero :
  forall (fuel : nat) (X : Type) (back_cell : Stored9 X),
    stored_refill_depth_le 0 back_cell ->
    stored9_full_split_suffix_empty back_cell ->
    kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count
      fuel back_cell = 0.
Proof.
  intros fuel X back_cell Hdepth Hsuffix.
  destruct fuel as [|fuel];
    destruct back_cell as [b|pre sm suf|sm];
    cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count
         kcad9_concat_ocaml_full_split_open_back_base_splice_payload_count
         stored_refill_depth_le stored9_full_split_suffix_empty] in *.
  - reflexivity.
  - destruct Hsuffix as [_ Hsuf].
    rewrite (buf6_splice_payload_count_zero _ sm Hdepth).
    rewrite (buf6_splice_payload_count_zero _ suf Hsuf).
    reflexivity.
  - contradiction.
  - reflexivity.
  - destruct Hsuffix as [_ Hsuf].
    rewrite (buf6_splice_payload_count_zero _ sm Hdepth).
    rewrite (buf6_splice_payload_count_zero _ suf Hsuf).
    reflexivity.
  - contradiction.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count_zero_thm :
  forall (fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_refill_depth_bound 0 b ->
    inv_kcad9_ocaml_full_split_suffix_empty b ->
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
      fuel a b = 0.
Proof.
  intros fuel X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Hdepth Hsuffix;
    cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
         inv_kcad9_ocaml_refill_depth_bound
         inv_kcad9_ocaml_full_split_suffix_empty] in *;
    try reflexivity.
  destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject;
    [|reflexivity].
  destruct
    (middle9_refill_depth_le_eject 0 X m2 m2_rest back_cell
       Hdepth Heject) as [_ Hback_depth].
  destruct
    (middle9_full_split_suffix_empty_eject X m2 m2_rest back_cell
       Hsuffix Heject) as [_ Hback_suffix].
  apply
    kcad9_concat_ocaml_full_split_open_back_middle_fuel_splice_payload_count_zero;
    assumption.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count_zero_thm :
  forall (fuel : nat) (X : Type)
         (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    all_kcad9_ocaml_full_split_right_const_suffix_empty ks ->
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
      fuel acc ks = 0.
Proof.
  intros fuel X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hall.
  - reflexivity.
  - cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
         all_kcad9_ocaml_full_split_right_const_suffix_empty] in *.
    destruct Hall as [Hk_right [Hk_suffix Hks]].
    rewrite
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count_zero_thm
         fuel X acc k (proj2 Hk_right) Hk_suffix).
    apply IH. exact Hks.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_singletons_splice_payload_count_zero_thm :
  forall (fuel : nat) (X : Type) (xs : list X),
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
      fuel (@kcad9_empty X) (map kcad9_singleton xs) = 0.
Proof.
  intros fuel X xs.
  apply
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count_zero_thm.
  apply all_kcad9_ocaml_full_split_right_const_suffix_empty_singletons_thm.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_singleton_folds_splice_payload_count_zero_thm :
  forall (fuel : nat) (X : Type) (xss : list (list X)),
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
      fuel
      (@kcad9_empty X)
      (map
        (fun xs =>
           kcad9_concat_ocaml_shape_left_fold
             (@kcad9_empty X) (map kcad9_singleton xs))
        xss) = 0.
Proof.
  intros fuel X xss.
  apply
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count_zero_thm.
  apply all_kcad9_ocaml_full_split_right_const_suffix_empty_left_fold_singletons_thm.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_concat_left_fold_singletons_splice_payload_count_zero_thm :
  forall (concat_fuel : nat) (X : Type) (xs ys : list X),
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
      concat_fuel
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs))
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton ys)) = 0.
Proof.
  intros concat_fuel X xs ys.
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_full_split_right_const_suffix_empty_seq_thm
       X ys) as [[_ Hdepth] [Hsuffix _]].
  apply
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count_zero_thm;
    assumption.
Qed.

Theorem inv_kcad9_ocaml_reachable_depth_boundary_deep_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth depth k ->
    inv_kcad9_ocaml_boundary_deep k.
Proof.
  intros depth X [|b|h m t] [Hready Hdeep];
    cbn [inv_kcad9_ocaml_reachable_depth
         inv_kcad9_ocaml_ready_or_empty_depth
         inv_kcad9_ocaml_boundary_deep
         inv_kcad9_ocaml_boundaries
         inv_kcad9_ocaml_deep_xbase] in *.
  - split; exact I.
  - destruct Hready as [Hb _].
    split; [exact Hb|exact Hdeep].
  - destruct Hready as [Hh [_ [Ht [_ _]]]].
    split; [split; assumption|exact Hdeep].
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_small_middle_public_open_back_reusable_const_thm :
  forall (concat_fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_reachable_depth 1 a ->
    inv_kcad9_ocaml_reachable_depth 1 b ->
    kcad9_ocaml_middle_small_nonempty a ->
    kcad9_ocaml_middle_small_nonempty b ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel a b) =
      kcad9_to_list a ++ kcad9_to_list b /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel a b).
Proof.
  intros concat_fuel X a b Ha Hb Hsmall_a Hsmall_b.
  split.
  - apply kcad9_concat_ocaml_full_split_open_back_shape_fuel_seq_thm.
  - pose proof
      (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm 1 X a Ha)
      as Ha_boundary.
    pose proof
      (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm 1 X b Hb)
      as Hb_boundary.
    pose proof
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
         concat_fuel X a b Ha_boundary Hb_boundary) as Hres_boundary.
    intros endpoint_fuel.
    assert (Hcont :
      kcad9_ocaml_refill_continuation_ready_fuel_depth
        endpoint_fuel 1
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel
          concat_fuel a b)).
    { destruct a as [|ba|h1 m1 t1];
        destruct b as [|bb|h2 m2 t2];
        cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
             kcad9_ocaml_refill_continuation_ready_fuel_depth
             kcad9_ocaml_middle_small_nonempty] in *;
        try exact I.
      - split.
        + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hsmall_b.
        + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hsmall_b.
      - split.
        + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
          cbn [middle9_small_nonempty buf6_empty buf6_elems].
          constructor.
        + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
          cbn [middle9_small_nonempty buf6_empty buf6_elems].
          constructor.
      - destruct Hb as [Hready_b _].
        cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready_b.
        destruct Hready_b as [Hh2 [_ [_ [_ _]]]].
        assert (Hmiddle :
          middle9_small_nonempty (buf6_push (StoredSmall9 h2) m2)).
        { apply middle9_small_nonempty_push_small; assumption. }
        split.
        + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hmiddle.
        + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hmiddle.
      - split.
        + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hsmall_a.
        + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hsmall_a.
      - destruct Ha as [Hready_a _].
        cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready_a.
        destruct Hready_a as [_ [_ [Ht1 [_ _]]]].
        assert (Hmiddle :
          middle9_small_nonempty (buf6_inject m1 (StoredSmall9 t1))).
        { apply middle9_small_nonempty_inject_small; assumption. }
        split.
        + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hmiddle.
        + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
          exact Hmiddle.
      - destruct Ha as [Hready_a _].
        destruct Hb as [Hready_b _].
        cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready_a, Hready_b.
        destruct Hready_a as [_ [_ [Ht1 [_ _]]]].
        destruct Hready_b as [Hh2 [_ [_ [_ _]]]].
        destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
        + destruct
            (middle9_small_nonempty_eject X m2 m2_rest back_cell
               Heject Hsmall_b) as [Hm2_rest Hback_cell].
          destruct back_cell as [bcell|pre sm suf|sm];
            cbn [stored9_small_nonempty] in Hback_cell;
            try contradiction.
          assert (Hbridge_middle :
            middle9_small_nonempty
              (buf6_push (StoredSmall9 h2) m2_rest)).
          { apply middle9_small_nonempty_push_small; assumption. }
          destruct concat_fuel;
            cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
                 kcad9_concat_ocaml_full_split_open_back_base
                 kcad9_ocaml_refill_continuation_ready_fuel_depth];
            split.
          * apply
              front_refill_continuation_ready_middle9_fuel_small_prefix_bridge;
              assumption.
          * apply
              back_refill_continuation_ready_middle9_fuel_small_prefix_bridge;
              assumption.
          * apply
              front_refill_continuation_ready_middle9_fuel_small_prefix_bridge;
              assumption.
          * apply
              back_refill_continuation_ready_middle9_fuel_small_prefix_bridge;
              assumption.
        + cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth].
          split.
          * apply
              front_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
            -- exact Hsmall_a.
            -- exact Ht1.
            -- cbn [middle9_small_nonempty buf6_empty buf6_elems].
               constructor.
            -- exact Hh2.
          * apply
              back_refill_continuation_ready_middle9_fuel_small_prefix_bridge.
            -- exact Hsmall_a.
            -- exact Ht1.
            -- cbn [middle9_small_nonempty buf6_empty buf6_elems].
               constructor.
            -- exact Hh2.
    }
    split.
    + eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
        eassumption.
    + exact Hcont.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_reusable_left_small_middle_public_open_back_reusable_const_thm :
  forall (concat_fuel : nat) (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_open_back_reusable_const a ->
    inv_kcad9_ocaml_reachable_depth 1 b ->
    kcad9_ocaml_middle_small_nonempty b ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel a b) =
      kcad9_to_list a ++ kcad9_to_list b /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel a b).
Proof.
  intros concat_fuel X a b Ha Hb Hsmall_b.
  split.
  - apply kcad9_concat_ocaml_full_split_open_back_shape_fuel_seq_thm.
  - destruct b as [|bb|h2 m2 t2].
    + destruct a; cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel];
        exact Ha.
    + pose proof (Ha 0) as Ha0.
      pose proof
        (inv_kcad9_ocaml_continuation_depth_reachable_thm
           0 1 X a Ha0) as Ha_reach.
      pose proof
        (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
           1 X a Ha_reach) as Ha_boundary.
      pose proof
        (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
           1 X (K9Simple bb) Hb) as Hb_boundary.
      pose proof
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
           concat_fuel X a (K9Simple bb) Ha_boundary Hb_boundary)
        as Hres_boundary.
      intros endpoint_fuel.
      assert (Hcont :
        kcad9_ocaml_refill_continuation_ready_fuel_depth
          endpoint_fuel 1
          (kcad9_concat_ocaml_full_split_open_back_shape_fuel
            concat_fuel a (K9Simple bb))).
      { destruct a as [|ba|h1 m1 t1];
          cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
               kcad9_ocaml_refill_continuation_ready_fuel_depth].
        - exact I.
        - split.
          + apply front_refill_continuation_ready_middle9_fuel_empty_thm.
          + apply back_refill_continuation_ready_middle9_fuel_empty_thm.
        - pose proof (Ha endpoint_fuel) as [Hreach_a Hmiddle_cont].
          cbn [inv_kcad9_ocaml_reachable_depth
               inv_kcad9_ocaml_ready_or_empty_depth
               kcad9_ocaml_refill_continuation_ready_fuel_depth]
            in Hreach_a, Hmiddle_cont.
          destruct Hreach_a as [Hready_a _].
          destruct Hready_a as [_ [_ [Ht1 [_ _]]]].
          destruct Hmiddle_cont as [Hfront Hback].
          split.
          + apply front_refill_continuation_ready_middle9_fuel_inject_small;
              assumption.
          + apply back_refill_continuation_ready_middle9_fuel_inject_small;
              assumption. }
      split.
      * eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
          eassumption.
      * exact Hcont.
    + pose proof (Ha 0) as Ha0.
      pose proof
        (inv_kcad9_ocaml_continuation_depth_reachable_thm
           0 1 X a Ha0) as Ha_reach.
      pose proof
        (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
           1 X a Ha_reach) as Ha_boundary.
      pose proof
        (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
           1 X (K9Triple h2 m2 t2) Hb) as Hb_boundary.
      pose proof
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
           concat_fuel X a (K9Triple h2 m2 t2) Ha_boundary Hb_boundary)
        as Hres_boundary.
      intros endpoint_fuel.
      assert (Hcont :
        kcad9_ocaml_refill_continuation_ready_fuel_depth
          endpoint_fuel 1
          (kcad9_concat_ocaml_full_split_open_back_shape_fuel
            concat_fuel a (K9Triple h2 m2 t2))).
      { destruct a as [|ba|h1 m1 t1];
          cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
               kcad9_ocaml_refill_continuation_ready_fuel_depth].
        - exact
            (proj2
              (kcad9_reachable_depth_one_small_middle_open_back_reusable_const_thm
                 X (K9Triple h2 m2 t2) Hb Hsmall_b endpoint_fuel)).
        - destruct Hb as [Hready_b _].
          cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready_b.
          destruct Hready_b as [Hh2 [_ [_ [_ _]]]].
          assert (Hmiddle :
            middle9_small_nonempty (buf6_push (StoredSmall9 h2) m2)).
          { apply middle9_small_nonempty_push_small; assumption. }
          split.
          + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
            exact Hmiddle.
          + apply back_refill_continuation_ready_middle9_fuel_small_nonempty.
            exact Hmiddle.
        - pose proof (Ha endpoint_fuel) as [Hreach_a Hmiddle_cont].
          cbn [inv_kcad9_ocaml_reachable_depth
               inv_kcad9_ocaml_ready_or_empty_depth
               kcad9_ocaml_refill_continuation_ready_fuel_depth]
            in Hreach_a, Hmiddle_cont.
          destruct Hreach_a as [Hready_a _].
          destruct Hready_a as [_ [_ [Ht1 [_ _]]]].
          destruct Hmiddle_cont as [Hfront Hback].
          destruct Hb as [Hready_b _].
          cbn [inv_kcad9_ocaml_ready_or_empty_depth] in Hready_b.
          destruct Hready_b as [Hh2 [_ [_ [_ _]]]].
          destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
          + destruct
              (middle9_small_nonempty_eject X m2 m2_rest back_cell
                 Heject Hsmall_b) as [Hm2_rest Hback_cell].
            destruct back_cell as [bcell|pre sm suf|sm];
              cbn [stored9_small_nonempty] in Hback_cell; try contradiction.
            assert (Hbridge_middle :
              middle9_small_nonempty
                (buf6_push (StoredSmall9 h2) m2_rest)).
            { apply middle9_small_nonempty_push_small; assumption. }
            destruct concat_fuel;
              cbn [kcad9_concat_ocaml_full_split_open_back_middle_fuel
                   kcad9_concat_ocaml_full_split_open_back_base
                   kcad9_ocaml_refill_continuation_ready_fuel_depth];
              split.
            * apply front_refill_continuation_ready_middle9_fuel_inject_big_small;
                assumption.
            * apply back_refill_continuation_ready_middle9_fuel_inject_big_small;
                assumption.
            * apply front_refill_continuation_ready_middle9_fuel_inject_big_small;
                assumption.
            * apply back_refill_continuation_ready_middle9_fuel_inject_big_small;
                assumption.
          + cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth].
            split.
            * apply front_refill_continuation_ready_middle9_fuel_inject_big_small.
              -- exact Hfront.
              -- exact Ht1.
              -- cbn [middle9_small_nonempty buf6_empty buf6_elems].
                 constructor.
              -- exact Hh2.
            * apply back_refill_continuation_ready_middle9_fuel_inject_big_small.
              -- exact Hback.
              -- exact Ht1.
              -- cbn [middle9_small_nonempty buf6_empty buf6_elems].
                 constructor.
              -- exact Hh2. }
      split.
      * eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
          eassumption.
      * exact Hcont.
Qed.

Theorem kcad9_endpoint_script_expected_fuel_two_under_full_split_reusable_left_small_middle_public_thm :
  forall (concat_fuel : nat) (X : Type) (a b : KCadeque9 X)
         (ops : list KCad9EndpointSide) (xs_final : list X),
    inv_kcad9_ocaml_open_back_reusable_const a ->
    inv_kcad9_ocaml_reachable_depth 1 b ->
    kcad9_ocaml_middle_small_nonempty b ->
    kcad9_endpoint_script_model
      (kcad9_to_list a ++ kcad9_to_list b) ops = Some xs_final ->
    exists k_final,
      kcad9_endpoint_script_expected 2
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel
          concat_fuel a b)
        (kcad9_to_list a ++ kcad9_to_list b) ops k_final xs_final /\
      kcad9_to_list k_final = xs_final /\
      inv_kcad9_ocaml_open_back_reusable_const k_final.
Proof.
  intros concat_fuel X a b ops xs_final Ha Hb Hsmall_b Hmodel.
  destruct
    (kcad9_concat_ocaml_full_split_open_back_shape_fuel_reusable_left_small_middle_public_open_back_reusable_const_thm
       concat_fuel X a b Ha Hb Hsmall_b) as [Hseq Hinv].
  eapply kcad9_endpoint_script_expected_fuel_two_under_open_back_reusable_const_thm;
    eassumption.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_reusable_left_singleton_fold_right_zero_payload_thm :
  forall (concat_fuel : nat) (X : Type) (acc : KCadeque9 X)
         (xs : list X),
    inv_kcad9_ocaml_open_back_reusable_const acc ->
    kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count
      concat_fuel
      acc
      (kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs)) = 0 /\
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel
        acc
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))) =
      kcad9_to_list acc ++ xs /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel
        acc
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs))).
Proof.
  intros concat_fuel X acc xs Hinv.
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_full_split_right_const_suffix_empty_seq_thm
       X xs) as [[_ Hdepth] [Hsuffix Hseq_right]].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm
       X xs) as [Hreach_right _].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
       X (@kcad9_empty X) xs I I) as [_ Hsmall_right].
  split.
  - apply
      kcad9_concat_ocaml_full_split_open_back_shape_fuel_splice_payload_count_zero_thm;
      assumption.
  - destruct
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_reusable_left_small_middle_public_open_back_reusable_const_thm
         concat_fuel X acc
         (kcad9_concat_ocaml_shape_left_fold
           (@kcad9_empty X) (map kcad9_singleton xs))
         Hinv Hreach_right Hsmall_right) as [Hseq Hinv_concat].
    split.
    + rewrite Hseq, Hseq_right. reflexivity.
    + exact Hinv_concat.
Qed.

Definition inv_kcad9_ocaml_open_back_reusable_public_right_operand {X : Type}
  (k : KCadeque9 X) : Prop :=
  inv_kcad9_ocaml_reachable_depth 1 k /\
  kcad9_ocaml_middle_small_nonempty k /\
  inv_kcad9_ocaml_full_split_right_const k /\
  inv_kcad9_ocaml_full_split_suffix_empty k.

Theorem empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm :
  forall X : Type,
    inv_kcad9_ocaml_open_back_reusable_public_right_operand
      (@kcad9_empty X).
Proof.
  intros X.
  split.
  - apply empty_kcad9_ocaml_reachable_depth_thm.
  - split.
    + exact I.
    + split.
      * apply empty_kcad9_ocaml_full_split_right_const_thm.
      * apply empty_kcad9_ocaml_full_split_suffix_empty_thm.
Qed.

