Theorem kcad9_endpoint_script_expected_fuel_two_under_full_split_reusable_left_public_right_zero_splice_package_thm :
  forall (concat_fuel : nat) (X : Type) (acc right : KCadeque9 X)
         (ops : list KCad9EndpointSide) (xs_final : list X),
