Fixpoint all_kcad9_ocaml_open_back_reusable_public_right_operand {X : Type}
  (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_reachable_depth 1 k /\
      kcad9_ocaml_middle_small_nonempty k /\
      inv_kcad9_ocaml_full_split_right_const k /\
      inv_kcad9_ocaml_full_split_suffix_empty k /\
      all_kcad9_ocaml_open_back_reusable_public_right_operand ks'
  end.

Fixpoint all_kcad9_ocaml_open_back_reusable_public_right_operand_nonempty
  {X : Type} (ks : list (KCadeque9 X)) : Prop :=
  match ks with
  | [] => True
  | k :: ks' =>
      inv_kcad9_ocaml_reachable_depth 1 k /\
      kcad9_ocaml_middle_small_nonempty k /\
      inv_kcad9_ocaml_full_split_right_const k /\
      inv_kcad9_ocaml_full_split_suffix_empty k /\
      kcad9_to_list k <> [] /\
      all_kcad9_ocaml_open_back_reusable_public_right_operand_nonempty ks'
  end.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_public_right_middle_depth_bound_thm :
  forall (concat_fuel : nat) (X : Type)
         (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_middle_depth_bound 1 acc ->
    all_kcad9_ocaml_open_back_reusable_public_right_operand ks ->
    inv_kcad9_ocaml_middle_depth_bound 1
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
        concat_fuel acc ks).
Proof.
  intros concat_fuel X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hacc Hall.
  - exact Hacc.
  - cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
         all_kcad9_ocaml_open_back_reusable_public_right_operand] in *.
    destruct Hall as [_ [_ [Hright [_ Hall]]]].
    apply IH; [|exact Hall].
    eapply kcad9_concat_ocaml_full_split_open_back_shape_fuel_middle_depth_bound_thm.
    + exact Hacc.
    + apply inv_kcad9_ocaml_middle_depth_bound_succ_thm.
      apply inv_kcad9_ocaml_full_split_right_const_middle_depth_bound_thm.
      exact Hright.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_public_right_refill_depth_bound_thm :
  forall (concat_fuel : nat) (X : Type)
         (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_refill_depth_bound 1 acc ->
    all_kcad9_ocaml_open_back_reusable_public_right_operand ks ->
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
        concat_fuel acc ks).
Proof.
  intros concat_fuel X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hacc Hall.
  - exact Hacc.
  - cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold
         all_kcad9_ocaml_open_back_reusable_public_right_operand] in *.
    destruct Hall as [_ [_ [Hright [_ Hall]]]].
    apply IH; [|exact Hall].
    destruct Hright as [_ Hright_depth].
    eapply kcad9_concat_ocaml_full_split_open_back_shape_fuel_refill_depth_split_thm.
    + exact Hacc.
    + exact Hright_depth.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold_reusable_public_right_open_back_reusable_const_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X)),
    inv_kcad9_ocaml_open_back_reusable_const acc ->
    all_kcad9_ocaml_open_back_reusable_public_right_operand ks ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc ks) =
    kcad9_to_list acc ++ concat (map kcad9_to_list ks) /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc ks).
Proof.
  intros X acc ks.
  revert acc.
  induction ks as [|k ks IH]; intros acc Hacc Hall.
  - cbn [kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
         map concat].
    split; [rewrite app_nil_r; reflexivity|exact Hacc].
  - cbn [kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
         all_kcad9_ocaml_open_back_reusable_public_right_operand
         map concat] in *.
    destruct Hall as [Hreach [Hsmall [Hright [Hsuffix Hall]]]].
    assert (Hoperand :
      inv_kcad9_ocaml_open_back_reusable_public_right_operand k).
    { split; [exact Hreach|].
      split; [exact Hsmall|].
      split; [exact Hright|exact Hsuffix]. }
    destruct
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_reusable_left_public_right_open_back_reusable_const_thm
         X acc k Hacc Hoperand) as [Hseq_step Hinv_step].
    destruct (IH _ Hinv_step Hall) as [Hseq_tail Hinv_tail].
    split.
    + rewrite Hseq_tail, Hseq_step.
      rewrite app_assoc. reflexivity.
    + exact Hinv_tail.
Qed.

Theorem kcad9_endpoint_script_expected_fuel_two_under_zero_splice_left_fold_reusable_public_right_thm :
  forall (X : Type) (acc : KCadeque9 X) (ks : list (KCadeque9 X))
         (ops : list KCad9EndpointSide) (xs_final : list X),
