Theorem kcad9_push_ocaml_open_back_reusable_public_right_operand_thm :
  forall (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_open_back_reusable_public_right_operand k ->
    inv_kcad9_ocaml_open_back_reusable_public_right_operand
      (kcad9_push x k).
Proof.
  intros X x k [Hreach [Hsmall [Hright Hsuffix]]].
  split.
  - apply kcad9_push_ocaml_reachable_depth_thm. exact Hreach.
  - split.
    + apply kcad9_push_ocaml_middle_small_nonempty_thm. exact Hsmall.
    + split.
      * apply kcad9_push_ocaml_full_split_right_const_thm. exact Hright.
      * apply kcad9_push_ocaml_full_split_suffix_empty_thm. exact Hsuffix.
Qed.

Theorem kcad9_inject_ocaml_open_back_reusable_public_right_operand_thm :
