    + apply kcad9_inject_ocaml_middle_small_nonempty_thm. exact Hsmall.
    + split.
      * apply kcad9_inject_ocaml_full_split_right_const_thm. exact Hright.
      * apply kcad9_inject_ocaml_full_split_suffix_empty_thm. exact Hsuffix.
