Theorem kcad9_concat_ocaml_shape_singleton_right_open_back_reusable_public_right_operand_seq_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_open_back_reusable_public_right_operand k ->
    kcad9_to_list (kcad9_concat_ocaml_shape k (kcad9_singleton x)) =
      kcad9_to_list k ++ [x] /\
    inv_kcad9_ocaml_open_back_reusable_public_right_operand
      (kcad9_concat_ocaml_shape k (kcad9_singleton x)).
Proof.
  intros X k x [Hreach [Hsmall [Hright Hsuffix]]].
  split.
  - rewrite kcad9_concat_ocaml_shape_seq.
    cbn [kcad9_singleton kcad9_to_list kelem9_flat_list
         buf6_elems].
    reflexivity.
  - split.
    + eapply kcad9_concat_ocaml_shape_inv_reachable_depth_thm.
      * exact Hreach.
      * apply singleton_kcad9_ocaml_reachable_depth_thm.
    + split.
      * apply kcad9_concat_ocaml_shape_singleton_middle_small_nonempty.
        -- exact (proj1 (proj1 Hright)).
        -- exact Hsmall.
      * split.
        -- apply kcad9_concat_ocaml_shape_singleton_right_full_split_right_const_thm.
           exact Hright.
        -- apply kcad9_concat_ocaml_shape_singleton_right_full_split_suffix_empty_thm.
           exact Hsuffix.
Qed.

Theorem kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm :
  forall (X : Type) (acc : KCadeque9 X) (xs : list X),
    inv_kcad9_ocaml_open_back_reusable_public_right_operand acc ->
    kcad9_to_list
      (kcad9_concat_ocaml_shape_left_fold
        acc (map kcad9_singleton xs)) =
      kcad9_to_list acc ++ xs /\
    inv_kcad9_ocaml_open_back_reusable_public_right_operand
      (kcad9_concat_ocaml_shape_left_fold
        acc (map kcad9_singleton xs)).
Proof.
  intros X acc xs.
  revert acc.
  induction xs as [|x xs IH]; intros acc Hacc.
  - cbn [map kcad9_concat_ocaml_shape_left_fold].
    split; [rewrite app_nil_r; reflexivity|exact Hacc].
  - cbn [map kcad9_concat_ocaml_shape_left_fold].
    destruct
      (kcad9_concat_ocaml_shape_singleton_right_open_back_reusable_public_right_operand_seq_thm
         X acc x Hacc) as [Hseq_one Hinv_one].
    destruct (IH _ Hinv_one) as [Hseq_tail Hinv_tail].
    split.
    + rewrite Hseq_tail, Hseq_one.
      rewrite <- app_assoc. reflexivity.
    + exact Hinv_tail.
Qed.

Theorem kcad9_concat_ocaml_full_split_open_back_zero_splice_public_right_operand_not_closed_thm :
  exists (a b : KCadeque9 nat),
    inv_kcad9_ocaml_open_back_reusable_public_right_operand a /\
    inv_kcad9_ocaml_open_back_reusable_public_right_operand b /\
    ~ inv_kcad9_ocaml_open_back_reusable_public_right_operand
        (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape a b).
Proof.
  pose (a :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [1; 2])).
  pose (b :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [3; 4; 5])).
  exists a, b.
  assert (Ha :
    inv_kcad9_ocaml_open_back_reusable_public_right_operand a).
  { subst a.
    destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm
         nat (@kcad9_empty nat) [1; 2]
         (empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm nat))
      as [_ Ha].
    exact Ha. }
  assert (Hb :
    inv_kcad9_ocaml_open_back_reusable_public_right_operand b).
  { subst b.
    destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm
         nat (@kcad9_empty nat) [3; 4; 5]
         (empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm nat))
      as [_ Hb].
    exact Hb. }
  split; [exact Ha|].
  split; [exact Hb|].
  subst a b.
  intro Hbad.
  cbn [map kcad9_singleton kcad9_concat_ocaml_shape_left_fold
       kcad9_concat_ocaml_shape kcad9_empty kcad9_singleton
       kcad9_concat_ocaml_full_split_open_back_zero_splice_shape
       kcad9_concat_ocaml_full_split_open_back_zero_splice_base
       inv_kcad9_ocaml_open_back_reusable_public_right_operand
       kcad9_ocaml_middle_small_nonempty middle9_small_nonempty
       stored9_small_nonempty buf6_elems buf6_empty buf6_inject
       buf6_push buf6_eject] in Hbad.
  destruct Hbad as [_ [Hsmall _]].
  inversion Hsmall as [|? ? Hcell _]; subst.
  exact Hcell.
Qed.

Definition inv_kcad9_ocaml_open_back_pending_public_right_schedule
  {X : Type} (acc : KCadeque9 X) (pending : list (KCadeque9 X)) : Prop :=
  inv_kcad9_ocaml_open_back_reusable_const acc /\
  all_kcad9_ocaml_open_back_reusable_public_right_operand pending.

Record KCad9OpenBackPendingPublicRightSchedule (X : Type) : Type := {
  kcad9_open_back_pending_public_right_acc : KCadeque9 X;
  kcad9_open_back_pending_public_right_pending : list (KCadeque9 X)
}.

Record KCad9OpenBackPendingPublicRightTwoAccSchedule (X : Type) : Type := {
  kcad9_open_back_pending_public_right_two_acc_front : KCadeque9 X;
  kcad9_open_back_pending_public_right_two_acc_pending : list (KCadeque9 X);
  kcad9_open_back_pending_public_right_two_acc_back : KCadeque9 X
}.

Arguments kcad9_open_back_pending_public_right_acc {X} _.
Arguments kcad9_open_back_pending_public_right_pending {X} _.
Arguments kcad9_open_back_pending_public_right_two_acc_front {X} _.
Arguments kcad9_open_back_pending_public_right_two_acc_pending {X} _.
Arguments kcad9_open_back_pending_public_right_two_acc_back {X} _.

Definition kcad9_open_back_pending_public_right_schedule_state_inv
    {X : Type} (sched : KCad9OpenBackPendingPublicRightSchedule X) : Prop :=
  inv_kcad9_ocaml_open_back_pending_public_right_schedule
    (kcad9_open_back_pending_public_right_acc sched)
    (kcad9_open_back_pending_public_right_pending sched).

Definition kcad9_open_back_pending_public_right_schedule_state_right_operand_inv
