       (kcad9_open_back_pending_public_right_acc right ::
        kcad9_open_back_pending_public_right_pending right)).

Definition kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_schedule
    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
