    (kcad9_open_back_pending_public_right_acc right ::
     kcad9_open_back_pending_public_right_pending right).

Definition kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule
    {X : Type}
    (left right : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    : KCad9OpenBackPendingPublicRightTwoAccSchedule X :=
  {| kcad9_open_back_pending_public_right_two_acc_front :=
       kcad9_open_back_pending_public_right_two_acc_front left;
     kcad9_open_back_pending_public_right_two_acc_pending :=
       kcad9_open_back_pending_public_right_two_acc_pending left ++
       [kcad9_open_back_pending_public_right_two_acc_back left;
        kcad9_open_back_pending_public_right_two_acc_front right] ++
       kcad9_open_back_pending_public_right_two_acc_pending right;
     kcad9_open_back_pending_public_right_two_acc_back :=
       kcad9_open_back_pending_public_right_two_acc_back right |}.

Definition kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xss : list (list X)) : KCad9OpenBackPendingPublicRightTwoAccSchedule X :=
  {| kcad9_open_back_pending_public_right_two_acc_front :=
       kcad9_open_back_pending_public_right_two_acc_front sched;
     kcad9_open_back_pending_public_right_two_acc_pending :=
       kcad9_open_back_pending_public_right_two_acc_pending sched ++
       (kcad9_open_back_pending_public_right_two_acc_back sched ::
        map
          (fun xs =>
            kcad9_concat_ocaml_shape_left_fold
              (@kcad9_empty X) (map kcad9_singleton xs))
          xss);
     kcad9_open_back_pending_public_right_two_acc_back := kcad9_empty |}.

