    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X) : nat :=
  kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count
