    (kcad9_open_back_pending_public_right_two_acc_front sched)
    (kcad9_open_back_pending_public_right_two_acc_pending sched ++
     [kcad9_open_back_pending_public_right_two_acc_back sched]).

Definition kcad9_two_acc_scheduled_public_deque (X : Type) : Type :=
  KCad9OpenBackPendingPublicRightTwoAccSchedule X.

Definition kcad9_two_acc_scheduled_public_deque_inv
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : Prop :=
  kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv sched.

Definition kcad9_two_acc_scheduled_public_deque_refill_depth_inv
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : Prop :=
  kcad9_two_acc_scheduled_public_deque_inv sched /\
  inv_kcad9_ocaml_refill_depth_bound 1
    (kcad9_open_back_pending_public_right_two_acc_front sched).

Definition kcad9_two_acc_scheduled_public_deque_right_operand_inv
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : Prop :=
  kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv sched.

Definition kcad9_two_acc_scheduled_public_deque_full_split_budget
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : Prop :=
  kcad9_open_back_pending_public_right_two_acc_state_full_split_budget sched.

Definition kcad9_two_acc_scheduled_public_deque_right_full_split_budget
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : Prop :=
  kcad9_open_back_pending_public_right_two_acc_state_right_full_split_budget
    sched.

Definition kcad9_two_acc_scheduled_public_deque_seq
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) : list X :=
  kcad9_open_back_pending_public_right_two_acc_state_seq sched.

Definition kcad9_two_acc_scheduled_public_deque_empty
    {X : Type} : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
    (@kcad9_open_back_pending_public_right_schedule_state_empty X).

Definition kcad9_two_acc_scheduled_public_deque_push
    {X : Type} (x : X)
    (sched : kcad9_two_acc_scheduled_public_deque X)
    : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_push x sched.

Definition kcad9_two_acc_scheduled_public_deque_inject
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X) (x : X)
    : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_inject sched x.

Definition kcad9_two_acc_scheduled_public_deque_concat
    {X : Type}
    (left right : kcad9_two_acc_scheduled_public_deque X)
    : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule
    left right.

Definition kcad9_two_acc_scheduled_public_deque_append_singleton_folds
    {X : Type}
    (sched : kcad9_two_acc_scheduled_public_deque X)
    (xss : list (list X)) : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds
