Definition kcad9_two_acc_scheduled_public_deque_zero_splice_materialize
    {X : Type} (sched : kcad9_two_acc_scheduled_public_deque X)
    : KCadeque9 X :=
  kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
    sched.

Definition kcad9_two_acc_scheduled_public_deque_full_split_materialize
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X) : KCadeque9 X :=
  kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
    concat_fuel sched.

Definition kcad9_two_acc_scheduled_public_deque_full_split_payload_count
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X) : nat :=
  kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
    concat_fuel sched.

Definition kcad9_open_back_pending_public_right_schedule_state_enqueue
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightSchedule X)
    (right : KCadeque9 X) : KCad9OpenBackPendingPublicRightSchedule X :=
  {| kcad9_open_back_pending_public_right_acc :=
       kcad9_open_back_pending_public_right_acc sched;
     kcad9_open_back_pending_public_right_pending :=
       kcad9_open_back_pending_public_right_pending sched ++ [right] |}.

Definition kcad9_open_back_pending_public_right_schedule_state_push
    {X : Type} (x : X)
    (sched : KCad9OpenBackPendingPublicRightSchedule X)
    : KCad9OpenBackPendingPublicRightSchedule X :=
  {| kcad9_open_back_pending_public_right_acc :=
       kcad9_push x (kcad9_open_back_pending_public_right_acc sched);
     kcad9_open_back_pending_public_right_pending :=
       kcad9_open_back_pending_public_right_pending sched |}.

Definition kcad9_open_back_pending_public_right_schedule_state_inject
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightSchedule X) (x : X)
    : KCad9OpenBackPendingPublicRightSchedule X :=
  kcad9_open_back_pending_public_right_schedule_state_enqueue
    sched (kcad9_singleton x).

Definition kcad9_open_back_pending_public_right_schedule_state_reenter
    {X : Type} (acc : KCadeque9 X)
    : KCad9OpenBackPendingPublicRightSchedule X :=
  {| kcad9_open_back_pending_public_right_acc := acc;
     kcad9_open_back_pending_public_right_pending := [] |}.

Definition kcad9_two_acc_scheduled_public_deque_reenter
    {X : Type} (acc : KCadeque9 X)
    : kcad9_two_acc_scheduled_public_deque X :=
  kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
    (kcad9_open_back_pending_public_right_schedule_state_reenter acc).

Definition kcad9_two_acc_scheduled_public_deque_pop
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X)
    : option (X * kcad9_two_acc_scheduled_public_deque X) :=
  match kcad9_pop_ocaml_shape_fuel 2
          (kcad9_two_acc_scheduled_public_deque_full_split_materialize
             concat_fuel sched) with
  | Some (x, acc') =>
      Some (x, kcad9_two_acc_scheduled_public_deque_reenter acc')
  | None => None
  end.

Definition kcad9_two_acc_scheduled_public_deque_eject
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X)
    : option (kcad9_two_acc_scheduled_public_deque X * X) :=
  match kcad9_eject_ocaml_shape_fuel 2
          (kcad9_two_acc_scheduled_public_deque_full_split_materialize
             concat_fuel sched) with
  | Some (acc', x) =>
      Some (kcad9_two_acc_scheduled_public_deque_reenter acc', x)
  | None => None
  end.

