Lemma all_kcad9_ocaml_open_back_reusable_public_right_operand_app :
  forall (X : Type) (xs ys : list (KCadeque9 X)),
    all_kcad9_ocaml_open_back_reusable_public_right_operand xs ->
    all_kcad9_ocaml_open_back_reusable_public_right_operand ys ->
