Lemma list_cons_as_snoc :
  forall (X : Type) (x : X) (xs : list X),
    exists init last, x :: xs = init ++ [last].
Proof.
  intros X x xs.
  revert x.
  induction xs as [|y ys IH]; intros x.
  - exists [], x. reflexivity.
  - destruct (IH y) as (init & last & Hys).
    exists (x :: init), last.
    cbn [app].
    rewrite <- Hys.
    reflexivity.
Qed.

Lemma app_singleton_eq :
  forall (X : Type) (xs ys : list X) (x y : X),
    xs ++ [x] = ys ++ [y] ->
    xs = ys /\ x = y.
Proof.
  intros X xs ys x y H.
  apply (f_equal (@rev X)) in H.
  repeat rewrite rev_app_distr in H.
  cbn [rev app] in H.
  injection H as Hxy Hrev.
  apply (f_equal (@rev X)) in Hrev.
  repeat rewrite rev_involutive in Hrev.
  subst.
  split; reflexivity.
Qed.

