Theorem all_kcad9_ocaml_open_back_reusable_public_right_operand_nonempty_left_fold_singletons_thm :
  forall (X : Type) (xss : list (list X)),
    Forall (fun xs => xs <> []) xss ->
    all_kcad9_ocaml_open_back_reusable_public_right_operand_nonempty
      (map
        (fun xs =>
          kcad9_concat_ocaml_shape_left_fold
            (@kcad9_empty X) (map kcad9_singleton xs))
        xss).
Proof.
  intros X xss Hxss.
  induction Hxss as [|xs xss Hxs_nonempty _ IH].
  - exact I.
  - destruct xs as [|x xs].
    + contradiction Hxs_nonempty. reflexivity.
    + cbn [map all_kcad9_ocaml_open_back_reusable_public_right_operand_nonempty].
      destruct
        (kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm
           X (@kcad9_empty X) (x :: xs)
           (empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm X))
        as [Hseq [Hreach [Hsmall [Hright Hsuffix]]]].
      split; [exact Hreach|].
      split; [exact Hsmall|].
      split; [exact Hright|].
      split; [exact Hsuffix|].
      split.
      * change
          (kcad9_to_list
            (kcad9_concat_ocaml_shape_left_fold
              (@kcad9_empty X) (map kcad9_singleton (x :: xs))) <> []).
        intro Hempty.
        rewrite Hseq in Hempty.
        discriminate.
      * exact IH.
Qed.

