      kcad9_open_back_pending_public_right_two_acc_front sched /\
    kcad9_open_back_pending_public_right_two_acc_pending sched' = []).

Definition kcad9_open_back_pending_public_right_two_acc_state_eject_step_fuel_two
    {X : Type}
    (sched sched' : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (x : X) : Prop :=
  (exists back_prefix,
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_back sched) =
      back_prefix ++ [x] /\
    kcad9_eject_ocaml_shape_fuel 2
      (kcad9_open_back_pending_public_right_two_acc_back sched) =
    Some
      (kcad9_open_back_pending_public_right_two_acc_back sched', x) /\
    kcad9_open_back_pending_public_right_two_acc_front sched' =
      kcad9_open_back_pending_public_right_two_acc_front sched /\
    kcad9_open_back_pending_public_right_two_acc_pending sched' =
      kcad9_open_back_pending_public_right_two_acc_pending sched) \/
  (exists rest right right_prefix,
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_back sched) = [] /\
    kcad9_open_back_pending_public_right_two_acc_pending sched =
      rest ++ [right] /\
    kcad9_to_list right = right_prefix ++ [x] /\
    kcad9_eject_ocaml_shape_fuel 2 right =
    Some
      (kcad9_open_back_pending_public_right_two_acc_back sched', x) /\
    kcad9_open_back_pending_public_right_two_acc_front sched' =
      kcad9_open_back_pending_public_right_two_acc_front sched /\
    kcad9_open_back_pending_public_right_two_acc_pending sched' = rest) \/
  (exists front_prefix,
    kcad9_open_back_pending_public_right_two_acc_pending sched = [] /\
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_back sched) = [] /\
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_front sched) =
      front_prefix ++ [x] /\
    kcad9_eject_ocaml_shape_fuel 2
      (kcad9_open_back_pending_public_right_two_acc_front sched) =
    Some
      (kcad9_open_back_pending_public_right_two_acc_front sched', x) /\
    kcad9_open_back_pending_public_right_two_acc_pending sched' = [] /\
    kcad9_open_back_pending_public_right_two_acc_back sched' =
      kcad9_open_back_pending_public_right_two_acc_back sched).

Fixpoint kcad9_open_back_pending_public_right_two_acc_state_endpoint_script_expected
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X) (ops : list KCad9EndpointSide)
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  match ops with
  | [] => sched_final = sched /\ xs_final = xs
  | KCad9EndpointFront :: ops' =>
      match xs with
