    + destruct
        (list_unsnoc
          (kcad9_open_back_pending_public_right_two_acc_state_seq sched))
        as [[xs x]|] eqn:Hunsnoc.
      * cbn [kcad9_endpoint_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel.
        assert (Hseq :
          kcad9_open_back_pending_public_right_two_acc_state_seq sched =
