        destruct (IH sched1 xs_final Hinv1)
          as (sched_final & Hscript & Hinv_final & Hseq_final).
        { rewrite Hseq1. exact Hmodel. }
        exists sched_final.
        split.
        -- cbn [kcad9_open_back_pending_public_right_two_acc_state_endpoint_script_expected].
           rewrite Hunsnoc.
           exists sched1.
           split.
           ++ unfold
                kcad9_open_back_pending_public_right_two_acc_state_eject_step_fuel_two.
              exact Hbranch.
           ++ split; [exact Hseq1|].
              rewrite <- Hseq1. exact Hscript.
        -- split; [exact Hinv_final|exact Hseq_final].
