Fixpoint kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X) (ops : list (KCad9TwoAccPublicConcatOp X))
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  match ops with
  | [] => sched_final = sched /\ xs_final = xs
  | KCad9TwoAccPublicConcatPush x :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel
        (kcad9_open_back_pending_public_right_two_acc_state_push x sched)
        (x :: xs) ops' sched_final xs_final
  | KCad9TwoAccPublicConcatInject x :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel
        (kcad9_open_back_pending_public_right_two_acc_state_inject sched x)
        (xs ++ [x]) ops' sched_final xs_final
  | KCad9TwoAccPublicConcatPop :: ops' =>
      match xs with
      | [] => False
      | x :: xs' =>
          exists sched1,
            kcad9_open_back_pending_public_right_two_acc_state_pop_step_fuel_two
              sched sched1 x /\
            kcad9_open_back_pending_public_right_two_acc_state_seq sched1 =
              xs' /\
            kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
              concat_fuel sched1 xs' ops' sched_final xs_final
      end
  | KCad9TwoAccPublicConcatEject :: ops' =>
      match list_unsnoc xs with
      | Some (xs', x) =>
          exists sched1,
            kcad9_open_back_pending_public_right_two_acc_state_eject_step_fuel_two
              sched sched1 x /\
            kcad9_open_back_pending_public_right_two_acc_state_seq sched1 =
              xs' /\
            kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
              concat_fuel sched1 xs' ops' sched_final xs_final
      | None => False
      end
  | KCad9TwoAccPublicConcatAppendRightOperand operand :: ops' =>
      let sched1 :=
        kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_operand
          concat_fuel sched operand in
      kcad9_open_back_pending_public_right_two_acc_state_append_right_operand_payload_count
        concat_fuel sched operand = 0 /\
      sched1 =
        kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
          sched operand /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched1 =
        xs ++ kcad9_to_list operand /\
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel sched1 (xs ++ kcad9_to_list operand)
        ops' sched_final xs_final
  | KCad9TwoAccPublicConcatAppendRightSchedule rsched :: ops' =>
      let sched1 :=
        kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_schedule
          concat_fuel sched rsched in
      kcad9_open_back_pending_public_right_two_acc_state_append_right_schedule_payload_count
        concat_fuel sched rsched = 0 /\
      sched1 =
        kcad9_open_back_pending_public_right_two_acc_state_append_right_schedule
          sched rsched /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched1 =
        xs ++
        kcad9_open_back_pending_public_right_schedule_state_seq rsched /\
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel sched1
        (xs ++
         kcad9_open_back_pending_public_right_schedule_state_seq rsched)
        ops' sched_final xs_final
  end.

Theorem kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_under_nonempty_pending_inv_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (ops : list (KCad9TwoAccPublicConcatOp X))
         (xs_final : list X),
    kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
      sched ->
    kcad9_two_acc_public_concat_script_operands_inv ops ->
    kcad9_two_acc_public_concat_script_model
      (kcad9_open_back_pending_public_right_two_acc_state_seq sched) ops =
      Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel sched
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros concat_fuel X sched ops.
  revert sched.
  induction ops as [|op ops IH]; intros sched xs_final Hinv Hops Hmodel.
  - cbn [kcad9_two_acc_public_concat_script_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split; [split; reflexivity|].
    split; [exact Hinv|reflexivity].
  - destruct op as [x|x| | |operand|rsched].
    + cbn [kcad9_two_acc_public_concat_script_model
           kcad9_two_acc_public_concat_script_operands_inv] in Hmodel, Hops.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_push_nonempty_pending_inv_thm
           X x sched Hinv) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_push_seq_thm
           X x sched) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_push x sched)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_public_concat_script_model
           kcad9_two_acc_public_concat_script_operands_inv] in Hmodel, Hops.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_inject_nonempty_pending_inv_thm
           X sched x Hinv) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_inject_seq_thm
           X sched x) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_inject sched x)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_public_concat_script_operands_inv] in Hops.
      destruct
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        as [|x xs] eqn:Hseq.
      * cbn [kcad9_two_acc_public_concat_script_model] in Hmodel.
        discriminate.
      * cbn [kcad9_two_acc_public_concat_script_model] in Hmodel.
        destruct
          (kcad9_open_back_pending_public_right_two_acc_state_pop_nonempty_pending_step_thm
             X sched x xs Hinv Hseq)
          as (sched1 & Hinv1 & Hseq1 & Hseq_step & Hbranch).
        destruct (IH sched1 xs_final Hinv1 Hops)
          as (sched_final & Hscript & Hinv_final & Hseq_final).
        { rewrite Hseq1. exact Hmodel. }
        exists sched_final.
        split.
        -- cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
           exists sched1.
           split.
           ++ unfold
                kcad9_open_back_pending_public_right_two_acc_state_pop_step_fuel_two.
              exact Hbranch.
           ++ split; [exact Hseq1|].
              rewrite <- Hseq1. exact Hscript.
        -- split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_public_concat_script_operands_inv] in Hops.
      destruct
        (list_unsnoc
          (kcad9_open_back_pending_public_right_two_acc_state_seq sched))
        as [[xs x]|] eqn:Hunsnoc.
      * cbn [kcad9_two_acc_public_concat_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel.
        assert (Hseq :
          kcad9_open_back_pending_public_right_two_acc_state_seq sched =
          xs ++ [x]).
        { apply list_unsnoc_some_app. exact Hunsnoc. }
        destruct
          (kcad9_open_back_pending_public_right_two_acc_state_eject_nonempty_pending_step_thm
             X sched xs x Hinv Hseq)
          as (sched1 & Hinv1 & Hseq1 & Hseq_step & Hbranch).
        destruct (IH sched1 xs_final Hinv1 Hops)
          as (sched_final & Hscript & Hinv_final & Hseq_final).
        { rewrite Hseq1. exact Hmodel. }
        exists sched_final.
        split.
        -- cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
           rewrite Hunsnoc.
           exists sched1.
           split.
           ++ unfold
                kcad9_open_back_pending_public_right_two_acc_state_eject_step_fuel_two.
              exact Hbranch.
           ++ split; [exact Hseq1|].
              rewrite <- Hseq1. exact Hscript.
        -- split; [exact Hinv_final|exact Hseq_final].
      * cbn [kcad9_two_acc_public_concat_script_model] in Hmodel.
        rewrite Hunsnoc in Hmodel. discriminate.
    + cbn [kcad9_two_acc_public_concat_script_model
           kcad9_two_acc_public_concat_script_operands_inv] in Hmodel, Hops.
      destruct Hops as [Hright Hops].
      destruct
        (kcad9_open_back_pending_public_right_two_acc_state_append_right_operand_full_split_nonempty_pending_package_thm
           concat_fuel X sched operand Hinv Hright)
        as [Hpayload [Heq [Hinv1 Hseq1]]].
      set (sched1 :=
        kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_operand
          concat_fuel sched operand).
      fold sched1 in Hpayload, Heq, Hinv1, Hseq1.
      destruct (IH sched1 xs_final Hinv1 Hops)
        as (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
        fold sched1.
        split; [exact Hpayload|].
        split; [exact Heq|].
        split; [exact Hseq1|].
        rewrite <- Hseq1. exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_public_concat_script_model
           kcad9_two_acc_public_concat_script_operands_inv] in Hmodel, Hops.
      destruct Hops as [Hright Hops].
      destruct
        (kcad9_open_back_pending_public_right_two_acc_state_append_right_schedule_full_split_nonempty_pending_package_thm
           concat_fuel X sched rsched Hinv Hright)
        as [Hpayload [Heq [Hinv1 Hseq1]]].
      set (sched1 :=
        kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_schedule
          concat_fuel sched rsched).
      fold sched1 in Hpayload, Heq, Hinv1, Hseq1.
      destruct (IH sched1 xs_final Hinv1 Hops)
        as (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected].
        fold sched1.
        split; [exact Hpayload|].
        split; [exact Heq|].
        split; [exact Hseq1|].
        rewrite <- Hseq1. exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_empty_nonempty_pending_inv_thm :
  forall X : Type,
    kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
      (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
        (@kcad9_open_back_pending_public_right_schedule_state_empty X)).
Proof.
  intros X.
  cbn [kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
       kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
       kcad9_open_back_pending_public_right_schedule_state_empty
       kcad9_open_back_pending_public_right_acc
       kcad9_open_back_pending_public_right_pending
       kcad9_open_back_pending_public_right_two_acc_front
       kcad9_open_back_pending_public_right_two_acc_pending
       kcad9_open_back_pending_public_right_two_acc_back].
  split.
  - apply empty_kcad9_ocaml_open_back_reusable_const_thm.
  - split.
    + exact I.
    + apply empty_kcad9_ocaml_open_back_reusable_const_thm.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_empty_seq_thm :
  forall X : Type,
    kcad9_open_back_pending_public_right_two_acc_state_seq
      (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
        (@kcad9_open_back_pending_public_right_schedule_state_empty X)) = [].
Proof.
  intros X.
  reflexivity.
Qed.

Theorem kcad9_two_acc_public_concat_script_operands_inv_left_fold_singleton_operand_thm :
  forall (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccPublicConcatOp X)),
    kcad9_two_acc_public_concat_script_operands_inv ops ->
    kcad9_two_acc_public_concat_script_operands_inv
      (KCad9TwoAccPublicConcatAppendRightOperand
        (kcad9_concat_ocaml_shape_left_fold
          (@kcad9_empty X) (map kcad9_singleton xs)) :: ops).
Proof.
  intros X xs ops Hops.
  cbn [kcad9_two_acc_public_concat_script_operands_inv].
  split.
  - destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm
         X (@kcad9_empty X) xs
         (empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm X))
      as [_ Hoperand].
    exact Hoperand.
  - exact Hops.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_from_empty_thm :
  forall (concat_fuel : nat) (X : Type)
         (ops : list (KCad9TwoAccPublicConcatOp X))
         (xs_final : list X),
    kcad9_two_acc_public_concat_script_operands_inv ops ->
    kcad9_two_acc_public_concat_script_model [] ops = Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel
        (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
          (@kcad9_open_back_pending_public_right_schedule_state_empty X))
        [] ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros concat_fuel X ops xs_final Hops Hmodel.
  set (sched_empty :=
    kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
      (@kcad9_open_back_pending_public_right_schedule_state_empty X)).
  pose proof
    (kcad9_open_back_pending_public_right_two_acc_state_empty_nonempty_pending_inv_thm
       X) as Hinv.
  pose proof
    (kcad9_open_back_pending_public_right_two_acc_state_empty_seq_thm X)
    as Hseq.
  fold sched_empty in Hinv, Hseq.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_under_nonempty_pending_inv_thm
       concat_fuel X sched_empty ops xs_final Hinv Hops)
    as (sched_final & Hscript & Hinv_final & Hseq_final).
  { rewrite Hseq. exact Hmodel. }
  exists sched_final.
  split.
  - rewrite Hseq in Hscript. exact Hscript.
  - split; [exact Hinv_final|exact Hseq_final].
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_from_empty_left_fold_singletons_thm :
  forall (concat_fuel : nat) (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccPublicConcatOp X))
         (xs_final : list X),
    kcad9_two_acc_public_concat_script_operands_inv ops ->
    kcad9_two_acc_public_concat_script_model xs ops = Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel
        (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
          (@kcad9_open_back_pending_public_right_schedule_state_empty X))
        []
        (KCad9TwoAccPublicConcatAppendRightOperand
          (kcad9_concat_ocaml_shape_left_fold
            (@kcad9_empty X) (map kcad9_singleton xs)) :: ops)
        sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros concat_fuel X xs ops xs_final Hops Hmodel.
  apply
    kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_from_empty_thm.
  - apply
      kcad9_two_acc_public_concat_script_operands_inv_left_fold_singleton_operand_thm.
    exact Hops.
  - cbn [kcad9_two_acc_public_concat_script_model].
    rewrite app_nil_l.
    rewrite kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm.
    exact Hmodel.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_public_concat_then_endpoint_script_expected_from_empty_left_fold_singletons_thm :
  forall (concat_fuel : nat) (X : Type) (xs : list X)
         (concat_ops : list (KCad9TwoAccPublicConcatOp X))
         (endpoint_ops : list KCad9EndpointSide)
         (xs_mid xs_final : list X),
    kcad9_two_acc_public_concat_script_operands_inv concat_ops ->
    kcad9_two_acc_public_concat_script_model xs concat_ops = Some xs_mid ->
    kcad9_endpoint_script_model xs_mid endpoint_ops = Some xs_final ->
    exists sched_mid sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected
        concat_fuel
        (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
          (@kcad9_open_back_pending_public_right_schedule_state_empty X))
        []
        (KCad9TwoAccPublicConcatAppendRightOperand
          (kcad9_concat_ocaml_shape_left_fold
            (@kcad9_empty X) (map kcad9_singleton xs)) :: concat_ops)
        sched_mid xs_mid /\
      kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
        sched_mid /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_mid =
        xs_mid /\
      kcad9_open_back_pending_public_right_two_acc_state_endpoint_script_expected
        sched_mid xs_mid endpoint_ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros concat_fuel X xs concat_ops endpoint_ops xs_mid xs_final
    Hconcat_ops Hconcat_model Hendpoint_model.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_public_concat_script_expected_from_empty_left_fold_singletons_thm
       concat_fuel X xs concat_ops xs_mid Hconcat_ops Hconcat_model)
    as (sched_mid & Hconcat & Hinv_mid & Hseq_mid).
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_endpoint_script_expected_under_nonempty_pending_inv_thm
       X sched_mid endpoint_ops xs_final Hinv_mid)
    as (sched_final & Hendpoint & Hinv_final & Hseq_final).
  { rewrite Hseq_mid. exact Hendpoint_model. }
  exists sched_mid, sched_final.
  split; [exact Hconcat|].
  split; [exact Hinv_mid|].
  split; [exact Hseq_mid|].
  rewrite Hseq_mid in Hendpoint.
  split; [exact Hendpoint|].
  split; [exact Hinv_final|exact Hseq_final].
Qed.

Theorem kcad9_open_back_pending_public_right_schedule_zero_splice_materialize_thm :
  forall (X : Type) (acc : KCadeque9 X)
         (pending : list (KCadeque9 X)),
    inv_kcad9_ocaml_open_back_pending_public_right_schedule acc pending ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc pending) =
    kcad9_to_list acc ++ concat (map kcad9_to_list pending) /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc pending).
Proof.
  intros X acc pending [Hacc Hpending].
  apply
    kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold_reusable_public_right_open_back_reusable_const_thm;
    assumption.
Qed.

Theorem kcad9_open_back_pending_public_right_schedule_enqueue_zero_splice_materialize_thm :
  forall (X : Type) (acc : KCadeque9 X)
         (pending : list (KCadeque9 X)) (right : KCadeque9 X),
    inv_kcad9_ocaml_open_back_pending_public_right_schedule acc pending ->
    inv_kcad9_ocaml_open_back_reusable_public_right_operand right ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc (pending ++ [right])) =
    kcad9_to_list acc ++ concat (map kcad9_to_list pending) ++
      kcad9_to_list right /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
        acc (pending ++ [right])).
Proof.
  intros X acc pending right Hsched Hright.
  destruct
    (kcad9_open_back_pending_public_right_schedule_zero_splice_materialize_thm
       X acc (pending ++ [right])
       (kcad9_open_back_pending_public_right_schedule_enqueue_thm
          X acc pending right Hsched Hright)) as [Hseq Hinv].
  split.
  - change
      (kcad9_to_list
        (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
          acc (pending ++ [right])) =
       kcad9_to_list acc ++ concat (map kcad9_to_list pending) ++
       kcad9_to_list right).
    rewrite Hseq.
    rewrite map_app.
    rewrite concat_app.
    cbn [map concat].
    rewrite app_nil_r.
    rewrite app_assoc.
    reflexivity.
  - exact Hinv.
Qed.

Theorem kcad9_open_back_pending_public_right_schedule_state_zero_splice_materialize_thm :
  forall (X : Type)
         (sched : KCad9OpenBackPendingPublicRightSchedule X),
    kcad9_open_back_pending_public_right_schedule_state_inv sched ->
    kcad9_to_list
      (kcad9_open_back_pending_public_right_schedule_state_zero_splice_materialize
        sched) =
    kcad9_open_back_pending_public_right_schedule_state_seq sched /\
    inv_kcad9_ocaml_open_back_reusable_const
