Theorem kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize_thm :
  forall (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X),
    kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
      sched ->
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
        sched) =
    kcad9_open_back_pending_public_right_two_acc_state_seq sched /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
        sched).
Proof.
  intros X [front pending back] [Hfront [Hpending Hback]].
  cbn [kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
       kcad9_open_back_pending_public_right_two_acc_state_seq
       kcad9_open_back_pending_public_right_two_acc_front
       kcad9_open_back_pending_public_right_two_acc_pending
       kcad9_open_back_pending_public_right_two_acc_back].
  assert (Hall :
    all_kcad9_ocaml_open_back_reusable_public_right_operand
      (pending ++ [back])).
  { apply all_kcad9_ocaml_open_back_reusable_public_right_operand_app.
    - exact Hpending.
    - cbn [all_kcad9_ocaml_open_back_reusable_public_right_operand].
      destruct Hback as [Hreach [Hsmall [Hright Hsuffix]]].
      split; [exact Hreach|].
      split; [exact Hsmall|].
      split; [exact Hright|].
      split; [exact Hsuffix|exact I]. }
  destruct
    (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold_reusable_public_right_open_back_reusable_const_thm
       X front (pending ++ [back])
       (inv_kcad9_ocaml_open_back_reusable_public_right_operand_reusable_const_thm
          X front Hfront)
       Hall) as [Hseq Hinv].
  split.
  - change
      (kcad9_to_list
        (kcad9_concat_ocaml_full_split_open_back_zero_splice_shape_left_fold
          front (pending ++ [back])) =
       kcad9_to_list front ++ concat (map kcad9_to_list pending) ++
       kcad9_to_list back).
    rewrite Hseq.
    rewrite map_app.
    rewrite concat_app.
    cbn [map concat].
    rewrite app_nil_r.
    repeat rewrite app_assoc.
    reflexivity.
  - exact Hinv.
Qed.

