Theorem kcad9_open_back_pending_public_right_two_acc_state_full_split_budget_materialize_package_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X),
    kcad9_open_back_pending_public_right_two_acc_state_full_split_budget
      sched ->
    kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
      concat_fuel sched = 0 /\
