  intros concat_fuel X [front pending back]
    [Hfront [Hpending [Hback Hback_suffix]]].
  cbn [kcad9_open_back_pending_public_right_two_acc_state_full_split_budget
       kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
       kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
       kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
       kcad9_open_back_pending_public_right_two_acc_state_seq
       kcad9_open_back_pending_public_right_two_acc_front
       kcad9_open_back_pending_public_right_two_acc_pending
       kcad9_open_back_pending_public_right_two_acc_back] in *.
  assert (Hall :
    all_kcad9_ocaml_full_split_right_const_suffix_empty (pending ++ [back])).
  { apply all_kcad9_ocaml_full_split_right_const_suffix_empty_app.
    - exact Hpending.
    - cbn [all_kcad9_ocaml_full_split_right_const_suffix_empty].
      split; [exact Hback|].
      split; [exact Hback_suffix|exact I]. }
  split.
  - apply
      kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_splice_payload_count_zero_thm.
    exact Hall.
  - split.
    + apply
        kcad9_concat_ocaml_full_split_open_back_shape_fuel_left_fold_zero_splice_eq_thm.
      exact Hall.
    + split.
      * change
          (kcad9_to_list
