    as [Hpayload [Heq [Hseq Hinv]]].
  split; [exact Hpayload|].
  split; [exact Heq|].
  split.
  - rewrite Hseq. exact Hseq_final.
  - exact Hinv.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_public_concat_then_endpoint_full_split_if_left_operand_from_empty_left_fold_singletons_thm :
  forall (concat_fuel : nat) (X : Type) (xs : list X)
         (concat_ops : list (KCad9TwoAccPublicConcatOp X))
         (endpoint_ops : list KCad9EndpointSide)
         (xs_mid xs_final : list X),
    kcad9_two_acc_public_concat_script_operands_inv concat_ops ->
