        xs_final /\
      (kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
        sched_final ->
       kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
        concat_fuel sched_final = 0 /\
       kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
        concat_fuel sched_final =
       kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
        sched_final /\
       kcad9_to_list
        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_final) = xs_final /\
       inv_kcad9_ocaml_open_back_reusable_const
        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_final)).
Proof.
  intros concat_fuel X xs concat_ops endpoint_ops xs_mid xs_final
    Hconcat_ops Hconcat_model Hendpoint_model.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_public_concat_then_endpoint_script_expected_from_empty_left_fold_singletons_thm
       concat_fuel X xs concat_ops endpoint_ops xs_mid xs_final
       Hconcat_ops Hconcat_model Hendpoint_model)
    as (sched_mid & sched_final & Hconcat & _Hinv_mid & _Hseq_mid &
        Hendpoint & Hinv_final & Hseq_final).
  exists sched_mid, sched_final.
  split; [exact Hconcat|].
  split; [exact Hendpoint|].
  split; [exact Hinv_final|].
  split; [exact Hseq_final|].
  intro Hleft_final.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_left_operand_full_split_materialize_package_thm
       concat_fuel X sched_final Hleft_final)
    as [Hpayload [Heq [Hseq Hinv]]].
  split; [exact Hpayload|].
  split; [exact Heq|].
  split.
  - rewrite Hseq. exact Hseq_final.
  - exact Hinv.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_empty_left_fold_singletons_full_split_package_thm :
  forall (concat_fuel : nat) (X : Type) (xs : list X),
    let sched0 :=
      kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
        (@kcad9_open_back_pending_public_right_schedule_state_empty X) in
    let operand :=
      kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs) in
    let sched :=
      kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
        sched0 operand in
    kcad9_open_back_pending_public_right_two_acc_state_append_right_operand_payload_count
      concat_fuel sched0 operand = 0 /\
    kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_operand
      concat_fuel sched0 operand = sched /\
    kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
      sched /\
    kcad9_open_back_pending_public_right_two_acc_state_seq sched = xs /\
    kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
      concat_fuel sched = 0 /\
    kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
      concat_fuel sched =
    kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
      sched /\
    kcad9_to_list
      (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
        concat_fuel sched) = xs /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
        concat_fuel sched).
Proof.
  intros concat_fuel X xs.
  set (sched0 :=
    kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
      (@kcad9_open_back_pending_public_right_schedule_state_empty X)).
  set (operand :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton xs)).
  set (sched :=
    kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
      sched0 operand).
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_open_back_reusable_public_right_operand_seq_thm
       X (@kcad9_empty X) xs
       (empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm X))
    as [Hoperand_seq Hoperand].
  assert (Hsched0 :
    kcad9_open_back_pending_public_right_two_acc_state_inv sched0).
  { subst sched0.
    apply kcad9_open_back_pending_public_right_two_acc_state_nonempty_pending_inv_inv_thm.
    apply kcad9_open_back_pending_public_right_two_acc_state_empty_nonempty_pending_inv_thm. }
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_append_right_operand_full_split_package_thm
       concat_fuel X sched0 operand Hsched0 Hoperand)
    as [Happend_payload [Happend_eq [_ Happend_seq]]].
  assert (Hright_sched :
    kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
      sched).
  { subst sched.
    cbn [kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
         kcad9_open_back_pending_public_right_two_acc_state_replace_back
         kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
         kcad9_open_back_pending_public_right_schedule_state_empty
         kcad9_concat_ocaml_full_split_open_back_zero_splice_shape
         kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
         kcad9_open_back_pending_public_right_acc
         kcad9_open_back_pending_public_right_pending
         kcad9_open_back_pending_public_right_two_acc_front
         kcad9_open_back_pending_public_right_two_acc_pending
         kcad9_open_back_pending_public_right_two_acc_back].
    split.
    - apply empty_kcad9_ocaml_open_back_reusable_public_right_operand_thm.
    - split; [exact I|exact Hoperand]. }
  assert (Hseq_sched :
    kcad9_open_back_pending_public_right_two_acc_state_seq sched = xs).
  { subst sched.
    rewrite <- Happend_eq.
    rewrite Happend_seq.
    subst sched0 operand.
    rewrite kcad9_open_back_pending_public_right_two_acc_state_empty_seq_thm.
    rewrite kcad9_concat_ocaml_shape_left_fold_singletons_seq_thm.
    reflexivity. }
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize_package_thm
       concat_fuel X sched Hright_sched)
    as [Hmaterialize_payload [Hmaterialize_eq [Hmaterialize_seq Hmaterialize_inv]]].
  split; [exact Happend_payload|].
  split; [exact Happend_eq|].
  split; [exact Hright_sched|].
  split; [exact Hseq_sched|].
  split; [exact Hmaterialize_payload|].
  split; [exact Hmaterialize_eq|].
  split.
  - change
      (kcad9_to_list
        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched) = xs).
    rewrite Hmaterialize_seq. exact Hseq_sched.
  - exact Hmaterialize_inv.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_empty_left_fold_singletons_public_growth_full_split_package_thm :
  forall (concat_fuel : nat) (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccPublicOp X)) (xs_final : list X),
    kcad9_two_acc_public_script_growth_only ops ->
    kcad9_two_acc_public_script_model xs ops = Some xs_final ->
    let sched0 :=
      kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
        (@kcad9_open_back_pending_public_right_schedule_state_empty X) in
    let operand :=
      kcad9_concat_ocaml_shape_left_fold
        (@kcad9_empty X) (map kcad9_singleton xs) in
    let sched_start :=
      kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
        sched0 operand in
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_append_right_operand_payload_count
        concat_fuel sched0 operand = 0 /\
      kcad9_open_back_pending_public_right_two_acc_state_full_split_append_right_operand
        concat_fuel sched0 operand = sched_start /\
      kcad9_open_back_pending_public_right_two_acc_state_public_script_expected
        sched_start xs ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
        concat_fuel sched_final = 0 /\
      kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
        concat_fuel sched_final =
      kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
        sched_final /\
      kcad9_to_list
        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_final) = xs_final /\
      inv_kcad9_ocaml_open_back_reusable_const
        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_final).
Proof.
  intros concat_fuel X xs ops xs_final Hgrowth Hmodel.
  set (sched0 :=
    kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
      (@kcad9_open_back_pending_public_right_schedule_state_empty X)).
  set (operand :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton xs)).
  set (sched_start :=
    kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
      sched0 operand).
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_empty_left_fold_singletons_full_split_package_thm
       concat_fuel X xs)
    as [Happend_payload [Happend_eq [Hright_start [Hseq_start _]]]].
  cbn zeta in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold sched0 in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold operand in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold sched_start in Happend_eq, Hright_start, Hseq_start.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_public_growth_script_expected_under_right_operand_inv_thm
       X sched_start ops xs_final Hright_start Hgrowth)
    as (sched_final & Hscript & Hright_final & Hseq_final).
  { rewrite Hseq_start. exact Hmodel. }
  rewrite Hseq_start in Hscript.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize_package_thm
       concat_fuel X sched_final Hright_final)
    as [Hmaterialize_payload [Hmaterialize_eq [Hmaterialize_seq Hmaterialize_inv]]].
  exists sched_final.
  split; [exact Happend_payload|].
  split; [exact Happend_eq|].
  split; [exact Hscript|].
  split; [exact Hright_final|].
  split; [exact Hseq_final|].
  split; [exact Hmaterialize_payload|].
  split; [exact Hmaterialize_eq|].
  split.
  - rewrite Hmaterialize_seq. exact Hseq_final.
  - exact Hmaterialize_inv.
Qed.

Inductive KCad9TwoAccRightGrowthOp (X : Type) : Type :=
| KCad9TwoAccRightGrowthPush : X -> KCad9TwoAccRightGrowthOp X
| KCad9TwoAccRightGrowthInject : X -> KCad9TwoAccRightGrowthOp X
| KCad9TwoAccRightGrowthAppendSingletonFolds :
    list (list X) -> KCad9TwoAccRightGrowthOp X
| KCad9TwoAccRightGrowthConcatRightState :
    KCad9OpenBackPendingPublicRightTwoAccSchedule X ->
    KCad9TwoAccRightGrowthOp X.

Arguments KCad9TwoAccRightGrowthPush {X} _.
Arguments KCad9TwoAccRightGrowthInject {X} _.
Arguments KCad9TwoAccRightGrowthAppendSingletonFolds {X} _.
Arguments KCad9TwoAccRightGrowthConcatRightState {X} _.

Fixpoint kcad9_two_acc_right_growth_script_operands_inv
    {X : Type} (ops : list (KCad9TwoAccRightGrowthOp X)) : Prop :=
  match ops with
  | [] => True
  | KCad9TwoAccRightGrowthPush _ :: ops' =>
      kcad9_two_acc_right_growth_script_operands_inv ops'
  | KCad9TwoAccRightGrowthInject _ :: ops' =>
      kcad9_two_acc_right_growth_script_operands_inv ops'
  | KCad9TwoAccRightGrowthAppendSingletonFolds _ :: ops' =>
      kcad9_two_acc_right_growth_script_operands_inv ops'
  | KCad9TwoAccRightGrowthConcatRightState rsched :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
        rsched /\
      kcad9_two_acc_right_growth_script_operands_inv ops'
  end.

Fixpoint kcad9_two_acc_right_growth_script_model {X : Type}
    (xs : list X) (ops : list (KCad9TwoAccRightGrowthOp X))
    : option (list X) :=
  match ops with
  | [] => Some xs
  | KCad9TwoAccRightGrowthPush x :: ops' =>
      kcad9_two_acc_right_growth_script_model (x :: xs) ops'
  | KCad9TwoAccRightGrowthInject x :: ops' =>
      kcad9_two_acc_right_growth_script_model (xs ++ [x]) ops'
  | KCad9TwoAccRightGrowthAppendSingletonFolds xss :: ops' =>
      kcad9_two_acc_right_growth_script_model (xs ++ concat xss) ops'
  | KCad9TwoAccRightGrowthConcatRightState rsched :: ops' =>
      kcad9_two_acc_right_growth_script_model
        (xs ++
         kcad9_open_back_pending_public_right_two_acc_state_seq rsched)
        ops'
  end.

Fixpoint kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X) (ops : list (KCad9TwoAccRightGrowthOp X))
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  match ops with
  | [] => sched_final = sched /\ xs_final = xs
  | KCad9TwoAccRightGrowthPush x :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        (kcad9_open_back_pending_public_right_two_acc_state_push x sched)
        (x :: xs) ops' sched_final xs_final
  | KCad9TwoAccRightGrowthInject x :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        (kcad9_open_back_pending_public_right_two_acc_state_inject sched x)
        (xs ++ [x]) ops' sched_final xs_final
  | KCad9TwoAccRightGrowthAppendSingletonFolds xss :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        (kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds
          sched xss)
        (xs ++ concat xss) ops' sched_final xs_final
  | KCad9TwoAccRightGrowthConcatRightState rsched :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        (kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule
          sched rsched)
        (xs ++
         kcad9_open_back_pending_public_right_two_acc_state_seq rsched)
        ops' sched_final xs_final
  end.

Theorem kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected_under_right_operand_inv_thm :
  forall (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (ops : list (KCad9TwoAccRightGrowthOp X)) (xs_final : list X),
    kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
      sched ->
    kcad9_two_acc_right_growth_script_operands_inv ops ->
    kcad9_two_acc_right_growth_script_model
      (kcad9_open_back_pending_public_right_two_acc_state_seq sched) ops =
      Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        sched
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros X sched ops.
  revert sched.
  induction ops as [|op ops IH]; intros sched xs_final Hinv Hops Hmodel.
  - cbn [kcad9_two_acc_right_growth_script_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split; [split; reflexivity|].
    split; [exact Hinv|reflexivity].
  - destruct op as [x|x|xss|rsched].
    + cbn [kcad9_two_acc_right_growth_script_model
           kcad9_two_acc_right_growth_script_operands_inv] in Hmodel, Hops.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_push_right_operand_inv_thm
           X x sched Hinv) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_push_seq_thm
           X x sched) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_push x sched)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_right_growth_script_model
           kcad9_two_acc_right_growth_script_operands_inv] in Hmodel, Hops.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_inject_right_operand_inv_thm
           X sched x Hinv) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_inject_seq_thm
           X sched x) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_inject sched x)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_right_growth_script_model
           kcad9_two_acc_right_growth_script_operands_inv] in Hmodel, Hops.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds_right_operand_inv_thm
           X sched xss Hinv) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds_seq_thm
           X sched xss) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds
             sched xss)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
    + cbn [kcad9_two_acc_right_growth_script_model
           kcad9_two_acc_right_growth_script_operands_inv] in Hmodel, Hops.
      destruct Hops as [Hright Hops].
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule_right_operand_inv_thm
           X sched rsched Hinv Hright) as Hinv1.
      pose proof
        (kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule_seq_thm
           X sched rsched) as Hseq1.
      destruct
        (IH
           (kcad9_open_back_pending_public_right_two_acc_state_concat_right_two_acc_schedule
             sched rsched)
           xs_final Hinv1 Hops) as
        (sched_final & Hscript & Hinv_final & Hseq_final).
      { rewrite Hseq1. exact Hmodel. }
      rewrite Hseq1 in Hscript.
      exists sched_final.
      split.
      * cbn [kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected].
        exact Hscript.
      * split; [exact Hinv_final|exact Hseq_final].
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected_under_left_operand_inv_thm :
  forall (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (ops : list (KCad9TwoAccRightGrowthOp X)) (xs_final : list X),
    kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
      sched ->
    kcad9_two_acc_right_growth_script_operands_inv ops ->
    kcad9_two_acc_right_growth_script_model
      (kcad9_open_back_pending_public_right_two_acc_state_seq sched) ops =
      Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
        sched
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        ops sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros X sched ops.
  revert sched.
