Inductive KCad9TwoAccGrowthEndpointPhase (X : Type) : Type :=
| KCad9TwoAccGrowthEndpointPhaseStep :
    list (KCad9TwoAccRightGrowthOp X) ->
    list KCad9EndpointSide ->
    KCad9TwoAccGrowthEndpointPhase X.

Arguments KCad9TwoAccGrowthEndpointPhaseStep {X} _ _.

Fixpoint kcad9_two_acc_growth_endpoint_phase_operands_inv {X : Type}
    (phases : list (KCad9TwoAccGrowthEndpointPhase X)) : Prop :=
  match phases with
  | [] => True
  | KCad9TwoAccGrowthEndpointPhaseStep growth_ops _ :: phases' =>
      kcad9_two_acc_right_growth_script_operands_inv growth_ops /\
      kcad9_two_acc_growth_endpoint_phase_operands_inv phases'
  end.

Fixpoint kcad9_two_acc_growth_endpoint_phase_model {X : Type}
    (xs : list X) (phases : list (KCad9TwoAccGrowthEndpointPhase X))
    : option (list X) :=
  match phases with
  | [] => Some xs
  | KCad9TwoAccGrowthEndpointPhaseStep growth_ops endpoint_ops :: phases' =>
      match kcad9_two_acc_right_growth_script_model xs growth_ops with
      | Some xs_mid =>
          match kcad9_endpoint_script_model xs_mid endpoint_ops with
          | Some xs_after =>
              kcad9_two_acc_growth_endpoint_phase_model xs_after phases'
          | None => None
          end
      | None => None
      end
  end.

Fixpoint kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected
    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X) (phases : list (KCad9TwoAccGrowthEndpointPhase X))
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  match phases with
  | [] => sched_final = sched /\ xs_final = xs
  | KCad9TwoAccGrowthEndpointPhaseStep growth_ops endpoint_ops :: phases' =>
      exists sched_mid sched_after xs_mid xs_after,
        kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
          sched xs growth_ops sched_mid xs_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
          sched_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_seq sched_mid =
          xs_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
          concat_fuel sched_mid = 0 /\
        kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_mid =
        kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
          sched_mid /\
        kcad9_endpoint_script_expected 2
          (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
            concat_fuel sched_mid)
          xs_mid endpoint_ops
          (kcad9_open_back_pending_public_right_two_acc_front sched_after)
          xs_after /\
        kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
          sched_after /\
        kcad9_open_back_pending_public_right_two_acc_state_seq sched_after =
          xs_after /\
        kcad9_open_back_pending_public_right_two_acc_pending sched_after =
          [] /\
        kcad9_open_back_pending_public_right_two_acc_back sched_after =
          @kcad9_empty X /\
        kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected
          concat_fuel sched_after xs_after phases' sched_final xs_final
  end.

Theorem kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected_under_left_operand_inv_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (phases : list (KCad9TwoAccGrowthEndpointPhase X))
         (xs_final : list X),
    kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
      sched ->
    kcad9_two_acc_growth_endpoint_phase_operands_inv phases ->
    kcad9_two_acc_growth_endpoint_phase_model
      (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
      phases = Some xs_final ->
    exists sched_final,
      kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected
        concat_fuel sched
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        phases sched_final xs_final /\
      kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
        sched_final /\
      kcad9_open_back_pending_public_right_two_acc_state_seq sched_final =
        xs_final.
Proof.
  intros concat_fuel X sched phases.
  revert sched.
  induction phases as [|phase phases IH];
    intros sched xs_final Hsched Hphases Hmodel.
  - cbn [kcad9_two_acc_growth_endpoint_phase_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split.
    + cbn [kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected].
      split; reflexivity.
    + split; [exact Hsched|reflexivity].
  - destruct phase as [growth_ops endpoint_ops].
    cbn [kcad9_two_acc_growth_endpoint_phase_operands_inv
         kcad9_two_acc_growth_endpoint_phase_model] in Hphases, Hmodel.
    destruct Hphases as [Hgrowth_ops Hphases].
    destruct
      (kcad9_two_acc_right_growth_script_model
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        growth_ops) as [xs_mid|] eqn:Hgrowth_model;
      try discriminate.
    destruct (kcad9_endpoint_script_model xs_mid endpoint_ops)
      as [xs_after|] eqn:Hendpoint_model;
      try discriminate.
    destruct
      (kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected_under_left_operand_inv_thm
         X sched growth_ops xs_mid Hsched Hgrowth_ops Hgrowth_model)
      as (sched_mid & Hgrowth & Hleft_mid & Hseq_mid).
    destruct
      (kcad9_endpoint_script_expected_fuel_two_under_full_split_two_acc_left_operand_state_reenter_thm
         concat_fuel X sched_mid endpoint_ops xs_after Hleft_mid)
      as (Hpayload & Heq & sched_after & Hendpoint & Hleft_after &
          Hseq_after & Hpending_after & Hback_after).
    { rewrite Hseq_mid. exact Hendpoint_model. }
    rewrite Hseq_mid in Hendpoint.
    destruct
      (IH sched_after xs_final Hleft_after Hphases)
      as (sched_final & Hrest & Hleft_final & Hseq_final).
    { rewrite Hseq_after. exact Hmodel. }
    rewrite Hseq_after in Hrest.
    exists sched_final.
    split.
    + cbn [kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected].
      exists sched_mid, sched_after, xs_mid, xs_after.
      split; [exact Hgrowth|].
      split; [exact Hleft_mid|].
      split; [exact Hseq_mid|].
      split; [exact Hpayload|].
      split; [exact Heq|].
      split; [exact Hendpoint|].
      split; [exact Hleft_after|].
      split; [exact Hseq_after|].
      split; [exact Hpending_after|].
      split; [exact Hback_after|exact Hrest].
    + split; [exact Hleft_final|exact Hseq_final].
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected_under_left_operand_inv_front_refill_depth_bound_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (phases : list (KCad9TwoAccGrowthEndpointPhase X))
         (xs_final : list X),
