        (kcad9_open_back_pending_public_right_two_acc_front sched_final) /\
      inv_kcad9_ocaml_middle_depth_bound 1
        (kcad9_open_back_pending_public_right_two_acc_front sched_final).
Proof.
  intros concat_fuel X sched phases.
  revert sched.
  induction phases as [|phase phases IH];
    intros sched xs_final Hsched Hfront_refill Hphases Hmodel.
  - cbn [kcad9_two_acc_growth_endpoint_phase_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split.
    + cbn [kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected].
      split; reflexivity.
    + split; [exact Hsched|].
      split; [reflexivity|].
      split; [exact Hfront_refill|].
      apply inv_kcad9_ocaml_refill_depth_bound_middle_depth_bound_thm.
      exact Hfront_refill.
  - destruct phase as [growth_ops endpoint_ops].
    cbn [kcad9_two_acc_growth_endpoint_phase_operands_inv
         kcad9_two_acc_growth_endpoint_phase_model] in Hphases, Hmodel.
    destruct Hphases as [Hgrowth_ops Hphases].
    destruct
      (kcad9_two_acc_right_growth_script_model
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
        growth_ops) as [xs_mid|] eqn:Hgrowth_model;
      try discriminate.
    destruct (kcad9_endpoint_script_model xs_mid endpoint_ops)
      as [xs_after|] eqn:Hendpoint_model;
      try discriminate.
    destruct
      (kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected_under_left_operand_inv_front_refill_depth_bound_thm
         X sched growth_ops xs_mid Hsched Hfront_refill Hgrowth_ops
         Hgrowth_model)
      as (sched_mid & Hgrowth & Hleft_mid & Hseq_mid &
          Hfront_mid).
    destruct
      (kcad9_endpoint_script_expected_fuel_two_under_full_split_two_acc_left_operand_state_refill_depth_reenter_thm
         concat_fuel X sched_mid endpoint_ops xs_after Hleft_mid
         Hfront_mid)
      as (Hpayload & Heq & _Hseq_materialized & _Hinv_materialized &
          _Hrefill_materialized & _Hdepth_materialized &
          sched_after & Hendpoint & Hleft_after & Hseq_after &
          Hpending_after & Hback_after & Hfront_after_refill &
          Hfront_after_depth).
    { rewrite Hseq_mid. exact Hendpoint_model. }
    rewrite Hseq_mid in Hendpoint.
    destruct
      (IH sched_after xs_final Hleft_after Hfront_after_refill Hphases)
      as (sched_final & Hrest & Hleft_final & Hseq_final &
          Hfront_final_refill & Hfront_final_depth).
    { rewrite Hseq_after. exact Hmodel. }
    rewrite Hseq_after in Hrest.
    exists sched_final.
    split.
    + cbn [kcad9_open_back_pending_public_right_two_acc_state_growth_endpoint_phase_expected].
      exists sched_mid, sched_after, xs_mid, xs_after.
      split; [exact Hgrowth|].
      split; [exact Hleft_mid|].
      split; [exact Hseq_mid|].
      split; [exact Hpayload|].
      split; [exact Heq|].
      split; [exact Hendpoint|].
      split; [exact Hleft_after|].
      split; [exact Hseq_after|].
      split; [exact Hpending_after|].
      split; [exact Hback_after|exact Hrest].
    + split; [exact Hleft_final|].
      split; [exact Hseq_final|].
      split; [exact Hfront_final_refill|exact Hfront_final_depth].
Qed.

