Inductive KCad9TwoAccScheduledPublicOp (X : Type) : Type :=
| KCad9TwoAccScheduledPublicPush : X -> KCad9TwoAccScheduledPublicOp X
| KCad9TwoAccScheduledPublicInject : X -> KCad9TwoAccScheduledPublicOp X
| KCad9TwoAccScheduledPublicAppendSingletonFolds :
    list (list X) -> KCad9TwoAccScheduledPublicOp X
| KCad9TwoAccScheduledPublicConcatRightState :
    KCad9OpenBackPendingPublicRightTwoAccSchedule X ->
    KCad9TwoAccScheduledPublicOp X
| KCad9TwoAccScheduledPublicPop : KCad9TwoAccScheduledPublicOp X
| KCad9TwoAccScheduledPublicEject : KCad9TwoAccScheduledPublicOp X.

Arguments KCad9TwoAccScheduledPublicPush {X} _.
Arguments KCad9TwoAccScheduledPublicInject {X} _.
Arguments KCad9TwoAccScheduledPublicAppendSingletonFolds {X} _.
Arguments KCad9TwoAccScheduledPublicConcatRightState {X} _.
Arguments KCad9TwoAccScheduledPublicPop {X}.
Arguments KCad9TwoAccScheduledPublicEject {X}.

Fixpoint kcad9_two_acc_scheduled_public_script_operands_inv
    {X : Type} (ops : list (KCad9TwoAccScheduledPublicOp X)) : Prop :=
  match ops with
  | [] => True
  | KCad9TwoAccScheduledPublicPush _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  | KCad9TwoAccScheduledPublicInject _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  | KCad9TwoAccScheduledPublicAppendSingletonFolds _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  | KCad9TwoAccScheduledPublicConcatRightState rsched :: ops' =>
      kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv
        rsched /\
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  | KCad9TwoAccScheduledPublicPop :: ops' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  | KCad9TwoAccScheduledPublicEject :: ops' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops'
  end.

Fixpoint kcad9_two_acc_scheduled_public_script_model {X : Type}
    (xs : list X) (ops : list (KCad9TwoAccScheduledPublicOp X))
    : option (list X) :=
  match ops with
  | [] => Some xs
  | KCad9TwoAccScheduledPublicPush x :: ops' =>
      kcad9_two_acc_scheduled_public_script_model (x :: xs) ops'
  | KCad9TwoAccScheduledPublicInject x :: ops' =>
      kcad9_two_acc_scheduled_public_script_model (xs ++ [x]) ops'
  | KCad9TwoAccScheduledPublicAppendSingletonFolds xss :: ops' =>
      kcad9_two_acc_scheduled_public_script_model (xs ++ concat xss) ops'
  | KCad9TwoAccScheduledPublicConcatRightState rsched :: ops' =>
      kcad9_two_acc_scheduled_public_script_model
        (xs ++
         kcad9_open_back_pending_public_right_two_acc_state_seq rsched)
        ops'
  | KCad9TwoAccScheduledPublicPop :: ops' =>
      match xs with
      | [] => None
      | _ :: xs' => kcad9_two_acc_scheduled_public_script_model xs' ops'
      end
  | KCad9TwoAccScheduledPublicEject :: ops' =>
      match list_unsnoc xs with
      | Some (xs', _) =>
          kcad9_two_acc_scheduled_public_script_model xs' ops'
      | None => None
      end
  end.

Fixpoint kcad9_two_acc_scheduled_public_script_growth_only
    {X : Type} (ops : list (KCad9TwoAccScheduledPublicOp X)) : Prop :=
  match ops with
  | [] => True
  | KCad9TwoAccScheduledPublicPush _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_growth_only ops'
  | KCad9TwoAccScheduledPublicInject _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_growth_only ops'
  | KCad9TwoAccScheduledPublicAppendSingletonFolds _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_growth_only ops'
  | KCad9TwoAccScheduledPublicConcatRightState _ :: ops' =>
      kcad9_two_acc_scheduled_public_script_growth_only ops'
  | KCad9TwoAccScheduledPublicPop :: _ => False
  | KCad9TwoAccScheduledPublicEject :: _ => False
  end.

Fixpoint kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
    {X : Type} (ops : list (KCad9TwoAccScheduledPublicOp X))
    : list (KCad9TwoAccRightGrowthOp X) :=
  match ops with
  | [] => []
  | KCad9TwoAccScheduledPublicPush x :: ops' =>
      KCad9TwoAccRightGrowthPush x ::
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  | KCad9TwoAccScheduledPublicInject x :: ops' =>
      KCad9TwoAccRightGrowthInject x ::
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  | KCad9TwoAccScheduledPublicAppendSingletonFolds xss :: ops' =>
      KCad9TwoAccRightGrowthAppendSingletonFolds xss ::
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  | KCad9TwoAccScheduledPublicConcatRightState rsched :: ops' =>
      KCad9TwoAccRightGrowthConcatRightState rsched ::
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  | KCad9TwoAccScheduledPublicPop :: ops' =>
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  | KCad9TwoAccScheduledPublicEject :: ops' =>
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops'
  end.

Definition kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_growth_script_expected
    {X : Type}
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X) (ops : list (KCad9TwoAccScheduledPublicOp X))
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected
    sched xs
    (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
       ops)
    sched_final xs_final.

Theorem kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script_operands_inv_thm :
  forall (X : Type) (ops : list (KCad9TwoAccScheduledPublicOp X)),
    kcad9_two_acc_scheduled_public_script_operands_inv ops ->
    kcad9_two_acc_scheduled_public_script_growth_only ops ->
    kcad9_two_acc_right_growth_script_operands_inv
      (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops).
Proof.
  intros X ops.
  induction ops as [|op ops IH]; intros Hops Hgrowth.
  - exact I.
  - destruct op as [x|x|xss|rsched| |];
      cbn [kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_scheduled_public_script_growth_only
           kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
           kcad9_two_acc_right_growth_script_operands_inv] in *;
      try contradiction.
    + apply IH; assumption.
    + apply IH; assumption.
    + apply IH; assumption.
    + destruct Hops as [Hright Hops].
      split; [exact Hright|].
      apply IH; assumption.
Qed.

Theorem kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script_model_thm :
  forall (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccScheduledPublicOp X)),
    kcad9_two_acc_scheduled_public_script_growth_only ops ->
    kcad9_two_acc_right_growth_script_model xs
      (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops) =
    kcad9_two_acc_scheduled_public_script_model xs ops.
Proof.
  intros X xs ops.
  revert xs.
  induction ops as [|op ops IH]; intros xs Hgrowth.
  - reflexivity.
  - destruct op as [x|x|xss|rsched| |];
      cbn [kcad9_two_acc_scheduled_public_script_growth_only
           kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
           kcad9_two_acc_right_growth_script_model
           kcad9_two_acc_scheduled_public_script_model] in *;
      try contradiction;
      apply IH;
      exact Hgrowth.
Qed.

Theorem kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_growth_script_left_operand_front_middle_depth_materialize_reenter_middle_depth_bound_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (ops : list (KCad9TwoAccScheduledPublicOp X))
         (xs_final : list X),
