    Hinv Hfront_depth Hops Hgrowth Hmodel.
  assert (Hright_ops :
    kcad9_two_acc_right_growth_script_operands_inv
      (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops)).
  { apply
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script_operands_inv_thm;
      assumption. }
  assert (Hright_model :
    kcad9_two_acc_right_growth_script_model
      (kcad9_open_back_pending_public_right_two_acc_state_seq sched)
      (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
        ops) = Some xs_final).
  { rewrite
      kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script_model_thm;
      [exact Hmodel|exact Hgrowth]. }
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_right_growth_script_expected_under_left_operand_inv_front_middle_depth_bound_thm
       X sched
       (kcad9_two_acc_scheduled_public_growth_script_as_right_growth_script
         ops)
       xs_final Hinv Hfront_depth Hright_ops Hright_model)
    as (sched_final & Hscript & Hinv_final & Hseq_final &
        Hfront_final).
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_left_operand_full_split_materialize_reenter_middle_depth_bound_thm
       concat_fuel X sched_final Hinv_final Hfront_final)
