        Hmaterialized_depth & Hreenter_inv & Hreenter_seq &
        Hreenter_front_depth).
  rewrite Hseq_final in Hseq_materialized, Hreenter_seq.
  exists sched_final.
  unfold
    kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_growth_script_expected.
  split; [exact Hscript|].
  split; [exact Hinv_final|].
  split; [exact Hseq_final|].
  cbn zeta.
  split; [exact Hpayload|].
  split; [exact Heq|].
  split; [exact Hseq_materialized|].
  split; [exact Hmaterialized_inv|].
  split; [exact Hmaterialized_depth|].
  split; [exact Hreenter_inv|].
  split; [exact Hreenter_seq|exact Hreenter_front_depth].
Qed.

