Definition kcad9_two_acc_public_concat_op_as_scheduled_public_op
    {X : Type} (op : KCad9TwoAccPublicConcatOp X)
    : KCad9TwoAccScheduledPublicOp X :=
  match op with
  | KCad9TwoAccPublicConcatPush x =>
      KCad9TwoAccScheduledPublicPush x
  | KCad9TwoAccPublicConcatInject x =>
      KCad9TwoAccScheduledPublicInject x
  | KCad9TwoAccPublicConcatPop =>
      KCad9TwoAccScheduledPublicPop
  | KCad9TwoAccPublicConcatEject =>
      KCad9TwoAccScheduledPublicEject
  | KCad9TwoAccPublicConcatAppendRightOperand operand =>
      KCad9TwoAccScheduledPublicConcatRightState
        (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
          (kcad9_open_back_pending_public_right_schedule_state_reenter
            operand))
  | KCad9TwoAccPublicConcatAppendRightSchedule rsched =>
      KCad9TwoAccScheduledPublicConcatRightState
        (kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
          rsched)
  end.

