  cbn [kcad9_open_back_pending_public_right_schedule_state_right_operand_inv
       kcad9_open_back_pending_public_right_schedule_state_reenter
       kcad9_open_back_pending_public_right_acc
       kcad9_open_back_pending_public_right_pending
       all_kcad9_ocaml_open_back_reusable_public_right_operand].
  split; [exact Hacc|exact I].
Qed.

Theorem kcad9_two_acc_public_concat_script_as_scheduled_public_script_operands_inv_thm :
  forall (X : Type) (ops : list (KCad9TwoAccPublicConcatOp X)),
    kcad9_two_acc_public_concat_script_operands_inv ops ->
    kcad9_two_acc_scheduled_public_script_operands_inv
      (kcad9_two_acc_public_concat_script_as_scheduled_public_script ops).
Proof.
  intros X ops.
  induction ops as [|op ops IH]; intros Hops.
  - exact I.
  - destruct op as [x|x| | |operand|rsched];
      cbn [kcad9_two_acc_public_concat_script_as_scheduled_public_script
           kcad9_two_acc_public_concat_op_as_scheduled_public_op map
           kcad9_two_acc_public_concat_script_operands_inv
           kcad9_two_acc_scheduled_public_script_operands_inv] in *.
    + apply IH. exact Hops.
    + apply IH. exact Hops.
    + apply IH. exact Hops.
    + apply IH. exact Hops.
    + destruct Hops as [Hoperand Hops].
      split.
      * apply kcad9_open_back_pending_public_right_two_acc_state_from_single_acc_right_operand_inv_thm.
        apply kcad9_open_back_pending_public_right_schedule_state_reenter_right_operand_inv_thm.
        exact Hoperand.
      * apply IH. exact Hops.
    + destruct Hops as [Hrsched Hops].
      split.
      * apply kcad9_open_back_pending_public_right_two_acc_state_from_single_acc_right_operand_inv_thm.
        exact Hrsched.
      * apply IH. exact Hops.
