Theorem kcad9_two_acc_public_concat_script_as_scheduled_public_script_model_thm :
  forall (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccPublicConcatOp X)),
    kcad9_two_acc_scheduled_public_script_model xs
      (kcad9_two_acc_public_concat_script_as_scheduled_public_script ops) =
    kcad9_two_acc_public_concat_script_model xs ops.
Proof.
  intros X xs ops.
  revert xs.
  induction ops as [|op ops IH]; intros xs.
  - reflexivity.
  - destruct op as [x|x| | |operand|rsched];
      cbn [kcad9_two_acc_public_concat_script_as_scheduled_public_script
           kcad9_two_acc_public_concat_op_as_scheduled_public_op map
           kcad9_two_acc_scheduled_public_script_model
           kcad9_two_acc_public_concat_script_model].
    + apply IH.
    + apply IH.
    + destruct xs as [|x xs]; [reflexivity|apply IH].
    + destruct (list_unsnoc xs) as [[xs' x]|]; [apply IH|reflexivity].
    + rewrite kcad9_open_back_pending_public_right_two_acc_state_reenter_seq_thm.
      apply IH.
    + rewrite kcad9_open_back_pending_public_right_two_acc_state_from_single_acc_seq_thm.
      apply IH.
Qed.

Definition kcad9_two_acc_scheduled_public_op_phase {X : Type}
    (op : KCad9TwoAccScheduledPublicOp X)
    : KCad9TwoAccGrowthEndpointPhase X :=
  match op with
  | KCad9TwoAccScheduledPublicPush x =>
      KCad9TwoAccGrowthEndpointPhaseStep
        [KCad9TwoAccRightGrowthPush x] []
  | KCad9TwoAccScheduledPublicInject x =>
      KCad9TwoAccGrowthEndpointPhaseStep
        [KCad9TwoAccRightGrowthInject x] []
  | KCad9TwoAccScheduledPublicAppendSingletonFolds xss =>
      KCad9TwoAccGrowthEndpointPhaseStep
        [KCad9TwoAccRightGrowthAppendSingletonFolds xss] []
  | KCad9TwoAccScheduledPublicConcatRightState rsched =>
      KCad9TwoAccGrowthEndpointPhaseStep
        [KCad9TwoAccRightGrowthConcatRightState rsched] []
  | KCad9TwoAccScheduledPublicPop =>
      KCad9TwoAccGrowthEndpointPhaseStep [] [KCad9EndpointFront]
  | KCad9TwoAccScheduledPublicEject =>
      KCad9TwoAccGrowthEndpointPhaseStep [] [KCad9EndpointBack]
  end.

Definition kcad9_two_acc_scheduled_public_script_phases {X : Type}
    (ops : list (KCad9TwoAccScheduledPublicOp X))
    : list (KCad9TwoAccGrowthEndpointPhase X) :=
  map kcad9_two_acc_scheduled_public_op_phase ops.

Theorem kcad9_two_acc_scheduled_public_script_phases_operands_inv_thm :
  forall (X : Type) (ops : list (KCad9TwoAccScheduledPublicOp X)),
    kcad9_two_acc_scheduled_public_script_operands_inv ops ->
    kcad9_two_acc_growth_endpoint_phase_operands_inv
      (kcad9_two_acc_scheduled_public_script_phases ops).
Proof.
  intros X ops.
  induction ops as [|op ops IH]; intros Hops.
  - exact I.
  - destruct op as [x|x|xss|rsched| |];
      cbn [kcad9_two_acc_scheduled_public_script_phases
           kcad9_two_acc_scheduled_public_op_phase map
           kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_growth_endpoint_phase_operands_inv
           kcad9_two_acc_right_growth_script_operands_inv] in *.
    + split; [exact I|apply IH; exact Hops].
    + split; [exact I|apply IH; exact Hops].
    + split; [exact I|apply IH; exact Hops].
    + destruct Hops as [Hright Hops].
      split.
      * split; [exact Hright|exact I].
      * apply IH. exact Hops.
    + split; [exact I|apply IH; exact Hops].
    + split; [exact I|apply IH; exact Hops].
Qed.

Theorem kcad9_two_acc_scheduled_public_script_phases_model_thm :
  forall (X : Type) (xs : list X)
         (ops : list (KCad9TwoAccScheduledPublicOp X)),
    kcad9_two_acc_growth_endpoint_phase_model xs
      (kcad9_two_acc_scheduled_public_script_phases ops) =
