      cbn [kcad9_two_acc_scheduled_public_script_phases
           kcad9_two_acc_scheduled_public_op_phase map
           kcad9_two_acc_growth_endpoint_phase_model
           kcad9_two_acc_right_growth_script_model
           kcad9_endpoint_script_model
           kcad9_two_acc_scheduled_public_script_model].
    + apply IH.
    + apply IH.
    + apply IH.
    + apply IH.
    + destruct xs as [|x xs]; [reflexivity|apply IH].
    + destruct (list_unsnoc xs) as [[xs' x]|]; [apply IH|reflexivity].
Qed.

Definition kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_script_expected
    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
