        (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_final).
Proof.
  intros concat_fuel X xs ops xs_final Hops Hmodel.
  set (sched0 :=
    kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
      (@kcad9_open_back_pending_public_right_schedule_state_empty X)).
  set (operand :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton xs)).
  set (sched_start :=
    kcad9_open_back_pending_public_right_two_acc_state_append_right_operand
      sched0 operand).
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_empty_left_fold_singletons_full_split_package_thm
       concat_fuel X xs)
    as [Happend_payload [Happend_eq [Hright_start [Hseq_start _]]]].
  cbn zeta in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold sched0 in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold operand in Happend_payload, Happend_eq, Hright_start, Hseq_start.
  fold sched_start in Happend_eq, Hright_start, Hseq_start.
  pose proof
    (kcad9_open_back_pending_public_right_two_acc_state_right_operand_inv_left_operand_inv_thm
       X sched_start Hright_start) as Hleft_start.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_script_full_split_materialize_under_left_operand_inv_thm
       concat_fuel X sched_start ops xs_final Hleft_start Hops)
    as (sched_final & Hscript & Hleft_final & Hseq_final &
        Hpayload & Heq & Hseq_materialized & Hinv_materialized).
  { rewrite Hseq_start. exact Hmodel. }
  rewrite Hseq_start in Hscript.
  exists sched_final.
  split; [exact Happend_payload|].
  split; [exact Happend_eq|].
  split; [exact Hscript|].
  split; [exact Hleft_final|].
  split; [exact Hseq_final|].
  split; [exact Hpayload|].
  split; [exact Heq|].
  split; [exact Hseq_materialized|exact Hinv_materialized].
Qed.

