Fixpoint kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv
    {X : Type}
    (segments : list (list (KCad9TwoAccScheduledPublicOp X) *
                     list KCad9EndpointSide)) : Prop :=
  match segments with
  | [] => True
  | (ops, _) :: segments' =>
      kcad9_two_acc_scheduled_public_script_operands_inv ops /\
      kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv segments'
  end.

Fixpoint kcad9_two_acc_scheduled_public_endpoint_segments_model
    {X : Type} (xs : list X)
    (segments : list (list (KCad9TwoAccScheduledPublicOp X) *
                     list KCad9EndpointSide)) : option (list X) :=
  match segments with
  | [] => Some xs
  | (ops, endpoint_ops) :: segments' =>
      match kcad9_two_acc_scheduled_public_script_model xs ops with
      | Some xs_mid =>
          match kcad9_endpoint_script_model xs_mid endpoint_ops with
          | Some xs_after =>
              kcad9_two_acc_scheduled_public_endpoint_segments_model
                xs_after segments'
          | None => None
          end
      | None => None
      end
  end.

Fixpoint kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_endpoint_segments_expected
    {X : Type} (concat_fuel : nat)
    (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs : list X)
    (segments : list (list (KCad9TwoAccScheduledPublicOp X) *
                     list KCad9EndpointSide))
    (sched_final : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
    (xs_final : list X) : Prop :=
  match segments with
  | [] => sched_final = sched /\ xs_final = xs
  | (ops, endpoint_ops) :: segments' =>
      exists sched_mid sched_after xs_mid xs_after,
        kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_script_expected
          concat_fuel sched xs ops sched_mid xs_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
          sched_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_seq sched_mid =
          xs_mid /\
        kcad9_open_back_pending_public_right_two_acc_state_full_split_payload_count
          concat_fuel sched_mid = 0 /\
        kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
          concat_fuel sched_mid =
        kcad9_open_back_pending_public_right_two_acc_state_zero_splice_materialize
          sched_mid /\
        kcad9_endpoint_script_expected 2
          (kcad9_open_back_pending_public_right_two_acc_state_full_split_materialize
            concat_fuel sched_mid)
          xs_mid endpoint_ops
          (kcad9_open_back_pending_public_right_two_acc_front sched_after)
          xs_after /\
        kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
          sched_after /\
        kcad9_open_back_pending_public_right_two_acc_state_seq sched_after =
          xs_after /\
        kcad9_open_back_pending_public_right_two_acc_pending sched_after = [] /\
        kcad9_open_back_pending_public_right_two_acc_back sched_after =
          @kcad9_empty X /\
        kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_endpoint_segments_expected
          concat_fuel sched_after xs_after segments' sched_final xs_final
  end.

Theorem kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_endpoint_segments_expected_under_left_operand_inv_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : KCad9OpenBackPendingPublicRightTwoAccSchedule X)
         (segments : list (list (KCad9TwoAccScheduledPublicOp X) *
                          list KCad9EndpointSide))
         (xs_final : list X),
    kcad9_open_back_pending_public_right_two_acc_state_left_operand_inv
      sched ->
    kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv
      segments ->
