  revert sched.
  induction segments as [|[ops endpoint_ops] segments IH];
    intros sched xs_final Hsched Hsegments Hmodel.
  - cbn [kcad9_two_acc_scheduled_public_endpoint_segments_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split; [split; reflexivity|].
    split; [exact Hsched|reflexivity].
  - cbn [kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv] in
      Hsegments.
    destruct Hsegments as [Hops Hsegments].
    cbn [kcad9_two_acc_scheduled_public_endpoint_segments_model] in Hmodel.
    destruct
      (kcad9_two_acc_scheduled_public_script_model
        (kcad9_open_back_pending_public_right_two_acc_state_seq sched) ops)
      as [xs_mid|] eqn:Hscript_model; [|discriminate].
    destruct (kcad9_endpoint_script_model xs_mid endpoint_ops)
      as [xs_after|] eqn:Hendpoint_model; [|discriminate].
    destruct
      (kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_script_then_endpoint_reenter_under_left_operand_inv_thm
         concat_fuel X sched ops endpoint_ops xs_mid xs_after
         Hsched Hops Hscript_model Hendpoint_model)
      as (sched_mid & sched_after & Hscript & Hleft_mid & Hseq_mid &
          Hpayload & Heq & Hendpoint & Hleft_after & Hseq_after &
          Hpending_after & Hback_after).
    destruct
      (IH sched_after xs_final Hleft_after Hsegments)
      as (sched_final & Hsegments_expected & Hleft_final & Hseq_final).
    { rewrite Hseq_after. exact Hmodel. }
    rewrite Hseq_after in Hsegments_expected.
    exists sched_final.
    split.
    + cbn [kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_endpoint_segments_expected].
      exists sched_mid, sched_after, xs_mid, xs_after.
      split; [exact Hscript|].
      split; [exact Hleft_mid|].
      split; [exact Hseq_mid|].
      split; [exact Hpayload|].
      split; [exact Heq|].
      split; [exact Hendpoint|].
      split; [exact Hleft_after|].
      split; [exact Hseq_after|].
      split; [exact Hpending_after|].
      split; [exact Hback_after|].
      exact Hsegments_expected.
    + split; [exact Hleft_final|exact Hseq_final].
Qed.

