    Hsegments Hsegments_model Hendpoint_model.
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_scheduled_public_endpoint_segments_then_endpoint_reenter_from_empty_left_fold_singletons_thm
       concat_fuel X xs segments endpoint_ops xs_mid xs_final
       Hsegments Hsegments_model Hendpoint_model)
    as (sched_mid & sched_final & Happend_payload & Happend_eq &
        Hsegments_expected & Hleft_mid & Hseq_mid & Hpayload & Heq &
        Hseq_materialized & Hendpoint & Hleft_final & Hseq_final &
        Hpending_final & Hback_final).
  destruct
    (kcad9_open_back_pending_public_right_two_acc_state_left_operand_full_split_materialize_package_thm
       concat_fuel X sched_final Hleft_final)
    as (Hfinal_payload & Hfinal_eq & Hfinal_seq & Hfinal_inv).
  rewrite Hseq_final in Hfinal_seq.
  exists sched_mid, sched_final.
  split; [exact Happend_payload|].
  split; [exact Happend_eq|].
  split; [exact Hsegments_expected|].
  split; [exact Hleft_mid|].
  split; [exact Hseq_mid|].
  split; [exact Hpayload|].
  split; [exact Heq|].
  split; [exact Hseq_materialized|].
  split; [exact Hendpoint|].
  split; [exact Hleft_final|].
  split; [exact Hseq_final|].
  split; [exact Hpending_final|].
  split; [exact Hback_final|].
  split; [exact Hfinal_payload|].
  split; [exact Hfinal_eq|].
  split; [exact Hfinal_seq|exact Hfinal_inv].
Qed.

Fixpoint kcad9_two_acc_public_concat_endpoint_segments_operands_inv
    {X : Type}
    (segments : list (list (KCad9TwoAccPublicConcatOp X) *
                     list KCad9EndpointSide)) : Prop :=
  match segments with
  | [] => True
  | (ops, _) :: segments' =>
      kcad9_two_acc_public_concat_script_operands_inv ops /\
      kcad9_two_acc_public_concat_endpoint_segments_operands_inv segments'
  end.

Fixpoint kcad9_two_acc_public_concat_endpoint_segments_model
    {X : Type} (xs : list X)
    (segments : list (list (KCad9TwoAccPublicConcatOp X) *
                     list KCad9EndpointSide)) : option (list X) :=
  match segments with
  | [] => Some xs
  | (ops, endpoint_ops) :: segments' =>
      match kcad9_two_acc_public_concat_script_model xs ops with
      | Some xs_mid =>
          match kcad9_endpoint_script_model xs_mid endpoint_ops with
          | Some xs_after =>
              kcad9_two_acc_public_concat_endpoint_segments_model
                xs_after segments'
          | None => None
          end
      | None => None
      end
  end.

Definition kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments
    {X : Type}
    (segments : list (list (KCad9TwoAccPublicConcatOp X) *
                     list KCad9EndpointSide))
    : list (list (KCad9TwoAccScheduledPublicOp X) *
            list KCad9EndpointSide) :=
  map
    (fun segment =>
       match segment with
       | (ops, endpoint_ops) =>
           (kcad9_two_acc_public_concat_script_as_scheduled_public_script
              ops,
            endpoint_ops)
       end)
    segments.

Theorem kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments_operands_inv_thm :
  forall (X : Type)
         (segments : list (list (KCad9TwoAccPublicConcatOp X) *
                          list KCad9EndpointSide)),
    kcad9_two_acc_public_concat_endpoint_segments_operands_inv
      segments ->
    kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv
      (kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments
        segments).
Proof.
  intros X segments.
  induction segments as [|[ops endpoint_ops] segments IH];
    intros Hsegments.
  - exact I.
  - cbn [kcad9_two_acc_public_concat_endpoint_segments_operands_inv
         kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments
         kcad9_two_acc_scheduled_public_endpoint_segments_operands_inv
         map] in *.
    destruct Hsegments as [Hops Hsegments].
    split.
    + apply
        kcad9_two_acc_public_concat_script_as_scheduled_public_script_operands_inv_thm.
      exact Hops.
    + apply IH. exact Hsegments.
Qed.

Theorem kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments_model_thm :
  forall (X : Type) (xs : list X)
         (segments : list (list (KCad9TwoAccPublicConcatOp X) *
                          list KCad9EndpointSide)),
    kcad9_two_acc_scheduled_public_endpoint_segments_model xs
      (kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments
        segments) =
    kcad9_two_acc_public_concat_endpoint_segments_model xs segments.
Proof.
  intros X xs segments.
  revert xs.
  induction segments as [|[ops endpoint_ops] segments IH]; intros xs.
  - reflexivity.
  - cbn [kcad9_two_acc_public_concat_endpoint_segments_as_scheduled_public_endpoint_segments
         kcad9_two_acc_scheduled_public_endpoint_segments_model
         kcad9_two_acc_public_concat_endpoint_segments_model
         map].
    rewrite kcad9_two_acc_public_concat_script_as_scheduled_public_script_model_thm.
    destruct (kcad9_two_acc_public_concat_script_model xs ops)
      as [xs_mid|]; [|reflexivity].
    destruct (kcad9_endpoint_script_model xs_mid endpoint_ops)
      as [xs_after|]; [|reflexivity].
    apply IH.
Qed.

