Theorem kcad9_two_acc_scheduled_public_deque_pop_refill_depth_inv_full_split_budget_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : kcad9_two_acc_scheduled_public_deque X)
         (x : X) (xs : list X),
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched ->
    kcad9_two_acc_scheduled_public_deque_seq sched = x :: xs ->
    exists sched',
      kcad9_two_acc_scheduled_public_deque_pop concat_fuel sched =
        Some (x, sched') /\
      kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched' /\
      kcad9_two_acc_scheduled_public_deque_full_split_budget sched' /\
      kcad9_two_acc_scheduled_public_deque_seq sched' = xs /\
      kcad9_two_acc_scheduled_public_deque_full_split_payload_count
        concat_fuel sched = 0 /\
      kcad9_two_acc_scheduled_public_deque_full_split_materialize
        concat_fuel sched =
      kcad9_two_acc_scheduled_public_deque_zero_splice_materialize
        sched /\
      inv_kcad9_ocaml_middle_depth_bound 1
        (kcad9_open_back_pending_public_right_two_acc_front sched').
Proof.
  intros concat_fuel X sched x xs Hsched Hseq_sched.
  set (acc :=
    kcad9_two_acc_scheduled_public_deque_full_split_materialize
      concat_fuel sched).
  destruct
    (kcad9_two_acc_scheduled_public_deque_refill_depth_inv_full_split_materialize_reenter_full_split_budget_thm
       concat_fuel X sched Hsched)
    as (Hpayload & Heq & Hseq_acc & _Hleft & Hreusable &
        Hrefill & _Hdepth & _Hreenter_refill & _Hreenter_budget &
        _Hreenter_seq & _Hreenter_depth).
  fold acc in Hpayload, Heq, Hseq_acc, Hreusable, Hrefill.
  assert (Hseq_acc_start : kcad9_to_list acc = x :: xs).
  { rewrite Hseq_acc. exact Hseq_sched. }
  assert (Hmodel :
    kcad9_endpoint_script_model (x :: xs) [KCad9EndpointFront] = Some xs).
  { reflexivity. }
  destruct
    (kcad9_endpoint_script_expected_fuel_two_under_open_back_reusable_const_refill_depth_one_thm
       X acc (x :: xs) [KCad9EndpointFront] xs
       Hreusable Hrefill Hseq_acc_start Hmodel)
    as (acc_final & Hendpoint & Hseq_final & Hreusable_final &
        Hrefill_final & Hdepth_final).
  cbn [kcad9_endpoint_script_expected] in Hendpoint.
  destruct Hendpoint as (acc_step & Hpop & Htail).
  cbn [kcad9_endpoint_script_expected] in Htail.
  destruct Htail as [Hacc_final _]. subst acc_final.
  set (sched' := kcad9_two_acc_scheduled_public_deque_reenter acc_step).
  assert (Hsched'_refill :
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched').
  { subst sched'.
    split.
    - apply kcad9_two_acc_scheduled_public_deque_reenter_inv_thm.
      exact Hreusable_final.
    - unfold kcad9_two_acc_scheduled_public_deque_reenter.
      cbn [kcad9_open_back_pending_public_right_two_acc_state_from_single_acc
           kcad9_open_back_pending_public_right_schedule_state_reenter
           kcad9_open_back_pending_public_right_acc
           kcad9_open_back_pending_public_right_pending
           kcad9_open_back_pending_public_right_two_acc_front].
      exact Hrefill_final. }
  exists sched'.
  split.
  - subst sched'.
    unfold kcad9_two_acc_scheduled_public_deque_pop.
    fold acc. rewrite Hpop. reflexivity.
  - split; [exact Hsched'_refill|].
    split.
    + apply kcad9_two_acc_scheduled_public_deque_refill_depth_inv_full_split_budget_thm.
      exact Hsched'_refill.
    + split.
      * subst sched'.
        rewrite kcad9_two_acc_scheduled_public_deque_reenter_seq_thm.
        exact Hseq_final.
      * split; [exact Hpayload|].
        split; [exact Heq|].
        subst sched'.
        apply kcad9_two_acc_scheduled_public_deque_reenter_front_middle_depth_bound_thm.
        exact Hdepth_final.
Qed.

