Definition kcad9_two_acc_scheduled_public_deque_step
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X)
    (op : KCad9TwoAccScheduledPublicOp X)
    : option (kcad9_two_acc_scheduled_public_deque X) :=
  match op with
  | KCad9TwoAccScheduledPublicPush x =>
      Some (kcad9_two_acc_scheduled_public_deque_push x sched)
  | KCad9TwoAccScheduledPublicInject x =>
      Some (kcad9_two_acc_scheduled_public_deque_inject sched x)
  | KCad9TwoAccScheduledPublicAppendSingletonFolds xss =>
      Some
        (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
          sched xss)
  | KCad9TwoAccScheduledPublicConcatRightState rsched =>
      Some (kcad9_two_acc_scheduled_public_deque_concat sched rsched)
  | KCad9TwoAccScheduledPublicPop =>
      match kcad9_two_acc_scheduled_public_deque_pop concat_fuel sched with
      | Some (_, sched') => Some sched'
      | None => None
      end
  | KCad9TwoAccScheduledPublicEject =>
      match kcad9_two_acc_scheduled_public_deque_eject concat_fuel sched with
      | Some (sched', _) => Some sched'
      | None => None
      end
  end.

Fixpoint kcad9_two_acc_scheduled_public_deque_run
    {X : Type} (concat_fuel : nat)
    (sched : kcad9_two_acc_scheduled_public_deque X)
    (ops : list (KCad9TwoAccScheduledPublicOp X))
    : option (kcad9_two_acc_scheduled_public_deque X) :=
  match ops with
  | [] => Some sched
  | op :: ops' =>
      match kcad9_two_acc_scheduled_public_deque_step
              concat_fuel sched op with
      | Some sched' =>
          kcad9_two_acc_scheduled_public_deque_run
            concat_fuel sched' ops'
      | None => None
      end
  end.

Theorem kcad9_two_acc_scheduled_public_deque_append_singleton_folds_refill_depth_inv_full_split_budget_thm :
  forall (X : Type)
         (sched : kcad9_two_acc_scheduled_public_deque X)
         (xss : list (list X)),
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched ->
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv
      (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
        sched xss) /\
    kcad9_two_acc_scheduled_public_deque_full_split_budget
      (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
        sched xss) /\
