      (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
        sched xss) =
    kcad9_two_acc_scheduled_public_deque_seq sched ++ concat xss /\
    inv_kcad9_ocaml_middle_depth_bound 1
      (kcad9_open_back_pending_public_right_two_acc_front
        (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
          sched xss)).
Proof.
  intros X sched xss [Hsched Hfront_refill].
  assert (Hrefill :
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv
      (kcad9_two_acc_scheduled_public_deque_append_singleton_folds
        sched xss)).
  { split.
    - unfold kcad9_two_acc_scheduled_public_deque_inv,
        kcad9_two_acc_scheduled_public_deque_append_singleton_folds in *.
      apply
        kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds_left_operand_inv_thm.
      exact Hsched.
    - unfold kcad9_two_acc_scheduled_public_deque_append_singleton_folds.
      cbn [kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds
           kcad9_open_back_pending_public_right_two_acc_front].
      exact Hfront_refill. }
  split; [exact Hrefill|].
  split.
  - apply kcad9_two_acc_scheduled_public_deque_refill_depth_inv_full_split_budget_thm.
    exact Hrefill.
  - split.
    + unfold kcad9_two_acc_scheduled_public_deque_seq,
        kcad9_two_acc_scheduled_public_deque_append_singleton_folds.
      apply
        kcad9_open_back_pending_public_right_two_acc_state_append_singleton_folds_seq_thm.
    + destruct Hrefill as [_ Hfront_refill'].
      apply inv_kcad9_ocaml_refill_depth_bound_middle_depth_bound_thm.
      exact Hfront_refill'.
Qed.

Theorem kcad9_two_acc_scheduled_public_deque_concat_refill_depth_inv_full_split_budget_thm :
