      exact Hfront_refill'.
Qed.

Theorem kcad9_two_acc_scheduled_public_deque_run_refill_depth_inv_full_split_budget_thm :
  forall (concat_fuel : nat) (X : Type)
         (sched : kcad9_two_acc_scheduled_public_deque X)
         (ops : list (KCad9TwoAccScheduledPublicOp X))
         (xs_final : list X),
    kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched ->
    kcad9_two_acc_scheduled_public_script_operands_inv ops ->
    kcad9_two_acc_scheduled_public_script_model
      (kcad9_two_acc_scheduled_public_deque_seq sched) ops =
      Some xs_final ->
    exists sched_final,
      kcad9_two_acc_scheduled_public_deque_run
        concat_fuel sched ops = Some sched_final /\
      kcad9_two_acc_scheduled_public_deque_refill_depth_inv
        sched_final /\
      kcad9_two_acc_scheduled_public_deque_full_split_budget
        sched_final /\
      kcad9_two_acc_scheduled_public_deque_seq sched_final =
        xs_final /\
      inv_kcad9_ocaml_middle_depth_bound 1
        (kcad9_open_back_pending_public_right_two_acc_front sched_final).
