  intros concat_fuel X sched ops.
  revert sched.
  induction ops as [|op ops IH]; intros sched xs_final Hsched Hops Hmodel.
  - cbn [kcad9_two_acc_scheduled_public_deque_run
         kcad9_two_acc_scheduled_public_script_model] in Hmodel.
    injection Hmodel as Hxs_final. subst xs_final.
    exists sched.
    split; [reflexivity|].
    split; [exact Hsched|].
    split.
    + apply kcad9_two_acc_scheduled_public_deque_refill_depth_inv_full_split_budget_thm.
      exact Hsched.
    + split; [reflexivity|].
      destruct Hsched as [_ Hfront_refill].
      apply inv_kcad9_ocaml_refill_depth_bound_middle_depth_bound_thm.
      exact Hfront_refill.
  - destruct op as [x|x|xss|rsched| |].
    + cbn [kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_scheduled_public_script_model] in Hops, Hmodel.
      set (sched1 := kcad9_two_acc_scheduled_public_deque_push x sched).
      assert (Hsched1 :
        kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched1).
      { destruct Hsched as [Hsched Hfront_refill].
        subst sched1. split.
        - apply kcad9_two_acc_scheduled_public_deque_push_inv_thm.
          exact Hsched.
        - unfold kcad9_two_acc_scheduled_public_deque_push.
          cbn [kcad9_open_back_pending_public_right_two_acc_state_push
               kcad9_open_back_pending_public_right_two_acc_front].
          apply kcad9_push_ocaml_refill_depth_bound_thm.
          exact Hfront_refill. }
      destruct (IH sched1 xs_final Hsched1 Hops) as
        (sched_final & Hrun & Hfinal_refill & Hfinal_budget &
         Hseq_final & Hdepth_final).
      { unfold sched1.
        rewrite kcad9_two_acc_scheduled_public_deque_push_seq_thm.
        exact Hmodel. }
      exists sched_final.
      cbn [kcad9_two_acc_scheduled_public_deque_run
           kcad9_two_acc_scheduled_public_deque_step].
      fold sched1.
      split; [exact Hrun|].
      split; [exact Hfinal_refill|].
      split; [exact Hfinal_budget|].
      split; [exact Hseq_final|exact Hdepth_final].
    + cbn [kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_scheduled_public_script_model] in Hops, Hmodel.
      set (sched1 := kcad9_two_acc_scheduled_public_deque_inject sched x).
      assert (Hsched1 :
        kcad9_two_acc_scheduled_public_deque_refill_depth_inv sched1).
      { destruct Hsched as [Hsched Hfront_refill].
        subst sched1. split.
        - apply kcad9_two_acc_scheduled_public_deque_inject_inv_thm.
          exact Hsched.
        - unfold kcad9_two_acc_scheduled_public_deque_inject.
          cbn [kcad9_open_back_pending_public_right_two_acc_state_inject
               kcad9_open_back_pending_public_right_two_acc_front].
          exact Hfront_refill. }
      destruct (IH sched1 xs_final Hsched1 Hops) as
        (sched_final & Hrun & Hfinal_refill & Hfinal_budget &
         Hseq_final & Hdepth_final).
      { unfold sched1.
        rewrite kcad9_two_acc_scheduled_public_deque_inject_seq_thm.
        exact Hmodel. }
      exists sched_final.
      cbn [kcad9_two_acc_scheduled_public_deque_run
           kcad9_two_acc_scheduled_public_deque_step].
      fold sched1.
      split; [exact Hrun|].
      split; [exact Hfinal_refill|].
      split; [exact Hfinal_budget|].
      split; [exact Hseq_final|exact Hdepth_final].
    + cbn [kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_scheduled_public_script_model] in Hops, Hmodel.
      destruct
        (kcad9_two_acc_scheduled_public_deque_append_singleton_folds_refill_depth_inv_full_split_budget_thm
           X sched xss Hsched)
        as (Hsched1 & _Hbudget1 & Hseq1 & _Hdepth1).
      set (sched1 :=
        kcad9_two_acc_scheduled_public_deque_append_singleton_folds
          sched xss).
      destruct (IH sched1 xs_final Hsched1 Hops) as
        (sched_final & Hrun & Hfinal_refill & Hfinal_budget &
         Hseq_final & Hdepth_final).
      { unfold sched1. rewrite Hseq1. exact Hmodel. }
      exists sched_final.
      cbn [kcad9_two_acc_scheduled_public_deque_run
           kcad9_two_acc_scheduled_public_deque_step].
      fold sched1.
      split; [exact Hrun|].
      split; [exact Hfinal_refill|].
      split; [exact Hfinal_budget|].
      split; [exact Hseq_final|exact Hdepth_final].
    + cbn [kcad9_two_acc_scheduled_public_script_operands_inv
           kcad9_two_acc_scheduled_public_script_model] in Hops, Hmodel.
      destruct Hops as [Hright Hops].
      destruct
        (kcad9_two_acc_scheduled_public_deque_concat_refill_depth_inv_full_split_budget_thm
           X sched rsched Hsched Hright)
        as (Hsched1 & _Hbudget1 & Hseq1 & _Hdepth1).
      set (sched1 := kcad9_two_acc_scheduled_public_deque_concat sched rsched).
      destruct (IH sched1 xs_final Hsched1 Hops) as
        (sched_final & Hrun & Hfinal_refill & Hfinal_budget &
         Hseq_final & Hdepth_final).
      { unfold sched1. rewrite Hseq1. exact Hmodel. }
      exists sched_final.
      cbn [kcad9_two_acc_scheduled_public_deque_run
           kcad9_two_acc_scheduled_public_deque_step].
      fold sched1.
      split; [exact Hrun|].
      split; [exact Hfinal_refill|].
      split; [exact Hfinal_budget|].
      split; [exact Hseq_final|exact Hdepth_final].
    + cbn [kcad9_two_acc_scheduled_public_script_operands_inv] in Hops.
      destruct
        (kcad9_two_acc_scheduled_public_deque_seq sched)
        as [|x xs] eqn:Hseq_sched.
      * cbn [kcad9_two_acc_scheduled_public_script_model] in Hmodel.
        discriminate.
