           (@kcad9_empty X) (map kcad9_singleton xs))
         Hinv Hreach_chunk Hsmall_chunk) as [Hseq_one Hinv_one].
    destruct (IH _ Hinv_one) as [Hseq_tail Hinv_tail].
    split.
    + rewrite Hseq_tail, Hseq_one, Hseq_chunk.
      rewrite <- app_assoc. reflexivity.
    + exact Hinv_tail.
