Theorem kcad9_concat_ocaml_full_split_open_back_shape_fuel_singleton_right_open_back_reusable_const_thm :
  forall (concat_fuel : nat) (X : Type) (acc : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_open_back_reusable_const acc ->
    kcad9_to_list
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel acc (kcad9_singleton x)) =
      kcad9_to_list acc ++ [x] /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel
        concat_fuel acc (kcad9_singleton x)).
Proof.
  intros concat_fuel X acc x Hinv.
  split.
  - rewrite kcad9_concat_ocaml_full_split_open_back_shape_fuel_seq_thm.
    cbn [kcad9_singleton kcad9_to_list kelem9_flat_list buf6_elems].
    reflexivity.
  - pose proof (Hinv 0) as Hacc0.
    pose proof
      (inv_kcad9_ocaml_continuation_depth_reachable_thm
         0 1 X acc Hacc0) as Hacc_reach.
    pose proof
      (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
         1 X acc Hacc_reach) as Hacc_boundary.
    pose proof
      (inv_kcad9_ocaml_reachable_depth_boundary_deep_thm
         1 X (kcad9_singleton x)
         (singleton_kcad9_ocaml_reachable_depth_thm 1 X x))
      as Hsingleton_boundary.
    pose proof
      (kcad9_concat_ocaml_full_split_open_back_shape_fuel_boundary_deep_thm
         concat_fuel X acc (kcad9_singleton x)
         Hacc_boundary Hsingleton_boundary) as Hres_boundary.
    intros endpoint_fuel.
    assert (Hcont :
      kcad9_ocaml_refill_continuation_ready_fuel_depth
        endpoint_fuel 1
        (kcad9_concat_ocaml_full_split_open_back_shape_fuel
          concat_fuel acc (kcad9_singleton x))).
    { destruct acc as [|ba|h m t];
        cbn [kcad9_concat_ocaml_full_split_open_back_shape_fuel
             kcad9_singleton
             kcad9_ocaml_refill_continuation_ready_fuel_depth].
      - exact I.
      - split.
        + apply front_refill_continuation_ready_middle9_fuel_empty_thm.
        + apply back_refill_continuation_ready_middle9_fuel_empty_thm.
      - pose proof (Hinv endpoint_fuel) as [Hreach Hmiddle_cont].
        cbn [inv_kcad9_ocaml_reachable_depth
             inv_kcad9_ocaml_ready_or_empty_depth
             kcad9_ocaml_refill_continuation_ready_fuel_depth]
          in Hreach, Hmiddle_cont.
        destruct Hreach as [Hready _].
        destruct Hready as [_ [_ [Ht [_ _]]]].
        destruct Hmiddle_cont as [Hfront Hback].
        split.
        + apply front_refill_continuation_ready_middle9_fuel_inject_small;
            assumption.
        + apply back_refill_continuation_ready_middle9_fuel_inject_small;
            assumption. }
    split.
    + eapply inv_kcad9_ocaml_boundary_deep_continuation_reachable_thm;
        eassumption.
    + exact Hcont.
Qed.

