Qed.

Theorem kcad9_concat_ocaml_selective_open_back_nested_big_back_cell_depth_counterexample_thm :
  let h1 := mkBuf6 [XBase9 0] in
  let t1 := mkBuf6 [XBase9 1] in
  let h2 := mkBuf6 [XBase9 2] in
  let nested_back :=
    StoredBig9
      (mkBuf6 [XBase9 3])
      (mkBuf6
        [StoredMiddle9
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 4])])])
      (mkBuf6 [XBase9 5]) in
  let t2 := mkBuf6 [XBase9 6] in
  let a := K9Triple h1 buf6_empty t1 in
  let b := K9Triple h2 (mkBuf6 [nested_back]) t2 in
  let k0 := kcad9_concat_ocaml_selective_open_back_shape_fuel 1 a b in
  exists k1 k2 k3,
    kcad9_to_list k0 = [0;1;2;3;4;5;6] /\
    kcad9_pop_ocaml_shape_fuel 2 k0 = Some (0, k1) /\
    kcad9_pop_ocaml_shape_fuel 2 k1 = Some (1, k2) /\
    kcad9_pop_ocaml_shape_fuel 2 k2 = Some (2, k3) /\
    ~ inv_kcad9_ocaml_middle_depth_bound 1 k3.
Proof.
