Lemma stored9_small_nonempty_refill_depth_le :
  forall (depth : nat) (X : Type) (s : Stored9 X),
    stored9_small_nonempty s ->
    stored_refill_depth_le depth s.
Proof.
  intros depth X [b|pre sm suf|sm] Hsmall;
    cbn [stored9_small_nonempty stored_refill_depth_le] in *;
    try contradiction.
  exact I.
Qed.

Lemma middle9_small_nonempty_refill_depth_le :
  forall (depth : nat) (X : Type) (m : Buf6 (Stored9 X)),
    middle9_small_nonempty m ->
    middle9_refill_depth_le depth m.
Proof.
  intros depth X [xs] Hsmall.
  unfold middle9_small_nonempty in Hsmall.
  unfold middle9_refill_depth_le.
  cbn [buf6_elems] in *.
  induction Hsmall as [|cell rest Hcell _ IH]; cbn.
  - exact I.
  - split.
    + apply stored9_small_nonempty_refill_depth_le. exact Hcell.
    + exact IH.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_refill_depth_bound_thm :
  forall (X : Type) (a b : KCadeque9 X),
    kcad9_ocaml_middle_small_nonempty a ->
    kcad9_ocaml_middle_small_nonempty b ->
    inv_kcad9_ocaml_refill_depth_bound 1
      (kcad9_concat_absorb_open_back_shape_fuel 1 a b).
Proof.
  intros X [|ba|h1 m1 t1] [|bb|h2 m2 t2] Hsmall_a Hsmall_b;
    cbn [kcad9_concat_absorb_open_back_shape_fuel
         inv_kcad9_ocaml_refill_depth_bound
         kcad9_ocaml_middle_small_nonempty] in *;
    try exact I.
  - apply middle9_small_nonempty_refill_depth_le. exact Hsmall_b.
  - apply middle9_refill_depth_le_push.
    + exact I.
    + apply middle9_small_nonempty_refill_depth_le. exact Hsmall_b.
  - apply middle9_small_nonempty_refill_depth_le. exact Hsmall_a.
  - apply middle9_refill_depth_le_inject.
    + apply middle9_small_nonempty_refill_depth_le. exact Hsmall_a.
    + exact I.
  - destruct (buf6_eject m2) as [[m2_rest back_cell]|] eqn:Heject.
    + destruct
        (middle9_small_nonempty_eject X m2 m2_rest back_cell
           Heject Hsmall_b) as [Hm2_rest Hback_cell].
      destruct back_cell as [bcell|pre sm suf|sm];
        cbn [stored9_small_nonempty] in Hback_cell; try contradiction.
      cbn [kcad9_concat_absorb_open_back_bridge_cell_fuel
           kcad9_concat_absorb_back_bridge_cell].
      apply middle9_refill_depth_le_inject.
      * apply middle9_small_nonempty_refill_depth_le. exact Hsmall_a.
      * cbn [stored_refill_depth_le].
        apply middle9_refill_depth_le_push.
        -- exact I.
        -- apply middle9_small_nonempty_refill_depth_le. exact Hm2_rest.
    + apply middle9_refill_depth_le_inject.
      * apply middle9_small_nonempty_refill_depth_le. exact Hsmall_a.
      * cbn [stored_refill_depth_le].
        apply middle9_refill_depth_le_empty.
Qed.

