Theorem kcad9_endpoint_script_expected_fuel_two_under_open_back_shape_fuel_one_left_fold_singletons_refill_depth_thm :
  forall (X : Type) (xs ys : list X)
         (ops : list KCad9EndpointSide) (xs_final : list X),
