Theorem kcad9_concat_absorb_open_back_shape_fuel_one_left_fold_singletons_triples_open_back_reusable_const_thm :
  forall (X : Type) (xs ys : list X)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 : Buf6 (KElem9 X)) (m2 : Buf6 (Stored9 X))
         (t2 : Buf6 (KElem9 X)),
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton xs) =
      K9Triple h1 m1 t1 ->
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty X) (map kcad9_singleton ys) =
      K9Triple h2 m2 t2 ->
    kcad9_to_list
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (K9Triple h1 m1 t1) (K9Triple h2 m2 t2)) =
      xs ++ ys /\
    inv_kcad9_ocaml_open_back_reusable_const
      (kcad9_concat_absorb_open_back_shape_fuel 1
        (K9Triple h1 m1 t1) (K9Triple h2 m2 t2)).
Proof.
  intros X xs ys h1 m1 t1 h2 m2 t2 Hxs Hys.
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm
       X xs) as [Hreach_xs Hseq_xs].
  destruct
    (kcad9_concat_ocaml_shape_left_fold_singletons_reachable_depth_one_seq_thm
       X ys) as [Hreach_ys Hseq_ys].
  assert (Hm1_small : middle9_small_nonempty m1).
  { destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
         X (@kcad9_empty X) xs I I) as [_ Hsmall].
    rewrite Hxs in Hsmall.
    cbn [kcad9_ocaml_middle_small_nonempty] in Hsmall.
    exact Hsmall. }
  assert (Hm2_small : middle9_small_nonempty m2).
  { destruct
      (kcad9_concat_ocaml_shape_left_fold_singletons_boundary_middle_small_nonempty
         X (@kcad9_empty X) ys I I) as [_ Hsmall].
    rewrite Hys in Hsmall.
    cbn [kcad9_ocaml_middle_small_nonempty] in Hsmall.
    exact Hsmall. }
  rewrite Hxs in Hreach_xs, Hseq_xs.
  rewrite Hys in Hreach_ys, Hseq_ys.
  cbn [inv_kcad9_ocaml_reachable_depth inv_kcad9_ocaml_ready_or_empty_depth
       inv_kcad9_ocaml_deep_xbase] in Hreach_xs, Hreach_ys.
  destruct Hreach_xs as [Hready_xs Hdeep_xs].
  destruct Hready_xs as
    [Hh1_size [_ [Ht1_size [_ _]]]].
  destruct Hdeep_xs as [Hh1_xbase [Hm1_xbase Ht1_xbase]].
  destruct Hreach_ys as [Hready_ys Hdeep_ys].
  destruct Hready_ys as
    [Hh2_size [_ [Ht2_size [_ _]]]].
  destruct Hdeep_ys as [Hh2_xbase [Hm2_xbase Ht2_xbase]].
  destruct
    (kcad9_concat_absorb_open_back_shape_fuel_one_small_middle_open_back_reusable_const_thm
       X h1 m1 t1 h2 m2 t2
       Hh1_size Hh1_xbase Hm1_small Hm1_xbase Ht1_size Ht1_xbase
       Hh2_size Hh2_xbase Hm2_small Hm2_xbase Ht2_size Ht2_xbase)
    as [Hseq Hinv].
  split.
  - rewrite Hseq. rewrite Hseq_xs, Hseq_ys. reflexivity.
  - exact Hinv.
Qed.

