Lemma front_refill_continuation_ready_middle9_fuel_open_back_singleton_tail :
  forall fuel : nat,
    front_refill_continuation_ready_middle9_fuel fuel 1
      (mkBuf6
        [StoredMiddle9
           (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])]);
         StoredSmall9 (mkBuf6 [XBase9 4])]).
Proof.
  intros [|fuel].
  - cbn [front_refill_continuation_ready_middle9_fuel
         front_ready_or_empty_middle9_depth front_ready_middle9_depth
         front_ready_stored9_depth front_ready_stored9
         buf6_pop buf6_elems].
    split.
    + right.
      exists (StoredMiddle9 (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])).
      exists (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 4])]).
      split; [reflexivity|].
      exists (StoredSmall9 (mkBuf6 [XBase9 3])).
      exists (mkBuf6 []).
      split; [reflexivity|].
      cbn [front_ready_stored9_depth front_ready_stored9
           buf6_size_ge buf6_size buf6_elems].
      exact (le_n 1).
    + exact I.
  - cbn [front_refill_continuation_ready_middle9_fuel
         front_ready_or_empty_middle9_depth front_ready_middle9_depth
         front_ready_stored9_depth front_ready_stored9
         buf6_pop buf6_push buf6_is_empty buf6_elems k9_middle_push].
    split.
    + right.
      exists (StoredMiddle9 (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])).
      exists (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 4])]).
      split; [reflexivity|].
      exists (StoredSmall9 (mkBuf6 [XBase9 3])).
      exists (mkBuf6 []).
      split; [reflexivity|].
      cbn [front_ready_stored9_depth front_ready_stored9
           buf6_size_ge buf6_size buf6_elems].
      exact (le_n 1).
    + apply front_refill_continuation_ready_middle9_fuel_small_nonempty.
      cbn [middle9_small_nonempty stored9_small_nonempty
           buf6_push buf6_elems buf6_size_ge buf6_size].
      repeat constructor; exact (le_n 1).
Qed.

