  - cbn [front_refill_continuation_ready_middle9_fuel
         front_ready_or_empty_middle9_depth front_ready_middle9_depth
         front_ready_stored9_depth front_ready_stored9
         buf6_pop buf6_elems].
    split.
    + right.
      exists (StoredSmall9 (mkBuf6 [XBase9 1])).
      exists
        (mkBuf6
          [StoredBig9 (mkBuf6 [XBase9 2])
             (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
             (mkBuf6 [XBase9 4])]).
      split; [reflexivity|].
      cbn [front_ready_stored9_depth front_ready_stored9
           buf6_size_ge buf6_size buf6_elems].
      exact (le_n 1).
    + split.
      * cbn [buf6_size_ge buf6_size buf6_elems]. exact (le_n 1).
      * apply front_refill_continuation_ready_middle9_fuel_open_back_singleton_bridge.
Qed.

Lemma back_refill_continuation_ready_middle9_fuel_open_back_singleton_chunks :
  forall fuel : nat,
    back_refill_continuation_ready_middle9_fuel fuel 1
      (mkBuf6
        [StoredSmall9 (mkBuf6 [XBase9 1]);
         StoredBig9 (mkBuf6 [XBase9 2])
           (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
           (mkBuf6 [XBase9 4])]).
Proof.
  intros [|fuel].
  - cbn [back_refill_continuation_ready_middle9_fuel
         back_ready_or_empty_middle9_depth back_ready_middle9_depth
         back_ready_stored9_depth back_ready_stored9
         buf6_eject buf6_elems rev app].
    split.
    + right.
      exists (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 1])]).
      exists
        (StoredBig9 (mkBuf6 [XBase9 2])
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
          (mkBuf6 [XBase9 4])).
      split; [reflexivity|].
      cbn [back_ready_stored9_depth back_ready_stored9
           buf6_size_ge buf6_size buf6_elems].
      exact (le_n 1).
    + exact I.
  - cbn [back_refill_continuation_ready_middle9_fuel
         back_ready_or_empty_middle9_depth back_ready_middle9_depth
         back_ready_stored9_depth back_ready_stored9
         buf6_eject buf6_inject buf6_is_empty buf6_elems rev app
         k9_middle_inject].
    split.
    + right.
      exists (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 1])]).
      exists
        (StoredBig9 (mkBuf6 [XBase9 2])
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
          (mkBuf6 [XBase9 4])).
      split; [reflexivity|].
      cbn [back_ready_stored9_depth back_ready_stored9
           buf6_size_ge buf6_size buf6_elems].
      exact (le_n 1).
    + split.
      * change (back_refill_continuation_ready_middle9_fuel fuel 1
            (mkBuf6
              [StoredSmall9 (mkBuf6 [XBase9 1]);
               StoredSmall9 (mkBuf6 [XBase9 2]);
               StoredMiddle9
                 (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])])).
        apply back_refill_continuation_ready_middle9_fuel_open_back_singleton_prefix.
      * cbn [buf6_size_ge buf6_size buf6_elems]. exact (le_n 1).
Qed.

Theorem kcad9_concat_absorb_open_back_shape_fuel_one_singleton_chunks_open_back_reusable_const_thm :
  let a :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [0; 1; 2]) in
  let b :=
    kcad9_concat_ocaml_shape_left_fold
      (@kcad9_empty nat) (map kcad9_singleton [3; 4; 5]) in
  let k := kcad9_concat_absorb_open_back_shape_fuel 1 a b in
  kcad9_to_list k = [0; 1; 2; 3; 4; 5] /\
  inv_kcad9_ocaml_open_back_reusable_const k.
Proof.
  cbn [kcad9_concat_ocaml_shape_left_fold map kcad9_singleton
       kcad9_concat_ocaml_shape kcad9_concat_absorb_open_back_shape_fuel
       kcad9_concat_absorb_open_back_bridge_cell_fuel
       kcad9_concat_absorb_back_bridge_cell buf6_eject buf6_inject
       buf6_push buf6_empty buf6_elems].
  split; [reflexivity|].
  intros fuel.
  change (inv_kcad9_ocaml_continuation_depth fuel 1
    (K9Triple (mkBuf6 [XBase9 0])
      (mkBuf6
        [StoredSmall9 (mkBuf6 [XBase9 1]);
         StoredBig9 (mkBuf6 [XBase9 2])
           (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
           (mkBuf6 [XBase9 4])])
      (mkBuf6 [XBase9 5]))).
  split.
  - cbn [inv_kcad9_ocaml_reachable_depth inv_kcad9_ocaml_ready_or_empty_depth
         inv_kcad9_ocaml_deep_xbase front_ready_or_empty_middle9_depth
         front_ready_middle9_depth front_ready_stored9_depth
         front_ready_stored9 back_ready_or_empty_middle9_depth
         back_ready_middle9_depth back_ready_stored9_depth back_ready_stored9
         xbase_middle9_deep xbase_stored9_deep all_xbase9
         buf6_pop buf6_eject buf6_elems rev app
         buf6_size_ge buf6_size].
    repeat split; try (constructor; [exact I|constructor]);
      try exact (le_n 1).
    + right.
      exists (StoredSmall9 (mkBuf6 [XBase9 1])).
      exists
        (mkBuf6
          [StoredBig9 (mkBuf6 [XBase9 2])
             (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
             (mkBuf6 [XBase9 4])]).
      split; [reflexivity|exact (le_n 1)].
    + right.
      exists (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 1])]).
      exists
        (StoredBig9 (mkBuf6 [XBase9 2])
          (mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])])
          (mkBuf6 [XBase9 4])).
      split; [reflexivity|exact (le_n 1)].
    + repeat constructor.
  - cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth].
    split.
    + apply front_refill_continuation_ready_middle9_fuel_open_back_singleton_chunks.
    + apply back_refill_continuation_ready_middle9_fuel_open_back_singleton_chunks.
Qed.

Theorem kcad9_concat_absorb_open_back_shape_stored_middle_back_cell_continuation_depth_thm :
  let h1 := mkBuf6 [XBase9 0] in
  let t1 := mkBuf6 [XBase9 1] in
  let h2 := mkBuf6 [XBase9 2] in
  let inner := mkBuf6 [StoredSmall9 (mkBuf6 [XBase9 3])] in
  let m2 := mkBuf6 [StoredMiddle9 inner] in
  let t2 := mkBuf6 [XBase9 4] in
  let a := K9Triple h1 buf6_empty t1 in
  let b := K9Triple h2 m2 t2 in
  let k := kcad9_concat_absorb_open_back_shape a b in
  inv_kcad9_ocaml_continuation_depth 1 1 b /\
  kcad9_to_list k = [0;1;2;3;4] /\
  inv_kcad9_ocaml_continuation_depth 0 1 k.
Proof.
  vm_compute.
  repeat (cbn; repeat match goal with
  | |- _ /\ _ => split
  | |- _ \/ _ => right
  | |- exists _, _ => eexists
  | |- Some _ = Some _ => reflexivity
  | |- _ <= _ => lia
  | |- _ >= _ => lia
  | |- Forall _ _ => constructor
  | |- True => exact I
  end); try lia; try (repeat constructor); try reflexivity.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_total_under_ready_depth_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_depth depth k ->
    k <> K9Empty ->
    exists x k', kcad9_pop_ocaml_shape_fuel fuel k = Some (x, k').
Proof.
  intros fuel depth X [|b|h m t] Hinv Hne; [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_pop_xbase9 X b Hb Hxb) as [x [b' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [Hh [Hxh _]].
    destruct (buf6_pop_xbase9 X h Hh Hxh) as [x [h' Hpop]].
    cbn [kcad9_pop_ocaml_shape_fuel]. rewrite Hpop.
    destruct (Nat.leb 5 (buf6_size h')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_total_under_ready_depth_thm :
  forall (fuel depth : nat) (X : Type) (k : KCadeque9 X),
    inv_kcad9_ocaml_ready_depth depth k ->
    k <> K9Empty ->
    exists k' x, kcad9_eject_ocaml_shape_fuel fuel k = Some (k', x).
Proof.
  intros fuel depth X [|b|h m t] Hinv Hne; [contradiction Hne; reflexivity| |].
  - destruct Hinv as [Hb Hxb].
    destruct (buf6_eject_xbase9 X b Hb Hxb) as [b' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (buf6_is_empty b'); eexists; eexists; reflexivity.
  - destruct Hinv as [_ [_ [Ht [Hxt _]]]].
    destruct (buf6_eject_xbase9 X t Ht Hxt) as [t' [x Heject]].
    cbn [kcad9_eject_ocaml_shape_fuel]. rewrite Heject.
    destruct (Nat.leb 5 (buf6_size t')); eexists; eexists; reflexivity.
Qed.

Theorem kcad9_pop_ocaml_shape_fuel_inv_boundaries_under_ready_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X)
         (x : X) (k' : KCadeque9 X),
    inv_kcad9_ocaml_ready_depth depth k ->
    kcad9_pop_ocaml_shape_fuel (S depth) k = Some (x, k') ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros depth X [|b|h m t] x k' Hinv Hpop;
    cbn [kcad9_pop_ocaml_shape_fuel] in Hpop.
  - discriminate.
  - destruct (buf6_pop b) as [[e b']|] eqn:Hpb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Hpop as Hx Hk'; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    destruct (buf6_pop h) as [[e h']|] eqn:Hph; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size h')) eqn:Hcmp;
      injection Hpop as Hx Hk'; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries].
      apply PeanoNat.Nat.leb_le in Hcmp. split; [|exact Ht].
      unfold buf6_size_ge. lia.
    + destruct (buf6_is_empty h') eqn:Hempty.
      * destruct (refill_h_K9Triple_fuel_front_ready_depth
                    depth X h' m t Hempty Hfront)
          as (h'' & m' & Hrefill & Hh'').
        rewrite Hrefill. cbn [inv_kcad9_ocaml_boundaries].
        split; assumption.
      * apply refill_h_K9Triple_fuel_inv_boundaries_present.
        -- apply buf6_is_empty_false_size_ge_1. exact Hempty.
        -- exact Ht.
Qed.

Theorem kcad9_eject_ocaml_shape_fuel_inv_boundaries_under_ready_depth_thm :
  forall (depth : nat) (X : Type) (k : KCadeque9 X)
         (k' : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_ready_depth depth k ->
    kcad9_eject_ocaml_shape_fuel (S depth) k = Some (k', x) ->
    inv_kcad9_ocaml_boundaries k'.
Proof.
  intros depth X [|b|h m t] k' x Hinv Heject;
    cbn [kcad9_eject_ocaml_shape_fuel] in Heject.
  - discriminate.
  - destruct (buf6_eject b) as [[b' e]|] eqn:Heb; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (buf6_is_empty b') eqn:Hempty;
      injection Heject as Hk' Hx; subst x k'; cbn [inv_kcad9_ocaml_boundaries].
    + exact I.
    + apply buf6_is_empty_false_size_ge_1. exact Hempty.
  - destruct Hinv as [Hh [Hxh [Ht [Hxt [Hfront Hback]]]]].
    destruct (buf6_eject t) as [[t' e]|] eqn:Het; [|discriminate].
    destruct e as [y|s]; [|discriminate].
    destruct (Nat.leb 5 (buf6_size t')) eqn:Hcmp;
      injection Heject as Hk' Hx; subst x k'.
    + cbn [inv_kcad9_ocaml_boundaries].
      apply PeanoNat.Nat.leb_le in Hcmp. split; [exact Hh|].
      unfold buf6_size_ge. lia.
    + destruct (buf6_is_empty t') eqn:Hempty.
      * destruct (refill_t_K9Triple_fuel_back_ready_depth
                    depth X h m t' Hempty Hback)
          as (m' & t'' & Hrefill & Ht'').
        rewrite Hrefill. cbn [inv_kcad9_ocaml_boundaries].
        split; assumption.
      * apply refill_t_K9Triple_fuel_inv_boundaries_present.
        -- exact Hh.
        -- apply buf6_is_empty_false_size_ge_1. exact Hempty.
Qed.

