Theorem kcad9_concat_ocaml_shape_tt_empty_right_middle_back_ready_thm :
  forall (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 t2 : Buf6 (KElem9 X)),
    buf6_size_ge 1 h2 ->
    match kcad9_concat_ocaml_shape
            (K9Triple h1 m1 t1)
            (K9Triple h2 buf6_empty t2) with
    | K9Triple _ m_new _ => back_ready_middle9_depth 0 m_new
    | _ => False
    end.
Proof. apply kcad9_concat_ocaml_shape_tt_empty_right_middle_back_ready. Qed.

Theorem kcad9_concat_ocaml_shape_tt_back_nested_ready_depth_thm :
  forall (depth : nat) (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 t2 b : Buf6 (KElem9 X)),
    buf6_size_ge 1 b ->
    match kcad9_concat_ocaml_shape
            (K9Triple h1 m1 t1)
            (K9Triple h2 (back_nested_middle9 depth (StoredSmall9 b)) t2) with
    | K9Triple _ m_new _ => back_ready_middle9_depth depth m_new
    | _ => False
    end.
Proof. apply kcad9_concat_ocaml_shape_tt_back_nested_ready_depth. Qed.

Theorem kcad9_concat_ocaml_shape_tt_back_nested_not_ready_too_shallow_thm :
  forall (depth fuel_depth : nat) (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 t2 b : Buf6 (KElem9 X)),
    fuel_depth < depth ->
    ~ match kcad9_concat_ocaml_shape
              (K9Triple h1 m1 t1)
              (K9Triple h2 (back_nested_middle9 depth (StoredSmall9 b)) t2) with
      | K9Triple _ m_new _ => back_ready_middle9_depth fuel_depth m_new
      | _ => False
      end.
Proof. apply kcad9_concat_ocaml_shape_tt_back_nested_not_ready_too_shallow. Qed.

Theorem kcad9_concat_ocaml_shape_tt_back_nested_exceeds_any_depth_thm :
  forall (fuel_depth : nat) (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 t2 b : Buf6 (KElem9 X)),
    ~ match kcad9_concat_ocaml_shape
              (K9Triple h1 m1 t1)
              (K9Triple h2
                 (back_nested_middle9 (S fuel_depth) (StoredSmall9 b))
                 t2) with
      | K9Triple _ m_new _ => back_ready_middle9_depth fuel_depth m_new
      | _ => False
      end.
Proof. apply kcad9_concat_ocaml_shape_tt_back_nested_exceeds_any_depth. Qed.

Theorem kcad9_concat_ocaml_shape_tt_back_nested_exceeds_ready_depth_thm :
  forall (fuel_depth : nat) (X : Type)
         (h1 : Buf6 (KElem9 X)) (m1 : Buf6 (Stored9 X))
         (t1 h2 t2 b : Buf6 (KElem9 X)),
    buf6_size_ge 1 b ->
    match kcad9_concat_ocaml_shape
            (K9Triple h1 m1 t1)
            (K9Triple h2
               (back_nested_middle9 (S fuel_depth) (StoredSmall9 b))
               t2) with
    | K9Triple _ m_new _ => back_ready_middle9_depth (S fuel_depth) m_new
    | _ => False
    end.
Proof. apply kcad9_concat_ocaml_shape_tt_back_nested_exceeds_ready_depth. Qed.

Theorem kcad9_concat_ocaml_shape_ready_or_empty_same_depth_example_thm :
  forall fuel_depth : nat,
    let h1 := mkBuf6 [XBase9 1] in
    let t1 := mkBuf6 [XBase9 2] in
    let h2 := mkBuf6 [XBase9 3] in
    let bmid := mkBuf6 [XBase9 4] in
    let t2 := mkBuf6 [XBase9 5] in
    let a := K9Triple h1 buf6_empty t1 in
    let b :=
      K9Triple h2 (back_nested_middle9 fuel_depth (StoredSmall9 bmid)) t2 in
    inv_kcad9_ocaml_ready_or_empty_depth fuel_depth a /\
    inv_kcad9_ocaml_ready_or_empty_depth fuel_depth b /\
    inv_kcad9_ocaml_ready_or_empty_depth fuel_depth
        (kcad9_concat_ocaml_shape a b).
Proof.
  intros fuel_depth.
  assert (Hmid : buf6_size_ge 1 (mkBuf6 [XBase9 4])).
  { unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
  split.
  - cbn [inv_kcad9_ocaml_ready_or_empty_depth].
    repeat split.
    + unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
    + constructor; [exact I|constructor].
    + unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
    + constructor; [exact I|constructor].
    + left. reflexivity.
    + left. reflexivity.
  - split.
    + cbn [inv_kcad9_ocaml_ready_or_empty_depth].
      repeat split.
      * unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
      * constructor; [exact I|constructor].
      * unfold buf6_size_ge, buf6_size, buf6_elems. cbn. lia.
      * constructor; [exact I|constructor].
      * right. apply back_nested_middle9_front_ready_depth. exact Hmid.
      * right. apply back_nested_middle9_ready_depth. exact Hmid.
    + eapply kcad9_concat_ocaml_shape_inv_ready_or_empty_depth_same_thm;
        cbn [inv_kcad9_ocaml_ready_or_empty_depth];
        repeat split; try (constructor; [exact I|constructor]);
        try (unfold buf6_size_ge, buf6_size, buf6_elems; cbn; lia);
        try (left; reflexivity).
      * right. apply back_nested_middle9_front_ready_depth. exact Hmid.
      * right. apply back_nested_middle9_ready_depth. exact Hmid.
Qed.

Lemma xbase_middle9_deep_stored_middle :
  forall (X : Type) (sm : Buf6 (Stored9 X)),
    xbase_middle9_deep sm ->
    xbase_stored9_deep (StoredMiddle9 sm).
Proof.
  intros X [xs] Hdeep.
  cbn [xbase_middle9_deep xbase_stored9_deep buf6_elems] in *.
  revert Hdeep.
  induction xs as [|s rest IH]; intros Hdeep.
  - exact I.
  - inversion Hdeep as [|? ? Hs Hrest]; subst.
    cbn. split; [exact Hs|].
    apply IH. exact Hrest.
Qed.

Theorem back_nested_middle9_deep_xbase_thm :
  forall (depth : nat) (X : Type) (b : Buf6 (KElem9 X)),
    all_xbase9 b ->
    xbase_middle9_deep (back_nested_middle9 depth (StoredSmall9 b)).
Proof.
  induction depth as [|depth IH]; intros X b Hxb.
  - cbn [back_nested_middle9 xbase_middle9_deep xbase_stored9_deep
         buf6_inject buf6_empty buf6_elems].
    constructor; [exact Hxb|constructor].
  - cbn [back_nested_middle9 xbase_middle9_deep xbase_stored9_deep
         buf6_inject buf6_empty buf6_elems].
    constructor; [|constructor].
    apply xbase_middle9_deep_stored_middle.
    exact (IH X b Hxb).
Qed.

Theorem front_nested_middle9_deep_xbase_thm :
  forall (depth : nat) (X : Type) (b : Buf6 (KElem9 X)),
    all_xbase9 b ->
    xbase_middle9_deep (front_nested_middle9 depth (StoredSmall9 b)).
Proof.
  induction depth as [|depth IH]; intros X b Hxb.
  - cbn [front_nested_middle9 xbase_middle9_deep xbase_stored9_deep
         buf6_push buf6_empty buf6_elems].
    constructor; [exact Hxb|constructor].
  - cbn [front_nested_middle9 xbase_middle9_deep xbase_stored9_deep
         buf6_push buf6_empty buf6_elems].
    constructor; [|constructor].
    apply xbase_middle9_deep_stored_middle.
    exact (IH X b Hxb).
Qed.

Theorem inv_kcad9_ocaml_continuation_depth_requires_unbounded_depth_thm :
  forall fuel_depth : nat,
    exists k : KCadeque9 nat,
      inv_kcad9_ocaml_continuation_depth 0 (S fuel_depth) k /\
      ~ inv_kcad9_ocaml_continuation_depth 0 fuel_depth k.
Proof.
  intros fuel_depth.
  pose (h := mkBuf6 [XBase9 0]).
  pose (b := mkBuf6 [XBase9 1]).
  pose (t := mkBuf6 [XBase9 2]).
  pose (m := back_nested_middle9 (S fuel_depth) (StoredSmall9 b)).
  pose (k := K9Triple h m t).
  assert (Hb : buf6_size_ge 1 b).
  { unfold b, buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
  assert (Hxb : all_xbase9 b).
  { unfold b. constructor; [exact I|constructor]. }
  exists k. split.
  - split.
    + split.
      * cbn [inv_kcad9_ocaml_ready_or_empty_depth k h t].
        repeat split; try (unfold h, t, buf6_size_ge, buf6_size, buf6_elems;
                           cbn; lia);
          try (constructor; [exact I|constructor]).
        -- right. unfold m.
           apply back_nested_middle9_front_ready_depth. exact Hb.
        -- right. unfold m.
           apply back_nested_middle9_ready_depth. exact Hb.
      * cbn [inv_kcad9_ocaml_deep_xbase k h t].
        repeat split; try (constructor; [exact I|constructor]).
        unfold m. apply back_nested_middle9_deep_xbase_thm. exact Hxb.
    + cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
           front_refill_continuation_ready_middle9_fuel
           back_refill_continuation_ready_middle9_fuel].
      split.
      * split.
        -- right. unfold m.
           apply back_nested_middle9_front_ready_depth. exact Hb.
        -- exact I.
      * split.
        -- right. unfold m.
           apply back_nested_middle9_ready_depth. exact Hb.
        -- exact I.
  - intros [[Hready _] _].
    cbn [inv_kcad9_ocaml_ready_or_empty_depth k] in Hready.
    destruct Hready as [_ [_ [_ [_ [_ Hback]]]]].
    destruct Hback as [Hempty|Hback].
    + unfold m in Hempty.
      destruct fuel_depth;
        cbn [back_nested_middle9 buf6_inject buf6_empty buf6_eject
             buf6_elems] in Hempty;
        discriminate.
    + unfold m in Hback.
      exact
        (back_nested_middle9_not_ready_too_shallow
           (S fuel_depth) fuel_depth nat b ltac:(lia) Hback).
Qed.

Theorem inv_kcad9_ocaml_continuation_depth_requires_unbounded_front_depth_thm :
  forall fuel_depth : nat,
    exists k : KCadeque9 nat,
      inv_kcad9_ocaml_continuation_depth 0 (S fuel_depth) k /\
      ~ inv_kcad9_ocaml_continuation_depth 0 fuel_depth k.
Proof.
  intros fuel_depth.
  pose (h := mkBuf6 [XBase9 0]).
  pose (b := mkBuf6 [XBase9 1]).
  pose (t := mkBuf6 [XBase9 2]).
  pose (m := front_nested_middle9 (S fuel_depth) (StoredSmall9 b)).
  pose (k := K9Triple h m t).
  assert (Hb : buf6_size_ge 1 b).
  { unfold b, buf6_size_ge, buf6_size, buf6_elems. cbn. lia. }
  assert (Hxb : all_xbase9 b).
  { unfold b. constructor; [exact I|constructor]. }
  exists k. split.
  - split.
    + split.
      * cbn [inv_kcad9_ocaml_ready_or_empty_depth k h t].
        repeat split; try (unfold h, t, buf6_size_ge, buf6_size, buf6_elems;
                           cbn; lia);
          try (constructor; [exact I|constructor]).
        -- right. unfold m.
           apply front_nested_middle9_ready_depth. exact Hb.
        -- right. unfold m.
           apply front_nested_middle9_back_ready_depth. exact Hb.
      * cbn [inv_kcad9_ocaml_deep_xbase k h t].
        repeat split; try (constructor; [exact I|constructor]).
        unfold m. apply front_nested_middle9_deep_xbase_thm. exact Hxb.
    + cbn [kcad9_ocaml_refill_continuation_ready_fuel_depth
           front_refill_continuation_ready_middle9_fuel
           back_refill_continuation_ready_middle9_fuel].
      split.
      * split.
        -- right. unfold m.
           apply front_nested_middle9_ready_depth. exact Hb.
        -- exact I.
      * split.
        -- right. unfold m.
           apply front_nested_middle9_back_ready_depth. exact Hb.
        -- exact I.
  - intros [[Hready _] _].
    cbn [inv_kcad9_ocaml_ready_or_empty_depth k] in Hready.
    destruct Hready as [_ [_ [_ [_ [Hfront _]]]]].
    destruct Hfront as [Hempty|Hfront].
    + unfold m in Hempty.
      destruct fuel_depth;
        cbn [front_nested_middle9 buf6_push buf6_empty buf6_pop
             buf6_elems] in Hempty;
        discriminate.
    + unfold m in Hfront.
      exact
        (front_nested_middle9_not_ready_too_shallow
           (S fuel_depth) fuel_depth nat b ltac:(lia) Hfront).
Qed.

Theorem kcad9_push_inv_ocaml_boundaries_thm :
  forall (X : Type) (x : X) (k : KCadeque9 X),
    inv_kcad9_ocaml_boundaries k ->
    inv_kcad9_ocaml_boundaries (kcad9_push x k).
Proof. apply kcad9_push_inv_ocaml_boundaries. Qed.

Theorem kcad9_inject_inv_ocaml_boundaries_thm :
  forall (X : Type) (k : KCadeque9 X) (x : X),
    inv_kcad9_ocaml_boundaries k ->
    inv_kcad9_ocaml_boundaries (kcad9_inject k x).
Proof. apply kcad9_inject_inv_ocaml_boundaries. Qed.

Theorem kcad9_concat_ocaml_shape_inv_boundaries_thm :
  forall (X : Type) (a b : KCadeque9 X),
    inv_kcad9_ocaml_boundaries a ->
    inv_kcad9_ocaml_boundaries b ->
    inv_kcad9_ocaml_boundaries (kcad9_concat_ocaml_shape a b).
Proof. apply kcad9_concat_ocaml_shape_inv_boundaries. Qed.
